INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:10:age_period_1', 'numerology', 'Этот девятилетний отрезок проходит под знаком поворота: Колесо Фортуны окрашивает период временем, когда привычное сдвигается с места и открывается что-то новое. Скорее всего, здесь важнее гибкость, чем упорное следование старому плану, — обстоятельства могут не раз поменять маршрут. Это не значит, что от вас ничего не зависит; наоборот, ценность приобретает умение вовремя перестроиться и не держаться за то, что уже исчерпало себя. Как вы пройдёте отрезок, зависит от вашей готовности видеть в переменах приглашение, а не помеху.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:10:age_period_2', 'numerology', 'На этом витке жизни ощутимее обычного дыхание циклов — подъёмы и спады сменяют друг друга, задавая ритм всему периоду. Колесо Фортуны подсказывает: пытаться удержать ровную линию через силу здесь утомительно, куда мудрее подстроиться под естественное чередование активности и пауз. Спад в такой фазе — не провал, а часть движения, за которой обычно приходит новый подъём. Многое решает внутренний настрой: тревога делает качели изматывающими, а спокойное принятие превращает их в источник обновления. Выбор реакции — за вами.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:10:age_period_3', 'numerology', 'Отрезок, отмеченный Колесом Фортуны, нередко приносит удачные развороты — возможности, которые появляются как раз тогда, когда рушится привычный уклад. В этот девятилетний период стоит держать глаза открытыми: шанс здесь легко принять за случайную неразбериху и пройти мимо. Речь не о слепой ставке на везение, а о готовности действовать, когда открывается окно. Период располагает к тому, чтобы ловить момент и не бояться пробовать новое. Насколько щедрым он окажется, зависит и от вашей смелости, и от всей карты целиком, а не от одной позиции.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:10:age_period_4', 'numerology', 'Иногда судьба словно сама предлагает отпустить отжившее и обновиться, — и этот девятилетний цикл из таких. Колесо Фортуны здесь подсвечивает тему завершений: что-то отработавшее уходит, освобождая место следующему витку. Такое время легче прожить, если не цепляться за уходящее и не путать конец главы с концом истории. Понимание этой особенности помогает мягче обходиться с собой: перемены здесь естественны, и в них скрыт ресурс роста. Куда двинуться после поворота, во многом определяете вы сами.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:10:age_period_5', 'numerology', 'Середина пути под Колесом Фортуны — время, когда полезно свериться с направлением. Этот девятилетний отрезок склонен подбрасывать перемены, проверяющие, насколько вы гибки и готовы пересмотреть прежние решения. Не приговор и не обещание потрясений — скорее приглашение не костенеть, оставаться в диалоге с меняющейся жизнью. Здесь ценится способность отличать то, что стоит сохранить, от того, что пора отпустить. Проживёте ли вы период как турбулентность или как обновление, во многом решает ваш собственный настрой и осознанность.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:10:age_period_6', 'numerology', 'На этом отрезке колесо будто набирает ход: события ускоряются, одно тянет за собой другое, и жизнь просит от вас подвижности. Колесо Фортуны в этом девятилетнем цикле располагает к активной смене ритмов — новые обстоятельства, роли, интересы могут сменять друг друга быстрее привычного. Важно не выгореть в этой гонке: чередовать движение с восстановлением, не хвататься за всё сразу. Это склонность периода, а не его приговор — темп можно осознанно регулировать. То, что вы вынесете из отрезка, зависит от вашей меры и внимания к себе.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:10:age_period_7', 'numerology', 'Бывает, колесо замирает в нижней точке, — и этот девятилетний период как раз про умение переждать спад без отчаяния. Колесо Фортуны здесь напоминает: затишье тоже часть цикла, и за ним обычно следует новый оборот. Время располагает к тому, чтобы копить силы, переосмыслять пройденное и готовить почву для будущего подъёма, а не рваться вперёд любой ценой. Это не обещание тягот и не их отмена — скорее приглашение довериться ритму. Как вы распорядитесь паузой, зависит от вашего терпения и внутренней опоры.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:10:age_period_8', 'numerology', 'Последний в череде девятилетних отрезков проходит под знаком собирания плодов и подведения итогов. Колесо Фортуны на этом цикле подсвечивает тему интеграции: опыт прежних поворотов складывается в цельную картину, и перемены здесь чаще про мудрое обновление, чем про резкие сломы. Эту грань стоит развивать в свою пользу — оглядываться без сожалений, ценить пройденный круг и спокойно входить в следующий. Приговором период не является: как расставить акценты между итогом и новым стартом, решаете вы сами.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:10:health_crown', 'numerology', 'Смысл вы обретаете не раз и навсегда, а заново на каждом витке пути. Коронная зона с Колесом Фортуны говорит о духовности живой, меняющейся: то, что вдохновляло вчера, может исчерпаться, освобождая место новому пониманию, — и это не потеря веры, а её взросление. Такая склонность бережёт от догматизма: вы готовы пересматривать картину мира, когда жизнь делает поворот. Развивать её стоит как открытость — не цепляться за отжившие ответы, но и не обесценивать пройденное. Каждый цикл добавляет глубины, если проживать его осознанно.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:10:health_heart', 'numerology', 'Сердце в этой позиции бьётся в ритме перемен: эмоции и привязанности проходят через приливы близости и периоды отстранённости, и это ваш естественный такт, а не поломка чувств. Сердечная чакра с Колесом Фортуны говорит о человеке, чей эмоциональный тонус обновляется циклами — за теплом иногда идёт пауза, за паузой снова тепло. Беспокойство появляется, лишь когда спад воспринимается как конец; на деле это чаще разворот перед новым сближением. Склонность можно смягчать вниманием к себе и честным разговором с близкими — а как она раскроется, во многом решаете вы.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:10:health_root', 'numerology', 'Опора и жизненный тонус в вашем случае устроены необычно: они питаются не столько неподвижностью, сколько сменой ритмов. Корневая чакра отвечает за ощущение почвы под ногами, а Колесо Фортуны подсказывает, что устойчивость приходит к вам через обновление — смену обстановки, дел, впечатлений. Долгий застой скорее подтачивает бодрость, чем бережёт силы. Это склонность, а не предписание: прислушивайтесь к себе, чередуйте нагрузку с восстановлением, давайте телу и делам естественные циклы. Внутренняя опора крепнет, когда вы доверяете переменам, а не сопротивляетесь им.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:10:health_sacral', 'numerology', 'Ваша чувственность и внутренняя энергия любят перемену настроений — ровная линия им не свойственна. Сакральная зона с Колесом Фортуны говорит о натуре, где вдохновение, влечение, азарт приходят волнами: то щедрый прилив, то тихий отлив, и в этом нет ничего тревожного. Тонус здесь оживает от новизны — впечатлений, встреч, смены обстановки, — а от однообразия тускнеет. Стоит принять эту цикличность как свою особенность, а не подгонять себя под чужой ровный график. Как проявится склонность, зависит от того, насколько бережно вы относитесь к собственным ритмам.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:10:health_solar_plexus', 'numerology', 'Самооценка и воля в этой зоне живут по закону колеса: сегодня уверенность на подъёме, завтра — на спаде, и важно не принимать нижнюю точку за приговор себе. Солнечное сплетение с Колесом Фортуны располагает к тому, чтобы ценность себя не была намертво привязана к текущему успеху. Сила здесь — в способности возвращать себе бодрость после спада, а не в том, чтобы никогда не оступаться. Работать с этим помогает мягкость: замечать, что настроение и вера в себя ходят циклами, и не рубить сплеча в нижней фазе. Власти над этим ровно столько, сколько осознанности.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:10:health_third_eye', 'numerology', 'Ясность приходит к вам не ровным светом, а вспышками на поворотах. Зона третьего глаза с Колесом Фортуны описывает интуицию, которая особенно остра в моменты перемен: когда привычная картина сдвигается, вы вдруг схватываете суть, замечаете скрытый узор событий. Эту грань стоит развивать — доверять внезапному пониманию, но и проверять его трезвым умом, чтобы не спутать прозрение с азартом. Интуиция здесь работает циклами: за периодом тумана нередко следует прояснение. Насколько ярко раскроется дар, покажет вся карта, а не одна позиция.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:10:health_throat', 'numerology', 'Ваш голос и манера общаться не терпят застывших форм — им нужна смена регистров. Горловая зона с Колесом Фортуны отмечает самовыражение, которое обновляется и ищет новые темы, интонации, аудитории; повторять одно и то же из года в год для вас тускло. Это ресурс: вы умеете переизобретать способ говорить о себе и подхватывать разговор на повороте. Есть и обратная сторона — бывает трудно держать одну линию, довести начатое высказывание до конца. Баланс приходит с практикой: пусть перемены обогащают речь, но у неё остаётся и своё узнаваемое ядро.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:10:money_line', 'numerology', 'Деньги приходят к вам не ровным ручьём, а с приливами и отливами — и это стоит принять как рабочий факт, а не как невезение. Колесо Фортуны на денежной линии описывает финансы, живущие циклами: за щедрым периодом порой следует затишье, а за спадом — новый подъём. Такая натура выигрывает от подушки безопасности и от умения не тратить всё на гребне волны. Это склонность, а не приговор к вечной нестабильности: осознанность и привычка сглаживать пики и спады делают доход куда спокойнее. Само по себе колесо богатства не обещает — оно вознаграждает гибкость и трезвый расчёт.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:10:point_center', 'numerology', 'Спокойнее и увереннее всего вы, как ни странно, чувствуете себя в движении. Центр октаграммы — ваша внутренняя зона комфорта, и Колесо Фортуны помещает туда вкус к переменам: там, где иные ищут постоянства, вам уютно в потоке, в смене декораций, в лёгком азарте перед новым витком. Это ресурс — вы восстанавливаетесь, когда что-то сдвигается с места, а застой, наоборот, тяготит. Стоит лишь помнить, что и потоку нужны берега: иногда опорой становится не следующий поворот, а умение ненадолго остановиться и оглядеться.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:10:point_day', 'numerology', 'Среди ваших личных талантов Колесо Фортуны отмечает редкое умение — не цепенеть, когда обстоятельства меняются, а ловить их ритм. Точка «День» описывает то, что даётся почти само собой: вы чувствуете, где надвигается поворот, и умеете развернуться вместе с ним, а не против. Эта склонность к гибкости, к чтению циклов может стать вашей опорой — особенно там, где другие теряются от неожиданностей. Развивать её стоит осознанно: не полагаться слепо на удачу, а учиться отличать момент, когда пора действовать, от момента, когда мудрее переждать.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:10:point_f1', 'numerology', 'В этом секторе октаграммы Колесо Фортуны задаёт особую динамику — здесь ваша энергия любит движение и плохо переносит застой. Квадрант Ф1 показывает грань, где перемены работают на вас: смена задач, ритмов, обстановки будто подзаряжает, а рутина без обновления быстро гасит интерес. Это не значит, что вам суждено метаться, — скорее в этой зоне полезно закладывать разнообразие сознательно, чередовать нагрузку и отдых, впускать новое до того, как накопится усталость. Проявится ли грань как непоседливость или как здоровая гибкость, решают мера и осознанность.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:10:point_f2', 'numerology', 'Есть в вашей октаграмме участок, где особенно слышен ритм приливов и отливов. Квадрант Ф2 с Колесом Фортуны говорит о склонности жить циклами: за периодом активности здесь естественно следует пауза, за напряжением — спад, и это не сбой, а собственный такт этой зоны. Если пытаться держать ровную линию через силу, накапливается усталость; если признать чередование и планировать под него дела — появляется устойчивая продуктивность. Как распорядиться этим свойством, зависит от вас: можно бороться с волной, а можно научиться на ней держаться.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
