INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:10:point_f3', 'numerology', 'Здесь, в третьем квадранте октаграммы, тема удачи и случая проступает ярче обычного. Колесо Фортуны в зоне Ф3 располагает к тому, чтобы замечать возможности на изломе событий — там, где привычное рушится и открывается что-то ещё. Это склонность оказываться в нужный момент готовым к развороту, ловить шанс, который для других выглядит просто неразберихой. Важно не путать её с расчётом на везение: сектор даёт чутьё, но реализуется оно через действие и трезвую оценку. Насколько ярко раскроется грань, покажет вся карта в целом, а не одна позиция.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
