  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:10:point_f4', 'numerology', 'Четвёртый квадрант октаграммы — про то, как вы завершаете круг и начинаете новый. Колесо Фортуны в зоне Ф4 подсвечивает талант к обновлению: доводить цикл до конца, отпускать отжившее и без долгих сожалений входить в следующий виток. Эту грань стоит развивать в свою пользу — из неё вырастает способность не застревать в прошлом и превращать даже потери в точку роста. Не приговор и не обязанность вечно всё менять, а ресурс: там, где нужно перевернуть страницу, вы делаете это легче многих. Мера и уместность остаются за вами.', 'reviewed', 2)
