  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:10:purpose_spiritual', 'numerology', 'На духовном уровне ваша тема — принятие непостоянства как закона жизни. Колесо Фортуны в этой позиции разворачивает предназначение вокруг простой и трудной истины: всё движется, всё сменяется, и зрелость духа — в способности отпускать и доверять течению. Речь не о пассивности, а о глубоком согласии с ритмом бытия, где потеря и обретение — две стороны одного колеса. Такое понимание приходит не сразу и не насовсем, оно вызревает через прожитые циклы. Насколько далеко вы пройдёте по этому пути, определяет ваша внутренняя работа, а не судьба сама по себе.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:10:relationship_line', 'numerology', 'Отношения в вашей жизни редко стоят на месте — они дышат, проходя через сближения и отдаления. Колесо Фортуны на линии отношений говорит о склонности проживать любовь и дружбу циклами: периоды тепла сменяются паузами, а те — новым витком близости. Это не признак непрочности; напротив, пары и дружбы, где умеют переживать спады не как разрыв, а как поворот, часто оказываются самыми живыми. Важно не пугаться перемен и не принимать затишье за конец. Как сложится связь, зависит от обоих — от готовности расти вместе через смену сезонов.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
