  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:11:age_period_1', 'numerology', 'В первом девятилетнем цикле тема равновесия проступает как закладка внутренних правил честности. Справедливость окрашивает этот отрезок склонностью остро чувствовать, где справедливо, а где нет, и болезненно реагировать на обман и двойные стандарты. Это время, когда формируется личная мерка того, что честно. Как проживётся период, зависит от среды и выбора: он не предопределён, но располагает к тому, чтобы учиться прямоте и постепенно превращать чувство справедливости в осознанную опору.', 'reviewed', 2)
