INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:11:age_period_2', 'numerology', 'Второй цикл разворачивает мотив ответственности за собственные решения. Здесь одиннадцатый Аркан подсвечивает связь между поступками и их отзвуком: человек всё яснее видит, что посеянное возвращается. Это располагает к первым серьёзным взвешенным выборам и к привычке отвечать за них, не перекладывая на других. Тенденция раскрывается мягче, если не воспринимать её как строгий экзамен: период не приговор, а приглашение освоить взрослую меру честности с собой и миром.', 'reviewed', 2)
