INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:11:age_period_3', 'numerology', 'Третий девятилетний отрезок нередко становится временем сверки — когда хочется привести дела и отношения в соответствие с внутренней правдой. Справедливость располагает пересматривать договорённости, отпускать то, где перекос стал слишком заметен, и укреплять то, что честно. Это склонность к наведению порядка, а не команда «всё менять». Насколько ровно пройдёт этап, решает осознанность: спокойная сверка с собой даёт больше, чем резкие рывки, и превращает период в опору для дальнейшего.', 'reviewed', 2)
