INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:11:age_period_4', 'numerology', 'К четвёртому циклу тема причины и следствия звучит зрелее: становится виднее, из чего выросло нынешнее положение. Одиннадцатый Аркан располагает признавать свою роль в сложившемся — без самобичевания, но и без иллюзий. Это время честной инвентаризации, когда полезно назвать вещи их именами и мягко скорректировать курс. Период ничего не предрешает: он лишь склоняет к трезвости и к тому, чтобы строить дальнейшее на прочном, а не на удобном самообмане.', 'reviewed', 2)
