INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:11:age_period_5', 'numerology', 'Пятый отрезок часто ощущается как середина пути, где весы качаются заметнее обычного. Справедливость здесь располагает искать новый баланс между тем, что отдано миру, и тем, что человек оставляет себе. Это склонность честно спросить: всё ли идёт по совести, не пора ли перераспределить силы. Ответ не предписан судьбой — он рождается из осознанного выбора. Мягкая настройка равновесия в этот период возвращает ощущение цельности и бодрости, а не усталости от бесконечных уступок.', 'reviewed', 2)
