INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:11:age_period_6', 'numerology', 'В шестом цикле одиннадцатый Аркан проявляется как талант наводить справедливый порядок — уже не столько в себе, сколько вокруг. Это располагает брать на себя роль того, кто мирит, взвешивает и распределяет по-честному, будь то в семье или деле. Такую грань стоит развивать сознательно: она делает человека надёжной опорой для других. Период не диктует событий, а подсвечивает ресурс — зрелую способность держать равновесие там, где прочие теряют меру.', 'reviewed', 2)
