INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:11:age_period_7', 'numerology', 'Седьмой девятилетний отрезок склоняет к внутренней сверке итогов и к более спокойному взгляду на справедливость мира. Здесь важна не строгость, а примирение: принять, что не всё в жизни распределяется поровну, и найти в этом не обиду, а соразмерность. Одиннадцатый Аркан располагает отпускать старые счёты и мягче обходиться с собой. Это тенденция, а не приговор: чем меньше человек требует от себя безупречного суда, тем ровнее и светлее ощущается этот период.', 'reviewed', 2)
