INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:11:age_period_8', 'numerology', 'К восьмому циклу тема Справедливости звучит как итоговая цельность — согласие между прожитым и тем, во что человек верил. Это располагает смотреть на пройденное без прикрас и без излишней строгости, признавая и вклад, и честные ошибки. Одиннадцатый Аркан здесь дарит спокойствие принятия: ощущение, что жизнь сложилась по своей внутренней логике. Период ничего не предопределяет — он лишь помогает мягче обойтись с собой и увидеть в собственном пути разумную, выношенную соразмерность.', 'reviewed', 2)
