INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:11:health_crown', 'numerology', 'У вершины, где рождается чувство смысла, одиннадцатый Аркан говорит о высшем порядке вещей. Справедливость здесь — про доверие к закону причины и следствия: ощущение, что мир устроен небессмысленно и всё имеет свои корни. Такое мировоззрение даёт внутренний покой и опору, не требуя контролировать каждую мелочь. Это склонность, а не догма: она раскрывается как способность принимать порядок жизни без обиды, находя в нём не приговор, а разумную соразмерность, из которой прорастает смысл.', 'reviewed', 2)
