INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:11:health_heart', 'numerology', 'В сердечной области тема причины и следствия звучит через отношения и то, как человек обходится с чувствами. Справедливость располагает к эмоциональной взаимности: открываться там, где отвечают тем же, и не держать в себе невысказанных счетов. Такое равновесие бережёт сердечное тепло и не даёт обидам копиться в тихий груз. Это не обещание безоблачных связей, а склонность выстраивать близость на честности — и чем осознаннее человек называет свои чувства, тем легче на душе.', 'reviewed', 2)
