INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:11:health_root', 'numerology', 'На уровне корневой опоры тема равновесия отвечает за ощущение почвы под ногами. Справедливость подсказывает: устойчивость приходит там, где основание честное — когда человек не строит жизнь на том, что взято не по праву. Такая внутренняя прямота питает базовую бодрость и чувство безопасности. Это склонность, а не приговор: чем яснее и справедливее устроен быт и договорённости вокруг, тем ровнее держится жизненный тонус. Опору здесь укрепляет не сила, а согласие с самим собой.', 'reviewed', 2)
