INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:11:health_sacral', 'numerology', 'В зоне чувственности и творческой энергии одиннадцатый Аркан вносит мотив меры. Справедливость здесь — про здоровый баланс между «хочу» и «достаточно», между отдачей себя и заботой о себе. Когда удовольствие и близость строятся на взаимности, энергия течёт свободно и ровно; перекос же в любую сторону быстро считывается как усталость или пресыщение. Это тенденция, которую стоит слушать: она помогает наполняться из честных источников и не растрачивать себя там, где обмен неравный.', 'reviewed', 2)
