INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:11:health_solar_plexus', 'numerology', 'Солнечное сплетение — про волю и цену, которую человек назначает себе сам. Справедливость располагает к честной самооценке: не раздувать заслуги и не занижать себя из ложной скромности. Когда внутренние весы настроены верно, воля опирается на реальные силы, и это придаёт спокойную уверенность и бодрость в действии. Склонность к строгому суду над собой здесь тоже возможна — и её полезно замечать, возвращая к себе ту же справедливость, что человек охотно проявляет к другим.', 'reviewed', 2)
