INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:11:health_third_eye', 'numerology', 'На уровне внутреннего зрения Справедливость обостряет различение — способность отделять правду от удобной иллюзии. Здесь интуиция работает как тонкие весы: человек чувствует, где логика сходится, а где что-то подтасовано. Такая ясность располагает к трезвым, взвешенным суждениям и оберегает от самообмана. Это тенденция, которую питает спокойствие: чем меньше спешки и предвзятости, тем чище видение. Развивать её стоит без жёсткости к себе — как навык смотреть прямо, а не как повод судить.', 'reviewed', 2)
