INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:11:health_throat', 'numerology', 'Горло отвечает за голос и право называть вещи их именами. Одиннадцатый Аркан наделяет речь прямотой: тянет говорить по правде, без двусмысленностей и проглоченных слов. Когда сказанное совпадает с тем, что человек чувствует и думает, самовыражение течёт свободно и не оставляет комка недосказанного. Это склонность, а не строгое правило: развивая честную, но бережную речь, человек снимает лишнее напряжение и возвращает себе ясный, спокойный голос.', 'reviewed', 2)
