INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:11:money_line', 'numerology', 'В денежной теме одиннадцатый Аркан ставит во главу честный обмен. Справедливость располагает зарабатывать так, чтобы за каждым доходом стоял ясный вклад, и спокойно относиться к принципу «отдал — получил». Достаток здесь прибывает ровнее там, где нет перекоса: ни выжимания лишнего, ни работы себе в убыток. Это склонность, а не обещание конкретных сумм: финансовая устойчивость крепнет по мере того, как человек выстраивает отношения с деньгами на прозрачности и соразмерной отдаче.', 'reviewed', 2)
