INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:11:point_center', 'numerology', 'Спокойнее и естественнее всего этому человеку там, где всё названо своими именами и правила ясны для всех. Центр карты, занятый Справедливостью, описывает внутренний дом, где опорой служит равновесие: честный разговор, прозрачные договорённости, отсутствие двойного дна. В такой среде восстанавливаются силы, и из неё проще действовать. Стоит помнить, что это склонность, а не жёсткое условие, — но чем больше в жизни ясности и прямоты, тем устойчивее внутренняя точка покоя.', 'reviewed', 2)
