INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:11:point_day', 'numerology', 'Среди врождённых способностей здесь выделяется тонкое чувство меры — умение взвесить, где перегиб, а где недобор, и вернуть ситуацию к равновесию. Одиннадцатый Аркан, Справедливость, наделяет внутренними весами: человеку легко даётся честность с самим собой и трезвый взгляд на собственные поступки. Это талант видеть, как одно вытекает из другого, и не обманываться удобными объяснениями. Такую грань стоит развивать сознательно — она становится опорой в решениях, где другие путаются между желаемым и настоящим.', 'reviewed', 2)
