INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:11:point_f1', 'numerology', 'В первом секторе октаграммы тема равновесия окрашивает то, как человек встречает мир и первые импульсы к действию. Справедливость здесь проступает как потребность в честном начале: браться за дело без лукавства, соразмеряя силы, прежде чем обещать. Такая настройка располагает к прямоте и к тому, чтобы не начинать с обмана — ни другого, ни себя. Как именно раскроется эта грань, во многом решает осознанный выбор, а не одна лишь диспозиция.', 'reviewed', 2)
