INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:11:point_f2', 'numerology', 'Второй сектор высвечивает область, где накапливается и укрепляется собственное. Одиннадцатый Аркан вносит сюда мотив честного обладания: ценить заработанное, не присваивать лишнего и признавать вклад других. Это склонность выстраивать своё пространство на прочном, незаёмном основании, где каждое приобретение имеет ясное происхождение. Такую черту полезно развивать сознательно — она делает опору по-настоящему устойчивой, потому что под ней нет скрытого перекоса.', 'reviewed', 2)
