INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:11:point_f3', 'numerology', 'Обмен, контакты и соотнесение себя с другими — вот поле третьего сектора. Справедливость проявляется тут как чувство взаимности: давать и получать в соразмерных долях, не залезая в чужое и не обесценивая своё. Отсюда тяга к честному диалогу и умение замечать, где отношения кренятся в одну сторону. Это тенденция, а не приговор: её зрелость зависит от того, готов ли человек называть перекос вслух и мягко возвращать равновесие.', 'reviewed', 2)
