INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:11:point_f4', 'numerology', 'Там, где подводятся итоги и созревают плоды сделанного, работает четвёртый сектор октаграммы. Справедливость здесь звучит как честное подведение черты: смотреть на результат без прикрас, признавать и удачи, и промахи. Такая настройка располагает к внутренней целостности — когда человек умеет спокойно принять то, что сам вырастил. Понимание этой особенности помогает мягче относиться к себе и превратить привычку к трезвой оценке в ресурс, а не в источник самокритики.', 'reviewed', 2)
