INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:11:point_month', 'numerology', 'По материнской линии сюда приходит задача восстановить нарушенный когда-то баланс. Справедливость в этой точке говорит о наследии, где важно научиться честности там, где раньше молчали или сглаживали углы. Речь не о вине предков, а о склонности распутывать то, что оставалось неназванным: возвращать вещам их подлинные имена, не брать на себя чужого и не отдавать своего. Осознанная работа с этой темой облегчает связь с женской частью рода и превращает старый узел в спокойную внутреннюю опору.', 'reviewed', 2)
