INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:11:point_tasks', 'numerology', 'Главный урок этой конфигурации — научиться жить по внутренней правде, а не по удобству момента. Справедливость на месте ключевой задачи предлагает освоить искусство взвешенного выбора: видеть последствия, брать за них ответственность и не сваливать причину на обстоятельства. Это не обещание лёгкой дороги, а приглашение выстроить характер вокруг честности и меры. Тенденция раскрывается по мере того, как человек перестаёт искать виноватых и начинает читать связь между своими решениями и тем, что из них выросло.', 'reviewed', 2)
