INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:11:point_year', 'numerology', 'Отцовская линия задаёт мотив ответственности и честного порядка. Здесь одиннадцатый Аркан разворачивает тему справедливого распределения — сил, слова, отданного и полученного, — которую род словно передаёт для доработки. Это склонность держать данное слово и мерить себя той же меркой, что и других. Проявляется тенденция мягко, но настойчиво: как внутренний запрос на прямоту в делах, что тянутся от отцовской стороны. Насколько ровно она раскроется, зависит от осознанности и от всей карты в целом.', 'reviewed', 2)
