INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:11:purpose_ancestral', 'numerology', 'На родовом уровне предназначение звучит как восстановление равновесия в семейной истории. Одиннадцатый Аркан намекает: человеку по силам стать тем, кто распутывает старые перекосы — возвращает честность туда, где поколениями копилось невысказанное. Это не долг и не приговор, а возможность мягко закрыть незакрытые счёты рода и передать дальше более чистую опору. Раскрывается такая задача постепенно, через осознанность и готовность видеть связи между прошлым семьи и собственной жизнью.', 'reviewed', 2)
