INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:11:purpose_personal', 'numerology', 'Личное призвание здесь связано с тем, чтобы быть человеком слова и внутренней правды. Справедливость как персональный вектор располагает жить так, чтобы поступки не расходились с убеждениями, а обещанное исполнялось. Это путь честности — к себе в первую очередь — и умения нести ответственность за собственный выбор. Никакой предопределённости в этом нет: направление лишь очерчено, а наполнить его содержанием человек волен сам, шаг за шагом делая прямоту своей естественной манерой.', 'reviewed', 2)
