INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:11:purpose_social', 'numerology', 'В общественном плане одиннадцатый Аркан наделяет ролью того, кто вносит честность в общее пространство. Справедливость располагает вступаться за правду, примирять стороны и следить, чтобы вклад и признание распределялись по заслугам. Такому человеку часто доверяют роль арбитра — не по должности, а по внутренней прямоте. Это склонность, а не обязанность: насколько заметно она проявится в социуме, зависит от выбора и от того, готов ли человек быть голосом равновесия там, где другие молчат.', 'reviewed', 2)
