INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:11:purpose_spiritual', 'numerology', 'Духовный маршрут этой карты — постижение закона причины и следствия как живой, а не карательной силы. Справедливость на этом уровне предлагает учиться цельности: соединять то, во что веришь, с тем, как поступаешь. Отсюда склонность искать не поблажек у судьбы, а понимания её логики — и находить в ней не строгость, а соразмерность. Это грань, которую стоит развивать без надрыва: чем спокойнее человек принимает ответственность за своё, тем яснее ощущается внутренняя правота пути.', 'reviewed', 2)
