INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:11:relationship_line', 'numerology', 'На линии отношений Справедливость выводит на первый план взаимность и честность вдвоём. Здесь важна соразмерность вложенного: чтобы забота, внимание и уступки шли в обе стороны, а не оседали грузом на одном. Такая настройка располагает к прямым разговорам вместо накопленных обид и к союзу, где партнёры мерят себя одной меркой. Это тенденция, а не обещание: крепость связи рождается из готовности обоих называть перекосы и бережно возвращать равновесие, а не замалчивать его.', 'reviewed', 2)
