  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:12:age_period_2', 'numerology', 'Есть в вашей жизни цикл, окрашенный темой добровольной остановки. В эту пору привычные способы действовать могут вдруг перестать срабатывать — и это не сбой, а приглашение сменить ракурс. Повешенный делает такой период временем вызревания: как семя под снегом, что-то в вас копит силы, прежде чем прорасти. Понимание природы этапа помогает не корить себя за нехватку движения: здесь ценится глубина, а не скорость. Это склонность отрезка, а не предопределённая судьба — и многое зависит от того, доверитесь ли вы его неспешному ритму.', 'reviewed', 2)
