  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:12:age_period_3', 'numerology', 'Этот девятилетний отрезок Повешенный разворачивает как приглашение к паузе и переосмыслению. Возможно, в такое время жизнь мягко тормозит вас там, где вы привыкли разгоняться, — не чтобы наказать, а чтобы дать оглядеться. Двенадцатый Аркан подсказывает: полезнее не пробивать стену лбом, а отступить и поискать другой угол. Это не приговор, а тенденция периода: то, чем он станет — временем застоя или тихого прозрения, — во многом решает ваш осознанный выбор и готовность увидеть в остановке смысл, а не пустоту.', 'reviewed', 2)
