INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:12:age_period_5', 'numerology', 'В этом цикле особенно слышна тема отпускания. Повешенный предлагает пору, когда важнее отпустить лишнее, чем набрать новое, — разжать хватку там, где долго держали из привычки. Смена ракурса в такой период может касаться самых основ: взглядов, ролей, представлений о себе. Двенадцатый Аркан не обещает лёгкости, но и не грозит потерей — он про мудрое расставание с отжившим. Это склонность отрезка, а не заданность: чем осознаннее вы проживаете это отпускание, тем свободнее и легче входите в следующий этап.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:12:age_period_6', 'numerology', 'Тишина и негромкая внутренняя работа — вот к чему тяготеет один из девятилетних этапов вашего пути. Повешенный делает его временем, когда внешняя активность будто уходит на второй план, а на первый выступает осмысление. Понимание этого помогает не тревожиться из-за замедления: здесь спокойствие — не простой, а форма роста. В такую пору полезно наблюдать, ждать, давать решениям отстояться, вместо того чтобы форсировать. Это тенденция периода, а не приговор — и мягкое, без самокритики, отношение к его ритму нередко оказывается самым разумным способом его прожить.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:12:age_period_7', 'numerology', 'Этот отрезок жизни Повешенный связывает с переменой точки зрения на самого себя. Возможно, в такое время прежние ориентиры перестают казаться единственно верными, и появляется потребность посмотреть на свой путь под другим углом. Двенадцатый Аркан приглашает встретить это не как кризис, а как паузу для честной пересборки ценностей. Ничто здесь не предопределено: период может стать временем растерянности или временем ясности — разница в том, готовы ли вы осознанно принять остановку и услышать, что она пытается вам показать.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:12:age_period_8', 'numerology', 'Ещё один цикл вашей жизни проходит в ритме Повешенного — неспешном, созерцательном, обращённом внутрь. В такую пору взрослеет способность видеть привычное свежо, находить глубину там, где раньше скользили по поверхности. Этот этап хорошо использовать не для рывков, а для тонкой настройки: пересмотреть, что действительно важно, и отпустить то, что таковым лишь казалось. Это грань времени, которую можно развернуть себе на пользу, а не предначертание — раскрывается она тем полнее, чем спокойнее и осознаннее вы принимаете её тихое течение.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:12:health_crown', 'numerology', 'Коронный центр обращён к большому — к смыслу, к чувству связи с чем-то, что шире повседневности. Повешенный на этой высоте раскрывается легко: сам его образ — про взгляд из иной точки, про переворот, открывающий новое понимание. Здесь вам может быть свойственно нащупывать смысл не через доктрины и готовые ответы, а через опыт остановки, тишины, отпускания. Двенадцатый Аркан подсказывает мягко относиться к этому поиску: он не обязан быть быстрым. Понимание своей природы тут помогает не подгонять себя — внутренняя ясность вызревает в паузе, а не по расписанию.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:12:health_heart', 'numerology', 'В сердечной области — там, где живут привязанность, тепло, умение любить и принимать — Повешенный смягчает хватку. Он располагает любить без сжимания в кулак: отпускать близких в их свободу, принимать чувства такими, какие они есть, не переворачивая всё в попытке «исправить». Смена ракурса тут означает способность взглянуть на отношения глазами другого, побыть в паузе вместо немедленной реакции. Это тенденция, а не заданность — и то, обернётся ли она глубиной близости или уходом в себя, во многом решает ваш осознанный выбор в каждой конкретной связи.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:12:health_root', 'numerology', 'Корневая опора — это про почву под ногами, устойчивость, базовую жизненную силу. Повешенный вносит сюда особый оттенок: ощущение опоры может крепнуть не через привычную хватку и контроль, а через доверие и умение распустить лишнее напряжение. Двенадцатый Аркан намекает: устойчивость здесь рождается из спокойствия, а не из зажатости; иногда, чтобы почувствовать землю под ногами, полезно замедлиться и перестать судорожно за неё цепляться. Речь о внутреннем тонусе и склонности, а не о предопределённости — мягкая перенастройка отношения к опоре придаёт бодрости надёжнее, чем гонка за стабильностью любой ценой.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:12:health_sacral', 'numerology', 'Сакральная зона отвечает за вкус к жизни, чувственность, живую энергию удовольствия — и Повешенный придаёт ей неспешный, созерцательный тон. Здесь вам может быть ближе не жадное потребление впечатлений, а умение распробовать момент медленно, выбрать глубину вместо количества. Двенадцатый Аркан приглашает сменить ракурс: радость рождается не в погоне, а в паузе, когда позволяешь себе просто быть в ощущении. Это склонность, а не правило — и раскроется она тем полнее, чем меньше вы будете подгонять свои чувства и чем больше доверитесь их естественному ритму.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:12:health_solar_plexus', 'numerology', 'Солнечное сплетение — про волю, внутренний стержень, ощущение собственной ценности. Повешенный разворачивает эту тему неожиданно: сила здесь измеряется не напором, а способностью уступить контролю, не теряя себя. Ваша самооценка может расти не от количества побед, а от умения признать, что не всё надо продавливать. Двенадцатый Аркан подсказывает: порой самый достойный ход — отступить на шаг и посмотреть иначе, и это не слабость, а зрелость. Склонность эта не приговор: чем осознаннее вы отличаете мудрую паузу от избегания, тем крепче становится спокойная, не крикливая уверенность в себе.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:12:health_third_eye', 'numerology', 'Область третьего глаза — про внутреннее зрение, интуицию, способность видеть суть за поверхностью. Здесь Повешенный по-настоящему в своей стихии: его дар — смотреть на мир перевёрнутым и замечать то, что скрыто от торопливого взгляда. Ваша ясность может приходить не через анализ и напор, а через тихое созерцание, когда ум перестаёт суетиться и картина складывается сама. Это склонность, а не жёсткое правило: интуиция раскрывается тем чаще, чем больше пространства вы ей даёте. Доверие к паузе тут ценнее, чем стремление всё немедленно объяснить и разложить по полкам.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
