  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:12:health_throat', 'numerology', 'Горловой центр связан с голосом, самовыражением, умением сказать своё. Повешенный придаёт вашей манере говорить особую черту — ценность паузы и недосказанности. Иногда самое сильное высказывание здесь — молчание в нужный момент или слово, сказанное после того, как вы дали мысли отстояться. Двенадцатый Аркан приглашает выражать себя не залпом, а с внутренней остановкой, из которой рождается точность. Эту грань можно развивать: учиться слушать прежде, чем ответить, и находить свой ракурс вместо чужих готовых формул. Чем бережнее вы с ней, тем яснее и весомее звучит ваш голос.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:12:money_line', 'numerology', 'Денежная линия окрашена Повешенным в непривычные тона: достаток здесь связан не с напором и хваткой, а с умением отпустить и сменить угол зрения. Возможно, деньги приходят к вам не тогда, когда вы гонитесь за ними, а когда позволяете себе паузу и пересматриваете саму стратегию. Двенадцатый Аркан намекает: иногда стоит перевернуть привычную формулу «больше усилий — больше результата» и поискать неочевидный путь. Это тенденция, а не обещание богатства: то, как она проявится, зависит от вашего осознанного отношения к ресурсам, терпения и готовности не путать паузу с бездействием.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:12:point_center', 'numerology', 'По-настоящему в своей тарелке вы, вероятно, чувствуете себя в тишине и замедлении — там, где можно ничего не решать наскоком. Центр вашей октаграммы держит Повешенный: зона внутреннего покоя, созерцания, взгляда со стороны. Здесь вам естественно взять паузу, посмотреть на привычное свежим глазом, побыть наблюдателем прежде, чем действовать. Такой комфорт — ресурс, а не побег: он даёт устойчивость, когда вокруг спешка. Важно лишь не превращать уютную остановку в бесконечное откладывание — и тогда эта тихая зона станет надёжной опорой, из которой хорошо возвращаться к делам.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:12:point_day', 'numerology', 'Среди ваших сильных сторон есть редкий дар — умение остановиться там, где другие спешат, и посмотреть на ситуацию под неожиданным углом. Двенадцатый Аркан, Повешенный, наделяет способностью видеть привычное словно впервые: перевернуть картинку и найти в тупике не стену, а дверь. Эта черта располагает к глубине там, где вокруг ценят скорость, — и потому её порой недооценивают, в том числе вы сами. Стоит признать в себе это качество ресурсом: пауза для вас не слабость, а способ мышления. Чем осознаннее вы им пользуетесь, тем яснее становятся решения, до которых не добраться суетой.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:12:point_f1', 'numerology', 'Один из секторов вашей октаграммы, Ф1, окрашен настроением Повешенного — и в этой части жизни особенно ярко работает умение сменить ракурс. Здесь стоит развивать в себе привычку не хвататься за первое решение, а сначала повернуть задачу, посмотреть на неё с непривычной стороны. Двенадцатый Аркан подсказывает: в этом квадранте прорыв приходит через замедление, а не через нажим. Это грань характера, которую можно осознанно растить, — чем внимательнее вы к ней, тем чаще пауза оборачивается неожиданно точным ходом.', 'reviewed', 2)
