  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:12:point_f3', 'numerology', 'Есть в вашей карте область — квадрант Ф3, — где особенно нужна мягкость к себе. Повешенный придаёт ей оттенок паузы и созерцания: здесь вы, возможно, устроены так, что вам труднее гнать вперёд и легче остановиться, осмыслить, посмотреть иначе. Не стоит корить себя за этот темп — он не изъян, а особый способ проживать эту часть жизни. Понимание своей природы тут помогает обходиться с собой бережнее: то, что со стороны кажется медлительностью, изнутри нередко оказывается глубиной. Признайте эту черту — и она перестанет мешать, начав работать на вас.', 'reviewed', 2)
