  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:12:point_f4', 'numerology', 'Квадрант Ф4 вашей октаграммы хранит способность к внутреннему перевороту — умению увидеть привычное вверх ногами и вдруг понять то, что ускользало. Повешенный делает эту область местом тихих открытий: инсайты приходят сюда не в гонке, а в затишье. Эту грань можно развивать сознательно — приучать себя к паузам, к взгляду со стороны, к вопросу «а что, если посмотреть наоборот?». Не приговор и не обещание, а живая возможность: чем чаще вы даёте себе эту остановку, тем богаче становится ваш способ понимать происходящее.', 'reviewed', 2)
