INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:12:point_month', 'numerology', 'По материнской линии к вам приходит негромкая задача: научиться отпускать там, где предыдущие поколения привыкли держать и контролировать. Повешенный говорит о смене ракурса как о родовом уроке — умении переждать, довериться времени, увидеть в остановке не поражение, а точку опоры. Возможно, женщины рода несли в себе напряжение вечной готовности «тянуть» — и часть пути в том, чтобы это напряжение мягко распустить. Это не приговор, а склонность и приглашение: то, как задача раскроется, зависит от вашего осознанного выбора, а не от чьей-то предопределённости.', 'reviewed', 2)
