  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:12:point_tasks', 'numerology', 'Главный узел вашего пути завязан вокруг умения менять точку зрения. Повешенный ставит в центр не борьбу и не завоевание, а внутренний поворот: способность добровольно остановиться, чтобы увидеть жизнь иначе, чем требует привычка. Задача не в том, чтобы всё время двигаться, а в том, чтобы находить смысл в паузах и вырастать через них. Иногда прорыв приходит именно тогда, когда вы перестаёте давить и позволяете картине сложиться самой. Это направление развития, а не фатум, — и оно раскрывается тем полнее, чем осознаннее вы к нему относитесь.', 'reviewed', 2)
