  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:12:point_year', 'numerology', 'Отцовская линия приносит тему, в которой сила измеряется не действием, а способностью вовремя замереть. Там, где мужской род нередко ставил во главу угла напор и результат, двенадцатый Аркан предлагает иной ракурс: иногда самый зрелый шаг — не сделать ничего, дать событиям дозреть. Повешенный учит смотреть на дело с изнанки, находить смысл в паузе и не путать остановку с отступлением. Это располагающая тенденция, а не приговор: раскроется она настолько, насколько вы готовы переосмыслить унаследованную привычку решать всё натиском.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:12:purpose_ancestral', 'numerology', 'На уровне рода вам будто передан наказ — освоить то, на что предки не всегда находили время: искусство вовремя остановиться. Повешенный превращает родовое предназначение в тему исцеляющей паузы: где-то в линии семьи копилась привычка тянуть и не отпускать, и часть вашей роли — распустить этот узел, показать иной способ. Двенадцатый Аркан говорит о смене ракурса как о даре, который вы можете передать дальше уже облегчённым. Понимание этого помогает обходиться с собой мягче: вы не обязаны нести всё напряжение рода — достаточно осознанно прожить и переосмыслить свою часть.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:12:purpose_personal', 'numerology', 'Ваше личное предназначение звучит негромко, но ясно: показывать — прежде всего себе — что мир не исчерпывается привычным углом зрения. Повешенный делает вашим призванием умение остановиться и увидеть иначе, найти в паузе то, что ускользает в спешке. Возможно, ваш путь — не столько достигать, сколько переосмыслять, разворачивать смыслы, вносить в собственную жизнь глубину вместо погони. Это направление, которое стоит растить в себе сознательно, а не приговор: чем внимательнее вы к своему дару смены ракурса, тем отчётливее он проявляется как настоящее призвание.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:12:purpose_social', 'numerology', 'В обществе ваша роль может быть ролью того, кто замедляет общий бег и предлагает взглянуть иначе. Повешенный делает социальным призванием способность вносить паузу туда, где все спешат, — быть человеком, рядом с которым другие вспоминают, что можно остановиться и пересмотреть привычное. Двенадцатый Аркан связывает вас не с громким лидерством, а с тихим влиянием: сменой ракурса, спокойным вопросом, неочевидной точкой зрения. Это грань, которую стоит развивать сознательно, а не заданность — и раскроется она настолько, насколько вы решитесь предъявлять миру свой неторопливый взгляд.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
