  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:13:age_period_5', 'numerology', 'На пятом витке, когда внутренних сил обычно в достатке, отказ от лишнего даётся легче ради того, что по-настоящему важно. Тринадцатый Аркан здесь помогает перестроить приоритеты: отжившие цели и роли отступают, освобождая энергию для главного. Это грань этапа, которую стоит развивать в свою пользу, а не предопределённый сценарий. Полезно смотреть на завершения без драмы — как на способ сфокусироваться. Тогда склонность к переменам становится ресурсом зрелости: вы оставляете отработанное и вкладываетесь в живое, доверяя своему выбору.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
