  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:13:age_period_6', 'numerology', 'Шестой этап часто становится временем внутренней ревизии — бережного взгляда на то, что уже завершено, а что ещё дышит и просит продолжения. Тринадцатый Аркан здесь подсвечивает мягкое расставание с отжившим. Понимание такой особенности помогает не корить себя за то, что какие-то главы закрываются, и обходиться с собой теплее. Это тенденция, а не приговор — как именно она проявится, во многом решает осознанный выбор. Хорошая практика здесь — отпускать с благодарностью, признавая ценность прожитого. Так период превращается во время спокойного обновления, а не тревожной борьбы за неизменность.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:13:age_period_7', 'numerology', 'Седьмая ступень цикла нередко превращает умение отпускать в тихую мудрость. С Тринадцатым Арканом завершения на этом этапе переживаются легче — как естественная смена сезонов, а не как разрыв. Это грань периода, которую можно развивать в свою пользу: способность отделять зерно от шелухи и оставлять при себе только живое. Речь о склонности, а не о предопределённых событиях; их форму определяют ваш выбор и вся карта целиком. Опора здесь — принятие ритма, в котором одно уходит, чтобы другое пришло. Тогда отрезок дарит не ощущение убыли, а ясность и внутреннюю свободу.', 'reviewed', 2)
