  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:13:age_period_8', 'numerology', 'Восьмой круг подводит к завершению большого этапа и подготовке следующего. С Тринадцатым Арканом здесь становится ближе умение подводить итоги без страха и отпускать отслужившее с достоинством. Это не приговор и не обещание конкретных перемен, а тенденция отрезка, которую можно прожить осознанно. Ценно относиться к финалам как к порогам: за каждым закрытым этапом открывается пространство для следующего. Чем меньше вы держитесь за отжившее из тревоги, тем мягче идёт обновление. Как именно всё сложится, решают ваши шаги, а не один символ карты.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
