  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:13:health_crown', 'numerology', 'На вершине — про смысл, и Тринадцатый Аркан ведёт вас к нему через череду внутренних перерождений. В коронной зоне он располагает к духовному обновлению: прежние опоры, верования и большие ответы со временем перестают вмещать вас, и вы перерастаете их, чтобы найти следующие. Это не потеря веры, а её взросление — путь, на котором старые смыслы отмирают, освобождая место более глубоким. Тень — либо цепляться за отжившую картину, либо обесценивать всё подряд. Зрелость здесь — доверие тому, что за каждым завершением открывается более просторное понимание. Как это раскроется, зависит от вас и всей карты целиком.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:13:health_heart', 'numerology', 'Сердце в этой конфигурации умеет обновляться — и это, пожалуй, и дар, и уязвимость. Тринадцатый Аркан в сердечной зоне располагает к глубоким внутренним переменам в чувствах: отношения и привязанности проходят циклы, что-то в них отмирает и перерождается на новом уровне. Речь не о неизбежных разрывах, а о способности переживать эмоциональные завершения не как катастрофу, а как часть роста. Тень — либо холодно рубить связи, либо годами держать то, что давно остыло. Зрелость здесь — умение отпускать бережно и открывать сердце заново, доверяя, что после завершения приходит новая теплота.', 'reviewed', 2)
