  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:13:health_root', 'numerology', 'Корень — про ощущение почвы под ногами, и Тринадцатый Аркан вносит сюда особую динамику: ваша устойчивость крепнет не через неизменность, а через обновление. Похоже, вам трудно чувствовать опору там, где всё застыло; зато вы оживаете, когда позволяете старому уйти и перестраиваете основу заново. Это склонность, а не приговор: бодрость и внутренняя сила приходят, когда вы не держитесь за отжившее из страха. Помогает бережный ритм — завершать постепенно, оставляя себе точку опоры на время перемен, чтобы обновление шло без надрыва.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
