  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:13:health_throat', 'numerology', 'Голос здесь ищет правду через отказ от лишнего. Тринадцатый Аркан в горловой зоне располагает к тому, чтобы ваша речь и самовыражение периодически сбрасывали старую шелуху: отмирают заученные формулировки, чужие интонации, роли, в которых вы больше себя не узнаёте. Обновление проявляется как потребность говорить честнее и проще, отбрасывая то, что звучит фальшиво. Тень — либо резкость, когда режется по живому, либо молчание вместо трудного завершения разговора. Зрелая форма — умение вовремя сказать «здесь я ставлю точку» спокойно и ясно, освобождая место для нового, более подлинного голоса.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:13:money_line', 'numerology', 'Деньги здесь текут по логике обновления, а не накопления любой ценой. Тринадцатый Аркан на денежной линии располагает к циклам, где старые источники дохода, форматы работы или дела завершаются, освобождая место новым. Вам, возможно, тесно в замершей, «пожизненной» модели заработка — энергия возвращается, когда вы решаетесь отпустить исчерпавшее себя и перестроиться. Это склонность, а не обещание убытков или прибыли: важно отличать зрелое завершение от импульсивного обнуления. Осознанный подход превращает эту динамику в ресурс — умение вовремя закрывать нерабочее и вкладываться в то, что растёт.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:13:point_center', 'numerology', 'Парадокс: спокойнее всего вам может быть именно там, где что-то заканчивается и начинается заново. Центр октаграммы — про внутреннюю опору, и Тринадцатый Аркан ставит её на умение отпускать. В привычном застое вы, скорее всего, задыхаетесь, а вот в моменты перелома странным образом собираетесь и чувствуете себя на своём месте. Это ресурс: пока другие цепляются за старое, вы способны первым сделать шаг за порог. Комфорт в переменах не значит любовь к хаосу — зрелая форма этого качества в том, чтобы менять по-настоящему нужное и не разрушать ради самого ощущения движения.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:13:point_day', 'numerology', 'Тринадцатый Аркан здесь — не про утрату, а про редкий дар вовремя отпускать. В зоне личных талантов он проявляется как умение закрывать то, что отжило, не цепляясь за вчерашнее ради привычки. Вам, возможно, легче многих даётся расставание с ненужным: старым проектом, ролью, вещами и связями, которые давно держатся на инерции. Это талант обновления — способность расчистить пространство, чтобы в него вошло свежее. Как всякий ресурс, он раскрывается по мере осознанности: важно отличать зрелое завершение от бегства. Тогда склонность к трансформации становится вашей силой, а не поводом всё начинать с нуля из тревоги.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:13:point_f1', 'numerology', 'В этом секторе карты Тринадцатый Аркан работает как внутренняя генеральная уборка. Он отвечает за способность расчищать завалы — отношения, дела и убеждения, которые давно держатся на инерции. Здесь у вас, вероятно, силён инстинкт освобождать место: убирать лишнее, чтобы дышалось свободнее. Проявляться это может по-разному — от лёгкости в переменах до соблазна рубить сплеча. Осознанность подсказывает середину: сначала понять, что действительно отжило, а потом отпускать. Тогда квадрант становится источником обновления, а не поводом всё время что-то сносить.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:13:point_f2', 'numerology', 'Здесь тема обновления звучит тише и глубже — как медленная линька, а не резкий обрыв. Тринадцатый Аркан в квадранте Ф2 располагает к постепенным внутренним переменам: вы перерастаете прежние версии себя и оставляете их без драмы, слой за слоем. Ресурс этой зоны — терпение к процессу, понимание, что настоящая трансформация редко бывает мгновенной. Тень — застревание в бесконечном «перехожу, но никак не перейду». Помогает честный вопрос: этот этап ещё живёт или я просто боюсь поставить точку? Ответ на него превращает склонность к переменам в спокойную силу.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:13:point_f3', 'numerology', 'Представьте садовника осенью, который обрезает отжившее, чтобы весной сад ожил гуще. Примерно так Тринадцатый Аркан ведёт себя в квадранте Ф3: тут вам, возможно, дан навык вовремя убирать сухие ветви — незавершённые дела, выгоревшие связи, идеи, которые больше не плодоносят. Это не про холодность, а про заботу через отпускание. Важно не перепутать обрезку с вырубкой: зрелое проявление бережёт живое и расстаётся лишь с тем, что действительно иссякло. Тогда зона становится местом регулярного обновления, где на месте убранного вырастает более сильное.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:13:point_f4', 'numerology', 'Отлив уносит одно, чтобы прилив принёс другое — этот ритм близок квадранту Ф4 с Тринадцатым Арканом. Здесь трансформация связана с доверием естественному ходу вещей: умением отпустить в срок и не удерживать то, что уходит само. Ваш ресурс в этой зоне — чувство момента, когда пора завершать, и спокойствие перед пустой паузой, из которой рождается новое. Тень — принять любую убыль за потерю и цепляться. Осознанность помогает увидеть в завершении не обрыв, а фазу цикла. Как именно раскроется эта склонность, решает вся карта и ваш выбор, а не один Аркан.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:13:point_month', 'numerology', 'По материнской линии тянется тема больших перемен — и вместе с ней задача научиться проживать их иначе, чем это делали до вас. В роду, вероятно, накопился опыт резких сломов: переезды, разрывы, начинания с чистого листа, когда прежнее приходилось оставлять. Тринадцатый Аркан в этой точке предлагает не повторять надрыв, а превратить его в осознанное умение обновляться — мягко отпускать то, что завершилось, и беречь то, что живо. Это не груз и не приговор, а приглашение сделать семейную способность к переменам зрелой: там, где предки терпели или ломались, вы можете выбирать и завершать по-своему.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:13:point_tasks', 'numerology', 'Если свести смысл к одной фразе, ваш центральный урок звучит так: уметь завершать. Тринадцатый Аркан в точке главной задачи ставит трансформацию в самую сердцевину пути — не как разрушение, а как искусство вовремя перевернуть страницу. Жизнь будет подбрасывать ситуации, где придётся выбирать между привычным-но-мёртвым и новым-но-неясным. Смысл задачи не в том, чтобы всё ломать, а в том, чтобы различать: что отслужило и просится отпустить, а что ещё дышит. Понимание этого делает вас мягче к себе в моменты перемен и превращает страх финалов в спокойную зрелость.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:13:point_year', 'numerology', 'Отцовская ветвь приносит сюжет завершений и новых начал — то, что в роду по мужской линии, возможно, звучало как «начать заново», «поднять из руин», «отпустить и идти дальше». Тринадцатый Аркан в точке Года обозначает родовую задачу: научиться отделять отжившее без ожесточения. Речь о склонности, а не о судьбе — как она развернётся, зависит от вашего выбора и всей карты в целом. Здоровое проявление — способность подводить черту там, где этап исчерпан, и строить дальше на расчищенном месте, не сжигая за собой то, что ещё могло бы пригодиться.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:13:purpose_ancestral', 'numerology', 'На уровне рода вам, похоже, доверена задача обновления — прервать то, что отжило, и передать дальше очищенное. Тринадцатый Аркан в точке родового предназначения говорит о линии, которой важно завершить старые сценарии: страхи, повторяющиеся сюжеты, груз, тянущийся из поколения в поколение. Ваша роль — не нести это молча дальше, а мягко расстаться с отработанным, сохранив живое наследие. Это приглашение, а не приговор: как оно исполнится, решаете вы. Завершая то, что пора отпустить, вы освобождаете место не только себе, но и тем, кто идёт следом.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:13:purpose_personal', 'numerology', 'Ваше личное призвание связано с обновлением — быть тем, кто помогает завершать и начинать заново. Тринадцатый Аркан в этой точке намекает, что вы полнее всего раскрываетесь там, где нужно провести через перемену: закрыть отжившее, расчистить, дать место новому. Это не значит разрушать; скорее — сопровождать переходы, свои и чужие, с достоинством. Предназначение здесь звучит как склонность, а не разнарядка: оно исполняется настолько, насколько вы выбираете его осознанно. Там, где вы позволяете себе меняться и не боитесь финалов, личный путь обретает силу и подлинность.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:13:purpose_social', 'numerology', 'В обществе вы можете быть тем, кто помогает переменам случаться по-человечески. Тринадцатый Аркан в точке социального предназначения располагает к роли проводника через завершения: тот, кто закрывает отжившие форматы, обновляет уклад, помогает людям и делам перейти на новый виток. Ваша социальная сила — не в сохранении статус-кво, а в умении бережно демонтировать устаревшее. Тень — ломать ради самого разрушения. Зрелая форма — менять с уважением к тому, что было, оставляя людям опору в переходе. Насколько это раскроется, зависит от вашего выбора, а не от одного Аркана.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:13:purpose_spiritual', 'numerology', 'Духовный путь здесь строится на искусстве отпускать. Тринадцатый Аркан в этой точке связывает ваше предназначение с темой перерождения: расти, отбрасывая прежние оболочки — привязанности, представления о себе, старые опоры, которые уже малы. Это движение вглубь через череду тихих внутренних смертей и рождений, где каждое завершение открывает более просторный смысл. Не эзотерическая мистика, а зрелое взросление души. Проявится ли эта склонность как дар — зависит от вашей осознанности и всей карты: когда вы перестаёте цепляться, путь сам ведёт к следующему, более честному этапу.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:13:relationship_line', 'numerology', 'Отношения в вашей карте несут отпечаток обновления: Тринадцатый Аркан на линии связей говорит о способности близости меняться, а не застывать. Это не предсказание разрывов, а склонность проживать отношения как живой процесс, где отжившие форматы уступают место более честным. С вами рядом трудно законсервироваться: вы либо перерастаете связь вместе, либо чувствуете, когда что-то в ней завершилось. Тень — рубить сгоряча или, наоборот, держаться за пепел. Зрелость — отпускать бережно и обновлять близость изнутри. Как это проявится, зависит от обоих и от всей карты, а не предопределено заранее.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:14:age_period_1', 'numerology', 'Первый девятилетний цикл под знаком «Умеренности» окрашивает раннюю пору темой мягкого равновесия. В этот отрезок закладывается способность не кидаться в крайности: события и близкие словно учат ровному ритму, терпению, умению ждать. Такой фон располагает к спокойному, а не взрывному складу основ. Понимание этой особенности помогает мягче смотреть на себя-раннего: если в этом периоде было много «постепенности», это ресурс, а не скука. Умеренность в начале пути — как ровный фундамент, который потом держит всю постройку.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:14:age_period_2', 'numerology', 'Второй цикл вносит тему смешения и пробы: пора, когда разное — интересы, влияния, компании — приходится как-то совмещать в себе. Аркан «Умеренность» здесь склоняет к тому, чтобы не рвать на части, а искать сплав, подбирать пропорцию между своим и чужим. Это одна из граней периода, которую можно развивать в свою пользу: навык интеграции, полученный тут, пригодится надолго. Не жёсткая программа, а тенденция — раскрывается она тем полнее, чем меньше давления «выбрать раз и навсегда» и больше свободы пробовать и настраивать.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:14:age_period_3', 'numerology', 'Третий девятилетний отрезок под четырнадцатым Арканом просит терпения там, где хочется рывка. Это время, располагающее к постепенному вызреванию: результаты приходят не сразу, зато прочно, как медленно поднявшееся тесто. Тема баланса здесь — про умение выдержать паузу и не форсировать. Понимание этой склонности помогает мягче обходиться с собой: если период кажется «медленным», возможно, он про качество, а не про скорость. Умеренность на этом отрезке — ресурс выдержки, который стоит принять, а не подгонять.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:14:age_period_4', 'numerology', 'Ближе к середине пути, в четвёртом девятилетнем цикле, Аркан «Умеренность» вносит тему примирения накопленных противоречий. Складывается возможность свести прежде враждовавшие стороны себя — амбицию и покой, долг и желание — к рабочему согласию. Это не приговор, а склонность периода: то, как она проявится, во многом зависит от осознанного выбора. Здесь выигрывает не тот, кто ломает через колено, а тот, кто терпеливо ищет пропорцию. Умеренность в этом времени работает как настройка инструмента перед долгой партией — незаметно, но решает многое.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:14:age_period_5', 'numerology', 'Пятый девятилетний период под знаком «Умеренности» звучит как приглашение к равновесию на середине пути. Это отрезок, где ценится умение не растратить силы разом, а распределить их — как опытный ходок бережёт дыхание на длинной тропе. Тема здесь про соразмерность нагрузки и отдыха, амбиций и возможностей. Это грань, которую можно развивать в свою пользу; она бережёт от надрыва. Проявится тенденция мягче, если слушать свой ритм, а не чужой темп. Умеренность на этом отрезке — про выносливость, а не про спринт.', 'reviewed', 2)
