  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:14:age_period_6', 'numerology', 'Донастройка, а не переворот — так можно описать шестой цикл под четырнадцатым Арканом. Он располагает не к резким разворотам, а к аккуратным поправкам курса: чуть убавить здесь, чуть добавить там. Это время, когда мудрость меры особенно к месту — крайности уже утомляют, а точность радует. Это не жёсткая данность, а склонность: как именно она проявится, зависит от вашего выбора и всей карты. Умеренность здесь работает как рука, что подводит громкость к нужной — без грохота и без тишины, ровно так, чтобы звучало верно.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
