  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:14:age_period_7', 'numerology', 'Седьмой девятилетний отрезок под Арканом «Умеренность» клонит к спокойному собиранию плодов. Это пора, когда прежние крайности склонны улечься, а на первый план выходит умение соединять пережитое в цельную картину. Тема баланса тут — про интеграцию опыта, про то, чтобы примирить в себе разные возрасты и решения. Это не приговор, а тенденция: проявление зависит от осознанности и всей карты целиком. Умеренность на этом отрезке — как хороший купаж: множество лет и оттенков, сведённых в один узнаваемый, ровный вкус.', 'reviewed', 2)
