  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:14:age_period_8', 'numerology', 'Зрелое равновесие и щедрость меры — так звучит тема восьмого цикла под Арканом «Умеренность». Этот отрезок располагает к роли того, кто уравновешивает и делится накопленным — не поучая, а самим ровным присутствием. Здесь ценится способность соединять поколения, сглаживать резкости, держать тон. Это не жёсткая программа, а склонность: то, как она раскроется, во многом зависит от осознанного выбора. Умеренность в этом времени — про тихую устойчивость, что не гонится за новым любой ценой и не цепляется за старое, а спокойно течёт между ними, как вода находит свой уровень.', 'reviewed', 2)
