  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:14:health_crown', 'numerology', 'На вершине, где речь о смысле, Аркан «Умеренность» отводит от крайностей веры и отрицания к живому срединному пути. Коронная чакра в этой позиции описывает духовность без фанатизма и без пустоты: способность соединять земное и высокое, не отрекаясь ни от того, ни от другого. Ваша тенденция здесь — искать целостность, где обыденное и священное перетекают друг в друга. Это не догма, а склонность, которую стоит развивать своим темпом. Умеренность на этом уровне — про смысл, что настаивается медленно, как чай, и оттого держится, а не выветривается за день.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:14:health_heart', 'numerology', 'Сердце в этой позиции настроено не на пылкие качели, а на ровное тепло. Сердечная чакра с четырнадцатым Арканом описывает эмоциональность, которая умеет остывать, не леденея, и согревать, не обжигая. В отношениях ваша склонность — искать середину между слиянием и отдалением, давать и брать в соразмерной мере. Это одна из граней, которую стоит развивать: она бережёт от эмоционального перегорания и делает близость устойчивой. Умеренность здесь — не холодность, а умение любить долго, дозируя жар так, чтобы огонь не спалил очаг, а грел его.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:14:health_root', 'numerology', 'Опора тела и чувство «я стою на земле» здесь окрашены темой меры. Корневая чакра с Арканом «Умеренность» описывает не бьющую через край витальность, а ровную, восполняемую силу — как родник, что течёт понемногу, зато не пересыхает. Ваша устойчивость строится на режиме: сон, движение, отдых в разумной дозе поддерживают бодрость лучше любых рывков. Это склонность, а не приговор: чем внимательнее вы к простым основам, тем надёжнее ощущается почва под ногами. Умеренность на этом уровне — про заземлённость, которая не истощает, а копит.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
