  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:14:health_sacral', 'numerology', 'Удовольствие и чувственность любят точную дозу — их сила не в избытке, а в наполненности момента. Сакральная чакра с четырнадцатым Арканом описывает способность наслаждаться, не заваливаясь в крайности: ни сухого воздержания, ни жадного перебора. Здесь ваша тенденция — смаковать, а не глотать: во вкусе, близости, творчестве важнее оттенок, чем количество. Это грань, которую можно развивать в свою пользу; она дарит ту чувственную бодрость, что не оставляет опустошённости наутро. Умеренность тут — не запрет на радость, а рецепт, в котором каждая нота слышна.', 'reviewed', 2)
