INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:14:health_solar_plexus', 'numerology', 'Воля бывает разной: одна давит напролом, другая держит курс без надрыва. Чакра солнечного сплетения с Арканом «Умеренность» склоняет ко второй — к силе, которая не выжигает изнутри. Ваша самооценка здесь опирается не на победы любой ценой, а на способность соблюдать меру: настоять, где нужно, и отпустить, где упорство лишь вредит. Это тенденция, а не жёсткая данность — раскрывается она тем ровнее, чем меньше вы меряете себя крайностями «всё или ничего». Умеренность на этом уровне даёт спокойную уверенность: ровный тлеющий жар вместо вспышки и золы.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
