  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:14:health_third_eye', 'numerology', 'Ясность приходит не в лихорадке ума, а в его спокойной, отстоявшейся воде. Чакра третьего глаза с четырнадцатым Арканом связывает интуицию с равновесием: чтобы разглядеть суть, вам важно сперва унять качели «то паника, то эйфория». Здесь ваша склонность — видеть картину целиком, соединяя логику и чутьё, а не выбирая между ними. Это грань, которую можно развивать: чем ровнее внутренний фон, тем чище сигнал. Умеренность на уровне восприятия работает как отстойник для мутной воды — дайте догадке осесть, и проступит ясный узор.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
