  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:14:health_throat', 'numerology', 'Слово тоже требует пропорции: сказать слишком много — расплескать, слишком мало — недодать. Горловая чакра с Арканом «Умеренность» описывает речь, которая ищет точную дозу — где промолчать, где смягчить, где договорить до конца. Ваша тенденция здесь — быть посредником, переводить резкое в приемлемое, сводить спорящих к общему тону. Это не приговор, а склонность, которую можно оттачивать: чем осознаннее вы выбираете меру в словах, тем весомее звучит сказанное. Умеренность в самовыражении — не немота, а настроенный голос, в котором нет ни крика, ни бормотания.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
