  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:14:money_line', 'numerology', 'Деньги по этой линии любят ровный поток, а не качели «густо-пусто». Аркан «Умеренность» описывает склонность к разумному распорядку: тратить и откладывать в соразмерной мере, не заваливаясь ни в скупость, ни в мотовство. Ваша сила здесь — терпение и постепенность; достаток растёт не рывком, а накоплением, как уровень воды за плотиной. Это не приговор и не обещание богатства, а тенденция, которую можно развивать осознанно: чем спокойнее ваш финансовый ритм, тем устойчивее опора. Умеренность в деньгах — про поток, который вы направляете, а не про дамбу, что однажды прорвётся.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:14:point_center', 'numerology', 'Там, где человеку легче всего дышится, у вас — тихая гладь равновесия. Центр октаграммы с Арканом «Умеренность» описывает зону комфорта, в которой вы восстанавливаетесь через размеренность: неспешный ритм, дела по мере, ничего через край. В этом внутреннем пространстве вам естественно смешивать труд и отдых в верной дозе, не перегибая ни в аскезу, ни в излишество. Это грань, которую можно развивать в свою пользу: чем чаще вы возвращаетесь к своему спокойному темпу, тем больше сил остаётся на остальное. Комфорт здесь — не лень, а точная настройка.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:14:point_day', 'numerology', 'Есть люди, которые не спешат хвататься за крайности, а ищут точную пропорцию — как повар, что кладёт соль щепотью, а не горстью. Четырнадцатый Аркан в точке «День» описывает именно такой дар: умение смешивать несмешиваемое, соединять пыл и расчёт так, чтобы получалось цельное. Ваша сильная сторона здесь — терпение и чувство меры, способность выдержать паузу и дать вещам дозреть. Это склонность, а не жёсткая программа: раскрывается она тем ярче, чем осознаннее вы опираетесь на неё в деле, а не гасите ради быстрого результата.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:14:point_f1', 'numerology', 'В этом секторе октаграммы четырнадцатый Аркан работает как художник-акварелист: важен не яркий мазок, а то, как один цвет перетекает в другой без резкой границы. Квадрант Ф1 подсвечивает вашу способность сглаживать переходы — между задачами, людьми, настроениями, — находя оттенок, который примиряет соседние. Тема здесь всё та же: баланс и интеграция, но приложенные именно к этой части поля. Склонность к плавности можно развивать сознательно; она особенно выручает там, где резкость только ломала бы, а мягкое соединение — держит.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:14:point_f2', 'numerology', 'Представьте косу из нескольких прядей: по отдельности они слабы, вместе — прочны. Квадрант Ф2 с Арканом «Умеренность» указывает на умение сплетать разнородные нити вашей жизни в единый узор — не отбрасывая ни одну, а находя каждой место. Это склонность к терпеливой сборке, где ценится не скорость, а то, насколько ровно ложится плетение. Не приговор, а тенденция: проявится она тем полнее, чем меньше вы будете рвать «лишние» пряди и чем больше — учиться вести их вместе. В этом секторе ваша сила — в соединении, а не в отсечении.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
