  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:14:point_f3', 'numerology', 'Две реки, сливаясь, не спорят, чей поток главный, — они находят общий уровень. В квадранте Ф3 Аркан «Умеренность» описывает похожую тему: умение свести встречные силы к спокойному общему руслу. Здесь ваша тенденция — не гасить противоречия, а давать им перемешаться и успокоиться, как вода находит свою поверхность. Это сектор терпения и постепенности: результат приходит не рывком, а выравниванием. Как именно раскроется эта грань, зависит от осознанности и всей карты; но направление — к текучему равновесию, а не к жёсткому напору.', 'reviewed', 2)
