INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:14:point_f4', 'numerology', 'Всякий устойчивый ритм держится на чередовании: вдох — выдох, усилие — пауза. Квадрант Ф4 с четырнадцатым Арканом говорит о вашем чувстве такого ритма в этой части жизни: способности дозировать нагрузку, не выгорая и не застаиваясь. Тема баланса здесь прикладная — про верное распределение сил во времени. Это не жёсткая программа, а склонность, которую стоит развивать: когда вы уважаете паузы наравне с рывками, энергии хватает надольше. В этом квадранте умеренность работает как дыхание — почти незаметно, но именно она держит вас на плаву.', 'reviewed', 2)
