  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:14:point_month', 'numerology', 'По женской линии рода нередко передаётся не имущество, а умение — и здесь, в точке «Месяц», оно связано с искусством примирять. Аркан «Умеренность» намекает: среди матерей и бабушек кто-то держал равновесие в доме, разбавлял горячие ссоры холодной ясностью, сшивал разошедшееся. Родовая задача по этой линии — не растерять этот навык, а сделать его своим: учиться соединять чужие крайности, не выгорая между ними. Это тенденция, которую можно развивать; проявится она мягче, если принять её как наследство, а не как обязанность.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
