  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:14:point_tasks', 'numerology', 'Главная задача, вписанная в эту точку, звучит не как подвиг, а как долгая алхимия: превратить разрозненное в сплав. Аркан «Умеренность» ставит перед вами тему интеграции — свести вместе то, что кажется несовместимым: чувства и рассудок, скорость и глубину, своё и общее. Это не приговор, а направление роста: смысл не в том, чтобы выбрать одну сторону, а в том, чтобы найти рабочую пропорцию между ними. Как именно раскроется эта задача, зависит от вашего осознанного выбора и всей карты в целом — но вектор ясен: терпеливо искать баланс там, где других тянет к крайностям.', 'reviewed', 2)
