  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:14:point_year', 'numerology', 'Отцовская линия в точке «Год» задаёт тему постепенной, а не рывковой силы. Четырнадцатый Аркан говорит о выдержке, которую копили мужчины рода: способности вести дело вдолгую, закалять характер как металл — медленным нагревом и охлаждением, а не одним ударом. Родовая задача здесь — унаследовать это терпение и умение соединять противоположные требования жизни, не ломаясь. Это одна из граней, которую стоит развивать сознательно: она становится опорой тогда, когда вы перестаёте гнаться за мгновенным итогом и начинаете ценить ровный, накопительный ход.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:14:purpose_ancestral', 'numerology', 'У рода бывает своя незавершённая работа, и здесь она про равновесие. Аркан «Умеренность» в позиции родового предназначения намекает на задачу, которую поколения передавали дальше: научиться соединять то, что прежде разрывало семью на полюса, — строгость и мягкость, долг и желание. Ваша роль в этой эстафете — не повторить перекос, а найти середину, которая прежним не давалась. Это одна из граней, которую можно развивать в свою пользу: примиряя в себе унаследованные крайности, вы словно распутываете старый узел. Не приговор, а приглашение довести родовую тему до баланса.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:14:purpose_personal', 'numerology', 'Личное предназначение здесь звучит негромко, но внятно: быть тем, кто соединяет. Четырнадцатый Аркан в этой позиции описывает призвание примирителя и настройщика — человека, чья роль в том, чтобы находить рабочую пропорцию между людьми, идеями, крайностями. Ваш путь раскрывается не через громкие свершения, а через терпеливое сведение частей в целое. Это не жёсткий сценарий, а склонность, которую можно понять и присвоить. Понимание её помогает мягче обходиться с собой: не корить за отсутствие «яркого» призвания, а увидеть силу в редком умении гармонизировать.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:14:purpose_social', 'numerology', 'В обществе ваша возможная роль — связующее звено, а не громкий флаг. Аркан «Умеренность» в позиции социального предназначения описывает призвание посредника: человека, который сводит интересы, гасит перегибы, ищет решение, устраивающее разные стороны. Ваш вклад раскрывается через баланс — там, где другие поляризуют, вы склонны примирять. Это тенденция, а не обязанность: понимание её помогает не обесценивать «тихую» работу дипломата и настройщика. Умеренность на социальном уровне — про то, чтобы держать общий котёл в нужной температуре, не давая ему ни остыть, ни выкипеть.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:14:purpose_spiritual', 'numerology', 'Духовный путь здесь — не восхождение рывком, а долгое, ровное дозревание. Четырнадцатый Аркан в этой позиции описывает предназначение, связанное с алхимией внутреннего: терпеливым превращением сырого опыта в мудрость, каплю за каплей. Ваша тема — срединный путь, где крайности аскезы и потакания уступают место мере. Это не предначертание, а склонность, которую можно раскрывать в своём темпе. Понимание её помогает мягче относиться к себе: рост тут измеряется не вспышками озарений, а ровностью, с которой вы день за днём смешиваете земное и высокое в единый напиток.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:14:relationship_line', 'numerology', 'Отношения по этой линии держатся не на страсти-вспышке, а на выверенной пропорции близости и свободы. Четырнадцатый Аркан описывает вашу склонность строить связь как совместный рецепт: понемногу от каждого, ничего через край. Здесь ценится умение остудить ссору и подогреть остывшее, дозируя тепло так, чтобы хватало обоим. Это не готовый сценарий, а тенденция: проявится она мягче, если видеть в паре не борьбу полюсов, а поиск общего вкуса. Умеренность в отношениях — не прохлада, а долгий ровный огонь, на котором связь не подгорает и не гаснет.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:15:age_period_1', 'numerology', 'В один из ранних девятилетних отрезков жизни на первый план выходит тема притяжения и границ. Пятнадцатый Аркан на этом периоде окрашивает его густыми желаниями и первыми опытами «хочу — не могу остановиться»: привязанности к людям, вещам, ощущениям проживаются особенно ярко. Это время, когда полезно учиться замечать, где увлечённость перерастает в зависимость, — не запретами, а вниманием. Проведённый осознанно, такой цикл даёт мощный запал и вкус к жизни. Как он сложится, зависит от выбора и поддержки вокруг, а не от предначертания.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:15:age_period_2', 'numerology', 'Следующий девятилетний виток разворачивает разговор о власти соблазнов над человеком. Здесь Пятнадцатый Аркан испытывает на прочность: искушения этого периода — будь то страсть, азарт или тяга к лёгкому пути — предлагают выбор, а не приговор. Многое из того, к чему тянет сейчас, при трезвом взгляде становится ресурсом: энергией, харизмой, способностью добиваться. При взгляде вслепую — вязкой привычкой. Ценность отрезка в том, чтобы познакомиться со своей тенью честно. Куда качнётся чаша, решает осознанность, а не заранее написанный сюжет.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:15:age_period_3', 'numerology', 'На третьем девятилетнем круге тема Пятнадцатого Аркана звучит как вопрос о цепях, которые мы носим по привычке. Это период, когда старые привязанности могут проявиться особенно отчётливо: то, что раньше казалось опорой, обнаруживает себя как ограничение. Хорошая новость — именно теперь их проще разглядеть и ослабить. Работа не в том, чтобы всё разрушить, а в том, чтобы вернуть себе право выбирать. Проживётся ли этот виток как освобождение или как борьба, зависит от вашей внутренней зрелости, а не от предопределённости.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
