  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:15:age_period_4', 'numerology', 'К четвёртому девятилетнему кругу за плечами уже накоплен опыт, и Пятнадцатый Аркан ставит человека лицом к лицу с его аппетитами. Это период зрелой встречи с желанием: уже понятно, что тянет и чем это оборачивается. Самое время перейти от «меня несёт» к «я выбираю», превратив прежние зависимости в осознанную силу. Соблазн отрезка — уверить себя, что менять поздно. Но цепи этого Аркана всегда держатся слабее, чем кажется. Как распорядиться этим временем, решаете вы, а не расклад.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:15:age_period_5', 'numerology', 'Пятый виток девятилетнего цикла подсвечивает связь между тем, чем вы владеете, и тем, что владеет вами. Пятнадцатый Аркан в этот период приглашает пересмотреть привязанности — к статусу, вещам, ролям, привычному образу себя. Это не про отказ от земного, а про то, чтобы держать его в руке, а не в сердце. Освобождённая от лишнего, энергия периода становится очень плодотворной. Пройдёт ли он как трезвая ревизия или как цепляние за старое — зависит от вашей осознанности, а не от предначертанного.', 'reviewed', 2)
