  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:15:age_period_6', 'numerology', 'Ближе к шестому девятилетнему витку у человека обычно накоплен богатый внутренний материал — и Пятнадцатый Аркан предлагает не прятать его, а собрать воедино: признать свои страсти и слабости частью целого. В светлом варианте это пора большой честности с собой и обретённой свободы. В теневом — риск застрять в старых утешениях, которые давно перестали радовать. Дружба со своей глубиной доступна в любой момент. Как ляжет этот цикл, зависит от вас, а не от карты.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
