  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:15:age_period_7', 'numerology', 'На седьмом круге девятилетнего цикла Пятнадцатый Аркан говорит о мудрости, добытой через опыт соблазнов. Это время, когда прежние привязанности можно наконец увидеть без осуждения — как часть прожитого пути, а не как вину. Отрезок располагает к тому, чтобы отпускать то, что держало, и передавать другим не запреты, а понимание. Соблазн периода — цинизм, усталая уверенность, что «всё уже ясно». Живой интерес к себе и миру важнее. Наполнится ли цикл свободой или горечью, решает ваша осознанность, а не предопределение.', 'reviewed', 2)
