  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:15:age_period_8', 'numerology', 'Восьмой девятилетний отрезок завершает большой разговор о власти земного над человеком. Пятнадцатый Аркан здесь про итоговое примирение: с телом, с желаниями, с тем, что когда-то держало в плену. Это возможность прийти к лёгкости — не потому, что страсти угасли, а потому, что вы научились быть их хозяином, а не пленником. Тень периода — застывшие привычки, выдающие себя за характер. Но переписать даже поздний сюжет всегда в вашей воле. Как проживётся этот виток, зависит от выбора, а не от предначертанного расклада.', 'reviewed', 2)
