  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:15:health_crown', 'numerology', 'Коронный центр тянется к смыслу и к тому, что больше нас, — и присутствие здесь Пятнадцатого Аркана поначалу кажется парадоксом. Но именно земной, «дьявольский» Аркан напоминает: дух не обязан бежать от плоти. Ваш путь к высокому идёт не мимо материального, а сквозь него — через принятие своих страстей, а не через их отрицание. Тень тут — духовная гордыня наизнанку: либо презрение к телесному, либо подмена смысла красивыми соблазнами и «гуру». Подлинное раскрывается в честности с собой. Куда приведёт этот поиск, зависит от вашей осознанности, а не от начертанного заранее.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:15:health_heart', 'numerology', 'Сердечный центр держит всё, что связано с любовью и близостью, — и Пятнадцатый Аркан ставит тут тонкий вопрос: где заканчивается привязанность и начинается зависимость? Ваша способность любить глубоко, страстно, всем существом — большая сила. Её теневая сторона — слипание с другим до потери себя, ревность, «без тебя не могу». Задача не в том, чтобы любить меньше, а в том, чтобы любить свободно: оставаться собой рядом с тем, кто дорог. Это склонность, а не судьба — насколько тепло и здорово раскроется сердце, зависит от вашей осознанности и всей карты в целом.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:15:health_root', 'numerology', 'Корневая чакра — про землю под ногами, про «я есть, я справлюсь». Пятнадцатый Аркан здесь как нельзя кстати: он про плоть, про инстинкт выживания, про умение крепко стоять и брать своё от жизни. В сильном варианте это отменная витальность и чувство опоры. В теневом — та самая цепкость, что заставляет держаться за нажитое, за старые страхи «а вдруг не хватит». Стоит замечать, когда забота о базе превращается в тревожное накопительство. Это не про самочувствие как таковое, а про образ опоры; насколько устойчиво — зависит от вашего осознанного выбора.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:15:health_sacral', 'numerology', 'Сакральный центр отвечает за удовольствие, влечение, живую чувственность — и Пятнадцатый Аркан чувствует себя здесь как дома. Это зона, где вы соприкасаетесь с миром на вкус и на ощупь: телесная радость, страсть, магнетизм, притяжение между людьми. Дар этой связки — умение по-настоящему наслаждаться и зажигать. Оборотная грань — соблазн сделать удовольствие мерилом всего и прикипеть к источнику острых ощущений. Тут важна не строгость, а честность: понимать, что вами движет. Как раскроется эта чувственность — светло или через привязанность, — во многом решает ваша осознанность.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:15:health_solar_plexus', 'numerology', 'Солнечное сплетение — это про личную волю и про то, каким вы себя чувствуете внутри. С Пятнадцатым Арканом сюда приходит тема силы и её теневых форм. В светлом изводе — крепкий внутренний стержень, умение хотеть и добиваться, здоровый аппетит к власти над своей жизнью. В теневом — зависимость самооценки от внешнего: от одобрения, статуса, побед, без которых будто «я никто». Полезно ловить момент, когда самоуважение начинает питаться чужим взглядом. Опора на себя — навык, а не приговор: он крепнет ровно настолько, насколько осознанно вы его растите.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:15:health_third_eye', 'numerology', 'Третий глаз отвечает за внутреннее зрение — способность видеть сквозь очевидное. Пятнадцатый Аркан здесь острит взгляд на изнанку вещей: вы чуете мотивы, подтексты, чужие и свои теневые пружины. Это редкий дар прозорливости — замечать то, что прячут. Обратная сторона — соблазн застрять в подозрительности, всюду искать подвох или очароваться собственными мрачными интерпретациями. Ясность рождается там, где вы смотрите на тень без страха и без упоения ею. Проявится это как трезвая интуиция или как навязчивая мнительность — зависит от вашей внутренней зрелости, а не от предопределения.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:15:health_throat', 'numerology', 'Умение назвать вслух, выразить, произнести неудобное живёт в горловом центре. Пятнадцатый Аркан добавляет сюда дерзости и честности: вы способны говорить о том, о чём другие молчат, — о желаниях, о теневом, о запретном. Это подкупающая прямота и харизма речи. Тень прячется в другом — в привычке манипулировать словом, обольщать, обходить правду или, наоборот, глотать невысказанное, пока оно не станет комом в груди. Свобода здесь — говорить своё, не порабощая и не порабощаясь. Как зазвучит ваш голос, решает выбор, а не расклад карт.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:15:money_line', 'numerology', 'С деньгами у вас отношения живые, почти телесные — Пятнадцатый Аркан на финансовой линии наделяет здоровым аппетитом к материальному. Вы способны хотеть, зарабатывать и наслаждаться нажитым без ложного стыда, и это сила. Оборотная сторона — риск, что вещи и суммы начнут владеть вами: гонка за большим, привязка самоценности к цифрам на счету, траты как способ заглушить пустоту. Свобода тут в том, чтобы деньги оставались инструментом, а не хозяином. Достаток — навык и выбор, а не обещание карты; как сложится, зависит от вашей меры и внимательности.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:15:point_center', 'numerology', 'Уютнее всего вам там, где тепло, вкусно и осязаемо. Центр октаграммы с Пятнадцатым Арканом описывает зону, в которой вы отдыхаете через тело и чувства: еда, прикосновения, приятные ритуалы, привычная роскошь мелочей. Это законный источник восстановления — но та же мягкая колея умеет незаметно затягивать, превращая отдых в привычку, от которой трудно оторваться. Секрет в мере: пусть удовольствие остаётся гостем, которого вы приглашаете, а не хозяином, который остаётся жить. Как ляжет этот баланс, зависит от вашего внимания к себе, а не от расклада.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:15:point_day', 'numerology', 'Внутри вас живёт сильная, притягательная энергия — та, что делает человека заметным в комнате и не даёт отвести взгляд. Пятнадцатый Аркан в зоне талантов говорит о честном родстве с желанием: вы умеете хотеть по-настоящему, чувствовать вкус вещей, наслаждаться земным. Обратная сторона этого дара — склонность прикипать: к человеку, привычке, ощущению — и не замечать, где увлечение стало цепью. Сила здесь в том, чтобы называть свои страсти вслух, а не прятать их в тени. Осознанная, эта энергия становится магнетизмом и азартом; как она развернётся, решает не карта, а ваш выбор.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:15:point_f1', 'numerology', 'Один из угловых секторов вашей октаграммы окрашен темой соблазна и привязанности. В квадранте Ф1 Пятнадцатый Аркан работает как скрытый магнит: он притягивает к вам людей, ситуации и вещи, к которым легко прикипеть. Полезно замечать этот механизм — не чтобы бороться с собой, а чтобы видеть, куда уходит энергия. Там, где вы честно называете своё желание, оно становится топливом; там, где прячете, — тихой зависимостью. Это не фатум, а свойство поля: его можно развернуть себе на пользу, если действовать с открытыми глазами.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:15:point_f2', 'numerology', 'Есть в вашей схеме участок, где земное тянет сильнее обычного. Квадрант Ф2 с Пятнадцатым Арканом говорит о густоте страстей: здесь желания плотные, вкусы яркие, а хватка — цепкая. Такой заряд можно прожить двояко. Если отдаться ему вслепую, он превращается в вязкую привязанность, из которой трудно вынырнуть. Если приручить — становится редкой способностью добиваться и наслаждаться результатом без чувства вины. Тень не требует изгнания, ей нужно ваше внимание. Куда качнётся маятник, решает осознанность, а не предрешённость.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:15:point_f3', 'numerology', 'Здесь речь о том, чем вы себя связываете — иногда добровольно, иногда по инерции. В квадранте Ф3 Пятнадцатый Аркан подсвечивает узкие места, где привычка выдаёт себя за необходимость, а «я не могу иначе» скрывает старый уговор с самим собой. Хорошая новость в том, что цепи этого Аркана всегда сняты не до конца — их можно ослабить. Разглядеть свой автоматизм, назвать его — и вернуть себе право выбирать заново. Это склонность, которую вы вправе переписать; проявится она мягко или жёстко, зависит от вашей внимательности.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:15:point_f4', 'numerology', 'Замыкающий сектор октаграммы держит разговор о власти желаний над человеком — и человека над желаниями. В квадранте Ф4 Пятнадцатый Аркан собирает воедино тему тени: всё, что вы прячете от себя, копит энергию именно здесь. Пока это остаётся в темноте, оно правит исподволь. Стоит вынести на свет — и та же сила питает азарт, харизму, вкус к жизни. Работа не в том, чтобы стать «безупречным», а в том, чтобы дружить со своей глубиной. Ничего не предрешено: направление задаёте вы, а карта лишь показывает, где искать.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:15:point_month', 'numerology', 'По материнской линии к вам приходит непростой, но ценный узел. Пятнадцатый Аркан на «точке Месяца» намекает на переданный по женскому роду сюжет привязанностей: где-то там любовь срасталась с зависимостью, забота — с контролем, а «нельзя без него» звучало как закон. Ваша родовая задача — не отречься от этого наследства, а распутать его: оставить тепло и глубину чувств, но вернуть себе свободу дышать. Разглядеть, что тянется из прошлого, — уже половина работы. Это склонность, а не приговор: узел, который в вашей воле ослабить и переплести заново.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:15:point_tasks', 'numerology', 'Главная работа этой жизни закручена вокруг честности с собственными желаниями. Пятнадцатый Аркан в позиции ключевой задачи ставит перед вами вопрос без лёгких ответов: чем вы держитесь и что держит вас? Тень — не враг, а часть, которую полезнее знать в лицо, чем прятать в подвал. Ваш путь — пройти сквозь притяжение земного: страсти, привязанности, соблазны — и выйти не аскетом, а хозяином, который сам решает, когда сказать «да», а когда «хватит». Это не обещание и не предсказание результата, а направление роста: чем больше осознанности, тем свободнее рука на штурвале.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:15:point_year', 'numerology', 'Отцовская ветка рода передаёт вам разговор о власти и о том, чем человек позволяет себя держать. Здесь Пятнадцатый Аркан разворачивает тему опоры, которая порой превращалась в путы: деньги, статус, дело, страсть — то, ради чего мужчины рода готовы были поступиться собой. Задача по этой линии — научиться владеть, не становясь одержимым; брать силу от земного, но не отдавать ему поводья. Вы вправе переписать сценарий: там, где предки видели капкан, вы можете увидеть ресурс. Направление зависит от осознанности, а не от предопределения — свобода выбора остаётся за вами.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:15:purpose_ancestral', 'numerology', 'На уровне рода вам, похоже, доверена работа расплетать старые узлы. Пятнадцатый Аркан в родовом предназначении говорит о наследии зависимостей и тяжёлых привязанностей, которое копилось поколениями, — и о шансе прервать это на вас. Не обвиняя предков, а с благодарностью и трезвостью: увидеть повторяющийся сюжет, прожить его иначе и передать дальше уже больше свободы, чем получили сами. Такая миссия не про геройство, а про терпеливую внутреннюю честность. Сбудется ли она — зависит не от предначертания, а от вашей готовности смотреть и меняться.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:15:purpose_personal', 'numerology', 'Ваше личное предназначение связано с тем, чтобы приручить собственную глубину. Пятнадцатый Аркан намекает: вам дано пройти близко к огню — к сильным желаниям, страстям, соблазнам — и не сгореть, а научиться этим огнём распоряжаться. Люди с таким рисунком часто становятся теми, кто понимает человеческую тень без осуждения, потому что знаком с ней изнутри. Смысл не в том, чтобы стать «идеальным», а в том, чтобы обрести свободу там, где раньше была одержимость. Это направление, а не обещание: насколько полно оно раскроется, решают ваши выборы день за днём.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:15:purpose_social', 'numerology', 'В обществе вам отведена роль того, кто не боится тёмных тем. Пятнадцатый Аркан в социальном предназначении часто говорит о людях, которые работают с человеческими страстями, зависимостями и теневыми сторонами — и помогают другим их разглядеть. Ваша харизма и честность способны освобождать: рядом с вами проще признать неудобную правду о себе. Тень роли — соблазн властвовать над чужими слабостями вместо того, чтобы помогать другим освобождаться словом и примером. Куда вы направите это влияние, решаете вы; карта лишь указывает на силу, которую предстоит применить с умом.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:15:purpose_spiritual', 'numerology', 'Духовная линия вашего пути идёт через принятие тени, а не через бегство от неё. Пятнадцатый Аркан предлагает необычный маршрут к свету: не отречение от земного, а его освящение — умение находить смысл в теле, в желании, в самой материи. Ваш рост случается там, где вы перестаёте делить себя на «хорошего» и «стыдного» и собираете целостность. Соблазн здесь — принять чужую догму за истину или спутать духовность с очередной красивой зависимостью. Подлинное растёт из внутренней свободы. Как далеко вы пройдёте, зависит от осознанности, а не от заранее написанного сценария.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:15:relationship_line', 'numerology', 'В отношениях вас ведёт мощное притяжение — и это одновременно ваш дар и ваш урок. Пятнадцатый Аркан на линии партнёрства говорит о страсти, магнетизме, глубокой химии, но и о риске спутать любовь с зависимостью, близость — с невозможностью отпустить. Вы умеете гореть в паре ярко; вопрос в том, остаётесь ли при этом собой. Здоровая версия этой энергии — честность про желания и договорённости вместо игр и власти. Отношения складываются из двух свобод, а не из цепей. Как проявится ваша притягательность, зависит от осознанности обоих, а не от предрешённости.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:16:age_period_1', 'numerology', 'Первый из девятилетних отрезков, отмеченный этим арканом, склонен разворачиваться как время сдвигов, а не плавного течения. Башня в возрастном цикле намекает на этап, когда что-то отжившее уходит, чтобы освободить дорогу новому — привычки, обстоятельства, взгляды могут меняться быстрее обычного. Это не обещание потрясений, а описание тенденции: период располагает к обновлению и честной переоценке. Прожитый осознанно, он даёт мощный толчок росту — ведь именно на расчищенном месте удобнее строить. Ключ — не держаться за уходящее из страха, а видеть в переменах ресурс, а не угрозу.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:16:age_period_2', 'numerology', 'Когда Башня окрашивает второй девятилетний период, его лейтмотивом часто становится освобождение. Этот отрезок пути располагает к тому, чтобы сбросить лишний груз — устаревшие роли, чужие ожидания, конструкции, которые держались лишь по инерции. Со стороны такие годы могут выглядеть беспокойными, но по сути это расчистка: жизнь словно помогает избавиться от того, что мешало дышать. Тенденция периода — не разрушение, а обновление через отпускание. Насколько мягко он пройдёт, зависит от готовности человека самому пересматривать отжившее, не дожидаясь, пока обстоятельства сделают это за него.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:16:age_period_3', 'numerology', 'Третий девятилетний виток под этим арканом нередко несёт тему прозрений. Башня здесь — про моменты, когда пелена спадает и становится видно то, что раньше ускользало: в делах, в людях, в собственных иллюзиях. Такой период располагает к честности с самим собой и к решениям, которые перекраивают привычный уклад. Это не про катастрофы, а про ясность, иногда неожиданную и неудобную. Прожитый внимательно, отрезок даёт зрелость особого рода — умение видеть суть без прикрас. Стоит лишь дать таким прозрениям осесть, отделяя очищающую ясность от простого беспокойства, и не рубить сплеча по горячим следам.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:16:age_period_4', 'numerology', 'На четвёртом девятилетнем отрезке аркан Башни чаще всего проявляется как тема перестройки. Это время, когда прежние опоры могут потребовать ревизии, а на месте разобранного — вырасти что-то более прочное и честное. Период располагает не к тому, чтобы избегать перемен, а к тому, чтобы научиться отстраивать заново — спокойно, без паники разбирая завалы и оставляя нужное. Такие годы способны заметно закалить, если относиться к ним как к обновлению, а не как к беде. И то, каким получится «новое здание», во многом определяют выборы самого человека, а не обстоятельства.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:16:age_period_5', 'numerology', 'Вопросы подлинности выходят на первый план, когда пятый девятилетний период окрашен этим арканом: что настоящее, а что держится на привычке и вот-вот осыплется. Башня на этом отрезке располагает к смелым переоценкам — работы, окружения, самого образа жизни. Внешне это может ощущаться как турбулентность, но внутренне чаще оказывается взрослением: человек перестаёт мириться с тем, что давно ему не по размеру. Тенденция периода — освобождение через честность. Пройденный осознанно, он приносит ощущение, что жизнь наконец стала своей, а не унаследованной по инерции.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:16:age_period_6', 'numerology', 'Мотив внезапных поворотов, за которыми открывается второе дыхание, часто силён на шестом девятилетнем цикле, окрашенном Башней. Этот отрезок пути располагает к обновлению через отказ от того, что исчерпало себя, — пусть даже расставаться приходится с привычным и удобным. Понимание этой особенности помогает мягче проходить период: не цепляться из последних сил, а довериться, что на освободившемся месте появится нечто более живое. Такие годы редко бывают скучными; их энергия — в способности начать заново. А насколько созидательным будет этот старт, зависит от того, с каким настроем человек его встречает.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:16:age_period_7', 'numerology', 'Время честной инвентаризации — вот на что похож седьмой девятилетний отрезок, тронутый Башней. То, что построено на компромиссах с собой, здесь может дать трещину — и это не приговор, а возможность наконец привести жизнь в согласие с собственной правдой. Период располагает к решительным, порой неожиданным шагам, которые расчищают залежавшееся. Прожитый внимательно, он приносит редкое чувство лёгкости — как после того, как выбросишь всё лишнее из переполненного дома. Мягкость к себе в такие годы — позволять переменам идти, не подгоняя и не тормозя их насильно.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:16:age_period_8', 'numerology', 'Восьмой девятилетний виток, отмеченный Башней, нередко становится временем зрелого обновления — когда перемены проживаются уже не как удар судьбы, а как осознанный выбор освободиться от лишнего. Этот период располагает к тому, чтобы отпустить отжившие роли и убеждения с достоинством, оставив только то, что действительно своё. Накопленный опыт помогает встречать сдвиги спокойнее, чем в молодости: человек уже знает, что за расчисткой приходит простор. Тенденция отрезка — не разрушение, а мудрое упрощение. И как всегда с этим арканом, направление задаёт сам идущий, а не обстоятельства.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:16:health_crown', 'numerology', 'Коронная зона отвечает за связь с большим смыслом, и Башня разворачивает здесь тему духовных переломов. Речь о моментах, когда прежняя картина мира вдруг перестаёт вмещать опыт и рассыпается, освобождая место более просторному пониманию. Такой человек склонен к кризисам смысла, которые на поверку оказываются точками роста: старая вера в то, как всё устроено, уступает живому, выстраданному знанию. Это не потеря опоры, а её углубление. Проявится ли это мягким прозрением или через потрясение — во многом зависит от готовности отпускать отжившие ответы и оставаться открытым новым вопросам.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:16:health_heart', 'numerology', 'Сердечная зона в этом сочетании не терпит фальши. Башня здесь про эмоции и привязанности, которые проходят проверку на подлинность: отношения, построенные на удобстве или страхе одиночества, рано или поздно дают трещину — и это, как ни странно, очищающий процесс. Такая натура склонна к глубоким, честным связям и с трудом выносит притворную теплоту. Перемены в сфере чувств здесь — не катастрофа, а способ сердца сбросить то, что мешало ему дышать. Бережное отношение к этой грани — не цепляться за отжившее из страха, а доверять, что расчищенное место заполнится более настоящим.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:16:health_root', 'numerology', 'Корневая чакра — про ощущение почвы под ногами, а Башня вносит в эту опору мотив движения. Такое сочетание описывает человека, чья устойчивость проверяется переменами: внешние опоры — привычный уклад, гарантии, знакомая обстановка — здесь не любят застывать надолго. Это не приговор, а приглашение искать корень не снаружи, а внутри: настоящая базовая безопасность у такой натуры рождается из доверия себе, а не из неизменности декораций. Для ровного тонуса и бодрости важнее всего ритм и заземляющие ритуалы — сон, движение, простые повторяемые дела, которые возвращают чувство опоры даже в турбулентности.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:16:health_sacral', 'numerology', 'Область чувственности и творческого потока в этом сочетании живёт волнами: подъёмы сменяются спадами, вдохновение приходит вспышками, а не ровным светом. Сакральная зона с Башней располагает к яркому, но переменчивому переживанию удовольствия и близости — застой и рутина гасят здесь энергию быстрее всего. Это склонность, а не судьба: она может проявляться как страстность и лёгкость на подъём, а может — как эмоциональные качели, если игнорировать собственные ритмы. Мягкое обращение с этой гранью — позволять чувствам обновляться, не удерживая силой ни восторг, ни спад, и находить радость в самой смене состояний.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
