  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:17:money_line', 'numerology', 'На денежной линии «Звезда» связывает достаток с верой в изобилие и вдохновением. Есть склонность притягивать возможности через оптимизм и открытость: когда человек верит, что дорога найдётся, он охотнее замечает шансы и пробует новое. Деньги здесь идут рядом со смыслом и мечтой, а не с одной лишь гонкой. Тонкость в том, чтобы надежда не подменяла расчёт: вдохновение задаёт направление, но плоды приносит соединённое с ним действие и трезвый счёт. Это не обещание богатства, а описание ресурса — доверия к достатку, которое стоит подкреплять конкретными шагами.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:17:point_center', 'numerology', 'В самом сердце матрицы, там, где человек отдыхает и восстанавливается, «Звезда» создаёт тихую атмосферу принятия и веры. Зона комфорта здесь — это состояние, когда можно выдохнуть, довериться жизни и почувствовать, что всё ещё впереди. Такой внутренний свет питает: из него черпают силы после усталости, к нему возвращаются, чтобы успокоиться. Склонность — искать покой не в контроле, а в надежде, в ощущении простора и чистоты. Развивать это можно бережно: позволяя себе мечтать, замедляться, набираться сил, — и тогда центр становится настоящим родником, а не местом ухода от дел.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:17:point_day', 'numerology', 'Точка «День» показывает то, что человек несёт в мир открыто, — и Семнадцатый Аркан окрашивает эту витрину светом надежды. Там, где другие видят тупик, такой человек различает проблеск: он умеет верить в лучший исход и заражать этой верой окружающих. Талант здесь — не наивный оптимизм, а способность держать ориентир в темноте, как держат курс по звезде. Проявится ли это как вдохновляющая опора для близких или растворится в мечтах о несбыточном — зависит от того, сколько трезвости человек добавляет к своей вере. «Звезда» даёт не приговор, а внутренний источник, из которого можно черпать, когда вокруг сгущается.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:17:point_f1', 'numerology', 'Квадрант Ф1 — один из секторов октаграммы, где формируется определённый склад внутренних ресурсов. Семнадцатый Аркан привносит сюда мотив надежды: способность не опускать руки, видеть возможность там, где условия кажутся скупыми. Это располагает к внутренней устойчивости особого рода — не жёсткой, а гибкой, питаемой верой в то, что ситуация может выправиться. Как этот ресурс раскроется, зависит от общего рисунка карты и от того, насколько человек готов ему довериться. «Звезда» не обещает лёгкой дороги — она даёт свет, при котором дорогу видно.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:17:point_f2', 'numerology', 'Ещё один сектор октаграммы, Ф2, отвечает за свой набор внутренних опор — и здесь «Звезда» звучит темой обновления. После трудного отрезка такой человек способен восстанавливаться, будто омывшись чистой водой: возвращать себе лёгкость, отпускать пережитое, начинать заново без надрыва. Склонность этой зоны — верить, что за спадом приходит подъём, и не застревать в унынии дольше необходимого. Это не значит закрывать глаза на сложности; скорее — хранить внутренний источник, из которого можно пополнять силы. Насколько он наполнен, во многом решает сам человек.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:17:point_f3', 'numerology', 'В квадранте Ф3 раскрывается то, чем человек делится с внешним миром, и Семнадцатый Аркан придаёт этому щедрый, вдохновляющий тон. Есть склонность становиться для других светом ориентира: поддержать словом, вернуть веру, показать, что не всё потеряно. Такая щедрость наполняет и самого дарящего — надежда, отданная другим, редко оставляет пустым. Важно лишь не растратить себя без остатка, спасая всех подряд. «Звезда» здесь располагает к роли тихого маяка, но каким будет его свет и на кого направлен — выбирает сам человек.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:17:point_f4', 'numerology', 'Сектор Ф4 октаграммы связан с тем, как человек заглядывает в будущее, — и «Звезда» окрашивает этот взгляд мечтой. Здесь живёт способность представлять лучшее, строить образ желаемого и тянуться к нему, не теряя вдохновения. Это ценный ресурс: мечта задаёт направление, придаёт смысл усилиям, не даёт застыть. Тонкая грань — удержать мечту в связи с реальностью, чтобы она вела, а не уводила. Семнадцатый Аркан располагает к вере в перспективу; насколько эта вера станет крыльями, а не облаком, зависит от того, сколько человек добавит к ней действия.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:17:point_month', 'numerology', 'Умение не гасить надежду — вот что материнская линия передаёт вам как родовую задачу. Женщины рода, возможно, передавали способность видеть свет впереди даже в трудные времена, и Семнадцатый Аркан подсказывает: этот дар стоит принять и пронести дальше. Родовая тема здесь — вернуть веру туда, где её однажды растеряли: научиться мечтать без вины, доверять течению жизни, восстанавливать силы после потрясений. Это не долг, взваленный предками, а мягкое приглашение развить в себе то, к чему располагает материнская ветвь.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:17:point_tasks', 'numerology', 'Главная жизненная задача под знаком Семнадцатого Аркана звучит почти как призвание — стать проводником надежды. Не в смысле громких обещаний, а в умении находить и зажигать свет там, где его перестали ждать: в себе, в деле, в других людях. Такого человека располагает вдохновлять, восстанавливать веру, показывать перспективу. Важно не путать это с бегством в мечты: задача выполняется, когда вдохновение опирается на реальные шаги. «Звезда» здесь — компас, а не убаюкивающая сказка; куда он приведёт, решает сам человек своими выборами.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:17:point_year', 'numerology', 'Отцовская ветвь вносит свой оттенок: здесь «Звезда» говорит о вере как об опоре, которую передают через поколения мужской линии. Речь о способности задавать направление — быть тем ориентиром, на который можно равняться, когда сбит с толку. Задача этой точки — не столько добиваться, сколько вдохновлять и удерживать горизонт: показывать, что после любой засухи бывает свежая вода. Проявляется это по-разному, и многое зависит от осознанности, но склонность ясна — превращать пережитый родом опыт в спокойную уверенность, что впереди есть к чему стремиться.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:17:purpose_ancestral', 'numerology', 'На уровне рода «Звезда» говорит о задаче вернуть и сохранить надежду для всей линии. Возможно, где-то в семейной истории вера в лучшее была подорвана, и теперь есть склонность стать тем, кто восстанавливает этот свет — не упрёком предкам, а благодарностью и обновлением. Родовое предназначение здесь — передавать дальше не тревогу, а доверие к жизни; учить своих близких мечтать и подниматься после трудностей. Это одна из граней, которую можно бережно развивать в свою пользу и на благо рода. Как она раскроется, зависит от осознанности и от всей карты в целом.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:17:purpose_personal', 'numerology', 'Личное предназначение под Семнадцатым Арканом связано с тем, чтобы жить из надежды и нести её как свой личный свет. Это путь человека, которому важно верить в лучшее и превращать эту веру в дела: вдохновлять, восстанавливать, показывать перспективу. Реализуется оно не через громкие свершения, а через саму способность сохранять внутренний ориентир и делиться им. Склонность здесь — искать своё, следовать за мечтой, доверять течению собственной жизни. Это не заранее прописанный сценарий, а приглашение: раскрыть в себе того, кто умеет светить, и решить, как именно распорядиться этим даром.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:17:purpose_social', 'numerology', 'В обществе «Звезда» раскрывается как призвание вдохновлять многих. Социальное предназначение здесь связано с тем, чтобы вносить в общее пространство надежду: поддерживать, объединять вокруг светлой идеи, показывать людям перспективу, когда они её теряют. Это может проявляться в самых разных ролях — от наставничества до творчества, — но суть одна: быть ориентиром, за которым тянутся. Склонность отдавать свет вовне наполняет смыслом, если человек не забывает восполнять себя. Каким станет этот вклад и на какую аудиторию направлен, определяют собственные выборы, а не предопределённый сценарий.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:17:purpose_spiritual', 'numerology', 'Духовное предназначение с Семнадцатым Арканом — это путь веры в самом глубоком смысле слова. Речь не о религии, а о живом доверии к жизни: способности чувствовать свет за пределами видимого и черпать из него силу. Такому человеку располагает роль тихого источника надежды для других — не проповедью, а самим присутствием, спокойной уверенностью, что тьма не окончательна. Развивать эту грань помогают тишина, честность с собой, готовность отпускать лишнее и доверять большему. «Звезда» здесь не обещает откровений по расписанию — она указывает направление, по которому душа хочет расти.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
