  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:17:relationship_line', 'numerology', 'В сфере близости «Звезда» приносит веру в любовь и способность видеть в партнёре лучшее. Линия отношений здесь окрашена надеждой: склонностью строить связь на доверии, вдохновлять друг друга, восстанавливаться после ссор, не копя обид. Такой человек умеет вносить в отношения свет и мечту о совместном будущем. Оборотная сторона — риск идеализировать и не замечать реального человека рядом; ясность приходит, когда надежда сочетается с трезвым взглядом. Семнадцатый Аркан не обещает конкретных встреч или сроков — он описывает саму способность любить открыто, к которой располагает эта позиция.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:18:age_period_1', 'numerology', 'В первом девятилетнем цикле лунная тема задаёт тон внутреннему миру: это время, когда особенно важны ощущение защищённости, тёплая атмосфера и право фантазировать. Восемнадцатый аркан подсвечивает богатое воображение, впечатлительность, раннюю чуткость к настроению вокруг. Такой период располагает к тому, чтобы учиться доверять чувствам и не бояться неизвестного. Это не сценарий с гарантиями, а окраска этапа — то, как она проявится, зависит от среды и от осознанного отношения к себе. Понимание этой ноты помогает мягче раскрывать её ресурс.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:18:age_period_2', 'numerology', 'Следующий девятилетний отрезок окрашен темой поиска себя в полутонах. Луна усиливает интуицию и чувствительность в момент, когда мир становится сложнее и однозначных ответов всё меньше. Это время учиться жить с неопределённостью: пробовать, ошибаться, сверяться с внутренним откликом, а не только с чужими мнениями. Впечатлительность может обостряться — и в этом не слабость, а взросление чутья. Это склонность, а не предначертание: многое решает то, насколько бережно вы обходитесь с собой на этом этапе.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
