  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:18:age_period_3', 'numerology', 'На этом витке жизни лунное начало зовёт вглубь — к творчеству, к образному мышлению, к более зрелому диалогу с собственным подсознанием. Период располагает доверять наитию в выборах и находить опору не только во внешних ориентирах, но и во внутренней тишине. Туман неопределённости здесь может ощущаться сильнее, но вместе с ним растёт и умение сквозь него двигаться. Как именно раскроется этот этап — не предрешено; это тенденция, которую осознанность способна обратить в ресурс, а невнимание — в тревожность.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:18:age_period_4', 'numerology', 'Этот девятилетний цикл предлагает соединить чутьё с делом. Луна к этому времени звучит уже не смутным предчувствием, а накопленным опытом распознавать людей и ситуации почти сразу. Период располагает опираться на интуицию зрело — проверяя её, но и доверяя ей там, где логике не хватает данных. Важно не растерять чувствительность в потоке обязанностей и оставлять место тишине. Это одна из граней жизни, которую можно развивать в свою пользу, выбирая внимание к себе вместо вечной спешки.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
