INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:18:age_period_5', 'numerology', 'Ближе к середине пути лунная тема часто разворачивается как потребность в глубине и осмыслении. Восемнадцатый аркан на этом отрезке располагает прислушиваться к себе внимательнее: к снам, к тихим сигналам настроения, к тому, что раньше отодвигалось на потом. Это время мягкой сверки — туда ли идёшь, тем ли живёшь. Неопределённость здесь не враг, а приглашение к честному разговору с собой. Проявится ли этап тревогой или обновлением — во многом зависит от вашего осознанного выбора и всей карты в целом.', 'reviewed', 2)
