INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:18:age_period_6', 'numerology', 'К этой поре жизни чутьё нередко вызревает в тихую мудрость. Луна располагает к тому, чтобы делиться накопленной чувствительностью — понимать людей, создавать вокруг атмосферу покоя, быть тем, к кому приходят за пониманием без осуждения. Период просит и заботы о себе: беречь внутренний источник, не растрачиваясь на чужие бури. Это тенденция, а не приговор — она раскрывается настолько, насколько осознанно вы позволяете себе и глубину, и отдых. Ресурс здесь — в спокойном доверии тому, что вы уже знаете сердцем.', 'reviewed', 2)
