  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:18:age_period_7', 'numerology', 'Поздний девятилетний цикл окрашен тягой к тишине и смыслу. Лунная тема звучит как примирение с неизвестностью: меньше нужды всё контролировать, больше доверия течению жизни, как воде, которая сама находит путь. Период располагает к созерцанию, к внутренней работе, к бережной связи с воспоминаниями и снами. Впечатлительность может усиливаться, и ей полезны мягкость и покой. Это одна из граней этапа, которую можно проживать себе во благо, выбирая принятие вместо борьбы с тем, что не в нашей власти.', 'reviewed', 2)
