  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:18:age_period_8', 'numerology', 'На этом отрезке лунное начало приглашает к спокойному итогу — не к сведению всего к ясным формулам, а к принятию жизни во всей её недосказанности. Восемнадцатый аркан располагает ценить тишину, интуитивную мудрость, тонкую связь с близкими и с тем, что за пределами очевидного. Неопределённость к этому времени может ощущаться уже не тревожно, а мягко, как привычные сумерки. Понимание этой ноты помогает обходиться с собой бережнее и находить опору внутри. Как проживётся этап — зависит от осознанности и всей карты целиком.', 'reviewed', 2)
