INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:18:health_crown', 'numerology', 'На вершине, где рождается ощущение смысла, лунная тема раскрывается как тяга к тайне и к тому, что больше нас. Восемнадцатый аркан располагает к мистическому чувству жизни: вы улавливаете связь вещей интуитивно, вам близки символы, тишина, созерцание, ощущение невидимых течений. Смысл приходит к вам не через жёсткие догмы, а через переживание и внутренний отклик. Важно лишь не терять в этих глубинах связь с землёй. Это не предопределение, а склонность, которая раскрывается настолько, насколько осознанно вы её проживаете.', 'reviewed', 2)
