INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:18:health_heart', 'numerology', 'Сердечная тема здесь звучит глубоко и приливно. Луна наделяет вас способностью чувствовать тонко, любить с оттенком нежной заботы, угадывать состояние близкого без слов. Эмоции могут накатывать волнами, и в этом их богатство, а не поломка. Важно лишь не растворяться в переживаниях других целиком и оставлять свет и для себя. Понимание этой чуткости помогает мягче обходиться с собой: не корить за впечатлительность, а видеть в ней дар глубокой связи. Насколько тепло он раскроется, во многом зависит от вашего выбора и от всей карты.', 'reviewed', 2)
