INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:18:health_root', 'numerology', 'Опора и жизненный тонус связаны здесь с чувством внутренней безопасности. Луна вносит в эту телесную основу тему эмоционального тыла: устойчивость приходит к вам не столько через жёсткий контроль, сколько через покой, ощущение дома, привычный ритм и заботу о себе. Когда вокруг тревожно и всё зыбко, полезно возвращаться к простым опорам — сну, воде, укладу, тишине. Так подсознание успокаивается, а бодрость и силы восстанавливаются. Это не приговор, а подсказка: ваша энергия любит бережный, а не насильственный режим. Прислушиваться к ней — ваш осознанный выбор.', 'reviewed', 2)
