INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:18:health_sacral', 'numerology', 'Чувственность и внутренний огонь здесь окрашены лунным светом — мягким, переменчивым, глубоким, как ночное море. Восемнадцатый аркан связывает вашу жизненную энергию с миром ощущений, желаний и образов: удовольствие приходит через атмосферу, прикосновение, воду, близость, а не через суету. Эта область откликается на приливы и отливы настроения, и это естественно — важно принимать свои циклы, а не воевать с ними. Творческая и чувственная сила здесь щедра к тем, кто даёт себе право чувствовать. Как её проживать — зависит от вашей осознанности и всей карты в целом.', 'reviewed', 2)
