INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:18:health_solar_plexus', 'numerology', 'Воля и самоощущение здесь опираются не на громкий напор, а на внутреннее чутьё. Луна смягчает эту зону: ваша самооценка чувствительна к атмосфере и к тому, как вас принимают, а сила проявляется скорее гибко, чем таранно — вы добиваетесь своего, чувствуя момент. Тень такой настройки — зависимость настроения от внешних оценок и сомнения в себе в туманные периоды. Ресурс — в умении опираться на тихую внутреннюю уверенность, которая не спорит, но и не сдаётся. Эту грань можно бережно укреплять в свою пользу.', 'reviewed', 2)
