INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:18:health_third_eye', 'numerology', 'Здесь Луна у себя дома. Область внутреннего зрения насыщена интуицией: вы видите не только фактами, но и предчувствиями, снами, внезапными озарениями, которые приходят будто из ниоткуда. Это сильный ресурс — но именно тут важно отличать ясное наитие от игры воображения и тревоги, ведь лунный свет умеет и подсвечивать, и морочить. Помогает проверка: записывать догадки, сверять их с реальностью, взращивать доверие к тем, что сбываются. Такую прозорливость стоит развивать бережно — она крепнет от внимания и честности с собой.', 'reviewed', 2)
