INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:18:health_throat', 'numerology', 'Голос здесь тянется к тому, чтобы выражать невыразимое — настроения, оттенки, то, что живёт ниже слов. Луна делает вашу речь образной, интуитивной, порой поэтичной; вам ближе намёк, метафора и мягкая интонация, чем сухая прямота. Иногда мысли трудно облечь в чёткую форму, будто они ещё под водой, — и тогда помогает творчество: письмо, музыка, дневник. Это не изъян речи, а особый способ высказываться. Развивая его осознанно, вы превращаете туманность в поэтику, а чуткость — в умение говорить с людьми на языке чувств.', 'reviewed', 2)
