INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:18:money_line', 'numerology', 'С деньгами у вас скорее интуитивные, чем сухо расчётливые отношения. Луна вносит сюда тему циклов и чутья: доход может идти волнами — приливы и отливы, — а решения нередко подсказывает внутреннее ощущение, а не только таблица. Это бывает ресурсом: вы улавливаете момент, чувствуете, чему люди готовы сказать «да». Но та же переменчивость просит подстраховки — привычки к резерву и ясного учёта, чтобы туман не оборачивался тревогой. Аркан ничего не предопределяет в кошельке; он лишь описывает склонность, которой стоит распоряжаться осознанно.', 'reviewed', 2)
