  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:18:point_center', 'numerology', 'Внутренне вам уютнее всего там, где есть место недосказанности и мягкому свету — не под резким прожектором фактов, а в атмосфере, которую можно почувствовать. В самом центре карты Луна создаёт зону, где вы отдыхаете, погружаясь в мечты, образы, тихие размышления и доверяясь наитию. Здесь восстанавливаются силы: через воду, музыку, сон, уединение, через право не всё объяснять словами. Важно лишь не превращать этот уютный полумрак в убежище от реальности. Как ресурс эта особенность работает тем лучше, чем осознаннее вы возвращаетесь из неё к делам дня.', 'reviewed', 2)
