INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:18:point_f1', 'numerology', 'В этом квадранте октаграммы лунная тема разворачивается как умение принимать решения не только рассудком. Восемнадцатый аркан подсказывает: иногда верный ответ приходит раньше аргументов — лёгким внутренним «да» или сопротивлением, которому стоит доверять. Здесь ваш ресурс — чуткость к полутонам, способность действовать в условиях, когда данных мало, а выбирать всё равно нужно. Стоит лишь проверять предчувствия, а не идти за каждой мимолётной тревогой. Насколько зрело раскроется эта грань, зависит от практики и от всей карты целиком.', 'reviewed', 2)
