INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:18:point_f4', 'numerology', 'В этой части карты лунное начало учит спокойствию посреди неизвестности. Там, где нет готовых ответов и всё зыбко, как отражение в воде, вы способны не паниковать, а ждать, пока картина прояснится сама, будто туман расходится к утру. Это ценный ресурс терпения и доверия к процессу. Важно лишь, чтобы ожидание не превращалось в вечную нерешительность. Как и любая склонность, эта грань — не данность раз и навсегда, а качество, которое крепнет от осознанной тренировки.', 'reviewed', 2)
