INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:18:point_month', 'numerology', 'По женской линии рода сюда протянулась ниточка особой душевной чуткости — дар угадывать состояние близких прежде, чем они признаются в нём сами. Луна, восемнадцатый аркан, окрашивает материнское наследие темой подсознания и интуиции: возможно, в семье передавалась привычка чувствовать атмосферу дома, беречь эмоциональный тыл, доверять снам и предчувствиям. Родовая задача здесь — не растворяться в чужих переживаниях, а научиться отделять своё от впитанного и превращать унаследованную впечатлительность в мягкую силу. Это не предопределение, а линия, вдоль которой можно расти осознанно.', 'reviewed', 2)
