INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:18:point_tasks', 'numerology', 'Главный узел судьбы завязан здесь на доверии к собственной глубине. Луна ставит перед вами задачу учиться жить в ладу с неопределённостью — не требовать от мира полной ясности, а находить дорогу по внутренним ориентирам, как штурман по звёздам сквозь ночь. Смысл не в том, чтобы разгадать все загадки разом, а в том, чтобы перестать бояться тумана и научиться различать голос интуиции среди шума тревоги. Это склонность, а не приговор: она раскроется тем полнее, чем внимательнее вы будете к тихим внутренним подсказкам и чем меньше станете заглушать их суетой.', 'reviewed', 2)
