INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:18:point_year', 'numerology', 'Отцовская ветвь рода приносит сюда иное звучание той же лунной темы: работу с неявным, с тем, что скрыто под поверхностью. Восемнадцатый аркан говорит о наследии, где ценились интуитивная смекалка, умение держать курс в тумане, доверие к внутреннему компасу даже без внешних гарантий. Задача этой линии — не бежать от неопределённости и не застревать в тревожных догадках, а обходиться с неизвестностью спокойно, как с приливом и отливом. Развитая, эта склонность становится опорой; заброшенная — рассеивается зря. Направление во многом задаёт ваш осознанный выбор.', 'reviewed', 2)
