INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:18:purpose_ancestral', 'numerology', 'На уровне рода сюда вписана тема хранения незримого — памяти, интуитивной мудрости, эмоциональной связи поколений. Луна говорит о задаче быть в семье тем, кто чувствует атмосферу, бережёт тыл, передаёт дальше не только вещи, но и тонкое знание о жизни. Возможно, роду важно, чтобы кто-то научился доверять внутреннему голосу и мягко исцелять доставшуюся впечатлительность, не передавая её как тревогу. Это не груз и не приговор, а линия, вдоль которой можно расти, превращая унаследованную чуткость в осознанный дар.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:18:purpose_personal', 'numerology', 'Личный путь здесь пролегает через доверие к собственной глубине. Луна намекает, что ваша самореализация связана не с гонкой за внешними метками, а с умением слышать себя, идти за внутренним чутьём и находить смысл в тонком, неочевидном. Возможно, вам ближе дело, где ценится интуиция, воображение или чуткость к людям. Предназначение здесь — не пункт назначения, а верность внутреннему компасу даже там, где дорога теряется в тумане. Эту грань можно развивать в свою пользу, шаг за шагом сверяясь с тем, что откликается по-настоящему.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:18:purpose_social', 'numerology', 'В обращении к обществу ваша сила — быть чутким проводником для других. Луна располагает к ролям, где важно почувствовать людей: поддержать, утешить, уловить общее настроение, сказать вслух то, что многие ощущают, но не формулируют. Вы способны создавать атмосферу доверия и мягко вести за собой в неясности, не давя. Тень — риск раствориться в чужих ожиданиях, поэтому важна внутренняя граница. Это одна из граней личности, которую можно развивать в свою пользу, если беречь при этом собственный источник света.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:18:purpose_spiritual', 'numerology', 'Духовная нить здесь ведёт вглубь, к тому, что нельзя потрогать, но можно почувствовать. Луна связывает ваш внутренний рост с работой над подсознанием: со снами, символами, тенями, которые важно не прятать, а мягко освещать и принимать. Путь тут — учиться доверять неопределённости как части большого замысла и находить опору не во внешних гарантиях, а во внутренней тишине. Восемнадцатый аркан не обещает готовых откровений — он приглашает в терпеливое исследование себя. Насколько глубоко раскроется эта склонность, зависит от вашей осознанности.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:18:relationship_line', 'numerology', 'В близости вы настроены на тонкую волну — чувствуете партнёра почти без слов, улавливаете смену его настроения по мелочи, тянетесь к глубокой эмоциональной связи, а не к поверхностной. Луна делает отношения для вас пространством чувств, заботы и интуитивного понимания. Обратная сторона этой чуткости — впечатлительность и склонность додумывать невысказанное, принимая туман за знак. Поэтому здесь особенно ценен открытый разговор: он рассеивает домыслы. Понимание этой особенности помогает мягче обходиться с собой и строить близость осознанно.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:19:age_period_1', 'numerology', 'Рассвет — точный образ для этого отрезка пути. Первый девятилетний цикл под Девятнадцатым Арканом окрашен темой свежего начала, любопытства и открытой жизненной энергии: время, когда хочется пробовать, смотреть на мир прямо и не бояться собственной яркости. Это склонность периода, а не расписанный сценарий — как он проживётся, зависит от выбора и обстоятельств. Но как ресурс здесь доступны лёгкость и бодрость, из которых хорошо строить основу для дальнейшего. Стоит просто позволять свету входить в жизнь и не гасить первые ростки радости.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:19:age_period_2', 'numerology', 'Когда разворачивается этот девятилетний виток, солнечная энергия крепнет и просит движения. Девятнадцатый Аркан наполняет период темой растущей уверенности и тепла: ясность из робкой становится устойчивой, а радость — опорой для действий. Вы располагаете здесь к тому, чтобы заявлять о себе смелее и превращать интерес в реальные шаги. Это тенденция, а не обещание конкретных событий: её проявление зависит от вашего выбора и всей картины в целом. Но сам заряд открытой жизненной силы в этом отрезке ощутимо силён и просит, чтобы им пользовались.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:19:age_period_3', 'numerology', 'Это время созревания, когда посеянное раньше набирает полноту. Под Девятнадцатым Арканом такой отрезок связан с темой щедрого, окрепшего света: радость становится глубже, а ясность — спокойнее и увереннее. Здесь есть склонность делиться накопленным теплом и вниманием, быть источником для других, не теряя себя. Это направление периода, а не заранее решённая история: как оно раскроется, зависит от вашей осознанности. Но как ресурс доступно ощущение зрелой силы — света, которому уже не нужно доказывать свою яркость, чтобы согревать.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:19:age_period_4', 'numerology', 'Честность с собой становится главной опорой на этом участке пути. Девятнадцатый Аркан окрашивает данный девятилетний цикл темой трезвого, светлого взгляда: время, когда важно видеть вещи прямо и жить в согласии со своей правдой. Вы располагаете к тому, чтобы наводить порядок, отсекать лишнее и опираться на то, что действительно наполняет. Это склонность, а не приговор — её проявление во многом определяет ваш выбор. Но сам солнечный ресурс здесь работает как свет, при котором хорошо видно, куда стоит идти дальше.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:19:age_period_5', 'numerology', 'Здесь всё держится на радости как топливе. Под Девятнадцатым Арканом этот отрезок связан с игрой, лёгкостью и живой энергией: время, когда важно не забывать про удовольствие от самого процесса жизни. Вы располагаете к тому, чтобы черпать силы в том, что вдохновляет, и не превращать путь в сплошное усилие. Это тенденция периода, а не гарантированный сюжет — многое зависит от того, разрешаете ли вы себе радоваться. Но как ресурс солнечная лёгкость здесь особенно доступна и способна вернуть вкус к жизни там, где он приугас.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:19:age_period_6', 'numerology', 'На этом отрезке свет естественно разворачивается к другим. Девятнадцатый Аркан связывает данный цикл с темой тепла, которым делятся: заботой, вниманием, способностью поддержать и вдохновить тех, кто рядом. Вы располагаете к роли того, кто согревает пространство вокруг, оставаясь при этом собой. Это склонность, а не обязанность светить всем без остатка — важно помнить и о себе. Как именно раскроется этот период, зависит от вашего выбора и всей карты. Но сам дар отдавать тепло, не истощаясь, здесь особенно ощутим.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:19:age_period_7', 'numerology', 'Зрелый, спокойный свет — так можно описать этот цикл. Под Девятнадцатым Арканом отрезок окрашен темой уверенной ясности, которой уже не нужно себя доказывать: радость становится тише и глубже, а тепло — ровным. Вы располагаете здесь к мудрой открытости — умению быть светлым без суеты и делиться опытом мягко, по существу. Это тенденция, а не расписанная судьба: как она проживётся, определяют ваш выбор и осознанность. Но как ресурс доступна редкая устойчивость — внутренний свет, на который можно опереться и самому, и тем, кто рядом.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
