  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:19:age_period_8', 'numerology', 'Похоже на золото позднего дня: тепло, собранное за годы, здесь можно щедро раздавать. Девятнадцатый Аркан связывает этот девятилетний цикл с полнотой и завершённостью солнечной энергии — временем, когда накопленная ясность и радость становятся наследием, которым делятся. Вы располагаете к спокойной щедрости и умению видеть главное. Это склонность периода, а не предрешённый финал: как он раскроется, зависит от вашего выбора и всей картины целиком. Но сам свет здесь мягок и полон — из тех, что согревают не жаром, а глубиной.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
