  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:19:health_crown', 'numerology', 'На макушке, там, где человек соприкасается с чем-то большим себя, Солнце говорит о смысле. Девятнадцатый Аркан в коронном центре описывает тихую духовную радость — ощущение, что жизнь светла и осмысленна не потому, что так велено, а потому что вы это чувствуете. Вы располагаете к ясной, не тяжёлой духовности: к доверию доброму ходу вещей и связи со светом, которая не требует сложных доктрин. Это склонность, а не данность свыше: она раскрывается через ваш опыт и выбор. Как ресурс этот свет способен поддерживать в моменты, когда внешние опоры кажутся ненадёжными.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:19:health_heart', 'numerology', 'В сердечном центре солнечная энергия превращается в тепло, которым делятся. Девятнадцатый Аркан наполняет зону эмоций и отношений щедростью и открытостью: склонностью любить ясно, радоваться близким и согревать тех, кто рядом, не ведя счёта. Здесь вы располагаете к искренности чувств — к тому, чтобы привязанность была светлой, а не тревожной. Это тенденция, которую хорошо развивать, а не заранее решённая история: её проявление зависит от вашего выбора и того, насколько безопасно вам открываться. Но как ресурс сердечное тепло здесь способно наполнять и вас, и ваши связи.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:19:health_root', 'numerology', 'Опорой здесь служит простое, но глубокое ощущение — жить хорошо. На уровне корневого центра Девятнадцатый Аркан описывает солнечную жизненную силу: базовое доверие к жизни, устойчивость и бодрость, что идут будто из самой земли. Это склонность чувствовать под собой твёрдую почву и радоваться самому факту существования, а не только достижениям. Речь об архетипе, а не о приговоре: насколько крепкой окажется эта опора, во многом зависит от того, как вы о себе заботитесь. Замечая, что вас наполняет, а что истощает, вы бережно поддерживаете этот солнечный корень.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:19:health_sacral', 'numerology', 'На уровне сакрального центра Солнце звучит как удовольствие от жизни во всей его полноте. Девятнадцатый Аркан вносит сюда тему тёплой чувственности, игры и живого интереса к телесной радости — к вкусу, движению, творчеству, близости. Вы располагаете к тому, чтобы наслаждаться моментом открыто и без вины, черпая в этом энергию. Это грань, которую можно развивать в свою пользу, а не готовая данность: проявляется она мягче или ярче в зависимости от вашего внутреннего разрешения себе радоваться. Свет здесь — про то, что удовольствие может быть чистым и питающим источником сил.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:19:health_solar_plexus', 'numerology', 'Солнечное сплетение и есть родной дом Девятнадцатого Аркана — недаром и название совпадает. В этом центре Солнце говорит о здоровой воле и тёплой, устойчивой самооценке: о способности ценить себя без надрыва и доказывать что-то в первую очередь себе, а не миру. Вы располагаете к внутренней ясности «я имею право быть» — тому спокойному свету, из которого рождается уверенность. Это склонность, а не обещание: она крепнет там, где вы позволяете себе быть собой, и тускнеет под грузом чужих ожиданий. Ухаживать за ней стоит так же бережно, как за огнём, который хочется сохранить.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:19:health_third_eye', 'numerology', 'Ясность — вот что Солнце приносит в центр интуиции. Девятнадцатый Аркан в зоне третьего глаза связан со способностью видеть суть просто и без мистического тумана: понимать, где правда, а где иллюзия, и доверять этому спокойному внутреннему свету. Вы располагаете к трезвому, светлому взгляду — интуиции, которая не пугает, а проясняет. Это грань, которую можно развивать, а не готовое всезнание: она крепнет, когда вы прислушиваетесь к себе и проверяете догадки жизнью. Проявится она сильнее или мягче в зависимости от вашей осознанности и всей карты целиком.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:19:health_throat', 'numerology', 'Голос здесь хочет звучать ясно и без оглядки. В горловом центре Девятнадцатый Аркан описывает солнечное самовыражение: способность говорить прямо, тепло и по существу, не пряча своей позиции за туманом. Вы располагаете к тому, чтобы делиться мыслями открыто и заражать других своей ясностью — в разговоре, в творчестве, в любом слове, которое произносите от себя. Это склонность, а не гарантированный талант оратора: она раскрывается настолько, насколько вы разрешаете себе быть услышанным. Чем меньше вы приглушаете собственный голос, тем светлее и точнее он звучит.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:19:money_line', 'numerology', 'Деньги здесь тянутся к тому, что вас по-настоящему зажигает. Девятнадцатый Аркан на денежной линии описывает склонность к достатку через открытость, видимость и радость от дела: когда вы не прячете свой талант, а показываете его миру, ресурсы приходят легче. Речь не об обещании богатства, а о тенденции — благополучие здесь связано с честностью, щедростью и умением заниматься тем, от чего внутри светло. Как это развернётся, зависит от вашего выбора и всей карты. Но ориентир ясен: там, где вы разрешаете себе сиять и делиться, энергия изобилия движется свободнее.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:19:point_center', 'numerology', 'В самой сердцевине октаграммы Солнце становится тем местом, куда вы возвращаетесь, чтобы восстановиться. Зона комфорта здесь — это состояние ясной, тёплой радости: там, где есть свет, простота и ощущение, что жизнь идёт своим добрым ходом, вы чувствуете себя дома. Девятнадцатый Аркан подсказывает, что ваш надёжный источник сил — не борьба и не напряжение, а открытость и лёгкость. Это ресурс, а не данность на все случаи: замечая, что именно вас наполняет, вы мягче обходитесь с собой и реже уходите в перегруз. Свет в центре — как ровное пламя, к которому всегда можно вернуться.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:19:point_day', 'numerology', 'Есть люди, рядом с которыми теплеет, — и Девятнадцатый Аркан в точке личных качеств описывает именно такой дар. Солнце здесь означает природную способность излучать ясность и радость: вы располагаете к открытости, к честному прямому взгляду, к энергии, которая заряжает окружающих. Это талант быть заметным без усилия и согревать, не требуя ничего взамен. Проявится он ярче или тише — зависит от вашего выбора и всей карты целиком; но сама склонность к свету у вас в запасе как надёжный ресурс. Стоит помнить: чтобы светить другим, важно не забывать наполнять и себя.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:19:point_f1', 'numerology', 'Представьте раннее утро, когда воздух ещё прозрачен и всё вокруг словно обещает ясный день, — примерно так солнечная энергия входит в первый квадрант октаграммы. Девятнадцатый Аркан окрашивает этот сектор темой свежести, открытости и живого интереса к жизни. Здесь вы располагаете к тому, чтобы начинать с лёгкостью, смотреть на вещи прямо и не бояться собственной яркости. Это склонность, а не сценарий: насколько развернётся этот свет, зависит от вашей осознанности и всей карты. Но как ресурс он даёт бодрость и умение видеть хорошее там, где другие замечают только серость.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:19:point_f2', 'numerology', 'Здесь свет уверенно набирает высоту. Во втором секторе октаграммы Девятнадцатый Аркан говорит о зрелой, окрепшей радости — той, что не вспыхивает и гаснет, а держится ровно, как солнце к середине дня. Вы располагаете к устойчивой открытости: способности согревать, вести за собой и оставаться ясным даже там, где вокруг напряжённо. Это тенденция, которую стоит развивать в свою пользу, а не готовый результат. Проявится она по-разному в зависимости от вашего выбора; но сам запас тепла и жизненной силы в этой зоне ощутимо велик.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:19:point_f3', 'numerology', 'Щедрость — ключевое слово третьего квадранта. Девятнадцатый Аркан наполняет этот сектор темой света, которым хочется делиться: радости, что становится больше, когда её отдаёшь. Здесь у вас есть склонность быть тем, кто освещает пространство вокруг — вниманием, теплом, простой человеческой ясностью. Важно помнить, что это ресурс, а не обязанность светить всем и всегда: раздавая тепло, полезно оставлять часть и себе. Насколько ярко раскроется эта грань, зависит от осознанности; но сама способность согревать других заложена здесь как настоящий дар.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:19:point_f4', 'numerology', 'Свет, который отдаёт тепло и при этом не убывает, — так проявляется Солнце в четвёртом секторе октаграммы. Девятнадцатый Аркан связывает этот квадрант с полнотой и завершённостью солнечной энергии: ясностью, которая уже ничего не доказывает, и радостью, которой достаточно самой по себе. Вы располагаете к спокойной внутренней устойчивости — умению быть источником, а не искателем чужого одобрения. Это тенденция, а не предопределённость: её проявление зависит от вашего выбора и всей карты. Но как опора этот ровный свет способен поддерживать вас годами.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:19:point_month', 'numerology', 'По материнской линии сюда приходит негромкая, но важная задача — научиться сиять, не спрашивая на это разрешения. Девятнадцатый Аркан связывает вас с женской ветвью рода темой открытой радости и жизненной силы: возможно, кому-то из прежних поколений было велено «не высовываться», и теперь эта способность к свету может вернуться в семью через вас. Это не долг и не приговор, а мягкая тенденция — раскрыть в себе право на тепло, ясность и открытость. Развивая её осознанно, вы обходитесь бережнее и с собой, и с теми, кто идёт следом.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:19:point_tasks', 'numerology', 'Главная задача, которую отмечает здесь Солнце, звучит просто и одновременно непросто — жить открыто. Девятнадцатый Аркан предлагает не прятать свою радость и ясность, а сделать их осью, вокруг которой строится путь: быть собой на виду, говорить прямо, делиться теплом. Это скорее направление движения, чем обязательство: тенденция становиться источником света для других раскрывается настолько, насколько вы сами её выбираете. И чем меньше вы гасите себя ради чужого удобства, тем естественнее эта энергия работает — не только на вас, но и на всех вокруг.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
