  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:19:point_year', 'numerology', 'Отцовская линия передаёт вам ясность будто наследство — прямой взгляд, внутреннее тепло и уверенность, которые не нужно никому доказывать. Девятнадцатый Аркан в этой точке говорит о родовой задаче по мужской ветви: пронести дальше свет, что живёт в этой линии, и не дать ему уйти в тень сомнений. Речь не о готовой судьбе, а о склонности — вы располагаете к тому, чтобы стать в своём роду человеком, рядом с которым спокойно и светло. Как именно это раскроется, решает ваш выбор; но сам ресурс открытой жизненной энергии здесь заложен прочно.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:19:purpose_ancestral', 'numerology', 'Роду вы можете вернуть то, что когда-то в нём пригасло, — право открыто радоваться и быть заметным. Девятнадцатый Аркан в теме родового предназначения говорит о задаче пронести свет через семейную линию: возможно, стать тем, кто снимает старый негласный запрет «не сиять слишком ярко». Это не груз и не приговор, а тенденция — раскрыть жизненную силу так, чтобы её тепла хватило и вам, и тем, кто рядом и следом. Как именно это проявится, зависит от вашего выбора; но сама возможность быть светлым звеном рода заложена здесь по-настоящему.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:19:purpose_personal', 'numerology', 'Смысл вашего личного пути в том, чтобы самому стать источником света, а не искать его во внешнем. Девятнадцатый Аркан подсказывает: ваш путь раскрывается через открытость, честность и радость — когда вы живёте на виду и занимаетесь тем, что по-настоящему зажигает. Это не предопределённая колея, а направление: склонность реализовать себя через ясность и тепло, которыми вы делитесь. Насколько полно она развернётся, решают ваш выбор и осознанность. Но сам ориентир прост — идти туда, где вам светло, и не гасить себя ради чужих сценариев.', 'reviewed', 2)
