  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:19:purpose_social', 'numerology', 'В обществе ваша роль связана с теплом, которое собирает людей вокруг. Девятнадцатый Аркан в теме социального предназначения описывает склонность быть заметным и объединяющим — тем, кто вносит в общее пространство ясность, оптимизм и живую энергию. Вы располагаете к открытому лидерству, основанному не на давлении, а на способности вдохновлять и согревать. Это тенденция, а не назначенная должность: как она проявится — через большую сцену или тёплый круг близких, — зависит от вашего выбора и всей карты. Но сам дар быть светлым центром для других здесь ощутим.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:19:purpose_spiritual', 'numerology', 'Духовный путь под этим Арканом — не про уход в тень и аскезу, а про свет. Девятнадцатый Аркан связывает духовное предназначение с радостью как формой служения: со склонностью нести ясность и тепло туда, где людям тяжело, и напоминать самим своим присутствием, что жизнь светла. Это направление, а не готовая миссия: раскрывается оно настолько, насколько вы сами выбираете жить открыто и осознанно. Речь не о том, чтобы поучать, а о том, чтобы светить — просто и без пафоса. Такой путь наполняет и вас, если не забывать возвращать тепло и себе.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:19:relationship_line', 'numerology', 'В отношениях Солнце просит честности и открытого тепла. Девятнадцатый Аркан на линии отношений описывает склонность любить ясно, без игр и полутонов: быть собой рядом с другим, радоваться ему и не прятать чувств за осторожностью. Вы располагаете к тому, чтобы согревать партнёрство своей энергией и делать его пространством света, а не борьбы. Это тенденция, а не гарантированный сюжет: близость раскрывается настолько, насколько оба готовы быть открытыми. Важно помнить и о балансе — тому, кто много отдаёт тепла, полезно позволять и себе быть согретым.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
