  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:1:age_period_1', 'numerology', 'Первый девятилетний отрезок задаёт разбег для всего, что будет дальше. Маг окрашивает его темой пробуждающейся воли: в это время склонно проступать желание пробовать, влиять, делать по-своему — учиться тому, что твои действия что-то меняют. Это не расписание событий, а настроение периода, фон, на котором удобнее осваивать инициативу. Проявится он мягче или ярче — зависит от обстоятельств и от всей карты; сам по себе цикл ничего не предопределяет, а лишь подсвечивает, какой ресурс сейчас под рукой.', 'reviewed', 2)
