  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:1:age_period_2', 'numerology', 'Во втором цикле энергия Мага звучит как приглашение к самостоятельности. Тенденция периода — искать своё, отделять собственные замыслы от чужих ожиданий, пробовать силы там, где раньше вели за руку. Это время удобно для того, чтобы инициатива окрепла и стала навыком, а не мимолётным порывом. Важно помнить: цикл описывает склонность, а не сценарий — он не обещает конкретных событий и не закрывает других путей. Как распорядиться этим зарядом, каждый решает сам, сверяясь со своей ситуацией.', 'reviewed', 2)
