  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:1:age_period_3', 'numerology', 'Третий девятилетний виток тяготеет к теме воплощения замыслов в дело. Маг здесь подсказывает: это фон, на котором проще собирать разрозненные умения в конкретный результат и брать ответственность за начатое. Склонность периода — действовать увереннее, опираясь на уже накопленный опыт. Никакой предопределённости в этом нет: время лишь подсвечивает доступный ресурс, а наполняете его вы своими решениями. Проявится тенденция настолько, насколько осознанно вы к ней отнесётесь.', 'reviewed', 2)
