  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:1:age_period_4', 'numerology', 'Четвёртый цикл часто про укрепление собственного дела и позиции. С Первым Арканом он окрашен мотивом мастерства: инициатива в это время склонна становиться точнее, а воля — спокойнее и целенаправленнее. Это подходящий фон, чтобы вкладываться в то, что действительно своё, не распыляясь. Речь о тенденции, а не об обещании достижений: период показывает, какая энергия под рукой, но что из неё вырастет, зависит от выбора и всей карты в целом. Свобода распорядиться остаётся за вами.', 'reviewed', 2)
