  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:1:age_period_5', 'numerology', 'К пятому витку у многих накапливается достаточно опыта, чтобы действовать без лишних доказательств. Маг вносит сюда зрелую инициативу: склонность распоряжаться ресурсами продуманно, начинать то, что откликается, и не гнаться за всем сразу. Это настроение периода, а не список того, что «случится», — цикл ничего не обещает и не отменяет свободы решать. Полезно относиться к нему как к попутному ветру: он помогает движению, но курс всё равно прокладываете вы сами.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
