  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:1:age_period_6', 'numerology', 'Шестой девятилетний отрезок нередко разворачивает внимание к качеству того, что делаешь. Энергия Мага звучит здесь как тяга наводить порядок в своих делах и доводить начатое до ума. Тенденция периода — соединять волю с заботой о деталях, действовать осмысленно, а не по инерции. Это склонность, а не приговор: время подсвечивает ресурс, но не диктует событий и не закрывает выбора. Как раскрыть этот фон в свою пользу, каждый определяет по своей ситуации и внутреннему чувству.', 'reviewed', 2)
