  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:1:age_period_8', 'numerology', 'К восьмому витку воля Мага обычно звучит тише, но глубже. Тенденция периода — распоряжаться накопленным осознанно: выбирать, во что вкладывать силы, и позволять себе не хвататься за всё подряд. Инициатива здесь всё больше про свободу делать по-своему и про мудрость вовремя остановиться. Это фон, а не предсказание: цикл описывает доступный ресурс, но событий не назначает и выбора не отнимает. Как им воспользоваться, по-прежнему решаете вы — спокойно и без спешки.', 'reviewed', 2)
