INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:1:health_crown', 'numerology', 'Венечная зона — про связь с большим смыслом, с тем, что выше повседневных задач. Маг вносит сюда неожиданный оттенок: духовность для вас склонна быть не созерцательной, а деятельной. Смысл проще нащупывается через дело, через ощущение «я приложил руку к чему-то важному», а не через отвлечённые размышления. Такую особенность полезно понимать, чтобы мягче обходиться с собой: иногда высшее открывается и в тишине, без всякого действия. Это ресурс, а не обязанность вечно созидать.', 'reviewed', 2)
