INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:1:health_heart', 'numerology', 'В зоне сердца энергия Мага смягчается и разворачивается к людям. Проступает склонность проявлять заботу деятельно: не столько говорить о чувствах, сколько что-то ради близких делать, решать, брать на себя. Это тёплая инициатива — готовность первым протянуть руку. Она не приговор и не единственно верный язык любви: иногда сердцу важнее просто быть рядом и слушать, а не действовать. Как именно раскроется эта грань, зависит от вас и от всей карты целиком — здесь много свободы выбора.', 'reviewed', 2)
