  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:1:health_root', 'numerology', 'Корневая чакра — про чувство почвы под ногами и запас жизненных сил. Маг в этой зоне описывает склонность черпать устойчивость из действия: когда вы заняты делом и чувствуете, что влияете на свою жизнь, внутренняя опора крепнет сама. Речь не о самочувствии в узком смысле, а о психологическом тонусе — о бодрости, которая приходит от инициативы. Стоит помнить: даже деятельной натуре нужен ритм, где за рывком следует восстановление. Баланс здесь — вопрос осознанного выбора, а не предписания.', 'reviewed', 2)
