  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:1:health_sacral', 'numerology', 'Сакральная зона отвечает за живость, вкус к жизни и удовольствие от процесса. Первый Аркан окрашивает её мотивом творческого запала: тяга творить, пробовать, увлекаться делом здесь тесно сплетается с чувственностью. Такая энергия располагает получать радость не только от результата, но и от самого движения к нему. Понимание этой особенности помогает мягче обходиться с собой — не выжигать себя гонкой, а позволять азарту чередоваться с паузами. Это ресурс бодрости, которым приятно распоряжаться бережно.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:1:health_solar_plexus', 'numerology', 'Солнечное сплетение — центр личной силы, и с ним Маг совпадает почти буквально. Здесь читается склонность питать самооценку через действие: вы чувствуете себя увереннее, когда берётесь за дело и доводите его до конца. Воля тут — не давление на других, а внутренний стержень, опора на «я могу». Тенденция полезная, если помнить: ценность человека не сводится к списку сделанного, и право на отдых у вас есть без всяких доказательств. Развивать эту грань — значит опираться на силу, не превращая её в кнут.', 'reviewed', 2)
