  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:1:health_third_eye', 'numerology', 'Третий глаз связан с внутренним зрением — способностью видеть суть и схватывать замысел раньше слов. Первый Аркан добавляет сюда деятельную ясность: интуиция не просто созерцает, а сразу ищет, как воплотить увиденное. Склонность здесь — доверять первому чёткому импульсу и превращать прозрение в план. Это грань, которую стоит развивать, не забывая проверять догадки опытом: ясность крепнет, когда её сверяют с реальностью. Как она сработает, во многом зависит от вашей внимательности к себе.', 'reviewed', 2)
