  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:1:health_throat', 'numerology', 'Горло — про голос в широком смысле: умение выразить себя и быть услышанным. Маг наделяет эту зону склонностью говорить, чтобы что-то произошло: слово здесь тянется стать действием, идея — предложением, замысел — договорённостью. Тенденция располагает к прямой, инициативной речи, к тому, чтобы озвучивать первым. Полезно уравновешивать её умением слушать — тогда воля в словах не давит, а ведёт. Это ресурс самовыражения, а не мерка; проявится он настолько, насколько осознанно вы им пользуетесь.', 'reviewed', 2)
