INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:1:money_line', 'numerology', 'Денежная линия — про то, как выстраиваются ваши отношения с ресурсами и достатком. Первый Аркан намекает: деньги для вас склонны приходить через действие и предприимчивость — когда вы создаёте, начинаете, берётесь за своё дело, а не ждёте, что сложится само. Это тенденция, а не обещание богатства: карта показывает канал, но наполняют его конкретные решения и осознанный труд. Полезнее всего эта грань работает, когда инициативу поддерживает трезвый расчёт и терпение.', 'reviewed', 2)
