INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:1:point_center', 'numerology', 'Центр октаграммы — место, где вы отдыхаете и восстанавливаетесь, ваша внутренняя точка опоры. Маг в этой зоне подсказывает: спокойнее и естественнее всего вам, когда есть дело в руках и свобода начать его по-своему. Активность здесь — не напряжение, а форма покоя: занятость, инициатива, ощущение «я справлюсь» возвращают силы. Стоит помнить и обратное — иногда отдых означает разрешить себе ничего не запускать. Эта склонность не жёсткое правило, а ресурс, которым удобно пользоваться осознанно.', 'reviewed', 2)
