INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:1:point_day', 'numerology', 'Точка «День» — это витрина ваших врождённых способностей, и Первый Аркан ставит в ней фигуру Мага: человека, который не ждёт идеальных условий, а собирает нужное из того, что под рукой. Здесь читается склонность брать инициативу на себя, доверять своей воле и превращать замысел в конкретное действие. Это ваш личный инструмент, а не приговор: сила Мага раскрывается ровно настолько, насколько вы решаетесь ею пользоваться — пробовать, начинать, отвечать за результат.', 'reviewed', 2)
