INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:1:point_f1', 'numerology', 'С квадранта Ф1 начинается ваша внутренняя биография — то, с каким материалом вы входите в жизнь. Маг задаёт здесь тон предприимчивости: ранняя склонность пробовать, брать вещи в свои руки, искать способ там, где другие видят тупик. Такой заряд удобно воспринимать как стартовый капитал характера — он не решает за вас, но даёт из чего строить. Развивать его значит превращать порывистое «хочу сделать» в устойчивый навык доводить начатое до конца.', 'reviewed', 2)
