INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:1:point_f2', 'numerology', 'Есть люди, у которых руки чешутся что-нибудь наладить, — и квадрант Ф2 с Первым Арканом описывает именно эту жилку. Тут проступает деятельная воля: желание влиять на обстоятельства, а не плыть по ним, и способность собирать результат из подручного. Это грань характера, которую стоит развивать в свою пользу: чем яснее вы видите свои ресурсы, тем меньше инициатива уходит в суету. Проявление зависит от всей карты и от того, куда вы направляете этот напор.', 'reviewed', 2)
