INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:1:point_f3', 'numerology', 'Квадрант Ф3 — про то, как вызревает и крепнет ваша самостоятельность. Маг привносит сюда мотив автора: тягу самому задавать правила своего дела, а не ждать чужой отмашки. Склонность эта не обязывает вечно быть первым — она лишь напоминает, что у вас есть воля и есть чем распорядиться. Полезнее всего она работает, когда инициатива подкреплена терпением: замысел важно не только зажечь, но и выносить. Это ресурс для развития, а не мерка, которой нужно соответствовать.', 'reviewed', 2)
