INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:1:point_f4', 'numerology', 'Ближе к зрелости, в квадранте Ф4, энергия Мага звучит спокойнее и мудрее. Здесь инициатива уже не про то, чтобы что-то доказать, а про то, чтобы делать по-своему без надрыва. Проступает склонность собирать накопленные ресурсы — знания, связи, опыт — и пускать их в дело осознанно, по мере надобности. Такую грань хорошо разворачивать в свою пользу: воля, прошедшая через опыт, становится не порывом, а мастерством. Как она проявится, во многом решаете вы сами.', 'reviewed', 2)
