INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:1:point_month', 'numerology', 'По материнской линии сюда приходит энергия начала — та, что учит не бояться первого шага. Первый Аркан в точке «Месяц» намекает: в женском роду копилась тема воли, самостоятельности и умения обходиться собственными силами. Возможно, кому-то из предшественниц этого не хватало, а кто-то, наоборот, держал на себе целый дом. Ваша родовая задача располагает к тому, чтобы принять эту инициативность как наследство и распорядиться ею мягко — не доказывая, а действуя из спокойной уверенности.', 'reviewed', 2)
