INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:1:point_tasks', 'numerology', 'Главная задача — это ось, вокруг которой закручивается вся карта. Когда на ней стоит Маг, смысл жизненного пути тяготеет к одному: научиться воплощать. Не копить идеи, а доводить их до вещественного результата, соединяя намерение, ресурс и действие. Это не обещание успеха и не список достижений, а направление роста — приглашение раз за разом отвечать на вопрос «что я могу сделать прямо сейчас из того, что уже есть». Проявится оно настолько, насколько осознанно вы за него беретесь.', 'reviewed', 2)
