INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:1:point_year', 'numerology', 'Отцовская ветвь несёт мотив мастера — того, кто берёт инструмент и делает. В точке «Год» Маг говорит о родовой теме деятельной воли: способности начинать, вести, отвечать за своё дело. Тенденция здесь — не растворять эту силу в сомнениях, а признать её законной частью себя. Как именно она развернётся, зависит от вас: наследство даёт заряд, но направление выбирает тот, кто его несёт. Можно сделать этот импульс опорой, а не грузом чужих ожиданий.', 'reviewed', 2)
