INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:1:purpose_ancestral', 'numerology', 'Родовое предназначение — про вклад, который выходит за пределы одной жизни, про эстафету, принятую от предков. Маг здесь говорит о задаче быть в роду тем, кто начинает и меняет: запускает новое там, где раньше топтались на месте. Это не приговор и не долг, а склонность — возможность стать точкой поворота, распорядившись волей и ресурсами рода осознанно. Как она проявится, решаете вы: наследство даёт материал, но что из него построить, зависит от вашего выбора.', 'reviewed', 2)
