  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:1:purpose_personal', 'numerology', 'Личное предназначение — то, к чему тянет изнутри, помимо чужих ожиданий. С Магом оно окрашено темой самореализации через созидание: ощущение осмысленности приходит, когда вы что-то начинаете и воплощаете своими руками. Это склонность быть скорее автором, чем исполнителем чужих сценариев. Формулировка мягкая: предназначение не расписано наперёд и ничего не обещает — оно лишь показывает направление, в котором ваши инициатива и воля работают на вас. Разворачивается оно через осознанный выбор, шаг за шагом.', 'reviewed', 2)
