  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:1:purpose_social', 'numerology', 'Социальное предназначение — про вашу роль среди людей, про то, чем вы полезны кругу вокруг. Маг рисует здесь фигуру зачинателя: того, кто предлагает, ведёт, показывает своим примером, что действовать можно. Склонность располагает быть инициатором в сообществе, а не ждать, пока начнёт кто-то другой. Это направление, а не обещание признания: ценность вашего вклада не в громкости, а в том, что вы приводите замыслы в движение. Как раскрыть эту грань — вопрос осознанного выбора.', 'reviewed', 2)
