INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:1:purpose_spiritual', 'numerology', 'Есть путь, на котором рост измеряется не достижениями, а зрелостью души, — и духовное предназначение про него. С Первым Арканом оно тяготеет к идее сотворчества: развиваться, воплощая, беря ответственность за то, что создаёшь. Воля здесь становится не инструментом амбиций, а способом служения большему. Такую грань хорошо понимать бережно: духовность не обещает наград и не сводится к результатам. Она раскрывается настолько, насколько вы готовы вкладывать себя осознанно и без спешки.', 'reviewed', 2)
