INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:1:relationship_line', 'numerology', 'Линия отношений показывает, что вы приносите в близкие связи. Маг привносит сюда деятельную натуру: склонность быть тем, кто предлагает, планирует, задаёт тон и берёт инициативу на себя. Это ценный вклад — рядом с вами отношения не застаиваются. Важно оставлять партнёру пространство тоже быть автором: сила Мага хороша, когда она приглашает к диалогу, а не решает за двоих. Тенденция не предопределяет сценарий связи — многое зависит от вас обоих и от готовности слышать друг друга.', 'reviewed', 2)
