INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:20:age_period_1', 'numerology', 'Самый ранний девятилетний виток здесь проходит под знаком первых осмыслений. Аркан «Суд» в этом периоде говорит о склонности рано начинать «сортировать» опыт — замечать, что важно, а что нет, и делать из первых впечатлений честные выводы. Это время закладывает привычку оглядываться и учиться на прожитом. Проживается такой отрезок по-разному в зависимости от среды и поддержки; сам по себе он не судьба, а почва, на которой позже вырастет умение подводить итоги. Многое определяет вся карта в целом.', 'reviewed', 2)
