INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:20:age_period_2', 'numerology', 'Второй девятилетний отрезок окрашен темой взросления через переоценку. Аркан «Суд» здесь склоняет пересматривать унаследованные правила и роли: то, что раньше принималось на веру, начинает проситься на честную проверку. Это пора, когда человек учится отделять своё от навязанного и слышать собственный голос. Такой пересмотр может идти мягко или бурно — зависит от осознанности и окружения, а не предрешён заранее. Это тенденция периода, а не приговор, и её оттенок задаёт вся карта.', 'reviewed', 2)
