INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:20:age_period_3', 'numerology', 'На третьем витке тема «Суда» звучит как первый серьёзный внутренний аудит. Аркан располагает подвести промежуточный итог: сверить мечты с реальностью, признать, что сбылось, а что нет, и решить, куда двигаться дальше уже осознанно. Это отрезок честных вопросов к себе и возможных разворотов. Их не стоит бояться — переоценка здесь работает как ресурс обновления, а не как крах. Как именно пройдёт этот период, определяет выбор человека и общий рисунок матрицы, а не рок.', 'reviewed', 2)
