INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:20:age_period_4', 'numerology', 'Четвёртый девятилетний цикл склонен становиться временем зрелой ревизии. Аркан «Суд» в этом периоде разворачивает тему переосмысления накопленного: хочется пересобрать прожитое, отпустить то, что больше не служит, и подтвердить главное. Это пора вторых шансов — когда отложенное можно вернуть к жизни на новом уровне. Такой пересмотр располагает к обновлению без разрушения. Он не задан жёстко: как отзовётся эта тенденция, зависит от осознанности и от того, как период сплетается со всей картой.', 'reviewed', 2)
