INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:20:age_period_5', 'numerology', 'Пятый отрезок часто приносит потребность честно оглянуться на пройденный путь. Аркан «Суд» здесь усиливает мотив подведения итогов: собрать разрозненные годы в связную историю, признать её ценность и освободиться от лишнего груза. Это время, когда переоценка приносит не тревогу, а ясность и чувство направления. Такая внутренняя работа располагает к спокойной зрелости. Она не предопределена — глубина и тон этого периода зависят от выбора человека и от всей конфигурации карты.', 'reviewed', 2)
