INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:20:age_period_6', 'numerology', 'Шестой девятилетний виток тяготеет к теме мудрого итога. Аркан «Суд» в этом периоде склоняет пересматривать не детали, а смыслы: ради чего всё было, что осталось важным, чем хочется делиться дальше. Это пора, когда прожитое становится опорой, а не грузом, и открывается вкус к передаче опыта. Такое осмысление располагает к внутренней свободе и щедрости. Как проявится эта склонность, зависит от осознанности и всей карты; сам период — не приговор, а приглашение к зрелой ясности.', 'reviewed', 2)
