INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:20:age_period_7', 'numerology', 'На седьмом витке звучит тема примирения с прожитым. Аркан «Суд» здесь располагает подводить большой честный итог: не судить себя строго, а признать и хорошее, и трудное как единый путь. Это отрезок, где переоценка ведёт к принятию и внутреннему покою, а прощение — к лёгкости. Такая работа возвращает целостность и благодарность. Её глубина не предрешена: она раскрывается по мере осознанности и в согласии со всей картой, оставаясь возможностью, а не обязательным сценарием.', 'reviewed', 2)
