INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:20:age_period_8', 'numerology', 'Восьмой девятилетний период склонен становиться временем спокойного собирания смыслов. Аркан «Суд» в этой зоне разворачивает тему завершения главы: оглянуться на длинный путь, подвести итог без страха и суеты, оставить дальше только зрелое и ценное. Это пора ясности, когда прожитое складывается в цельную картину и обретает смысл. Такое подведение итогов располагает к достоинству и внутренней тишине. Оно не предопределено — тон этого периода задают осознанность человека и вся карта целиком.', 'reviewed', 2)
