INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:20:health_crown', 'numerology', 'Вопрос смысла звучит здесь как зов, на который однажды хочется ответить. Коронная чакра под Арканом «Суд» связывает духовное измерение с темой подведения итогов: тянет осмыслить пройденное целиком, спросить себя, куда всё вело, и услышать более высокую перспективу. Такая склонность питает ощущение, что жизнь — связный путь, а не набор случайностей. Речь о поиске смысла, а не о готовых ответах: как этот зов раскроется, зависит от внутренней зрелости и всей карты, и всегда остаётся делом свободного выбора.', 'reviewed', 2)
