INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:20:health_heart', 'numerology', 'Сердце в этой позиции учится прощать — прежде всего задним числом. Сердечная чакра с Арканом «Суд» разворачивает тему переосмысления в области чувств: старые обиды и привязанности словно ждут пересмотра, чтобы отпустить их без горечи и освободить место теплу. Эта склонность располагает к зрелой близости, где отношения периодически честно сверяются, а не тянутся по инерции. Прощение здесь не обязанность, а возможность; насколько она реализуется, зависит от выбора человека и всей конфигурации карты.', 'reviewed', 2)
