INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:20:health_root', 'numerology', 'Ощущение почвы под ногами у этого человека завязано на честность с собой. Корневая чакра под Арканом «Суд» описывает опору и жизненный тонус через мотив переоценки: устойчивость рождается не из того, что всё застыло, а из умения время от времени пересматривать основания — на чём я стою и что меня держит. Такая внутренняя ревизия возвращает бодрость и чувство права на своё место. Это символическая склонность, а не приговор: как она отзовётся в самочувствии, зависит от образа жизни, осознанности и всей карты целиком.', 'reviewed', 2)
