INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:20:health_sacral', 'numerology', 'Живая энергия и вкус к удовольствию здесь проходят проверку смыслом. Сакральная зона с Арканом «Суд» связывает чувственность с темой пересмотра: желания то и дело просятся на честный «переучёт» — какие из них по-настоящему мои, а какие достались по привычке. Когда человек умеет отделять одно от другого, возвращается свежесть и вдохновение вместо механического повторения. Это про обновление отношений с собственными импульсами — склонность, которая раскрывается по выбору и звучит в связке со всей картой, а не сама собой.', 'reviewed', 2)
