INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:20:health_solar_plexus', 'numerology', 'Самооценка тут держится не на прошлых титулах, а на способности честно оценить себя сегодняшнего. Солнечное сплетение под Арканом «Суд» окрашивает волю темой итога: сила приходит, когда человек подводит промежуточную черту, признаёт свои настоящие заслуги и отпускает устаревшее «я». Такой внутренний суд, если он справедлив и мягок, укрепляет опору внутри. Опасность — в приговорах самому себе; ценность — в трезвой самоподдержке. Как проявится эта грань, определяет осознанность и весь рисунок карты, а не рок.', 'reviewed', 2)
