INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:20:health_third_eye', 'numerology', 'Ясность здесь приходит как момент прозрения — когда разрозненные детали вдруг складываются в целое. Третий глаз с Арканом «Суд» описывает интуицию через тему пробуждения: способность внезапно увидеть суть, услышать внутренний сигнал и понять, что настало время переоценить взгляды. Эта грань располагает к трезвому чутью — не мистике, а умению честно распознавать, где правда, а где самообман. Проявится ли она ясным видением или тревожной мнительностью, зависит от осознанности и от всей карты.', 'reviewed', 2)
