INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:20:health_throat', 'numerology', 'Голос обретает силу, когда человеку есть что подытожить. Горловая чакра под Арканом «Суд» связывает самовыражение с темой осмысленного слова: тянет говорить не ради шума, а чтобы назвать прожитое своими именами, подвести черту, обозначить выводы. Такая речь звучит весомо и честно. Обратная сторона — соблазн вечно выносить вердикты вслух; баланс приходит с тактом. Это склонность к разговору по существу, и раскрывается она по мере осознанности, в согласии с остальной картой, а не автоматически.', 'reviewed', 2)
