INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:20:money_line', 'numerology', 'Деньги в этой линии откликаются на честный «переучёт». Аркан «Суд» на денежной теме указывает на склонность подводить итоги в делах: пересматривать, что действительно приносит отдачу, отпускать отжившие проекты и давать второй шанс перспективным. Достаток здесь связан не со слепым накоплением, а с умением вовремя оценить сделанное и перестроиться. Это не обещание богатства и не приговор, а описание подхода: сила — в трезвой ревизии ресурсов, а результат зависит от решений человека и всей карты целиком.', 'reviewed', 2)
