INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:20:point_center', 'numerology', 'По-настоящему спокойно этому человеку становится не в застывшей стабильности, а в моменте честности с самим собой. Центр октаграммы с Арканом «Суд» описывает зону комфорта как пространство внутренней ревизии: там, где другие тревожатся, оглядываясь назад, здесь находят опору. Умение подвести итог, признать сделанное и мягко начать сначала — тот ресурс, к которому тянет вернуться в трудную минуту. Это склонность, а не обязанность; развитая осознанно, она даёт редкую устойчивость, но её оттенок зависит от всей карты.', 'reviewed', 2)
