INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:20:point_day', 'numerology', 'Есть люди, которым дан особый слух: они улавливают момент, когда прожитое просит осмысления, и не проходят мимо. Двадцатый Аркан на «Дне» описывает именно такой личный дар — способность честно оглянуться на пройденное, отделить важное от случайного и собрать разрозненный опыт в ясную картину. Это талант обновления, умение услышать внутренний зов и откликнуться, не застревая в старых ролях. Проявится ли он зрелой мудростью или склонностью к бесконечному самокопанию, зависит от осознанности и всей карты в целом; сам по себе это ресурс, а не приговор.', 'reviewed', 2)
