INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:20:point_f4', 'numerology', 'Четвёртый квадрант собирает разрозненное в целое. Если в других зонах «Суд» разбирает прошлое, то здесь он его интегрирует: сшивает опыт разных лет в связную историю, где даже ошибки обретают смысл. Эта грань располагает к зрелому взгляду — видеть не обрывки, а линию собственного пути и подводить по ней осмысленный итог. Дар этой зоны — цельность вместо фрагментов; но раскрывается он постепенно, по мере осознанности, и звучит по-своему в сочетании с остальной картой.', 'reviewed', 2)
