  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:20:point_month', 'numerology', 'Материнская линия здесь звучит как призыв завершить недосказанное. Двадцатый Аркан в точке «Месяц» разворачивает родовую тему подведения итогов: непрожитое и непонятое прежними поколениями по женской линии склонно возвращаться, пока кто-то не решится взглянуть на него прямо. Задача этой зоны — не судить предков, а пересобрать их опыт: признать, простить, отпустить лишнее и вынести дальше только зрелое. Это не фатум, а направление роста; насколько оно раскроется, зависит от готовности к внутренней работе и от всей карты целиком.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:20:point_tasks', 'numerology', 'Главная задача, зашитая в этой точке, — научиться вовремя останавливаться и оглядываться. Аркан «Суд» на «Задачах» говорит о жизненном сюжете переосмысления: человека раз за разом подводит к рубежам, где нужно подвести итог прожитого этапа и честно решить, что взять дальше, а что оставить позади. Это склонность к внутренним «переучётам», к пробуждению от инерции и переходу на новый виток. Сила такого пути — расти через осмысление, а не через слепое повторение; как именно он сложится, определяет свободный выбор, а не рок.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
