  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:20:point_year', 'numerology', 'Отцовская линия просит ревизии — спокойной, без обвинений. В точке «Год» Аркан «Суд» указывает на родовую тему переоценки: заслуги, амбиции и ошибки мужской линии словно ждут, когда их наконец рассмотрят при ясном свете и подведут честный итог. Здесь ценно не переписывать историю рода, а услышать её урок и освободить себя от автоматических повторов. Такая работа располагает к внутренней свободе, но происходит по выбору, а не по принуждению судьбы; многое решает контекст всей матрицы.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:20:purpose_ancestral', 'numerology', 'Роду в этой точке словно поручено закрыть давние счёты. Аркан «Суд» в зоне родового предназначения разворачивает тему завершения: одна из миссий линии — пересмотреть накопленное поколениями, простить старые долги и вынести дальше только зрелый опыт, не таща за собой отживший груз. Такой человек склонен становиться тем, на ком род подводит итог и начинает новую главу. Это возможность, а не повинность; насколько она осуществится, зависит от осознанной работы и от всей матрицы целиком.', 'reviewed', 2)
