INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:20:purpose_personal', 'numerology', 'Личное призвание в этой карте связано с ролью того, кто помогает подводить итоги — себе и другим. Аркан «Суд» в зоне личного предназначения указывает на путь через переосмысление: человека тянет к делу, где важно честно оценивать сделанное, обновлять устаревшее, давать вещам и людям второй шанс на новом уровне. Это склонность быть «будильником» — тем, кто пробуждает и помогает начать заново. Предназначение здесь не заданный маршрут, а направление, которое раскрывается по мере осознанного выбора и в связке со всей картой.', 'reviewed', 2)
