  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:20:purpose_social', 'numerology', 'В обществе этому человеку идёт роль того, кто помогает переоценивать и обновлять. Аркан «Суд» в зоне социального предназначения указывает на склонность влиять через справедливую ревизию: подводить итоги для команды, возвращать людям веру во второй шанс, будить там, где всё застыло в привычке. Это про честность и обновление в общем деле, а не про громкие вердикты. Такой вклад раскрывается постепенно и по выбору — как он проявится, зависит от осознанности и от того, как эта грань сплетается с остальной картой.', 'reviewed', 2)
