INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:20:purpose_spiritual', 'numerology', 'Духовный маршрут здесь пролегает через пробуждение. Аркан «Суд» в зоне духовного предназначения говорит о пути, где главное событие — внутренний зов, момент, когда человек перерастает прежнее понимание себя и поднимается на новый уровень. Это склонность к глубоким переоценкам мировоззрения, к «воскрешению» смыслов, которые казались забытыми. Такой путь располагает к зрелой вере — не слепой, а прошедшей честную проверку. Он не предопределён: раскрывается по мере готовности и звучит в согласии со всей картой.', 'reviewed', 2)
