  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:20:relationship_line', 'numerology', 'Отношения в этой линии живут по закону честного пересмотра. Аркан «Суд» на линии отношений описывает склонность периодически подводить итог: где мы, куда идём, что стоит договорить и простить. Такие пары и дружбы не тянутся по инерции — они время от времени будто заново «слышат» друг друга и обновляются. Плюс этой темы — зрелость и умение давать второй шанс; риск — превратить близость в суд с приговорами. Баланс приходит с тактом, и то, каким он будет, зависит от выбора обоих и от всей карты.', 'reviewed', 2)
