INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:21:age_period_1', 'numerology', 'Первый девятилетний отрезок под знаком «Мира» задаёт мягкую ноту цельности уже на старте. В ранние годы это может проявляться как ощущение защищённости и принадлежности — ребёнку важно чувствовать себя частью тёплого, понятного мира. Такой период располагает закладывать базовое доверие: всё связно, у всего есть место. Это не предопределение, а склонность фона; то, как она сыграет, зависит от среды и всей карты, но сама тема — про округлость, завершённость и уют начала пути.', 'reviewed', 2)
