INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:21:age_period_2', 'numerology', 'Во втором девятилетии тема собирания опыта в целое звучит уже отчётливее. «Мир» на этом этапе может проявляться как интерес к разнообразию — миру во всей его пестроте — и одновременно как потребность находить в нём порядок и связь. Это располагает завершать освоенное и переходить дальше без потери себя. Такая окраска периода — тенденция, а не расписание событий: как именно она развернётся, во многом зависит от окружения и осознанного выбора.', 'reviewed', 2)
