INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:21:age_period_3', 'numerology', 'К третьему отрезку жизни «Мир» приносит вкус первых завершённых кругов. Здесь тема Аркана может ощущаться как способность оглянуться и увидеть пройденное как цельный отрезок, а не набор случайностей. Период располагает к внутреннему согласию и укреплению чувства «я на своём месте», к тому, чтобы гармонично соединять уже накопленное с новым. Проявится это по-разному и не по приговору — многое решают контекст, зрелость и вся карта целиком.', 'reviewed', 2)
