INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:21:age_period_4', 'numerology', 'Четвёртое девятилетие под этим Арканом располагает к ощущению устойчивой полноты. «Мир» здесь может звучать как зрелая радость от того, что многое уже сложилось: сформированы опоры, найдено своё место, видна связность жизни. Это время, когда завершённость переживается не как остановка, а как надёжная площадка для следующего шага. Разумеется, это склонность, а не предопределённость: то, как раскроется этап, во многом зависит от осознанного выбора.', 'reviewed', 2)
