INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:21:age_period_5', 'numerology', 'На пятом отрезке жизни двадцать первый Аркан подсвечивает тему итога и синтеза. «Мир» располагает собирать разные линии — дело, отношения, внутренний путь — в единую, осмысленную картину и находить в этом опору. Такой период может ощущаться как согласие с собой и способность ценить целое, а не гнаться за недостающим фрагментом. Это не приговор и не сценарий: как именно сыграет эта нота, во многом определяют обстоятельства и мера осознанности.', 'reviewed', 2)
