INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:21:age_period_6', 'numerology', 'На шестом девятилетнем витке «Мир» окрашивает жизнь гармонией и темой завершённых дел. На этом этапе склонность Аркана может проявляться как умение отпускать отжившее без сожаления и радоваться собранной полноте — семье, ремеслу, кругу близких. Завершённость здесь ощущается как естественная зрелость плода, а не как утрата. То, как развернётся период, зависит от многих условий и всей карты целиком — это тенденция фона, а не предопределённый ход событий.', 'reviewed', 2)
