INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:21:age_period_7', 'numerology', 'Седьмой отрезок жизни под двадцать первым Арканом связан с ощущением подведённых итогов. «Мир» располагает смотреть на пройденное с благодарностью и целостностью — как на завершённый узор, в котором каждая нить не случайна. Этот период может дарить спокойствие того, кто чувствует себя в ладу с миром и собой. Понимание такой окраски помогает мягче обходиться с собой и опираться на неё как на ресурс, не превращая в жёсткий прогноз.', 'reviewed', 2)
