INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:21:age_period_8', 'numerology', 'Восьмое девятилетие замыкает большой круг, и «Мир» звучит здесь как естественная кульминация темы целостности. На этом этапе Аркан располагает переживать зрелую полноту: способность видеть жизнь как связное целое, ценить накопленное и делиться им. Завершённость раскрывается не как финал, а как щедрость итога — то, что можно передать дальше. Это склонность, а не приговор; насколько тепло она проявится, во многом зависит от осознанности и всего рисунка карты.', 'reviewed', 2)
