INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:21:health_crown', 'numerology', 'Коронная зона отвечает за чувство смысла и связь с чем-то большим, и здесь «Мир» звучит особенно естественно — как ощущение, что ты часть огромного стройного целого. Двадцать первый Аркан располагает переживать духовность не как отрыв от жизни, а как её полноту: мир осмыслен, круг замкнут, всё на месте. Это может проявляться как тихое согласие с ходом вещей и благодарность за пройденное. Такое переживание не даётся по расписанию — оно раскрывается тем, кто оставляет место тишине и созерцанию.', 'reviewed', 2)
