INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:21:health_heart', 'numerology', 'В сердечной зоне двадцать первый Аркан раскрывается как способность любить целостно и принимать людей вместе с их несовершенством. «Мир» располагает к эмоциональной полноте — состоянию, когда в отношениях чувствуешь себя дома, а привязанность не давит, а обнимает. Сердце здесь тянется к гармонии и к честным связям без недосказанности. Как это проявится — во многом зависит от осознанности: полнота чувства раскрывается там, где есть готовность и отдавать, и принимать.', 'reviewed', 2)
