INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:21:health_root', 'numerology', 'Корневая чакра — про опору, устойчивость и общий тонус, и «Мир» окрашивает её ощущением «я на своём месте». С этим Арканом заземлённость переживается через принадлежность: к земле, дому, кругу людей, — и отсюда берётся спокойная бодрость. Когда человек чувствует себя частью целого, появляется разрешение расслабиться и восстановить силы. Это описание энергии и настроя, а не приговор: поддержать опору помогают простые вещи — ритм, движение, связь с близкими.', 'reviewed', 2)
