INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:21:health_sacral', 'numerology', 'Там, где речь идёт о чувственности, вкусе к жизни и творческом токе, «Мир» звучит как полнота переживания. Сакральная зона с этим Арканом располагает наслаждаться моментом целиком, а не урывками, и находить удовольствие в завершённости — в доведённом до конца танце, разговоре, объятии. Энергия здесь любит гармонию и не терпит суеты. Это про настрой и вкус к жизни; питает такую чувственность внимание к себе и позволение себе радоваться.', 'reviewed', 2)
