INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:21:health_solar_plexus', 'numerology', 'Солнечное сплетение отвечает за волю, самоощущение и внутренний стержень. «Мир» в этой зоне располагает к спокойной, зрелой уверенности — той, что растёт не из борьбы, а из чувства завершённого дела и заслуженного места под солнцем. Самооценка здесь опирается на пройденный путь: «я уже многое собрал воедино, значит, справлюсь и дальше». Это тенденция, а не обещание; крепнет она тогда, когда человек замечает и присваивает свои завершённые победы, пусть и небольшие.', 'reviewed', 2)
