  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:21:health_third_eye', 'numerology', 'Когда говорят о внутреннем зрении и ясности ума, «Мир» добавляет сюда чувство целого. Зона третьего глаза с этим Арканом располагает видеть картину целиком — не отдельные фрагменты, а то, как они связаны и куда ведёт узор. Интуиция здесь работает как ощущение завершённости: «вот теперь всё сходится». Это склонность, а не сверхспособность; яснее она становится, когда человек даёт себе паузу, тишину и доверяет спокойному наблюдению вместо тревожной гонки за деталями.', 'reviewed', 2)
