INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:21:health_throat', 'numerology', 'Горловой центр — про голос, честность и умение быть услышанным. «Мир» окрашивает самовыражение темой завершённости: такому человеку важно договаривать до конца, сводить мысль к ясной форме и не оставлять важное невысказанным. В общении это может проявляться как редкий дар подводить итог, примирять точки зрения, находить слова, в которых спор наконец складывается в согласие. Понимание этой черты помогает бережнее обходиться с собой и опираться на неё как на ресурс.', 'reviewed', 2)
