INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:21:money_line', 'numerology', 'В денежной теме «Мир» звучит как достаток-итог, а не достаток-рывок. Эта линия располагает к устойчивому изобилию, которое приходит как закономерное завершение вложенного труда: не внезапный куш, а собранный по кирпичику целостный результат. Финансовое благополучие здесь часто связано с ощущением «дела на своём месте» и умением доводить проекты до полной, оплачиваемой формы. Это тенденция, а не обещание богатства; раскрывается она через терпение, вкус к завершённости и разумное обращение с ресурсами.', 'reviewed', 2)
