  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:21:point_center', 'numerology', 'В самой сердцевине рисунка «Мир» отвечает за то место, где человеку легко дышится. Зона комфорта с этим Арканом — про ощущение, что ты на своём месте и в ладу с окружающим: завершённость здесь переживается не как финал, а как уют полноты. Отдых приходит тогда, когда удаётся почувствовать себя частью большего целого — природы, круга близких, любимого дела. Эту опору стоит беречь: она не приговор и не обязанность, а тихий ресурс, к которому можно возвращаться.', 'reviewed', 2)
