INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:21:point_day', 'numerology', 'Двадцать первый Аркан «Мир» на «Дне» — это дар доводить начатое до внутренней завершённости и ощущать вкус финального аккорда. В личных качествах он может проявляться как редкая способность собирать разрозненное в целое: людей, идеи, детали проекта. Такой человек нередко чувствует себя своим в любой точке мира и умеет находить гармонию там, где другие видят хаос. Это не готовое обещание успеха, а талант-ресурс — он раскрывается тем полнее, чем осознаннее его пускают в дело.', 'reviewed', 2)
