  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:21:point_f1', 'numerology', 'Квадрант Ф1 показывает, из какого материала человек черпает силы в первой опоре октаграммы, и «Мир» окрашивает её темой цельности. Здесь ресурсом становится способность видеть картину целиком и доводить дела до округлого, завершённого вида. Такой заряд помогает не растекаться по мелочам, а собирать усилия в результат, который приятно оставить за спиной. Насколько активно это работает — зависит от того, даёт ли человек себе разрешение доводить начатое до конца.', 'reviewed', 2)
