INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:21:point_f2', 'numerology', 'Во второй грани октаграммы «Мир» проявляется как умение приводить разрозненное к согласию. Это тот внутренний ресурс, что включается, когда нужно свести концы с концами и увидеть в пёстрой мозаике стройный узор. Склонность к завершённости может ощущаться как спокойная уверенность: рано или поздно всё встанет на места, если действовать вдумчиво. Такая опора не работает сама собой — её питает готовность доводить процессы до внятного итога, а не бросать на середине.', 'reviewed', 2)
