INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:21:point_f3', 'numerology', 'Третий квадрант отвечает за более тонкий пласт опоры, и двадцать первый Аркан вносит сюда чувство завершённого круга. Ресурс проявляется как способность отпускать отжившее и переживать окончания без драмы — как естественную смену сезона. Отсюда рождается устойчивость: человек, знакомый с полнотой цикла, легче переносит перемены и не цепляется за то, что уже сыграло свою роль. То, насколько это раскроется, во многом зависит от осознанности и всей карты целиком.', 'reviewed', 2)
