INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:21:point_f4', 'numerology', 'Ф4 — четвёртая точка внутренней опоры, и «Мир» превращает её в тему гармонии и итога. Сила здесь — в умении собрать пройденный путь в осмысленное целое и опереться на накопленное, а не начинать всё заново с нуля. Это располагает к зрелому взгляду: ценить сделанное, видеть связь событий, чувствовать почву под ногами. Ресурс раскрывается тем полнее, чем чаще человек позволяет себе признавать завершённые этапы завершёнными.', 'reviewed', 2)
