INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:21:point_month', 'numerology', 'По материнской линии сюда приходит тема целостности — умение завершать то, что поколениями оставалось незаконченным. «Мир» в точке «Месяц» намекает: женская ветвь рода несла в себе стремление к полноте и внутреннему согласию, и эту ноту хорошо продолжить в своей жизни. Задача мягкая по сути — не столько исправлять, сколько собирать наследие в гармоничное целое, отпуская то, что уже отслужило. Проявится она по-разному и во многом зависит от того, насколько бережно человек относится к своим корням.', 'reviewed', 2)
