INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:21:point_tasks', 'numerology', 'Главный жизненный сюжет с двадцать первым Арканом звучит как путь к внутренней завершённости. «Мир» на точке «Задачи» описывает склонность двигаться к состоянию, где разные стороны жизни — дело, отношения, внутренний мир — складываются в единую картину без надрыва. Это не про то, что «всё обязательно сойдётся», а про направление: учиться собирать себя целиком и радоваться пройденным кругам. Как именно это раскроется — во многом дело осознанного выбора и всей карты в целом.', 'reviewed', 2)
