INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:21:point_year', 'numerology', 'Отцовская ветвь в этой позиции отзывается мотивом зрелости и итога. Аркан «Мир» на точке «Год» располагает к тому, чтобы довести до ясной формы то, что мужская линия рода начинала, но не всегда доводила до конца — дело, дом, репутацию, чувство укоренённости. Здесь ценится не спешка, а способность завершать основательно, чтобы за спиной оставалось что-то целостное. Понимание этого помогает мягче обходиться с семейным грузом и превращать его в опору, а не в долг.', 'reviewed', 2)
