INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:21:purpose_ancestral', 'numerology', 'На уровне рода «Мир» разворачивает тему собирания и примирения. Родовое предназначение с этим Арканом может звучать как задача завершить длинные семейные сюжеты — соединить разрозненные ветви, вернуть ощущение единого целого, поставить точку там, где поколения оставляли многоточие. Речь не о долге и не о вине, а о даре приводить наследие к гармонии. Понимание этого помогает мягче обходиться с собой и относиться к роду как к опоре, а его историю — как к материалу для целостности.', 'reviewed', 2)
