INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:21:purpose_personal', 'numerology', 'Личное предназначение с двадцать первым Арканом связано с идеей завершённого пути. «Мир» намекает, что человеку важно прийти к состоянию внутренней целостности — собрать себя из множества ролей и опытов в единую, узнаваемую фигуру. Это призвание не о внешних вершинах, а о качестве присутствия: быть в ладу с собой и миром, доводить своё до полной формы. Как именно раскроется эта нота — дело свободного выбора; предназначение здесь скорее приглашение, чем предписание.', 'reviewed', 2)
