INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:21:purpose_social', 'numerology', 'В общественном измерении двадцать первый Аркан отвечает за роль объединителя. Социальное предназначение с «Миром» располагает к тому, чтобы связывать людей, культуры, разрозненные группы в работающее целое — быть тем, при ком разное перестаёт враждовать и начинает складываться. Это может выражаться в деле, которое перекидывает мосты и доводит общие начинания до завершения. Проявится ли эта нота громко или тихо — во многом зависит от выбора и обстоятельств, а не предрешено.', 'reviewed', 2)
