INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:21:purpose_spiritual', 'numerology', 'Духовный маршрут под знаком «Мира» ведёт к переживанию единства. Здесь предназначение может проявляться как тяга собрать внутренний и внешний мир в одну картину, почувствовать себя дома во вселенной и принять её как целое. Это путь не аскезы и отрицания, а полноты — умения видеть священное в завершённости обычной жизни. Такая ориентация ничего не обещает заранее и раскрывается постепенно, тем полнее, чем честнее человек ищет собственный, а не заёмный смысл.', 'reviewed', 2)
