  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:21:relationship_line', 'numerology', 'Линия отношений с двадцать первым Арканом окрашена стремлением к цельным, доведённым до ясности связям. «Мир» располагает искать в паре не фрагмент, а полноту — ощущение, что вдвоём складывается устойчивое целое, где каждому есть место. Такой человек ценит завершённость и в чувствах: договорённости проговорены, недомолвок мало, отношения похожи на общий, обжитый дом. Это склонность, а не сценарий: близость такого качества рождается там, где оба готовы вкладываться и взрослеть.', 'reviewed', 2)
