  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:22:age_period_1', 'numerology', 'Первый из девятилетних отрезков проходит под знаком чистого начала. Двадцать второй Аркан окрашивает этот период духом первооткрывателя: время располагает пробовать, начинать с нуля, смотреть на мир широко открытыми глазами. Спонтанность и любопытство здесь — попутный ветер: этап благоприятен для того, чтобы закладывать привычку не бояться нового. Это не предсказание событий, а тон, настроение цикла — склонность, которую можно использовать как ресурс. Прожить его осознанно значит позволить себе исследование, не требуя от каждого шага гарантий. Как именно сложится отрезок, зависит от вас и от всей карты.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:22:age_period_2', 'numerology', 'Второй девятилетний виток снова несёт мотив свежего старта, но уже с оттенком осознанного выбора. Шут в этом периоде приглашает не застывать: пробовать направления, менять маршрут, если прежний перестал вдохновлять. Открытость непредсказуемому здесь — про смелость пересобрать себя, отпустить то, что отжило. Это тенденция, а не расписанный сценарий: этап скорее располагает к экспериментам, чем предрекает конкретные повороты. Осознанность помогает отличить живое обновление от бегства по кругу. Наполнить этот отрезок содержанием — ваша свободная работа; двадцать второй Аркан лишь задаёт лёгкое, подвижное настроение.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:22:age_period_3', 'numerology', 'Третий цикл дышит воздухом перемен и незавершённости — в хорошем смысле. Двадцать второй Аркан располагает воспринимать этот отрезок как страницу, которую ещё интересно писать: время пробовать непривычное, доверять чутью, начинать заново там, где прежнее исчерпало себя. Спонтанность здесь способна стать ресурсом роста, если опереть её на внимание к себе. Это не приговор и не обещание конкретных событий, а склонность, тон девятилетия. Прожитый осознанно, период учит лёгкости без легкомыслия. Как он развернётся, во многом решают ваши выборы, а не предначертание карты.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:22:age_period_4', 'numerology', 'Четвёртый девятилетний отрезок приносит настроение открытой двери. Шут подсказывает: это подходящее время, чтобы не держаться за отжившее и позволить себе новое начало — сменить фокус, попробовать роль, о которой раньше только думалось. Открытость непредсказуемому здесь работает как свежий ветер, разгоняющий застой. Важно помнить, что это тенденция, а не гарантия: этап располагает к обновлению, но наполняете его вы. Осознанно прожитый, он превращает перемены в осмысленный шаг, а не в метание. Проявится этот тон ровно настолько, насколько вы готовы идти ему навстречу.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:22:age_period_5', 'numerology', 'Пятый цикл окрашен духом лёгкого эксперимента. Двадцать второй Аркан вносит в этот отрезок вкус к пробе и игре: время располагает смотреть на привычное свежим взглядом и не бояться начинать сначала. Спонтанность здесь — одна из граней, которую можно развивать в свою пользу, превращая любопытство в источник живого интереса к жизни. Это не предсказание конкретных поворотов, а настроение девятилетия, склонность, а не приговор. Осознанность помогает направить эту энергию в созидание, а не в разбрасывание. Каким получится период, зависит от ваших решений и от карты целиком.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
