  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:22:age_period_6', 'numerology', 'Шестой девятилетний отрезок несёт тему обновления и второго дыхания. Шут располагает в этот период чувствовать себя странником, для которого ещё много неоткрытых дорог: тянет пробовать, менять, начинать с чистого листа. Открытость непредсказуемому здесь может стать опорой и источником бодрости, если сочетать её с заботой о себе. Это тон цикла, склонность, а не расписанные события — то, как он сложится, зависит от осознанного выбора. Прожить его мягко значит позволить себе новизну без спешки и суеты. Двадцать второй Аркан лишь подсказывает направление, наполняете его вы.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:22:age_period_7', 'numerology', 'Седьмой цикл дышит свободой и правом на свежий старт. Двадцать второй Аркан окрашивает этот отрезок настроением лёгкости: время располагает отпускать лишнее, пробовать непривычное и относиться к переменам как к части естественного движения жизни. Спонтанность здесь — ресурс, который помогает мягче обходиться с собой и не застревать в отжившем. Это не приговор и не обещание конкретики, а тон девятилетия, склонность. Осознанно прожитый, период учит доверять процессу. Как именно он развернётся, решают ваши шаги и вся карта в совокупности, а не одно лишь предначертание.', 'reviewed', 2)
