INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:22:age_period_8', 'numerology', 'Восьмой девятилетний отрезок вновь приносит мотив начала — будто круг замкнулся и открылся заново. Шут в этом периоде напоминает: обнулиться и шагнуть в новое можно в любом возрасте, и этот этап особенно к этому располагает. Открытость непредсказуемому здесь — про способность удивляться и не считать, что всё уже сыграно. Это тенденция, а не жёстко заданный сценарий: время скорее приглашает к обновлению, чем предрекает события. Осознанность превращает лёгкость в мудрость, а не в бегство. Каким станет отрезок, зависит от вас; двадцать второй Аркан лишь задаёт его подвижный, живой тон.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
