  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:22:health_crown', 'numerology', 'На вершине, где рождаются вопросы о смысле, у вас дышит вечный странник. Коронная зона связана с духовностью, и двадцать второй Аркан придаёт ей особую свободу: вы ищете не готовую догму, а живой опыт, и готовы начинать духовный путь заново всякий раз, когда прежние ответы перестают звучать. Спонтанность здесь — про доверие к большему, про шаг в неизвестность с открытым сердцем. Такая непривязанность к формам может стать источником глубокого покоя, если опирается на внутреннюю честность. Это не предопределение, а склонность искать смысл в движении; направление вы выбираете сами.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
