  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:22:health_heart', 'numerology', 'В сердечной зоне, где живут привязанность и тепло, звучит тема лёгкого, незакрепощённого чувства. Шут располагает любить открыто и не спешить навешивать ярлыки: эмоции приходят свежо, как первое утро, и просят простора, а не клетки. Двадцать второй Аркан склоняет ценить в близости спонтанность — искренний порыв, игру, готовность удивлять и удивляться. Это дар живого сердца, если он уравновешен верностью себе и другому; иначе лёгкость рискует обернуться бегством от глубины. Осознанность помогает соединить свободу и близость. Как именно — решаете вы; это не приговор, а приглашение к тёплой честности.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
