  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:22:health_root', 'numerology', 'Там, где обычно ищут прочную почву под ногами, у вас поселился дух лёгкого путника. Корневая зона отвечает за опору и жизненный тонус, и двадцать второй Аркан придаёт ей необычную окраску: устойчивость приходит к вам не через неподвижность, а через движение и обновление. Спонтанность здесь — источник бодрости: вы наполняетесь силами, когда впереди новое, и тускнеете в застое. Тенденция — черпать опору в самом ощущении открытой дороги. Стоит лишь помнить о заземлении: осознанно сочетая свободу с простыми ритуалами быта, вы делаете эту лёгкость надёжным ресурсом, а не почвой для тревоги. Это символический ориентир, а не приговор.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:22:health_sacral', 'numerology', 'Область удовольствия, творчества и живого влечения окрашена у вас игрой и азартом. Шут вносит в сакральную зону вкус к новизне: чувственность оживает там, где есть спонтанность, эксперимент, лёгкое «а что, если». Двадцать второй Аркан располагает к тому, чтобы радость рождалась из непредсказуемого, а не из привычного сценария. Это ресурс вдохновения и телесной бодрости — при условии, что открытость идёт рука об руку с уважением к себе и к другим. Осознанность превращает азарт в источник творческой энергии; без неё он способен рассеиваться. Как проявится эта грань, зависит от вас и от карты в целом — это ориентир, а не предопределение.', 'reviewed', 2)
