INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:22:health_solar_plexus', 'numerology', 'Внутренний стержень, отвечающий за волю и чувство собственной ценности, у вас питается свободой. Двадцать второй Аркан подсказывает: ваша сила крепнет не от жёсткого самоконтроля, а от права пробовать, ошибаться и начинать заново без самоедства. Спонтанность здесь работает на самооценку — вы уважаете себя, когда позволяете себе риск и новое. Тенденция — терять кураж в тесных рамках и оживать в просторе выбора. Осознанно направленная, эта черта даёт лёгкую, незанудную уверенность; без внимания к финалу может мешать доводить начатое. Баланс воли и спонтанности вы выстраиваете сами; это склонность, а не готовый вердикт.', 'reviewed', 2)
