INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:22:health_third_eye', 'numerology', 'Внутреннее зрение работает у вас через свежесть, а не через тяжёлый анализ. Область интуиции и ясности окрашена духом Шута: озарения приходят внезапно, будто из ниоткуда, когда вы отпускаете напряжённый поиск и доверяете первому чистому впечатлению. Двадцать второй Аркан располагает видеть привычное новыми глазами — замечать то, что ускользает от заранее готовых схем. Эта открытость непредсказуемому — ценный источник прозрений, если её не путать с импульсивностью. Осознанно вы учитесь отличать подлинную интуицию от простого желания перемен. Это грань, которую можно развивать; как она раскроется, зависит от всей карты.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
