  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:22:health_throat', 'numerology', 'Голос, которым вы заявляете о себе миру, у вас звонкий и импровизационный. Горловая зона отвечает за самовыражение, и двадцать второй Аркан делает вашу речь живой, неожиданной, свободной от заученных формул. Спонтанность проявляется как умение говорить от сердца, шутить, находить свежее слово там, где другие повторяют штампы. Это ресурс искренней коммуникации — при условии, что за лёгкостью стоит внимание к собеседнику. Осознанно ваш голос вдохновляет и располагает; в спешке он способен опережать мысль. Развивать эту грань значит соединять открытость с чуткостью; выбор ритма остаётся за вами.', 'reviewed', 2)
