INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:22:money_line', 'numerology', 'С деньгами у вас складываются отношения импровизатора, а не строгого бухгалтера. Двадцать второй Аркан вносит в финансовую линию дух пробы: доходы легче приходят через новое, через смелость начать неизведанное дело, чем через десятилетия в одной колее. Спонтанность здесь — и ресурс, и зона внимания: чутьё на возможности стоит уравновешивать простой дисциплиной, чтобы лёгкость не оборачивалась хаосом в тратах. Тенденция — оживать в проектах со свободой манёвра и скучать в жёстких рамках. Это не обещание богатства и не приговор к нужде, а склонность; ваш достаток вы выстраиваете осознанными решениями.', 'reviewed', 2)
