INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:22:point_center', 'numerology', 'В самой сердцевине, там, где человек отдыхает и восстанавливается, у вас поселился Шут. Комфортнее всего вам, как ни странно, в непредсказуемом: в свободе без жёсткого расписания, в возможности передумать, в лёгком «а давай попробуем». Двадцать второй Аркан располагает чувствовать себя дома именно тогда, когда впереди открытая дорога, а не расписанный по минутам маршрут. Опора для вас — не стабильность, а ощущение простора и права на новое начало. Стоит помнить: это ресурс, пока вы им управляете; тогда спонтанность становится тихой внутренней свободой, а не поводом избегать любых обязательств.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:22:point_day', 'numerology', 'Дар начинать с чистого листа — вот что читается в этой точке, отвечающей за врождённые способности. Двадцать второй Аркан, Шут, наделяет лёгкостью на подъём: там, где другие месяцами взвешивают, вы делаете первый шаг и разбираетесь по дороге. Ваш талант — не в дотошном плане, а в импровизации, в умении превратить неожиданность в приключение и увидеть свежим взглядом то, что остальные считают решённым. Эта спонтанность становится ресурсом, если опереть её на внимание к себе: тогда открытость непредсказуемому оборачивается не безрассудством, а живым чутьём на новое. Как именно раскроется этот дар, зависит от вас и от всей карты в целом.', 'reviewed', 2)
