  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:22:point_f1', 'numerology', 'Один из квадрантов вашей матрицы окрашен духом вечного странника. Здесь двадцать второй Аркан проявляется как готовность сорваться с места ради нового опыта, любопытство ребёнка, для которого мир ещё не поделён на «можно» и «нельзя». В этой зоне вы легки на подъём, охотно пробуете непроверенное и умеете начинать с нуля без лишнего драматизма. Такая открытость случаю — сила, когда опирается на осознанность: тогда вы не разбрасываетесь, а идёте туда, куда действительно зовёт интерес. Это грань, которую можно бережно развивать в свою пользу, а не сдерживать из одной лишь осторожности.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:22:point_f2', 'numerology', 'Здесь, в другом квадранте октаграммы, звучит нота импровизации. Шут наделяет эту часть вашей натуры способностью действовать по наитию, ловить момент и превращать заминку в неожиданный ход — так джазмен вплетает случайную ноту в мелодию. Спонтанность и открытость непредсказуемому проявляются как гибкость: план меняется на ходу, и вас это не выбивает, а вдохновляет. Тенденция — доверять первому свежему импульсу и не бояться незнакомого. Развитая осознанно, эта черта становится редким умением быть уместным даже в хаосе; без неё рискует обернуться суетой. Куда качнётся маятник, во многом зависит от вас.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:22:point_f3', 'numerology', 'Ещё одна грань матрицы дышит лёгкостью и несерьёзностью — в лучшем смысле слова. Двадцать второй Аркан вносит сюда игру: умение не превращать каждый шаг в судьбоносное решение, смеяться над собственными спотыканиями и начинать заново без тяжести на сердце. Открытость непредсказуемому здесь — про способность отпускать контроль и позволять жизни удивлять. Это склонность, а не приговор: осознанно она становится мудрой лёгкостью зрелого человека, неосознанно может уводить от нужной глубины. Баланс рождается там, где спонтанность встречается с вниманием к последствиям, — и выбор этой встречи остаётся за вами.', 'reviewed', 2)
