  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:22:point_f4', 'numerology', 'Замыкает четвёрку квадрантов мотив дороги без заранее вычерченного маршрута. В этой зоне Шут раскрывается как тяга к новому началу — готовность закрыть один этап и шагнуть в следующий, доверяя чутью больше, чем прогнозам. Спонтанность проявляется как способность обнулиться и начать сначала там, где другие держатся за отжившее. Такая внутренняя свобода — ценный ресурс, когда она осознанна: тогда перемены обновляют, а не рассеивают силы. Помните, что проявление любой грани зависит от всей карты и от ваших решений; это направление, а не жёстко заданный сценарий.', 'reviewed', 2)
