  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:22:point_month', 'numerology', 'По материнской линии сюда приходит негласное поручение: учиться доверять жизни и отпускать сверхконтроль. Шут, двадцать второй Аркан, намекает, что род копил осторожность — и теперь просит внести в неё воздуха, спонтанности, готовности к новому. Возможно, женщины вашей линии слишком крепко держались за привычное; ваша тенденция — разрешить себе лёгкость, начинать без гарантий и относиться к переменам как к части пути, а не к угрозе. Это не долг и не приговор, а мягкое приглашение развернуть родовой сценарий в сторону открытости. Проявится оно ровно настолько, насколько вы осознанно выберете этот разворот.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:22:point_tasks', 'numerology', 'Если свести смысл к одному вектору, главная работа вашей жизни — научиться идти налегке. Шут в этой ключевой точке говорит не о легкомыслии, а о смелости начинать снова и снова, не цепляясь за прошлые роли и итоги. Тенденция — доверять процессу больше, чем плану, и находить смысл в самом движении, а не только в пункте назначения. Ваша задача — приручить спонтанность: сделать её осознанным выбором, а не бегством, и позволить непредсказуемому обновлять вас, а не пугать. Это не заданный сверху приговор, а направление, которое вы вправе наполнить собственным содержанием.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:22:point_year', 'numerology', 'Отцовская линия разворачивает похожий сюжет, но со своим акцентом — на смелость первого шага. Двадцать второй Аркан здесь про наследуемую способность срываться в неизведанное без страховки и не терять при этом лёгкости. Мужская ветвь рода могла передавать либо страх риска, либо, наоборот, порыв всё бросить и уйти налегке; задача — найти зрелую середину, где спонтанность служит вам, а не сбивает с курса. Склонность к новым началам тут можно превратить в опору: пробовать, ошибаться, начинать заново — без вины и надрыва. Насколько это раскроется, решает не карта, а ваши осознанные шаги.', 'reviewed', 2)
