  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:22:purpose_ancestral', 'numerology', 'На уровне рода вам словно передан наказ вносить свежий воздух. Там, где предки, возможно, застывали в проверенных укладах, ваша роль — двадцать второй Аркан подсказывает это мягко — оживлять линию духом обновления, спонтанности, права на новое. Вы способны разомкнуть повторяющиеся сценарии и показать роду, что перемены не угроза, а дыхание жизни. Это не тяжкий долг и не приговор, а склонность быть тем, кто начинает новую главу общей истории. Насколько она проявится, зависит от вашего осознанного выбора и от карты в целом — родовые темы не диктуют, а лишь предлагают направление.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:22:purpose_personal', 'numerology', 'Ваше личное призвание связано с ролью первопроходца. Двадцать второй Аркан намекает: вам органично открывать двери, пробовать неизведанное и показывать другим, что начать с нуля — не страшно, а живо. Спонтанность и открытость новому здесь не каприз, а способ реализоваться: вы расцветаете там, где есть простор для эксперимента и право на свежий старт. Тенденция — тяготиться колеёй и оживать в начинаниях. Это направление, а не жёсткий приказ судьбы: наполнить его конкретикой, найти своё поле для первопроходчества — ваша осознанная работа. Предназначение раскрывается настолько, насколько вы идёте ему навстречу.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:22:purpose_social', 'numerology', 'В общественном поле вам идёт роль того, кто расшатывает застой и напоминает о свежем взгляде. Двадцать второй Аркан склоняет привносить в коллективы дух эксперимента: вы умеете предложить непривычное решение, разрядить напряжение шуткой, показать, что перемены возможны. Спонтанность здесь — социальный ресурс: рядом с вами люди чувствуют, что дозволено пробовать и ошибаться. Это тенденция, а не назначенная миссия; чтобы она сработала, важно соединить лёгкость с ответственностью перед теми, кого ведёшь за собой. Как именно раскроется эта грань в обществе, решаете вы своими осознанными шагами.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:22:purpose_spiritual', 'numerology', 'Духовная задача разворачивается здесь как путь налегке. Шут говорит о готовности идти, не зная всего маршрута, доверять большему и снова становиться учеником всякий раз, когда кажется, что всё уже понято. Двадцать второй Аркан располагает искать не окончательную истину в камне, а живое переживание, которое обновляется. Открытость непредсказуемому на этом уровне — про смирение и доверие, про способность отпустить контроль над «как должно быть». Это тонкая склонность, а не предписание: духовный путь вы прокладываете сами, и лёгкость Шута может стать в нём и опорой, и соблазном — осознанность помогает отличить одно от другого.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:22:relationship_line', 'numerology', 'В близких связях вами движет тяга к живому, не застывшему чувству. Двадцать второй Аркан окрашивает линию отношений духом лёгкости: вы цените в союзе свободу дышать, спонтанные жесты, способность обоих удивлять друг друга и не превращать любовь в свод правил. Тенденция — тянуться к тем, с кем можно оставаться собой и начинать день будто заново. Эта открытость — дар, если её уравновешивает надёжность; иначе лёгкость рискует стать уходом от близости. Осознанно вы учитесь соединять простор и верность. Это склонность, а не сценарий: какими будут ваши отношения, вы пишете вместе с партнёром.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:2:age_period_1', 'numerology', 'В первом девятилетнем отрезке тема Жрицы звучит как ранняя, ещё не осознанная чуткость. Это время, когда внутренний мир, воображение и способность тонко чувствовать закладываются как фундамент. Ребёнок или юный человек с таким акцентом нередко замечает больше, чем говорит, и живёт богатой внутренней жизнью. Понимание этого помогает бережнее относиться к себе тогдашнему — или к тем близким, кто проходит этот период сейчас: такой чуткости нужна безопасная, спокойная среда. Заложенное здесь тихое знание позже может стать опорой; как оно раскроется дальше — покажут следующие этапы.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:2:age_period_2', 'numerology', 'Следующий период — про первую встречу тонкого чутья с внешним миром и его правилами. Здесь внутреннее знание нередко проверяется на прочность: хочется соответствовать окружению, и негромкий внутренний голос легко приглушить ради «как у всех». Второй Аркан располагает как раз к тому, чтобы не потерять эту связь с собой под давлением среды. Тенденция такова, что уроки этого отрезка — про доверие: научиться замечать, когда интуиция была права, и не предавать её слишком легко. Что именно вынести из этого времени, во многом решаете вы сами.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:2:age_period_3', 'numerology', 'Третий отрезок часто связан с поиском своего и попыткой понять, чему внутри действительно можно верить. Верховная Жрица здесь располагает делать выбор не только рассудком, но и чутьём — прислушиваться к тому, что откликается, а что оставляет глухое сопротивление. Это время, когда полезно учиться отличать подлинное «моё» от чужих ожиданий. Одна из граней, которую можно развивать в свою пользу: привычка сверяться с собой перед важными поворотами. Насколько уверенно это получится, зависит от готовности доверять внутреннему знанию, а не только внешним ориентирам.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:2:age_period_4', 'numerology', 'Ближе к середине пути тема Жрицы просит соединить чутьё с делами и ответственностью. В этом периоде интуиция становится тише, но надёжнее: она помогает выбирать направление среди множества задач, не растрачивая себя на всё подряд. Склонность такова, что решения удаются лучше, когда вы не игнорируете внутренние сигналы ради одной лишь логики графиков и планов. Это одна из граней, которую стоит замечать: умение вовремя остановиться и спросить себя, туда ли я иду. Как распорядиться этим ресурсом, каждый решает по-своему.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:2:age_period_5', 'numerology', 'Этот период нередко разворачивает человека внутрь — к вопросам о смысле того, что уже сделано. Верховная Жрица располагает использовать такое затишье не как тревогу, а как возможность услышать себя заново, пересмотреть, что действительно важно. Внутреннее знание в это время может звучать особенно ясно, если дать ему тишину и не заглушать суетой. Тенденция — не бояться пауз и внутренних «зим», ведь в них часто вызревает следующий шаг. Понимание этого помогает мягче проходить время переоценки и не торопить то, что должно созреть само.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
