  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:2:age_period_6', 'numerology', 'К шестому отрезку накопленная чуткость всё чаще превращается в спокойную мудрость. Здесь Второй Аркан располагает не только слышать себя, но и делиться этим с другими — становиться человеком, рядом с которым легче думать и дышать. Тонкое знание, проверенное годами, теперь опирается на опыт, а не только на предчувствие. Это одна из граней, которую можно развивать в свою пользу: мягкое влияние, наставничество, умение поддержать без лишних слов. Проявится ли это так — зависит от вашей открытости; архетип лишь подсказывает, где может быть ваша сила в это время.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:2:age_period_7', 'numerology', 'Седьмой период тяготеет к внутреннему равновесию — когда чужое одобрение значит уже меньше, чем согласие с собой. Верховная Жрица в это время располагает жить из тихой уверенности: доверять накопленному знанию и не тратить силы на доказывание своей правоты. Тенденция — ценить простые, спокойные состояния и то, что по-настоящему наполняет, отпуская лишнее. Это не приговор и не расписание, а мягкий ориентир: чем больше вы в ладу со своей интуицией, тем ровнее проходит этот отрезок. Чем его наполнить, всегда остаётся вашим выбором.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
