  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:2:health_sacral', 'numerology', 'Энергия и чувственность здесь окрашены тонкостью и глубиной. Второй Аркан располагает к тому, чтобы удовольствие и живость приходили не от бурного напора, а изнутри — через настроенность на свои подлинные желания, а не навязанные. Вам ближе неспешная чувственность, в которой важны атмосфера, доверие и тишина между словами. Это одна из граней, которую можно развивать в свою пользу: чем внимательнее вы к тому, что вправду наполняет, тем ровнее течёт внутренняя энергия. Тело в этом смысле — чуткий собеседник, к которому стоит прислушиваться без спешки.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
