  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:2:health_solar_plexus', 'numerology', 'Воля и самооценка в этой зоне держатся на тихой внутренней уверенности, а не на громких доказательствах. Верховная Жрица подсказывает: ваша сила — в спокойном знании своей правоты, которое не нуждается в постоянном одобрении со стороны. Склонность такова, что самооценка крепнет, когда вы сверяетесь с собственным внутренним компасом, а не с чужими оценками. Здесь важно не путать мягкость с безволием: умение сказать «нет» без крика — тоже форма силы. Насколько уверенно она проявится, зависит от того, доверяете ли вы себе достаточно, чтобы не оправдываться.', 'reviewed', 2)
