  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:2:health_third_eye', 'numerology', 'Это словно родной дом Второго Аркана: тема интуиции и ясности здесь звучит в полную силу. Внутреннее зрение, способность видеть суть за внешним, предчувствие, точные образы во сне и наяву — всё это ваша естественная среда. Дар сильный, и именно поэтому его стоит заземлять: сверять озарения с реальностью и не принимать любую яркую мысль за истину. Понимание этой особенности помогает использовать её как ресурс, а не как повод уходить в фантазии. Ясность приходит к вам в тишине — стоит лишь освободить ей место среди внешнего шума.', 'reviewed', 2)
