  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:2:health_throat', 'numerology', 'Самовыражение под знаком Жрицы — история про ценность паузы и негромкого слова. Вам необязательно говорить много, чтобы быть услышанным: часто сильнее всего звучит именно то, что сказано тихо и вовремя. Здесь есть склонность больше слушать, чем говорить, и порой копить невысказанное внутри. Понимание этого помогает мягче обходиться с собой — не корить за молчаливость, но и учиться выпускать важное наружу, чтобы оно не застаивалось. Ваш дар — не красноречие напоказ, а точность: одно верное слово вместо десяти лишних.', 'reviewed', 2)
