  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:2:purpose_ancestral', 'numerology', 'Родовая тема просит собрать и сберечь то тихое знание, что копилось в семье поколениями. Верховная Жрица в этой позиции располагает стать своего рода хранителем — тем, кто чувствует связь времён, ценит память рода и умеет расслышать его негромкие уроки. Понимание этой грани помогает относиться к семейной истории не как к грузу, а как к источнику мудрости. Возможно, вам ближе роль того, кто хранит суть, а не громко о ней заявляет. Проявится ли это так — решаете вы; архетип лишь подсказывает, где может лежать ваш вклад в общий узор рода.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
