  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:2:purpose_personal', 'numerology', 'Личное предназначение здесь связано с тем, чтобы стать человеком, который умеет слышать — себя и других. Второй Аркан намекает: ваш путь во многом про доверие внутреннему знанию и про смелость жить в согласии с ним, даже когда вокруг советуют иначе. Это не грандиозная миссия напоказ, а тихая, но твёрдая верность себе. Тенденция такова, что чувство «я на своём месте» приходит, когда вы перестаёте заглушать интуицию ради удобных решений. Как именно это раскроется — зависит от ваших выборов и от всей карты целиком; архетип лишь показывает вектор.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
