  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:2:purpose_social', 'numerology', 'В обществе ваша сила может быть негромкой, но заметной по результату. Верховная Жрица располагает к роли того, к кому идут за советом, за взвешенным взглядом, за умением увидеть суть спора без лишних эмоций. Вы способны влиять не напором, а точностью и спокойствием — быть тем, кто вносит ясность и утишает шум. Это одна из граней, которую можно развивать в свою пользу: советник, посредник, наставник, чья ценность в глубине понимания, а не в громкости. Насколько ярко проявится эта роль, зависит от вашей готовности выходить к людям, а не только наблюдать со стороны.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:2:purpose_spiritual', 'numerology', 'Духовная линия ведёт вглубь — туда, где знание приходит не из книг, а из внутреннего опыта. Второй Аркан располагает к пути созерцания: искать истину в тишине, доверять постепенному раскрытию смысла и не спешить с окончательными ответами. Это склонность к внутренней работе, к вопросам «зачем» и «что за этим стоит». Здесь важно оставаться открытым и честным с собой, не превращая поиск в самолюбование. Как далеко вы пройдёте по этой дороге — дело свободного выбора; символ лишь очерчивает направление, а идти или нет — всегда за вами.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:2:relationship_line', 'numerology', 'В отношениях вы читаете партнёра почти без слов — по паузам, интонации, едва заметным переменам. Такая чуткость Второго Аркана делает близость глубокой, но требует бережности: легко начать домысливать за другого и обижаться на то, что человек не угадал невысказанное. Тенденция — доверять интуиции, но всё же проговаривать важное вслух, а не ждать, что вас прочтут так же тонко. Вам нужны отношения с пространством для тишины и доверия, где не обязательно заполнять каждую минуту разговором. Насколько тепло сложится связь, зависит от обоих — архетип лишь описывает ваш способ любить.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
