  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:3:age_period_1', 'numerology', 'Отмеченный Императрицей девятилетний отрезок ощущается как весна — время, когда хочется сажать и растить. В такой период располагает начинать живое: обустраивать пространство, пробовать творчество, вкладываться в отношения и заботу о себе. Энергия здесь созидательная и щедрая, поддерживающая начинания, у которых есть шанс расцвести. Тень — распыляться на слишком многое сразу. Это не сценарий, написанный заранее, а плодородная почва: что на ней взойдёт, зависит от того, каким семенам вы дадите место и внимание.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:3:age_period_2', 'numerology', 'На этот цикл третий Аркан приносит тему тепла — в отношениях с людьми и с собой. Отрезок располагает укреплять связи, создавать уют, учиться заботиться, не растворяясь без остатка. Хорошо раскрываются дела, где важны чувственность, красота, внимание к деталям быта. Императрица делает время мягче и щедрее, но напоминает: изобилие должно течь и к вам, а не только от вас. Как проявится эта склонность, зависит от вашей осознанности — период задаёт тон, а выбор наполняет его содержанием.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
