  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:3:age_period_3', 'numerology', 'В этом девятилетнем отрезке ярче обычного звучит творческая жилка. Третий Аркан открывает пору цветения: тянет создавать красивое, выражать себя, наполнять жизнь образами, вкусом, живыми впечатлениями. Это склонность к плодовитости замыслов — идей может оказаться больше, чем рук, чтобы их воплотить. Ресурс раскроется, если позволить себе играть и не обесценивать «несерьёзное». Ничего не предрешено: Императрица дарит вдохновение, но превратить его в плоды — ваша осознанная работа и выбор, куда направить этот расцвет.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:3:age_period_4', 'numerology', 'Этот цикл под знаком третьего Аркана хорош для обустройства и укоренения. Отрезок располагает наращивать основательность: налаживать быт и дело, создавать финансовую опору и вокруг себя ощущение достатка и надёжности. Императрица здесь про плоды, которые можно потрогать, — дом, ресурс, результат труда. Тень — привязать самоощущение к вещам и накоплению. Помня, что изобилие любит движение, вы проживёте этот период как время роста, а не тяжести. Всё зависит от того, во что именно вы решите вкладываться.', 'reviewed', 2)
