  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:3:age_period_5', 'numerology', 'Похоже на пору урожая — так можно описать этот отрезок под третьим Арканом. Время располагает собирать плоды прежних усилий и щедро делиться ими: тем, что накоплено, что умеете, чем можете напитать других. Императрица делает такой цикл изобильным, если не жадничать и не бояться отдавать. Обратная сторона — усталость от роли того, кто всех кормит; здесь важно пополнять и собственные запасы. Это склонность, а не обещание: насколько щедрым окажется урожай, во многом зависит от того, что и как вы сеяли прежде и как распорядитесь собранным.', 'reviewed', 2)
