  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:3:age_period_6', 'numerology', 'Здесь третий Аркан наделяет период ролью того, кто взращивает других. Отрезок располагает опекать, наставлять, создавать условия, в которых кто-то рядом расцветает, — дети, ученики, команда, дело. Императрица даёт терпение садовника и умение радоваться чужому росту как своему. Тонкая грань — не проживать жизнь только через заботу, оставляя место и себе. Понимание этой особенности помогает мягче обходиться с собой и превращать щедрость в осознанный дар, а не в обязанность без границ.', 'reviewed', 2)
