INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:3:age_period_7', 'numerology', 'Хорошо прожить этот отрезок как время наполнения себя — так его окрашивает третий Аркан. Период располагает восстанавливаться через красоту, покой, чувственные радости и заботу о собственном теле и доме. Императрица напоминает: чтобы давать, нужно быть наполненным, — и приглашает вернуть внимание к себе. Тень — соблазн заглушать усталость излишествами; здесь выручает честность с собой. Как распорядиться этой паузой изобилия, решаете вы: отрезок предлагает ресурс мягкого восстановления, но воспользоваться им — осознанный выбор.', 'reviewed', 2)
