  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:3:age_period_8', 'numerology', 'В этом отрезке третий Аркан звучит как зрелое, спокойное изобилие. Пора располагает подводить к плодоношению долгие вложения и передавать накопленное дальше — опыт, тепло, ресурсы, красоту, которую вы создали. Императрица даёт ощущение полноты, из которой хочется не хватать, а одаривать. Мягкое напоминание — ценить собранное и не обесценивать пройденный путь. Ничто не предрешено заранее: этот цикл предлагает щедрую зрелость, а то, чем вы её наполните и кому передадите, остаётся вашим осознанным выбором.', 'reviewed', 2)
