INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:3:health_crown', 'numerology', 'Смысл и связь с чем-то большим открываются здесь через восхищение живым. Императрица в коронной зоне описывает духовность не аскетичную, а насыщенную: священное переживается в красоте природы, в чуде роста, в изобилии самой жизни. Для вас путь к высокому может лежать через благодарность и любование, а не только через отречение. Это склонность чувствовать присутствие большого начала в простых земных дарах. Понимание этой грани помогает не искать смысл где-то далеко, а замечать его в том, что цветёт и питает прямо сейчас.', 'reviewed', 2)
