  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:3:health_heart', 'numerology', 'Сердечная зона у третьего Аркана — как сад в цвету. Императрица наполняет эмоциональную жизнь теплом, нежностью и щедростью на чувства: вам естественно любить деятельно — обнимать, кормить, обустраивать, окружать вниманием. Это склонность к отношениям, где заботятся и питают друг друга. Мягкое напоминание — держать баланс, чтобы любовь не превращалась в опеку, а близким оставалось пространство. Понимание этой особенности помогает бережнее обходиться и с собой, и с теми, кого любите, сохраняя в сердце лёгкость.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
