  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:3:health_root', 'numerology', 'Опора и телесная витальность в этой карте окрашены образом плодородной земли. Императрица на уровне корневой чакры говорит о связи с почвой под ногами — с телом, природой, простыми радостями, которые дают бодрость и ощущение «я есть». Ресурс здесь в укоренённости: прогулки, вкусная еда, уют, руки в земле буквально возвращают тонус и спокойствие. Склонность этой зоны — черпать жизненную силу из заботы о себе и своём быте. Чем внимательнее вы к этим простым опорам, тем устойчивее чувствуете себя изнутри.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
