  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:3:health_sacral', 'numerology', 'Чувственность и творческая энергия — родная стихия третьего Аркана, и в сакральной зоне он звучит особенно ярко. Императрица здесь про удовольствие быть живым: вкус, прикосновение, радость близости и созидания. Это склонность наполняться через чувства и щедро отдавать эту энергию в творчестве и отношениях. Ресурс огромный, но ему нужна честная мера — и аскеза, и излишество одинаково гасят этот огонь. Прислушиваясь к своим настоящим желаниям, вы держите зону в тонусе и превращаете чувственность в источник вдохновения.', 'reviewed', 2)
