  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:3:health_solar_plexus', 'numerology', 'Самооценка и внутренняя воля здесь опираются не на борьбу, а на щедрость. Третий Аркан в зоне солнечного сплетения предлагает необычную формулу силы: ценность рождается не из побед над кем-то, а из способности создавать и делиться. Императрица располагает к спокойному достоинству изобилия — уверенности, которая идёт от умения давать. Тень этой зоны — искать подтверждения своей значимости через бесконечную заботу о других в ущерб себе. Здоровый выбор — позволять себе принимать, признавать собственные плоды и опираться на них.', 'reviewed', 2)
