INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:3:health_third_eye', 'numerology', 'Интуиция в этой карте похожа на чутьё садовника, который заранее знает, что прорастёт. Третий Аркан в зоне третьего глаза наделяет образным, чувственным восприятием: вы скорее мыслите картинами и ощущениями, чем сухими схемами, и умеете уловить, где зреет потенциал. Это склонность к плодотворному воображению — способности вынашивать идею внутри, прежде чем воплотить её. Ясность здесь приходит через красоту и покой, а не через нажим. Доверяя этому мягкому внутреннему зрению, вы принимаете более живые и точные решения.', 'reviewed', 2)
