INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:3:health_throat', 'numerology', 'Голос и самовыражение окрашены здесь красотой и теплотой. В горловой зоне третий Аркан говорит о речи, которая согревает: вам близко выражать себя через создание приятного — слова, что утешают, интонации, что обволакивают, творчество, что радует глаз и слух. Это склонность доносить смысл не напором, а через образ, вкус, атмосферу. Ресурс раскрывается, когда вы позволяете себе вслух говорить о том, что цените и любите. Чем свободнее вы делитесь своей внутренней красотой, тем полнее звучит этот голос.', 'reviewed', 2)
