INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:3:money_line', 'numerology', 'Денежная тема окрашена здесь образом плодородия, а не голого расчёта. Третий Аркан располагает к отношению, где достаток приходит через созидание и заботу: вы скорее выращиваете ценность — делом, красотой, вниманием к людям, — чем гонитесь за цифрой. Императрица говорит об изобилии, которое любит движение: оно приходит легче, когда им делятся и вкладывают, а не сжимают в кулак. Это склонность, а не обещание богатства — многое зависит от ваших навыков, дисциплины и всей карты. Здоровое русло здесь — соединять щедрость с умением ценить и удерживать плоды своего труда.', 'reviewed', 2)
