  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:3:point_center', 'numerology', 'Комфортнее всего вам там, где можно творить, заботиться и быть окружённым красотой. В самом центре матрицы Императрица описывает ваше естественное состояние равновесия: уютный дом, вкусная еда, живые растения, тёплые люди — вот та почва, на которой вы восстанавливаетесь. Здесь вы щедры без усилий и создаёте изобилие будто между делом. Важно лишь помнить, что зона комфорта — не клетка: опираясь на неё, стоит иногда выходить и в непривычное. Но как базовый ресурс эта способность создавать тепло питает вас надёжнее многого другого.', 'reviewed', 2)
