  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:3:point_f1', 'numerology', 'В одном из четырёх секторов вашей октаграммы — квадранте Ф1 — Императрица окрашивает грань, связанную с тем, как вы проявляете себя вовне. Здесь живёт склонность создавать вокруг атмосферу тепла и достатка, притягивать людей заботой и вкусом. Эта часть личности умеет делать жизнь чувственно богатой: замечать красоту, наполнять быт смыслом, превращать простое в приятное. Развивая её сознательно, вы получаете мягкую, но ощутимую силу влияния — не давлением, а созиданием. Проявление, как всегда, зависит от вас и от всей карты целиком.', 'reviewed', 2)
