INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:3:point_f2', 'numerology', 'Квадрант Ф2 отвечает за более скрытую сторону, и третий Аркан наполняет её образом внутреннего изобилия. Это ваш тихий источник — способность питать себя изнутри впечатлениями, творчеством, чувственностью, а не ждать наполнения только снаружи. Такая грань располагает к плодовитости замыслов и умению восстанавливаться через красоту и уют. Обратная сторона — соблазн «заедать» или «закупать» тревогу; здесь выручает честность с собой. Это не приговор, а склонность, и то, во что она вырастет, определяет ваш осознанный выбор.', 'reviewed', 2)
