INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:3:point_f3', 'numerology', 'Есть в вас сектор, обращённый к другим людям, — квадрант Ф3, и Императрица делает его тёплым и щедрым. Тут проявляется дар опекать, поддерживать, создавать для окружающих ощущение, что о них позаботятся. Вы легко становитесь человеком, рядом с которым другим спокойно и сытно — и в прямом, и в переносном смысле. Эту грань стоит развивать бережно, чтобы забота оставалась выбором, а не долгом. Осознанно раскрытая, она делает вас центром притяжения, вокруг которого само собой складывается тепло.', 'reviewed', 2)
