INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:3:point_f4', 'numerology', 'Глубинный квадрант Ф4 хранит то, что зреет медленно и раскрывается не сразу. Здесь третий Аркан говорит о зрелом изобилии — о способности со временем стать по-настоящему плодоносным человеком, чьи усилия приносят обильный урожай. В этой части живёт терпеливая созидательная сила: она не спешит, но взращивает основательно. Понимание этой особенности помогает мягче обходиться с собой и не требовать плодов раньше срока. Дайте семенам вызреть — и опора, заложенная здесь, будет питать вас долго.', 'reviewed', 2)
