INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:3:point_month', 'numerology', 'По женской линии рода сюда приходит задача, связанная с материнским теплом и умением питать других. Третий Аркан говорит о наследии заботы: способности принимать, обнимать, создавать вокруг близких безопасность и изобилие. Иногда у этой эстафеты есть и обратная сторона — привычка отдавать себя без остатка. Мягкая работа здесь — научиться заботиться, не растворяясь, и позволять изобилию течь к вам, а не только от вас. Это не приговор, а направление, в котором род словно приглашает вас обновить старый сценарий любви и сделать его теплее.', 'reviewed', 2)
