INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:3:point_tasks', 'numerology', 'Если у вашей жизни есть сквозной сюжет, то здесь он о плодородии в самом широком смысле. Главная задача, помеченная третьим Арканом, — созидать и взращивать: людей, проекты, красоту, тепло вокруг себя. Императрица зовёт не копить, а приумножать и делиться, оставляя после себя больше, чем было. Это склонность быть источником и садовником, а не наблюдателем со стороны. Насколько полно раскроется эта линия, решает не судьба, а ваша готовность вкладываться и доводить начатое до цветения.', 'reviewed', 2)
