INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:3:point_year', 'numerology', 'Отцовская ветвь рода вносит свою краску: здесь Императрица разворачивается как тема достатка, опоры и созидательной силы, идущей по мужской линии. Речь о том, чтобы уметь обустраивать, обеспечивать, доводить замысел до плода. Родовая задача может звучать как приглашение примирить щедрость и ответственность — давать миру плоды своего труда и при этом ценить их. Как именно раскроется этот наказ предков, зависит от вашего осознанного выбора: родовые линии задают тему, но мелодию по ней вы пишете сами.', 'reviewed', 2)
