INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:3:purpose_ancestral', 'numerology', 'На уровне рода третий Аркан обозначает миссию, связанную с плодородием и продолжением. Речь не только о детях — о способности передавать дальше тепло, ресурсы, умение заботиться и создавать достаток. Возможно, ваша роль в семейной истории — стать тем, кто восстанавливает изобилие и щедрость там, где линия знала нужду или сухость. Это одна из граней, которую можно осознанно развивать и в свою пользу, и на благо близких. Родовое предназначение задаёт тему; воплощаете вы её собственными руками и выбором.', 'reviewed', 2)
