INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:3:purpose_personal', 'numerology', 'Ваше личное предназначение звучит как призвание созидателя и хранителя жизни. Третий Аркан говорит: вам органично приумножать — красоту, уют, тепло, дело — и оставлять мир чуть более плодородным, чем застали. Это не про масштаб и громкость, а про способность делать вокруг себя живее и полнее. Реализуется такой путь через конкретные плоды: то, что вы вырастили, обустроили, о ком позаботились. Насколько ярко раскроется предназначение, решает ваш осознанный выбор вкладывать себя туда, где что-то по-настоящему растёт.', 'reviewed', 2)
