INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:3:purpose_social', 'numerology', 'В обществе вам естественно быть тем, кто питает и объединяет. Третий Аркан описывает социальную роль через созидание общего блага — создавать пространства, где людям тепло, сытно и хочется расти. Это может быть забота о команде, о сообществе, о среде вокруг: всюду, где нужен человек, умеющий обустроить и поддержать. Склонность здесь — приносить пользу через изобилие, а не через конкуренцию. Раскрывая эту грань осознанно, вы становитесь тем, вокруг кого складывается что-то живое и общее.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
