  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:3:purpose_spiritual', 'numerology', 'В духовном измерении третий Аркан ведёт путём созидательной любви. Ваше движение вглубь может идти не через отказ от земного, а через его освящение — умение видеть священное в красоте, заботе, в самом чуде того, что жизнь рождает жизнь. Императрица предлагает духовность матери-природы: щедрую, питающую, принимающую. Это склонность расти душой, отдавая и взращивая, а не запирая себя. Как далеко поведёт этот путь, зависит от вашей внутренней работы и осознанности, а не предопределено заранее.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:3:relationship_line', 'numerology', 'Любовь у третьего Аркана деятельная — это щедрость сердца и рук. Императрица располагает заботиться, создавать дом, наполнять связь теплом, вкусом, вниманием к мелочам, из которых складывается уют. Рядом с вами хочется быть: вы умеете сделать так, чтобы другому было хорошо. Тонкая грань — не подменять близость опекой и оставлять партнёру право тоже давать. Осознанная забота, в которой есть место и вашим собственным потребностям, превращает эту линию в источник взаимного изобилия, а не одностороннего донорства.', 'reviewed', 2)
