INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:4:age_period_1', 'numerology', 'Первый девятилетний отрезок под знаком Четвёртого Аркана окрашен темой основания. Император в этом периоде склонен проявляться как потребность в опоре и понятных правилах — важна устойчивость, ясная рамка, ощущение, что мир надёжен. Это время, когда закладывается внутреннее отношение к порядку и ответственности. Как именно прозвучит эта нота, зависит от многих обстоятельств и всей карты целиком; аркан не предопределяет событий, а лишь подсвечивает вероятный оттенок этапа — тягу к структуре и почве под ногами.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:4:age_period_2', 'numerology', 'Во втором цикле мотив Императора звучит как проба собственных границ. Четвёртый Аркан располагает к тому, чтобы учиться держать структуру уже осмысленно: брать первую ответственность, выстраивать личный распорядок, примерять роль того, кто отвечает за своё. Этот отрезок склонен подчёркивать ценность дисциплины и самостоятельности. Проявится тема мягче или острее — зависит от контекста и осознанности; аркан описывает тональность периода, а не расписание событий, и оставляет широкий простор для выбора.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:4:age_period_3', 'numerology', 'Третий девятилетний период Четвёртый Аркан может окрашивать в тона строительства. Император здесь про активное возведение своего: дела, дома, системы, на которую можно опереться. Это время, когда тяга к порядку ищет практического воплощения, а ответственность становится инструментом, а не грузом. Насколько ярко зазвучит нота — вопрос обстоятельств и всей карты; аркан подсвечивает вероятный смысл этапа, но не диктует его наполнение и не обещает конкретных результатов. Многое решает то, как вы распорядитесь этим импульсом.', 'reviewed', 2)
