  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:4:age_period_4', 'numerology', 'Четвёртый цикл — и мотив устойчивости выходит на первый план. Император в этом отрезке склонен проявляться как потребность укрепить достигнутое: навести порядок в накопленном, отсеять лишнее, придать жизни более прочную форму. Тема ответственности здесь про зрелость, а не про суету. Аркан лишь намечает вероятную окраску периода и не предопределяет событий: то, как раскроется склонность, зависит от осознанного выбора и общего рисунка судьбы. Это приглашение к опоре, а не заданный сценарий.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:4:age_period_5', 'numerology', 'К пятому девятилетию тема Императора нередко поворачивается к ревизии опор. Четвёртый Аркан подсказывает: полезно проверить, на чём стоит ваша конструкция — какие правила ещё служат, а какие пора обновить. Это отрезок, когда порядок хочется не столько наращивать, сколько выверять и приводить в согласие с изменившейся жизнью. Понимание этой темы помогает мягче обходиться с собой и опираться на неё как на ресурс. Аркан описывает возможное содержание этапа, а не предписывает события, и оставляет свободу решать, что укрепить, а что отпустить.', 'reviewed', 2)
