  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:4:age_period_6', 'numerology', 'На шестом девятилетнем витке ответственность обычно становится негромкой, почти незаметной. Четвёртый Аркан в этом отрезке склонен проявляться как умение держать целое без надрыва — распоряжаться накопленным, поддерживать заведённый порядок, быть надёжной опорой для близких. Император здесь про власть, которая уже не нуждается в доказательствах. Аркан лишь очерчивает вероятный характер этого отрезка, а не назначает его события: как именно раскроется эта грань, решают обстоятельства и осознанность. Это приглашение к зрелой, спокойной роли, а не предопределение.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:4:age_period_7', 'numerology', 'Седьмой отрезок жизни Император нередко связывает с наставничеством. Четвёртый Аркан здесь про то, чтобы передавать порядок дальше: делиться опытом, укреплять построенное, становиться опорой для тех, кто идёт следом. Тяга к структуре разворачивается вовне, к заботе о продолжении рода и дела. Это одна из граней этапа, которую можно развивать в свою пользу. Аркан рисует лишь возможный тон этого времени, а не расписание событий, и не обещает конкретных обстоятельств — многое решает то, как вы распорядитесь накопленной устойчивостью.', 'reviewed', 2)
