INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:4:age_period_8', 'numerology', 'Восьмой, завершающий круг подводит тему Императора к итогу и наследию. Четвёртый Аркан склонен подчёркивать здесь ценность прочного основания, которое остаётся и служит дальше — традиции, дела, уклада, на который смогут опереться другие. Ответственность в этом отрезке про долговечность и смысл сделанного, а не про новые стройки. Аркан лишь обозначает вероятный лейтмотив этапа и не предопределяет событий: как проявит себя этот итоговый мотив, зависит от осознанного выбора и всей карты целиком. Это приглашение закрепить опору и передать её дальше, а не заданный наперёд сценарий.', 'reviewed', 2)
