INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:4:health_crown', 'numerology', 'Коронная чакра — про связь с большим смыслом, и Император вносит в неё мотив внутреннего закона. Четвёртый Аркан здесь про духовность не как парение, а как порядок высшего рода: следование ясным принципам, ощущение, что мир держится на понятной структуре, а свобода растёт из зрелой дисциплины. Это склонность искать смысл в устройстве вещей. То, как она проявится, зависит от осознанности: живая вера оставляет место тайне и не превращает принципы в жёсткую догму. Смысл крепче, когда в нём есть и опора, и простор.', 'reviewed', 2)
