INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:4:health_heart', 'numerology', 'На языке сердца Император звучит как тема надёжности. Четвёртый Аркан в сердечной зоне — про любовь, которая умеет быть опорой: не растворяться без остатка, а держать, защищать, оставаться рядом в трудный час. Здесь дремлет ресурс верности и ответственной привязанности. Оборотная сторона — риск подменить тепло контролем или спрятать чувства за фасадом «всё под контролем». Мягче всего эта грань раскрывается, когда порядок в отношениях служит близости, а не заменяет её; уязвимость и структура вполне совместимы.', 'reviewed', 2)
