INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:4:health_root', 'numerology', 'Корневая чакра резонирует с Императором особенно созвучно: обе темы — про опору. Четвёртый Аркан здесь про базовое ощущение почвы под ногами, про то, как режим, ритм и понятный распорядок питают бодрость и чувство устойчивости. Когда есть надёжная основа — сон, движение, привычный уклад — жизненные силы текут ровнее. Это склонность, а не приговор: тело благодарно откликается на порядок, но и на бережность. Слишком жёсткий режим утомляет не меньше, чем полное его отсутствие, поэтому важна золотая середина.', 'reviewed', 2)
