INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:4:health_sacral', 'numerology', 'Сакральная зона — про течение энергии и удовольствие, и Четвёртый Аркан вносит сюда неожиданный нюанс. Император и чувственность кажутся противоположностями, но структура умеет служить живому: когда у желаний есть здоровые берега, поток не разливается впустую, а наполняет. Эта грань располагает к тому, чтобы давать себе разрешение на радость внутри понятных рамок. Проявится ли она как зажатость или как зрелая чувственность — во многом зависит от осознанности: порядок здесь призван не гасить страсть, а давать ей русло.', 'reviewed', 2)
