INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:4:health_solar_plexus', 'numerology', 'Солнечное сплетение — территория воли, и Император на ней у себя дома. Четвёртый Аркан говорит о внутреннем стержне: способности принимать решения, держать границы и опираться на собственную самооценку, а не на чужое одобрение. Это ресурс личной силы — той, что строит, а не подавляет. Склонность располагает к уверенности; чтобы она не затвердевала в жёсткость или самоедство, полезно помнить, что твёрдость и самоценность спокойно уживаются с мягкостью к себе. Настоящая власть над собой не воюет с собой.', 'reviewed', 2)
