INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:4:health_third_eye', 'numerology', 'Интуиция обычно ассоциируется с текучим и неуловимым — а Четвёртый Аркан приносит в неё ясность формы. Император в зоне третьего глаза про трезвость видения: способность отделять существенное от шума, выстраивать мысли в понятный порядок, различать структуру за хаосом впечатлений. Это ресурс ясного, приземлённого ума, который умеет проверять озарения на прочность. Склонность располагает к рациональной опоре; чтобы она не заглушила тонкий сигнал интуиции, полезно оставлять место и для того знания, что приходит без объяснений.', 'reviewed', 2)
