INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:4:health_throat', 'numerology', 'Горловая чакра отвечает за голос, и Четвёртый Аркан придаёт ему вес. Император здесь про речь ясную и ответственную: умение говорить по делу, держать слово, обозначать границы без агрессии. Это ресурс того, кого слышат, потому что за словами стоит опора. Склонность располагает к чёткости; её тень — сухость или командный тон там, где нужнее живое участие. То, как проявится эта грань, во многом зависит от осознанного выбора: структура речи хороша, когда оставляет место интонации и теплу, а не только регламенту.', 'reviewed', 2)
