INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:4:money_line', 'numerology', 'Денежная тема с Императором — про порядок и основательность в ресурсах. Четвёртый Аркан располагает к системному подходу: планирование, дисциплина трат, умение выстраивать устойчивые опоры дохода вместо погони за быстрым кушем. Это склонность к роли рачительного хозяина, который строит финансовое основание надолго. Аркан описывает подход, а не обещает суммы и не предопределяет достаток. Раскрывается ресурс там, где строгость к цифрам сочетается с гибкостью: слишком жёсткий контроль над деньгами утомляет не меньше, чем полное его отсутствие.', 'reviewed', 2)
