INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:4:point_center', 'numerology', 'Комфортнее всего вам там, где есть ясные правила и понятная структура. Центр октаграммы с Четвёртым Арканом, Императором, говорит о естественной опоре на порядок: распорядок, план, границы дают чувство почвы под ногами. Это ваша внутренняя крепость — место, откуда удобно действовать и принимать решения. Ресурс работает лучше всего, когда стены крепости остаются проницаемыми: если порядок превращается в самоцель, зона комфорта сужается до жёсткой рамки. Осознанность помогает держать баланс между устойчивостью и свободой манёвра.', 'reviewed', 2)
