  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:4:point_day', 'numerology', 'Внутренний архитектор — так можно назвать эту грань таланта. Четвёртый Аркан, Император, в точке «День» говорит о врождённой тяге к порядку: вы умеете превращать хаос в понятную конструкцию, выстраивать опоры там, где другие видят лишь развалины. Это ресурс собранности и ответственности — способность держать слово и доводить начатое до устойчивого результата. Проявляется он мягче, когда структура служит вам, а не превращается в жёсткий панцирь; тогда дисциплина становится не клеткой, а надёжным каркасом для роста.', 'reviewed', 2)
