INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:4:point_f1', 'numerology', 'В квадранте Ф1 Четвёртый Аркан задаёт тон уверенного начала. Император здесь про то, как вы закладываете первый камень: со вниманием к основанию, с расчётом на долговечность, без суеты. Эта зона наделяет способностью структурировать старт — определить границы задачи, распределить силы, выстроить порядок действий. Склонность проявляется как деловая собранность; чтобы она не застыла в излишней жёсткости, полезно оставлять пространство для правок по ходу дела — крепкий фундамент не мешает менять чертёж.', 'reviewed', 2)
