INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:4:point_f2', 'numerology', 'Ф2 окрашивает тему Императора в оттенок устойчивого развития. Четвёртый Аркан в этом квадранте — про умение удерживать взятый курс: не бросать проект на середине, доводить структуру до рабочего состояния, отвечать за процесс. Здесь дремлет ресурс терпеливого строителя, который кладёт ряд за рядом, не гонясь за быстрым эффектом. Проявляется это как надёжность и последовательность. Мягче всего сила звучит тогда, когда упорство не переходит в упрямство и оставляет место обратной связи.', 'reviewed', 2)
