INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:4:point_f3', 'numerology', 'Квадрант Ф3 разворачивает Императора в сторону зрелого управления. Четвёртый Аркан подсказывает: в этой области ваш ресурс — умение держать целое, видеть систему связей, наводить порядок не в мелочах, а в самом устройстве. Это про ответственность за результат и за тех, кто в нём участвует. Склонность располагает к роли того, на ком держится конструкция. Чтобы она не обернулась перегрузкой, стоит помнить: делегировать и доверять — часть той же силы, а не её слабость.', 'reviewed', 2)
