INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:4:point_month', 'numerology', 'По материнской линии сюда приходит тема опоры. Император, Четвёртый Аркан, в точке «Месяц» намекает: род передаёт задачу учиться устойчивости — строить надёжный дом, держать границы, брать на себя разумную ответственность вместо того, чтобы растворяться в чужих ожиданиях. Это не груз, а наследуемый ресурс: женская сила рода здесь про порядок и защиту близких. Развивать её стоит бережно — так, чтобы забота не оборачивалась контролем, а твёрдость оставляла место теплу.', 'reviewed', 2)
