  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:4:point_tasks', 'numerology', 'Главная работа этой жизни — научиться строить. Император в точке «Задачи» ставит перед вами тему зрелой ответственности: превращать замыслы в устойчивые формы, наводить порядок в собственном пространстве и держать данное слово. Речь не о власти над другими, а о власти над собственным хаосом — о способности создать каркас, на который можно опереться самому и опереть близких. Задача располагает к дисциплине, но подлинный её смысл раскрывается там, где твёрдость соединяется с гибкостью, а правила служат жизни, а не наоборот.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
