  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:4:point_year', 'numerology', 'Отцовская линия приносит мотив фундамента. В точке «Год» Четвёртый Аркан — Император — очерчивает родовую задачу: научиться быть опорой, держать вертикаль, отвечать за своё дело и за тех, кто рядом. Здесь дремлет ресурс основательности, переданный по мужской ветви, — умение закладывать прочное основание и не бросать его на полпути. Раскрывается он тем полнее, чем меньше в нём жёсткости ради жёсткости: зрелая ответственность добровольна и не требует доказывать власть силой.', 'reviewed', 2)
