INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:4:purpose_ancestral', 'numerology', 'Задача рода, которую подсвечивает здесь Император, — вернуть линии утраченную опору. Четвёртый Аркан в поле родового предназначения говорит о призвании стать тем, кто наводит порядок там, где поколения жили в надломе или разладе: закладывает традицию, укрепляет фундамент семьи, возвращает близким чувство почвы под ногами. Это склонность быть не только наследником рода, но и его строителем. Обернётся ли она здоровой ответственностью или давящим долгом — во многом зависит от осознанного выбора. Зрелая опора не требует жертвовать собой: она даёт силу и предку, и потомку, а не забирает её.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:4:purpose_personal', 'numerology', 'Личное предназначение с Четвёртым Арканом звучит как призвание строить. Император намекает: ваш путь связан с созданием устойчивых форм — будь то дело, дом, система или сообщество, которому нужна крепкая опора. Здесь важна ответственность как осознанный выбор, а не тяжкая ноша. Это склонность быть тем, на ком держится конструкция, кто наводит порядок и задаёт рамку. Раскрывается она полнее там, где сила служит созиданию, а не самоутверждению; тогда роль опоры приносит не усталость, а глубокое чувство своего места.', 'reviewed', 2)
