  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:4:purpose_social', 'numerology', 'В социальном измерении Император наделяет ролью того, кто держит структуру. Четвёртый Аркан подсказывает: ваш вклад в общее — способность наводить порядок, выстраивать понятные правила, брать ответственность за устойчивость коллектива или дела. Люди тянутся к такой опоре, потому что рядом с ней спокойнее. Это склонность к организаторской, устроительной роли. Раскрывается она тем полнее, чем меньше в ней жажды власти ради власти: зрелый авторитет служит общему благу и умеет уступать, а не только управлять.', 'reviewed', 2)
