INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:4:purpose_spiritual', 'numerology', 'На духовном уровне Четвёртый Аркан переворачивает привычное: путь здесь не в отказе от формы, а в её освящении. Император подсказывает, что ваша духовная задача может быть связана с дисциплиной как практикой — регулярностью, верностью взятому направлению, умением строить внутренний храм ряд за рядом. Это склонность расти через порядок, а не через порывы. Развивать её стоит бережно: подлинная дисциплина рождается из любви к пути, а не из насилия над собой, и оставляет место живому дыханию, а не только своду правил.', 'reviewed', 2)
