  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:4:relationship_line', 'numerology', 'В отношениях Четвёртый Аркан приносит тему надёжности и ясных договорённостей. Император располагает к роли опоры: вы склонны строить связь основательно, ценить постоянство, брать ответственность за общий дом. Это ресурс верности и защиты — рядом с вами партнёру спокойно. Оборотная грань — соблазн всё держать под контролем или мерить любовь порядком. Мягче всего линия звучит там, где твёрдость соединяется с гибкостью: здоровые границы укрепляют близость, а не заменяют её, и оставляют партнёру свободу быть собой.', 'reviewed', 2)
