INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:5:age_period_1', 'numerology', 'Первый девятилетний виток проходит здесь под знаком впитывания. Пятый Аркан в этом периоде подсвечивает время первых учителей и образцов: закладываются представления о том, как устроен мир, «что правильно», на кого равняться. Это пора, когда особенно важны наставники и уклад вокруг — они дают фундамент. Склонность этого отрезка — учиться через подражание надёжным старшим и усваивать правила игры. Что из усвоенного станет опорой, а что позже захочется пересмотреть, покажет жизнь; пока же копится тот самый первичный опыт.', 'reviewed', 2)
