  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:5:age_period_2', 'numerology', 'На втором витке тема наставничества смещается к поиску своих ориентиров. Иерофант в этом периоде описывает время, когда унаследованные правила примеряются на себя: хочется найти учителей уже по собственному выбору, разобраться, каким устоям верить. Это располагает тянуться к знанию осмысленно, искать образцы, которые откликаются лично. Отрезок благоприятен для того, чтобы строить основание будущего на проверенном. Насколько глубоко это проявится, зависит от среды и выбора; но склонность укреплять фундамент через учёбу здесь ощутима.', 'reviewed', 2)
