  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:5:age_period_3', 'numerology', 'Третий период часто проходит как разговор с унаследованным. Пятый Аркан здесь высвечивает тему сверки: что из правил, полученных от старших и традиции, действительно твоё, а что стоит переосмыслить. Это время, когда наставничество работает в обе стороны — ещё учишься сам, но уже, возможно, начинаешь делиться. Располагает отрезок к выработке собственного свода принципов на основе прежнего опыта. Проявится это спокойным взрослением или внутренним спором с устоями — зависит от всей карты и осознанности; суть же в обретении своей опоры.', 'reviewed', 2)
