  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:5:age_period_4', 'numerology', 'К четвёртому витку в теме Иерофанта нередко проступает зрелость мастерства. Этот период подсвечивает время, когда накопленный опыт становится основательным настолько, что им естественно делиться: рядом появляются те, кто смотрит на вас как на знающего. Склонность отрезка — переходить из роли ученика в роль наставника, брать ответственность за передачу. Это ресурс авторитета и устойчивости. Насколько ярко проявится роль учителя, решают обстоятельства и выбор; но само движение к мастерству и порядку здесь заметно.', 'reviewed', 2)
