  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:5:age_period_5', 'numerology', 'Пятый девятилетний отрезок разворачивает тему передачи в полную силу. Пятый Аркан в этом периоде описывает пору, когда хочется не только владеть опытом, но и оставлять след: обучать, выстраивать структуры, укреплять ценности, которые считаешь важными. Это располагает к роли того, кто скрепляет и направляет — в семье, деле, сообществе. Ресурс отрезка — весомость и способность быть опорой для других. Как распорядиться этим, выбираете вы; традиция здесь работает лучше всего, когда остаётся живой и открытой новому.', 'reviewed', 2)
