  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:5:age_period_6', 'numerology', 'Шестой виток нередко приносит пересмотр устоев вглубь. Иерофант в этом периоде подсвечивает тему возвращения к основам с новым пониманием: то, что раньше принималось на веру, хочется осмыслить заново, отделить суть от формы. Это располагает к более зрелой, гибкой связи с традицией — уважать её, но не быть её пленником. Отрезок благоприятен для того, чтобы очистить своё мировоззрение от лишнего и укрепить главное. Проявится это тихой внутренней работой или обновлением взглядов — покажет жизнь; направление за вами.', 'reviewed', 2)
