  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:5:age_period_7', 'numerology', 'Седьмой период часто окрашен ролью хранителя. Пятый Аркан здесь описывает время, когда опыт складывается в спокойную мудрость и ценность обретает не сам поиск, а способность бережно нести и передавать накопленное. Склонность отрезка — быть тем, к кому приходят за взвешенным словом, за памятью, за ориентиром. Это ресурс достоинства и глубины. Насколько активно проявится роль наставника, зависит от вас; но тяга делиться нажитым осмысленно и без спешки в этом периоде особенно естественна и уместна.', 'reviewed', 2)
