  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:5:age_period_8', 'numerology', 'Восьмой виток подводит тему Иерофанта к итогу-передаче. Этот период подсвечивает пору, когда важнее всего становится то, что остаётся и продолжает жить в других: уроки, ценности, знание, отданное дальше. Располагает отрезок к роли старшего, который щедро делится нажитым, не цепляясь за него, и видит смысл в преемственности. Это время спокойной отдачи и осмысления пройденного как единого пути. Как именно проявится эта склонность, решает вся карта и ваш выбор; но щедрость знающего человека здесь — самый естественный и светлый ход.', 'reviewed', 2)
