INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:5:health_crown', 'numerology', 'Связь с высоким здесь ощущается как принадлежность к традиции, большей, чем одна жизнь. Коронный центр с Иерофантом раскрывает тему смысла через веру в широком смысле слова: потребность чувствовать, что твой путь вписан в нечто целое — учение, ценности, преемственность поколений. Это располагает искать опору не только внутри себя, но и в проверенных духовных ориентирах. Ресурс зоны — глубина и укоренённость мировоззрения. Живой она остаётся, пока вера открыта вопросу, а не превращается в набор застывших ответов.', 'reviewed', 2)
