  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:5:health_heart', 'numerology', 'Тепло здесь выражается через заботу-наставничество: любить — значит делиться, оберегать, помогать вырасти. Сердечный центр с Пятым Арканом окрашивает отношения оттенком опеки и общих ценностей: близость крепнет там, где есть уважение, доверие и совместная опора на что-то важное для обоих. Это располагает к роли того, кто поддерживает и направляет с теплотой, а не сверху вниз. Стоит лишь следить, чтобы желание помочь не превращалось в поучение — самое живое чувство оставляет другому свободу идти своим путём.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:5:health_root', 'numerology', 'Ощущение почвы под ногами здесь рождается из принадлежности к чему-то большему, чем ты сам. Пятый Аркан в зоне корневой опоры описывает, как традиция и уклад дают чувство укоренённости: знакомые ритуалы, порядок дня, связь с родом становятся источником спокойной устойчивости и бодрости. Когда есть внятная система координат, силы прибывают сами. Это склонность черпать тонус из надёжного и проверенного — и стоит беречь этот ресурс, не позволяя рутине превращаться в тяжесть. Опора крепка, пока остаётся живой.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:5:health_sacral', 'numerology', 'Творческий огонь в этой зоне разгорается через сопричастность и общий ритм. Сакральный центр с Пятым Арканом связывает удовольствие и жизненную энергию с темой совместности: радостью общего дела, ритуала, обучения, где есть и мастер, и ученик. Наслаждение здесь приходит не от хаоса, а от вложенности в осмысленный процесс. Это располагает к тому, чтобы черпать вдохновение в передаче и обмене — в том, что рождается между людьми, объединёнными общими ценностями. Важно оставлять место и спонтанности, чтобы порядок не остудил чувственность.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:5:health_solar_plexus', 'numerology', 'Уверенность в себе тут опирается на компетентность — на ощущение, что ты знаешь дело и стоишь на прочном основании. Солнечное сплетение с энергией Иерофанта связывает самооценку с ролью знающего, наставника, того, к чьему мнению прислушиваются. Воля здесь направлена на то, чтобы отстаивать ценности и держать порядок, а достоинство рождается из мастерства. Это ресурс внутренней опоры; тень — соблазн мерить себя лишь признанием других. Осознанность помогает ценить себя не только за роль учителя, но и просто так.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:5:health_third_eye', 'numerology', 'Ясность приходит сюда через призму осмысленного опыта — своего и унаследованного. Центр третьего глаза с Пятым Арканом описывает интуицию, опирающуюся на знание: способность видеть суть, соотнося новое с проверенным, различать за частностями закономерность. Это склонность понимать мир через смыслы и учения, доверять не только вспышке догадки, но и накопленной мудрости. Ресурс зоны — вдумчивая проницательность. Важно лишь, чтобы уважение к готовым системам не мешало замечать то, что в них ещё не описано.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:5:health_throat', 'numerology', 'Голос в этой зоне звучит как голос того, кто умеет объяснить. Горловой центр с Иерофантом раскрывает дар речи, обращённой к пониманию: способность формулировать ясно, ссылаться на опыт, передавать знание так, чтобы оно доходило. Здесь самовыражение тесно связано с темой обучения — тянет говорить о том, что важно, делиться выводами, находить точные слова. Это ресурс убедительности и авторитета в общении. Живым он остаётся, пока в вашей речи есть место и чужому слову — диалогу, а не только проповеди.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:5:money_line', 'numerology', 'Деньги на этой линии тяготеют к знанию и репутации. Иерофант в денежной зоне описывает достаток, который приходит через компетентность: экспертизу, обучение, консультирование, работу с проверенными системами и структурами. Тут располагает зарабатывать тем, что умеешь объяснять и передавать, — опыт становится капиталом. Ресурс этой зоны — доверие, которое вы вызываете как знающий человек. Устойчивее чувствует себя не спекулянт, а мастер: чем весомее ваша репутация и польза, тем спокойнее денежная опора. Форму же дохода вы выбираете сами.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:5:point_center', 'numerology', 'Спокойнее всего вам, вероятно, там, где есть ясные ориентиры: понятные правила, проверенные методы, роль знающего человека рядом. Центр матрицы с Пятым Арканом описывает зону, где опорой служат традиция и порядок — то, на что можно опереться, не тратя силы на постоянную импровизацию. Это ресурс: умение создавать устойчивость, быть тем самым надёжным наставником для себя и других. Стоит лишь помнить, что комфорт устоев не должен превращаться в стены — самая живая традиция та, что оставляет место вопросу и обновлению.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
