  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:5:point_day', 'numerology', 'К вам приходят за объяснением — и вы находите слова, от которых сложное становится понятным. Пятый Аркан в точке личных талантов рисует натуру наставника: дар структурировать знание, выстраивать порядок из хаоса и делиться накопленным без желания возвыситься. Здесь живёт уважение к проверенному опыту и умение стать опорой для тех, кто только учится. Склонность эта не обязывает вас надевать мантию учителя — но если прислушаться, она подскажет, где ваша сила: в передаче, в примере, в спокойной уверенности знающего человека.', 'reviewed', 2)
