  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:5:point_f1', 'numerology', 'Первый квадрант октаграммы окрашен здесь духом ученичества и почтения к мастерству. Тема Пятого Аркана проявляется тут как готовность искать образцы, опираться на авторитетов, впитывать проверенное прежде, чем действовать самому. В этом секторе матрицы живёт склонность выстраивать основание на прочном фундаменте знания, а не на пустом месте. Это придаёт поступкам основательность; важно лишь, чтобы уважение к традиции не заглушало собственный голос — сила Иерофанта в том, чтобы наследовать осмысленно, а не по инерции.', 'reviewed', 2)
