INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:5:point_f2', 'numerology', 'Во втором секторе октаграммы Пятый Аркан звучит как голос — способность облекать опыт в понятную форму и передавать его дальше. Здесь тема наставничества раскрывается через слово, объяснение, умение сформулировать то, что другие чувствуют смутно. Эта зона располагает к роли того, кто переводит сложное на человеческий язык: не поучает свысока, а делится. Проявляться это может по-разному — от тихого совета близким до потребности учить многих; направление подскажут остальные акценты карты.', 'reviewed', 2)
