INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:5:point_f3', 'numerology', 'Третий квадрант матрицы связывает энергию Иерофанта с чувством порядка и уклада. В этом секторе тема традиции работает как стремление выстраивать устойчивые структуры: правила, ритмы, договорённости, на которые можно положиться. Тут проявляется склонность ценить преемственность и не разбрасываться проверенным ради новизны. Ресурс этой зоны — надёжность и последовательность; тень — риск закостенеть в привычном. Осознанность помогает держать баланс между уважением к устоям и правом их пересматривать.', 'reviewed', 2)
