INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:5:point_f4', 'numerology', 'Четвёртый сектор октаграммы поднимает тему Пятого Аркана к вопросу смысла и посвящения. Здесь традиция и наставничество раскрываются не как набор правил, а как поиск того большего, чему стоит служить: ценностей, веры в широком смысле, внутреннего свода, который придаёт поступкам направление. Эта зона располагает к роли хранителя смысла — того, кто помнит, ради чего всё делается. Как именно это проявится, решаете вы; сам же квадрант дарит способность связывать повседневное с чем-то более высоким.', 'reviewed', 2)
