INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:5:point_month', 'numerology', 'Материнская линия несёт свою тихую науку — её редко записывают, но передают из поколения в поколение через жесты, привычки, слова за столом. Иерофант в этой точке говорит о задаче хранить и осмыслять эту преемственность: не просто повторять унаследованное, а понять, что в нём ценно, и передать дальше уже осознанно. Тут может проявляться тяга к семейным устоям, к роли той, кто держит нить между прошлым и будущим. Как распорядиться этим — выбор ваш: можно нести традицию как груз, а можно как живой ресурс.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:5:point_tasks', 'numerology', 'Главная линия судьбы здесь ведёт к роли моста. Иерофант — тот, кто соединяет разное: старшее и младшее поколения, высокое и обыденное, знание и того, кто к знанию тянется. В этой позиции тема традиции и наставничества становится не фоном, а сердцевиной пути: учиться самому, а затем щедро передавать. Это склонность становиться проводником — учителем, мастером, тем, к кому идут за ориентиром. Проявится ли она масштабно или в тесном кругу, зависит от вашего выбора и всей карты целиком; сама же задача — превращать опыт в то, чем можно поделиться.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:5:point_year', 'numerology', 'По отцовской линии передаётся другое — устройство, правила, представление о том, как всё должно быть устроено «по чести». Пятый Аркан здесь разворачивает тему наследуемого порядка: дисциплины, авторитета, свода принципов, на которых стоял род. Задача этой зоны — не слепо подчиниться этим устоям и не отвергнуть их с порога, а разобраться, какие из них по-прежнему работают, а какие пора обновить. Располагает это к вдумчивому отношению к корням и к тому, чтобы стать звеном, которое передаёт опыт дальше не механически, а с пониманием.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:5:purpose_ancestral', 'numerology', 'Роду в вашем лице, похоже, важна связка времён. Иерофант в зоне родового предназначения говорит о задаче хранителя: собирать, беречь и осмысленно передавать наследие семьи — её ценности, ремёсла, память, уроки. Это располагает к роли того, кто не даёт нити прерваться, кто объясняет младшим, откуда они и что стоит нести дальше. Проявится это или останется в тени — зависит от выбора; но склонность быть звеном преемственности здесь заметна, и в ней много тихой силы, если нести её без чувства долга-повинности.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:5:purpose_personal', 'numerology', 'Личный путь здесь тянется к тому, чтобы стать проводником знания. Пятый Аркан в зоне персонального предназначения описывает призвание учиться и учить — превращать пройденное в опору для других. Это склонность обретать себя через роль наставника, эксперта, того, кто хранит и передаёт нужное. Реализоваться она может в профессии, в творчестве, в тихом влиянии на близких — форму выбираете вы. Важно, что смысл здесь рождается не из накопления знания для себя, а из щедрости, с которой вы им делитесь.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:5:purpose_social', 'numerology', 'В обществе вам, вероятно, отведена роль носителя опыта. Иерофант в зоне социального предназначения описывает призвание, связанное с сообществами и институтами, с передачей знания в широком кругу: учить, наставлять, поддерживать порядок и ценности группы. Это склонность становиться авторитетом, к которому обращаются за ориентиром, — тем, кто скрепляет общее. Масштаб роли зависит от вас и обстоятельств. Важно помнить: подлинный авторитет здесь держится не на власти, а на пользе и уважении, а не на давлении.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
