  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:5:purpose_spiritual', 'numerology', 'Тяга к смыслу, который больше одной жизни, — вот что отличает эту зону. Пятый Аркан в поле духовного предназначения описывает призвание помогать другим прикасаться к главному: к ценностям, к вере в широком смысле, к внутренним ориентирам, что выводят за пределы повседневного. Это склонность к пути учителя духа — не в смысле сана, а в способности будить в людях живой вопрос и поддерживать их собственный поиск. Как призвание воплотится, подскажут вся карта и ваши решения. Важно одно: не удерживать обретённое понимание при себе, а делать его доступным, оставляя каждому свободу идти своей дорогой.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:5:relationship_line', 'numerology', 'В близости для вас, судя по этой линии, много значат общие ориентиры. Пятый Аркан на линии отношений окрашивает связи темой совместных ценностей, уважения и взаимного роста: партнёрство крепнет там, где есть чему учиться друг у друга и на что вместе опираться. Здесь может проявляться тяга к отношениям как к союзу единомышленников, а порой — к динамике, где один делится опытом, а другой перенимает. Это ресурс глубины и надёжности. Живыми такие связи остаются, пока роли не застывают и рядом остаётся равный, а не только ученик или наставник.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
