INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:6:age_period_1', 'numerology', 'Первый девятилетний отрезок — самое начало пути, когда закладывается способность привязываться и доверять. Шестой Аркан подсвечивает в этой поре тему близости: важным становится опыт тепла, принятия, ощущения «меня выбирают». Здесь скорее не выборы делаются, а впитывается их музыка — как рядом бывает хорошо, что значит согласие. Это не сценарий на всю жизнь, а склонность периода: заложенное чувство связи потом станет опорой. Мягкость среды в такие годы бесценна, и понимание этого помогает бережнее смотреть на себя-маленького.', 'reviewed', 2)
