INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:6:age_period_2', 'numerology', 'Во втором цикле мир расширяется, и тема выбора заявляет о себе всё отчётливее. Шестой Аркан связывает эту пору с первыми настоящими привязанностями за пределами семьи — с дружбой, симпатией, открытием, что люди бывают «свои» и «чужие». Склонность периода — учиться чувствовать созвучие и пробовать согласовывать своё с чужим. Это тенденция, а не расписание событий: то, как отрезок проживётся, зависит от среды и от всей карты. Ценно здесь одно — право выбирать близких по отклику, а не по случайности.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
