  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:6:age_period_3', 'numerology', 'Третий отрезок часто про пробу себя в отношениях всерьёз: тут проверяется, что для вас важно рядом с другим. Шестой Аркан вносит вопрос ценностей — совпадение или разлад становятся заметнее, чем прежде. Это пора, когда влечение и смысл могут спорить, и склонность периода — учиться слышать оба голоса. Ничего не предрешено: развилки этих лет — не ловушки, а тренировка честного выбора. Опыт близости, набранный здесь, потом складывается в более зрелое понимание, с кем и зачем вы хотите быть рядом.', 'reviewed', 2)
