INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:6:age_period_4', 'numerology', 'Четвёртый цикл склонен к укреплению того, что выбрано: связи проверяются временем, а не только чувством. Шестой Аркан говорит в эту пору о верности главному — о том, что зрелое «вместе» держится на ежедневном живом отклике, а не на однажды сказанном слове. Тенденция периода — сводить близость и ценности в устойчивое согласие, отделять настоящее от привычного. Это не приговор и не обещание: многое зависит от осознанности. Но именно здесь выбор часто перестаёт быть порывом и становится зрелым решением, за которое вы готовы отвечать.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
