  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:6:age_period_5', 'numerology', 'Пятый отрезок нередко приносит пересмотр: то, что казалось решённым, хочется сверить заново. Шестой Аркан подсвечивает в эту пору тему честного выбора — не бросить и не удержать любой ценой, а понять, где согласие ещё живо. Склонность периода — обновлять близость, а не просто нести её по инерции. Это тенденция, а не предсказание перемен: как проживётся отрезок, решаете вы. Ценность этих лет в том, что верность себе и верность другому можно наконец перестать противопоставлять.', 'reviewed', 2)
