INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:6:age_period_6', 'numerology', 'Шестой цикл тяготеет к согласию и зрелой гармонии. Аркан Влюблённых звучит здесь мягче, чем в бурные годы: близость становится не поиском, а умением быть рядом спокойно и глубоко. Склонность периода — ценить то, что выбрано, и находить радость в разделённом, а не в новом любой ценой. Это тенденция, а не итог, отлитый заранее: наполнить отрезок теплом или пройти его формально — ваш выбор. Согласование ценностей в эту пору часто из усилия превращается в естественный фон жизни.', 'reviewed', 2)
