INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:6:age_period_7', 'numerology', 'Седьмой отрезок располагает к мудрости о связях: к пониманию, что близость — это не обладание, а свободное «да», которое повторяют изо дня в день. Шестой Аркан в эту пору говорит о зрелой любви, где ценности давно сверены и потому не требуют споров. Склонность периода — беречь подлинное и мягко отпускать лишнее. Это не приговор возраста, а тенденция: годы дают шанс любить яснее и меньше зависеть от одобрения. То, каким станет отрезок, по-прежнему зависит от вашего выбора и всей карты.', 'reviewed', 2)
