INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:6:age_period_8', 'numerology', 'Восьмой цикл часто про наследие близости — про то, что остаётся другим от вашего умения выбирать и соединять. Шестой Аркан в эту зрелую пору говорит о щедрости связи: о готовности делиться теплом, опытом согласия, примером верности себе. Склонность периода — не цепляться, а передавать, видеть в отношениях не собственность, а дар. Это тенденция, а не предопределённый финал: смысл этих лет складывается из ваших решений. Согласованные однажды ценности становятся тихой опорой — и для вас, и для тех, кто рядом.', 'reviewed', 2)
