  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:6:health_crown', 'numerology', 'Коронный центр обращён к большему — к смыслу, что связывает частное с целым. Шестой Аркан привносит сюда мысль, что близость и любовь могут быть дорогой к этому смыслу: через связь с другим человек нередко нащупывает своё место в мире. Вам, вероятно, свойственно искать не отвлечённую истину, а живое согласие — единство, где ценности разделены, а не просто заявлены. Это тенденция, а не догма: духовная полнота раскрывается здесь через выбор соединять, а не отгораживаться. Тишина и ясность приходят, когда сердце и смысл смотрят в одну сторону.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:6:health_heart', 'numerology', 'Сердечный центр — родная территория шестого Аркана, и здесь его тема звучит в полную силу. Речь об эмоциональной открытости и об отношениях, построенных на согласии главного. Вам, вероятно, важно, чтобы чувство и ценности шли рука об руку — тогда сердце не разрывается между «хочу» и «правильно». Склонность к глубокой привязанности становится ресурсом, когда вы выбираете близость свободно, а не из страха одиночества. Это не сценарий, а тенденция: тепло и душевное равновесие крепнут там, где любовь и уважение к себе не исключают друг друга.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:6:health_root', 'numerology', 'Опора, ощущение почвы под ногами, запас сил — за них отвечает корневая чакра. Шестой Аркан связывает вашу устойчивость с темой близости: спокойнее и увереннее вам, похоже, там, где есть надёжные связи и согласие с близкими по ценностям. Ощущение «я на своём месте» питается здесь не одиночным усилием, а разделённой поддержкой. Это не приговор, а склонность: устойчивость и бодрость крепнут, когда рядом те, с кем совпадают главные ориентиры. Круг общения вы выбираете сами — и это делает опору по-настоящему вашей.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
