  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:6:health_sacral', 'numerology', 'Сакральная зона ведает вкусом к жизни, удовольствием и живой чувственностью. С шестым Арканом эта энергия окрашена темой притяжения и близости: радость приходит там, где есть искренний отклик, где влечение согласовано с ценностями, а не спорит с ними. Вам может быть свойственно оживать рядом с тем, что и кто по-настоящему созвучен. Это не предопределяет самочувствие, а описывает тенденцию: чувственность звучит полнее, когда вы позволяете себе выбирать близость осознанно, не из голода и не из спешки. Мягкость к себе тут — лучший союзник.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:6:health_solar_plexus', 'numerology', 'Солнечное сплетение — про внутренний стержень, волю и то, как вы себя цените. Шестой Аркан вплетает сюда неожиданный поворот: ваша уверенность заметно связана с умением выбирать и с качеством близких связей. Самооценка крепнет не тогда, когда вы угождаете всем, а когда решения растут из ваших ценностей. Тенденция такая: воля звучит яснее, если вы опираетесь на собственные ориентиры и не путаете любовь с одобрением. Это не приговор, а приглашение тренировать право выбирать. Бодрость духа приходит вместе с честностью перед собой.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
