INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:6:health_third_eye', 'numerology', 'Интуиция и способность видеть суть за внешним — забота области третьего глаза. Шестой Аркан направляет эту ясность на распознавание: что и кто вам по-настоящему близок, где согласие подлинное, а где лишь удобная видимость. Вам может быть дана тонкая чуткость к «своему» — умение чувствовать созвучие раньше, чем оно объяснено словами. Это не знание будущего, а склонность к точной внутренней настройке. Она крепнет, когда вы доверяете тихому «да» и «нет» и сверяете их со своими ценностями, не заглушая шумом чужих мнений.', 'reviewed', 2)
