INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:6:health_throat', 'numerology', 'Умение сказать о важном и быть услышанным живёт в горловом центре. Шестой Аркан придаёт этому оттенок диалога и согласования: вам, похоже, легче раскрываться там, где есть настоящий контакт, где слова встречают понимание. Тема близости проявляется как потребность делиться собой именно с теми, чьи ценности вам созвучны. Это располагает к искреннему, соединяющему разговору — но раскрывается, когда вы решаетесь говорить прямо, а не подстраивать голос под чужой лад. Ясность и лёгкость приходят вместе с честностью выбора: о чём и с кем стоит говорить.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
