  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:6:money_line', 'numerology', 'На денежной линии шестой Аркан переводит разговор в неожиданную плоскость: достаток здесь связан с выбором и с тем, насколько дело созвучно вашим ценностям. Похоже, ресурс приходит легче, когда вы заняты тем, что по-настоящему откликается, и работаете с людьми, которым доверяете. Тема согласования проявляется как умение договариваться и создавать взаимную выгоду, а не тянуть одеяло на себя. Это не обещание дохода и не предсказание богатства, а склонность: деньги охотнее держатся там, где есть согласие между тем, что вы делаете, и тем, что цените.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:6:point_center', 'numerology', 'В самом центре октаграммы — там, где вы отдыхаете и восстанавливаетесь, — расположился Аркан выбора и близости. Комфортнее всего вам, похоже, там, где есть тёплый контакт и согласие по главному: рядом с людьми, чьи ценности созвучны вашим. Шестой Аркан делает уютом не одиночество, а разделённость — общее пространство, где можно быть собой рядом с другим. Стоит помнить, что это ресурс, а не зависимость: опора на близость поддерживает, пока остаётся вашим свободным выбором, а не единственным способом чувствовать себя целым.', 'reviewed', 2)
