  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:6:point_day', 'numerology', '«День» в матрице — это то, что дано вам как личный инструмент, ваш повседневный дар. Шестой Аркан ставит сюда талант соединять: чувствовать, что действительно ценно, и выбирать это осознанно. Вам, вероятно, легко находить общий язык, замечать в человеке или деле подлинную суть и складывать разрозненное в согласие. Склонность к близости и точному выбору становится ресурсом, когда вы не растворяетесь в чужих ожиданиях, а сверяетесь со своими ценностями. Тогда обаяние и чуткость работают на вас, а не против.', 'reviewed', 2)
