  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:6:point_f1', 'numerology', 'Первый квадрант октаграммы показывает, как разворачивается энергия в одной из граней вашего внутреннего рисунка. Шестой Аркан приносит сюда мотив притяжения и выбора: вас тянет к тому, что откликается, и от этого притяжения многое в зоне приходит в движение. Склонность искать созвучие — с людьми, идеями, делами — может стать двигателем, если вы сверяете влечение с ценностями, а не идёте только за первым импульсом. Проявление зависит от осознанности и от всей карты в целом; сам по себе квадрант лишь задаёт направление, а не диктует его.', 'reviewed', 2)
