  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:6:point_f3', 'numerology', 'Третий квадрант касается глубины — того слоя, где чувства укореняются и обретают вес. Шестой Аркан вносит сюда тему подлинной близости: не поверхностной симпатии, а связи, проверенной совпадением ценностей. Вероятно, вам важно, чтобы отношения и дела имели внутреннюю правду, а не только удобную форму. Такая разборчивость — не капризность, а склонность беречь настоящее. Она становится силой, когда вы выбираете сознательно и не путаете требовательность с недоверием к миру. Многое здесь зависит от контекста всей карты.', 'reviewed', 2)
