INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:6:point_month', 'numerology', 'По материнской линии сюда приходит тема, которую передавали женщины рода: как любить, не теряя себя, и как выбирать близких по сердцу, а не по привычке. Шестой Аркан намекает, что где-то в этой линии решался вопрос согласования ценностей — между чувством и долгом, между «своим» и «принятым». Возможно, вам достаётся мягкая задача: научиться близости без жертвенности и делать выбор из свободы, а не из вины. Проявится это по-разному — многое зависит от того, насколько осознанно вы разбираете доставшийся узор.', 'reviewed', 2)
