  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:6:point_tasks', 'numerology', 'Центральная задача жизни, отмеченная шестым Арканом, крутится вокруг умения выбирать. Не метаться между вариантами, а в решающий момент понимать, что тебе ближе, и брать за это ответственность. Тема близости и согласования ценностей здесь становится стержнем: вас, вероятно, тянет строить связи, где чувства и смыслы совпадают. Это склонность, а не обязанность — она раскрывается, когда вы перестаёте бояться развилок и начинаете видеть в них не ловушку, а точку, где рождается ваша подлинность.', 'reviewed', 2)
