INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:6:point_year', 'numerology', 'Отцовская линия в этой точке говорит о наследии выбора — о том, как мужчины рода определяли, что для них по-настоящему важно и с кем они шли рядом. Шестой Аркан вносит сюда вопрос ценностей: где кончается верность себе и начинается компромисс. Такая родовая задача располагает искать опору не в готовых правилах, а в честном ответе «что мне дорого». Это не сценарий, отлитый заранее, а тенденция — приглашение довести до ясности то, что предки лишь нащупывали. Сила приходит, когда выбор становится по-настоящему вашим.', 'reviewed', 2)
