  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:6:purpose_ancestral', 'numerology', 'На уровне рода шестой Аркан говорит о задаче, которая больше одного человека: научить линию выбирать и любить свободнее, чем прежде. Возможно, через вас в семейной истории завершается старый спор между долгом и чувством, между «так принято» и «так дорого мне». Согласование ценностей становится наследием, которое вы не только принимаете, но и переосмысляете. Это не жёсткий сценарий, а тенденция: родовая тема близости раскрывается как ресурс, когда вы проживаете её осознанно и мягче, чем те, кто шёл до вас.', 'reviewed', 2)
