  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:6:purpose_personal', 'numerology', 'Личное предназначение с шестым Арканом звучит как призвание соединять и выбирать осознанно. Возможно, ваш путь — учиться строить связи, где чувство и ценности не спорят, и помогать этому складываться вокруг. Тема близости здесь не про растворение в другом, а про зрелую способность быть рядом, оставаясь собой. Это склонность, которую стоит развивать, а не приговор судьбы: предназначение раскрывается ровно настолько, насколько вы готовы делать честный выбор и отвечать за него. Всё остальное — дело свободы и всей вашей карты.', 'reviewed', 2)
