INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:6:purpose_social', 'numerology', 'В социальном измерении шестой Аркан наделяет вас темой согласия между людьми. Вам, вероятно, близка роль того, кто соединяет: находит общее там, где другие видят различия, помогает договориться и услышать друг друга. Общественный вклад здесь связан не с властью над людьми, а с искусством близости и совместного выбора. Это склонность, а не обязанность спасать всех: она становится силой, когда вы действуете из ценностей, а не из желания всем нравиться. Насколько заметно раскроется этот дар — зависит от вас и от всей карты.', 'reviewed', 2)
