INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:6:purpose_spiritual', 'numerology', 'Духовный слой предназначения окрашен темой единства: шестой Аркан намекает, что ваш внутренний рост во многом идёт через связь — с людьми, с миром, с тем, что для вас свято. Любовь здесь понимается широко: как способность выбирать соединение вместо разделения и держать согласие с собственной глубиной. Это не обещание особой миссии, а склонность видеть в близости духовную задачу. Она раскрывается, когда выбор делается осознанно и без принуждения, — тогда путь к смыслу становится не бегством от мира, а более тёплым присутствием в нём.', 'reviewed', 2)
