INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:6:relationship_line', 'numerology', 'Линия отношений с шестым Арканом — почти тавтология по смыслу, и всё же у неё свой оттенок. Речь о том, как вы входите в близость: для вас, похоже, важен не сам факт союза, а совпадение по главному — по ценностям и взглядам на жизнь. Тенденция такая: отношения раскрываются полно там, где есть свободный, а не вынужденный выбор друг друга. Это не предсказание встреч и не обещание конкретного сценария, а описание вашей внутренней настройки. Здоровая близость рождается, когда «вместе» не отменяет «я остаюсь собой».', 'reviewed', 2)
