INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:7:age_period_1', 'numerology', 'Когда Седьмой Аркан окрашивает первый девятилетний отрезок, это время склонно проходить под знаком разгона. Такой период располагает набирать ход: пробовать силы, учиться держать выбранное направление, впервые почувствовать вкус самостоятельного движения. Колесница здесь — про энергию старта и желание вести свою линию. Полезно помнить, что учиться рулить лучше без надрыва: важнее не скорость, а умение не терять курс. Это лишь тенденция отрезка, а не расписание событий; чем наполнить его, во многом зависит от вас.', 'reviewed', 2)
