INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:7:age_period_2', 'numerology', 'Второй девятилетний цикл под Колесницей нередко ощущается как проверка воли на прочность. Тема отрезка склонна разворачиваться вокруг умения удержать начатое: там, где первый порыв уже позади, характер закаляется в способности продолжать. Седьмой Аркан располагает к упорству и собранности именно в эту пору. Понимание такой особенности помогает мягче обходиться с собой, не путая паузу с поражением. Всё это — окраска периода, склонность, а не приговор; наполнение остаётся делом вашего выбора и всей карты.', 'reviewed', 2)
