INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:7:age_period_3', 'numerology', 'Третий отрезок с Седьмым Арканом часто про то, чтобы взять поводья осознанно. Если раньше движение могло быть скорее порывом, то теперь период располагает управлять им зряче — выбирать, куда вести энергию, и отсекать лишние маршруты. Колесница в эту пору поддерживает зрелую целеустремлённость: меньше рывков наугад, больше выверенного курса. Это склонность отрезка, а не заданная колея — свобода распорядиться ею целиком ваша. Какими окажутся эти годы, определит не карта сама по себе, а ваши решения в ней.', 'reviewed', 2)
