INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:7:age_period_4', 'numerology', 'На четвёртом девятилетнем витке Колесница склонна проявляться как тема направления сил в главное русло. Такой период располагает свести разбег прежних лет к ясной оси — сосредоточиться на том, что действительно ваше, и не распыляться. Седьмой Аркан здесь про собранную, но не суетливую волю. Это не приговор, а склонность: то, как отрезок проявится, во многом зависит от осознанного выбора и всей карты. Возможно, именно теперь захочется не столько мчаться, сколько выбрать один достойный маршрут и держать его.', 'reviewed', 2)
