INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:7:age_period_5', 'numerology', 'Пятый цикл под знаком Седьмого Аркана нередко приносит тему устойчивого хода. Это отрезок, когда движение располагает становиться ровнее: не рывками, а на длинной, выверенной скорости, с ощущением, что вы знаете, куда и зачем едете. Колесница поддерживает здесь спокойную уверенность возницы, прошедшего не одну дорогу. Это не приговор, а склонность — проявится она настолько, насколько откликнетесь осознанным выбором. Хорошее время сверить курс с ценностями и, если нужно, мягко скорректировать направление.', 'reviewed', 2)
