INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:7:age_period_6', 'numerology', 'Шестой девятилетний отрезок с Колесницей часто про мастерство управления, а не про гонку. Тема периода склонна смещаться от «быстрее» к «точнее»: важнее становится не набрать скорость, а вести дело умело, экономно расходуя силы. Седьмой Аркан располагает к опытной, спокойной воле — той, что уже не доказывает, а просто делает. Это лишь окраска отрезка, склонность, а не список предстоящих событий. Как наполнить эти годы, решаете вы; карта здесь скорее подсказывает настроение, чем диктует маршрут.', 'reviewed', 2)
