INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:7:age_period_7', 'numerology', 'Седьмой цикл под этим Арканом нередко звучит как тема передачи хода. Движение прежних лет располагает не столько к новым рывкам, сколько к тому, чтобы делиться накопленным умением держать курс — вести за собой, поддерживать тех, кто помоложе. Колесница в эту пору про зрелую силу, которой не нужно спешить, чтобы оставаться собой. Это склонность отрезка, а не предопределённый сценарий; наполнение зависит от вашего выбора. Возможно, самое ценное движение теперь — вглубь, а не вширь.', 'reviewed', 2)
