INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:7:age_period_8', 'numerology', 'Восьмой девятилетний виток с Седьмым Арканом склонен разворачивать тему пути в его широком смысле — как оглядки на пройденную дорогу и мягкого движения дальше. Период располагает ценить не разгон, а направление: понимание, ради чего был весь путь, и спокойное продолжение своим темпом. Колесница здесь про волю, которой уже нечего доказывать. Это лишь тенденция отрезка, а не приговор и не расписание; чем его наполнить, во многом решаете вы. Хорошее время двигаться неспешно, но осознанно.', 'reviewed', 2)
