INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:7:health_crown', 'numerology', 'В коронной зоне, где рождается чувство смысла, Седьмой Аркан придаёт духовному поиску характер пути. Вам, вероятно, ближе не созерцание с вершины, а дорога к ней: смысл раскрывается в движении, в самом устремлении вверх. Колесница здесь располагает искать не готовых ответов, а живого направления — идти к большему и вести за собой. Важно лишь, чтобы напор не заслонял тишину, в которой чаще всего и приходит понимание. Как соединить движение и покой — ваш личный выбор, зависящий от всей карты.', 'reviewed', 2)
