INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:7:health_heart', 'numerology', 'В сердечной зоне воля Колесницы встречается с миром чувств — и это интересный союз. Седьмой Аркан склоняет любить деятельно: заботиться поступками, вести и защищать близких, вкладываться в отношения с той же отдачей, что и в цели. Сила эта согревает, пока оставляет место мягкости; ведь сердце не всегда нужно «побеждать» или «решать», иногда достаточно просто быть рядом. Полезно замечать, когда напор стоит сменить на тишину присутствия. Это склонность, а не заданность — тон в отношениях вы выбираете сами.', 'reviewed', 2)
