INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:7:health_root', 'numerology', 'На уровне корневой опоры Седьмой Аркан говорит о жизненной силе, что любит выражаться в действии. Ваш тонус будто подпитывается движением: когда есть цель и понятный маршрут, откуда-то берутся бодрость и устойчивость. Колесница здесь — про заземлённую волю, про способность твёрдо стоять и одновременно двигаться. Стоит помнить, что даже выносливому вознице нужны остановки: чередовать разгон и отдых — не слабость, а забота о ресурсе. Речь о склонности и самочувствии, а не о приговоре; ритм вы настраиваете сами.', 'reviewed', 2)
