INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:7:health_sacral', 'numerology', 'В зоне сакральной энергии и чувственности Колесница добавляет теме страсти оттенок целеустремлённости. Влечение и творческий пыл здесь любят направление: удовольствие полнее, когда у желания есть русло, а не просто разлив. Седьмой Аркан располагает к азарту, к умению вести и вдохновлять, вкладывая в чувственную сферу тот же напор, что и в дела. Важно лишь не превращать живое течение в гонку за результатом — чувственность не терпит спешки. Это склонность, а не предопределение; меру и вкус выбираете вы сами.', 'reviewed', 2)
