INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:7:health_solar_plexus', 'numerology', 'Солнечное сплетение — родная стихия Колесницы, ведь именно здесь живут воля и чувство собственной силы. Седьмой Аркан в этой зоне располагает к крепкому внутреннему стержню: вам важно ощущать, что вы управляете своей жизнью, а не плывёте по течению. Самооценка тут во многом держится на достижениях и способности доводить дело до конца. В этом много опоры, но есть и ловушка — привязать самоуважение к одним лишь победам. Помнить, что ценность не измеряется скоростью, — задача осознанности; и решать это вам.', 'reviewed', 2)
