INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:7:health_third_eye', 'numerology', 'На уровне третьего глаза Колесница проявляется как ясность направления. Интуиция здесь работает не созерцательно, а прицельно: вы будто чувствуете, куда двигаться, и внутренний компас уверенно указывает курс. Седьмой Аркан располагает к трезвому, собранному видению — к умению за суетой различить главный вектор. Стоит лишь оставлять зазор для сомнения: слишком быстрая ясность порой проскакивает важные детали. Замедлиться и переспросить себя — не слабость, а зрелость. Это склонность, а не приговор, и настраиваете её вы.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:7:health_throat', 'numerology', 'Горловая зона окрашивает Колесницу в тему прямой, ведущей речи. Седьмой Аркан располагает говорить по существу и с направлением: вам ближе слово, которое куда-то ведёт — убеждает, зовёт, задаёт вектор, — чем разговор ни о чём. В такой манере много энергии и умения повести за собой. Рядом полезно держать паузу и слух: диалог живёт не только напором, но и умением уступить эфир другому. Где добавить движения, а где притормозить, подскажет чуткость; и выбор всегда за вами.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
