  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:7:point_f4', 'numerology', 'Ф4 — про то, как движущая сила Колесницы выходит вовне, в мир и дела. В этом квадранте склонность вести и задавать направление проявляется в контакте с обстоятельствами: вы скорее возьмёте ситуацию в свои руки, чем будете ждать, пока всё сложится само. Такой напор открывает двери, но рядом с ним стоит держать чуткость к чужому темпу — не всё вокруг готово мчаться с вашей скоростью. Понимание этого помогает мягче обходиться и с собой, и с людьми; выбор меры всегда за вами.', 'reviewed', 2)
