INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:7:point_month', 'numerology', 'По материнской линии этот Аркан приносит тему движения и воли как родовую задачу. Похоже, в женской ветви рода накапливался опыт того, как удерживать курс в трудную пору — брать поводья, когда обстоятельства несут, и доводить начатое до конца. Колесница просит не растерять этот заряд, а продолжить: превратить наследованную стойкость в осознанную способность выбирать направление и идти. Это не приговор и не долг, повешенный сверху, — скорее приглашение распорядиться семейной силой по-своему. Как именно откликнуться на неё, каждый решает сам.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:7:point_tasks', 'numerology', 'Если свести всю карту к одному вектору, Колесница в точке «Задачи» указывает на путь через волю и движение. Ваша магистральная тема — научиться управлять собственной энергией: не глушить её и не давать ей нести вас куда попало, а брать поводья и осознанно выбирать курс. Это работа длиной в жизнь — раз за разом собирать разрозненные желания в одно ясное направление и идти, несмотря на встречный ветер. Не судьба-предписание, а приглашение расти именно в этой плоскости; насколько глубоко — решаете вы, шаг за шагом.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:7:point_year', 'numerology', 'Отцовская ветвь передаёт сюда мотив цели и напора. В мужской линии рода будто бы жила энергия рывка — умение собраться, преодолеть сопротивление, взять высоту, — и Колесница предлагает принять эту эстафету осознанно. Родовая задача здесь не в том, чтобы слепо повторять чужие маршруты, а в том, чтобы освоить саму способность держать вектор и не сворачивать под давлением. Такая склонность располагает к целеустремлённости, но раскроется настолько, насколько вы сами захотите её развивать — свобода распорядиться наследством остаётся за вами.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:7:purpose_ancestral', 'numerology', 'На уровне рода Колесница говорит о задаче продолжать движение. Как будто предыдущим поколениям важно было куда-то прийти, что-то преодолеть, — и эта энергия рывка передаётся дальше как ресурс. Родовое предназначение здесь читается не как обязанность тащить чужой груз, а как возможность подхватить накопленную волю и повести род на шаг вперёд. Седьмой Аркан располагает быть тем, кто задаёт направление своей семье. Принять эту роль или переосмыслить по-своему — свободный выбор, и он всегда остаётся за человеком.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:7:purpose_personal', 'numerology', 'Личное предназначение под знаком Колесницы связано с темой самостоятельного пути. Похоже, вам важно не просто дойти, а провести собственный маршрут — туда, куда зовёт внутренний голос, даже если дорога непроторённая. Седьмой Аркан располагает быть возницей своей жизни: держать поводья, выбирать курс и брать ответственность за направление. Это не предписанная колея, а приглашение развивать в себе волю и ясность цели. Насколько полно раскрыть этот дар — решаете вы; предназначение здесь скорее вектор, чем готовый сценарий.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:7:purpose_social', 'numerology', 'В социальном измерении Колесница указывает на роль ведущего. Ваш вклад в общее дело, вероятно, связан со способностью задать направление и сдвинуть застоявшееся с места — там, где нужен тот, кто возьмёт поводья и поведёт. Седьмой Аркан располагает к лидерству через дело, а не через громкие слова: люди тянутся за тем, кто сам уверенно движется к цели. Настоящая сила такой роли — вести, не подавляя чужую волю. Брать ли на себя эту функцию и в какой мере, вы решаете сами; это возможность, а не повинность.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:7:purpose_spiritual', 'numerology', 'Духовное предназначение с Седьмым Арканом — про путь как форму роста. Здесь взросление души мыслится не остановкой, а осознанным движением: преодолением инерции, укрощением внутренних крайностей, умением вести себя к свету собственной волей. Колесница напоминает, что два коня — светлый и тёмный — везут одну повозку, и мастерство в том, чтобы согласовать их, а не отсечь одного. Такая склонность располагает к дисциплине духа, но раскрывается только через свободный выбор идти. Темп и глубину этого пути задаёте вы.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:7:relationship_line', 'numerology', 'На линии отношений Седьмой Аркан привносит энергию и напор. В паре вы, вероятно, склонны быть ведущим — задавать темп, брать инициативу, тянуть общий воз вперёд. В этом много силы и надёжности, но у Колесницы есть и оборотная сторона: желание всё держать под контролем и мчать по своему маршруту может обгонять чувства партнёра. Понимание этой особенности помогает мягче обходиться и с собой, и с близким — иногда отпустить поводья ценнее, чем удержать курс. Каким будет баланс, вы выбираете вдвоём.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:8:age_period_1', 'numerology', 'Когда в игру вступает этот девятилетний отрезок, восьмой Аркан вносит ноту взросления через самообладание. Такой период располагает к тому, чтобы учиться держать себя в руках и добиваться мягкой настойчивостью, а не напором. Это не расписание событий, а окрашивающий мотив: тема тихой силы может звучать фоном, приглашая опереться на терпение. Как именно сложится время, зависит от вашего выбора и всей карты, а не от одной этой позиции.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
