  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:8:age_period_2', 'numerology', 'Этот цикл словно предлагает урок выдержки. Восьмой Аркан здесь — про способность продолжать начатое ровно, не сгорая на полпути и не срываясь на резкость. Период располагает к укреплению внутреннего стержня и спокойной уверенности в себе. Ничего не предопределено: это лишь склонность, оттенок времени, и раскроется он тем полнее, чем осознаннее вы опираетесь на терпение вместо спешки.', 'reviewed', 2)
