  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:8:age_period_3', 'numerology', 'На этом девятилетнем витке тема силы поворачивается мягкой стороной. Скорее всего, время подсветит умение договариваться с собой — гасить вспышки, беречь спокойствие, настаивать без давления. Восьмой Аркан располагает к росту самообладания именно в отношениях с собственными порывами. Это не приговор, а приглашение: проявится мотив по-разному, и многое решает то, как вы им распорядитесь.', 'reviewed', 2)
