INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:8:age_period_4', 'numerology', 'Отрезок под знаком восьмого Аркана окрашен спокойной стойкостью. Здесь сила — это выносливость: держать нагрузку, не теряя тепла и ясности. Такой период располагает к тому, чтобы опираться на терпение и внутреннюю опору, а не на рывки. Это грань, которую стоит развивать в свою пользу, а не заранее написанный сюжет — темп и глубину задаёте вы сами.', 'reviewed', 2)
