INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:8:age_period_5', 'numerology', 'Когда наступает это время, на первый план может выйти тихое мужество. Восьмой Аркан говорит о зрелой силе — той, что уже не доказывает себя, а просто есть. Период располагает к спокойной уверенности и умению владеть своим состоянием в разных обстоятельствах. Никакой предопределённости тут нет: это склонность, ресурс, к которому можно осознанно возвращаться.', 'reviewed', 2)
