INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:8:age_period_6', 'numerology', 'Этот цикл будто предлагает переплавить прежнюю горячность в ровную внутреннюю силу. Восьмой Аркан располагает к самообладанию и мягкой настойчивости — к тому, чтобы вести дела без надрыва. Скорее склонность, чем сценарий: тема выдержки может звучать фоном, приглашая беречь спокойствие. Как раскроется период, зависит от вашего выбора, а не от одной этой точки в карте.', 'reviewed', 2)
