INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:8:age_period_7', 'numerology', 'На этом витке восьмой Аркан подсвечивает силу, обращённую внутрь. Время располагает к тому, чтобы укреплять доверие к себе и спокойно держать курс, не оглядываясь на суету. Это не обещание конкретных событий, а окрашивающий мотив: склонность к терпению и самообладанию может стать надёжной опорой. Проявится она тем ярче, чем осознаннее вы на неё опираетесь.', 'reviewed', 2)
