INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:8:health_crown', 'numerology', 'На вершине, где речь о смысле и связи с большим, чем ты сам, восьмой Аркан звучит как тихое смирение силы. Здесь самообладание перерастает в доверие: умение отпускать контроль там, где хватка только мешает. Такая склонность располагает к спокойному поиску смысла — без надрыва и без гонки за «просветлением». Это грань, которую можно развивать в свою пользу; как она раскроется, зависит от вашего выбора и всей карты, а не от одной этой точки. Сила тут — в том, чтобы быть, а не доказывать.', 'reviewed', 2)
