INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:8:health_heart', 'numerology', 'На уровне сердца восьмой Аркан соединяет силу с теплом — и это, пожалуй, самое точное его звучание. Здесь самообладание не остужает чувства, а бережёт их: способность любить, не растворяясь, и прощать, не предавая себя. Такая склонность располагает к устойчивой доброте — той, что не путают со слабостью. Понимание этой грани помогает мягче обходиться с собой в отношениях и делать её опорой. Это не сценарий, а ресурс: раскроется он ровно настолько, насколько вы позволите сердцу и разуму идти вместе.', 'reviewed', 2)
