INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:8:health_root', 'numerology', 'На уровне корневой опоры восьмой Аркан говорит об устойчивости — ощущении «я стою на своих ногах». Это символический слой про чувство базовой безопасности и жизненный тонус. Сила здесь проявляется как спокойная заземлённость: способность не паниковать, чувствуя под собой твёрдую почву. Такая склонность располагает к ровной бодрости и самообладанию в бытовых опорах жизни. Это не приговор — насколько устойчиво вы себя ощущаете, во многом зависит от того, как вы заботитесь о себе.', 'reviewed', 2)
