INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:8:health_sacral', 'numerology', 'В слое чувственности и живой энергии восьмой Аркан звучит как умение владеть своими желаниями, не гася их. Это символика удовольствия и внутреннего огня: сила здесь — не запрет на чувства, а спокойное согласие с ними. Такая склонность располагает к тому, чтобы наслаждаться, сохраняя меру, и не давать страстям управлять собой безраздельно. Проявится это по-разному; мягкое самообладание тут — ресурс, а не свод правил, и всё решает ваш собственный тон.', 'reviewed', 2)
