INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:8:health_solar_plexus', 'numerology', 'Солнечное сплетение — символ воли и чувства собственного достоинства, и восьмой Аркан здесь как дома. Его тема — сила, которой не нужно самоутверждаться за чужой счёт: спокойная уверенность вместо давления. Такая склонность располагает к здоровой самооценке и умению отстаивать своё без агрессии. Это грань, которую стоит развивать в свою пользу; как она проявится, зависит от осознанности — можно опираться на внутренний стержень, а можно раз за разом сомневаться в своём праве на голос.', 'reviewed', 2)
