INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:8:health_third_eye', 'numerology', 'В слое интуиции и внутренней ясности восьмой Аркан работает как выдержка ума: способность не хвататься за первую мысль, а дать ей отстояться. Сила здесь тихая — это ясность, которая рождается из спокойствия, а не из спешки. Такая склонность располагает к трезвому взгляду и доверию своему чутью без фанатизма. Понимание этой грани помогает мягче относиться к себе в моменты сомнений и делать спокойную наблюдательность ресурсом, а не требовать от себя мгновенных озарений.', 'reviewed', 2)
