INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:8:health_throat', 'numerology', 'Горло — про голос и право быть услышанным, и восьмой Аркан придаёт этому спокойную весомость. Сила в речи здесь не в громкости, а в том, чтобы говорить ровно и по существу, не срываясь на крик и не проглатывая важное. Такая склонность располагает к сдержанному, но твёрдому самовыражению. Понимание этой особенности помогает мягче обходиться с собой, когда слова даются трудно, и обращать спокойную настойчивость в ресурс, а не ждать, что нужные фразы придут сами.', 'reviewed', 2)
