INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:8:money_line', 'numerology', 'На денежной линии восьмой Аркан говорит о ровном, выносливом отношении к ресурсам — без азарта и без паники. Сила здесь в дисциплине и терпении: способности не рвать с места, а спокойно наращивать своё, выдерживая паузы и спады. Такая склонность располагает к устойчивости в деньгах, к умению держать курс, когда хочется бросить. Это грань, которую стоит развивать в свою пользу, а не обещание достатка: результат зависит от ваших решений и всей картины целиком.', 'reviewed', 2)
