INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:8:point_center', 'numerology', 'Там, где вы отдыхаете и восстанавливаетесь, живёт спокойная уверенность. Центр октаграммы с восьмым Арканом — это внутренняя опора, к которой хорошо возвращаться: самообладание здесь ощущается не как усилие, а как естественное состояние. В своей зоне комфорта вы склонны черпать силу из тишины и терпения, а не из борьбы. Это склонность, а не приговор: то, насколько ровно и тепло вы себя чувствуете, во многом решает осознанный выбор — опереться на этот ресурс или растратить его на лишнюю тревогу.', 'reviewed', 2)
