INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:8:point_day', 'numerology', 'Среди личных талантов у вас проступает та самая тихая сила, что не повышает голоса и всё же добивается своего. Восьмой Аркан — про руку, спокойно лежащую на гриве льва: не укрощение силой, а согласие, к которому приходят терпением. В зоне «День» это располагает к самообладанию, к умению держать удар без ожесточения и мягко настаивать на своём. Такая склонность становится ресурсом, когда вы опираетесь на неё осознанно, а не ждёте, что она сработает сама.', 'reviewed', 2)
