INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:8:point_f1', 'numerology', 'В квадранте Ф1 восьмой Аркан задаёт тон началу — тому, как вы входите в дела и отношения. Сила здесь мягкая, без напора: скорее ровное присутствие, чем натиск. Это располагает к тому, чтобы держаться уверенно с самого старта, не доказывая ничего лишними жестами. Такая настойчивость становится ресурсом, если ею пользоваться сознательно; проявится она по-разному — характер этой зоны лишь намечает склонность, а не расписывает сценарий.', 'reviewed', 2)
