INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:8:point_f2', 'numerology', 'Ф2 показывает, как вы держите нагрузку, когда становится трудно. Восьмой Аркан отвечает: не изломом и не капитуляцией, а терпеливой стойкостью — той, что позволяет гнуться и не ломаться. В этом квадранте склонность к самообладанию помогает переживать давление, сохраняя тепло и ясность. Это грань, которую стоит развивать в свою пользу, а не готовый исход: многое решает то, опираетесь ли вы на эту силу или забываете о ней в напряжённый момент.', 'reviewed', 2)
