INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:8:point_f3', 'numerology', 'Ф3 — про то, как вы соединяетесь с людьми и делами, и восьмой Аркан вносит сюда ноту сдержанной теплоты. Сила проявляется не в том, чтобы подавить, а в том, чтобы удержать союз, не теряя себя. Такая мягкая настойчивость располагает к спокойному влиянию — без нажима, но и без уступчивости в главном. Понимание этой склонности помогает мягче обходиться с собой и обращать её в опору, а не ждать, что всё сложится само.', 'reviewed', 2)
