INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:8:point_month', 'numerology', 'По материнской линии к вам приходит наука сдержанной силы — умения быть твёрдым, оставаясь тёплым. Это не про власть над другими, а про власть над собственными порывами: восьмой Аркан говорит о самообладании, которое взращивается медленно, как привычка не отвечать резкостью на резкость. Родовая задача здесь может проявляться как приглашение освоить мягкую настойчивость там, где прежние поколения выбирали либо давление, либо уступку. Проявится это по-разному — многое зависит от того, как вы распорядитесь наследством.', 'reviewed', 2)
