INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:8:point_tasks', 'numerology', 'Главный узел вашего пути завязан вокруг тихого мужества. Восьмой Аркан здесь — не о подвигах напоказ, а о ежедневном самообладании: удержать себя, когда проще вспыхнуть, и мягко продолжать движение, когда хочется всё бросить. Эта жизненная задача располагает к тому, чтобы приручать собственную горячность, превращая её в устойчивую внутреннюю силу. Такую грань можно осознанно развивать; проявится она тем ярче, чем честнее вы с собой, и никакой предопределённости в ней нет.', 'reviewed', 2)
