INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:8:point_year', 'numerology', 'Отцовская ветвь передаёт вам сюжет о силе, которая не доказывает себя криком. Восьмой Аркан в точке «Год» — про внутренний стержень и терпеливую настойчивость: способность довести начатое, не сорвавшись и не сломав ничего вокруг. Такая родовая задача располагает к тому, чтобы учиться спокойной твёрдости — грань характера, которую стоит развивать в свою пользу. Как именно она раскроется, зависит от вашего выбора и от всей карты целиком, а не от одной этой точки.', 'reviewed', 2)
