INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:8:purpose_ancestral', 'numerology', 'В родовом сюжете восьмой Аркан читается как задача передать дальше не силу кулака, а силу выдержки. Возможно, в вашей линии копилась привычка либо давить, либо терпеть молча — и предназначение здесь про то, чтобы найти третий путь: твёрдость с теплом. Такая склонность располагает к тому, чтобы стать тем, кто гасит старое напряжение, а не разносит его дальше. Проявится это по-разному; это не сценарий, а приглашение, и распорядиться им можно свободно.', 'reviewed', 2)
