INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:8:purpose_spiritual', 'numerology', 'На духовном уровне восьмой Аркан говорит о силе, которая учится служить, а не властвовать. Здесь предназначение — в укрощении не внешних обстоятельств, а собственной гордыни и страха; в том, чтобы обрести спокойствие, которое не зависит от бурь снаружи. Такая склонность располагает к внутренней зрелости и тихому мужеству. Это одна из граней личности, которую можно развивать в свою пользу — путь открыт, а темп и глубина остаются за вами.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:8:relationship_line', 'numerology', 'В отношениях восьмой Аркан — про силу, которая не давит, а держит. Это умение оставаться собой рядом с другим: не растворяться в угоду миру и не продавливать своё любой ценой. Такая склонность располагает к тёплой твёрдости — когда границы есть, но они не превращаются в стену. Понимание этой грани помогает мягче обходиться и с собой, и с близкими, обращая самообладание в опору для пары. Как это проявится, зависит от обоих и от всей карты, а не от одной линии.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:9:age_period_1', 'numerology', 'Первый девятилетний отрезок проходит под тихой звездой Отшельника. Это время, когда особенно ценно научиться быть с собой — находить занятие, в котором не скучно наедине, прислушиваться к своему любопытству. Девятый Аркан окрашивает период тягой к размышлению и наблюдению; возможно, здесь закладывается привычка искать смысл, а не только следовать за всеми. Это не сценарий с гарантией, а склонность отрезка — то, как он проживётся, зависит от среды, поддержки и осознанности, а не предопределено заранее.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:9:age_period_2', 'numerology', 'Потребность в собственном угле — своём пространстве, своих мыслях, времени наедине — может стать лейтмотивом второго девятилетнего цикла. Отшельник здесь располагает к тому, чтобы отделять своё от чужого и понемногу опираться на себя. Иногда это проявляется как задумчивость или желание отойти в сторону от шумной компании — и в этом нет ничего тревожного. Девятый Аркан лишь задаёт тон; наполнить этот период уходом в себя или зрелой самостоятельностью — вопрос выбора и обстоятельств.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
