  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:9:age_period_3', 'numerology', 'Честные вопросы к себе — кто я вне ролей и чужих ожиданий — часто становятся приметой третьего отрезка под девятым Арканом. Отшельник приглашает замедлиться и разобраться, а не бежать за готовыми ответами. Понимание этой особенности помогает мягче обходиться с собой в такие годы — не корить за потребность в паузе, а увидеть в ней ресурс для взросления. Это склонность периода, а не приговор: глубина, которая здесь копится, раскроется настолько, насколько вы позволите себе слушать собственный внутренний голос.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:9:age_period_4', 'numerology', 'Прежние ориентиры вдруг теряют вес, и хочется собрать собственный, проверенный тишиной свод смыслов — так Отшельник может окрасить четвёртый девятилетний цикл. Девятый Аркан располагает к переоценке, к неспешному разбору того, что действительно ваше. Спешки здесь не требуется — наоборот, ценится способность выдержать паузу. Как проживётся отрезок, позиция не предрешает: она лишь намекает, что зрелость этих лет любит уединение и вдумчивость больше, чем суету.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
