  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:9:age_period_5', 'numerology', 'Желание подвести итоги и понять, ради чего всё, нередко проступает в пятом отрезке под знаком девятого Аркана. Он располагает в эти годы к углублению: меньше внешнего блеска, больше внимания к сути, к качеству связей и дел. Возможно, потянет к уединённым занятиям, к тишине, в которой яснее слышно себя. Это не обещание перемен по календарю, а склонность периода. Проявится она мягко или заметно — зависит от вашего настроя и всей карты, а не задано жёстко наперёд.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
