  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:9:age_period_6', 'numerology', 'Роль хранителя опыта — вот к чему может склонять шестой девятилетний цикл под девятым Арканом. Отшельник здесь — тот, кто уже многое понял и может тихо светить другим; в эти годы к вам может тянуться потребность делиться, наставлять, осмыслять пройденное. Понимание этой особенности помогает мягче обходиться с собой — не гнаться за прежним темпом, а ценить накопленную глубину. Это склонность отрезка, а не предписанный сюжет: как распорядиться зрелостью этих лет, решаете вы сами.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
