  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:9:age_period_7', 'numerology', 'Седьмой отрезок Отшельник связывает с тишиной, которая не пугает, а наполняет. Это может быть пора, когда уединение перестаёт быть вынужденным и становится выбранным — временем для созерцания, любимого дела без спешки, разговоров с собой. Девятый Аркан располагает к тому, чтобы находить смысл в простом и глубоком. Ничего здесь не предрешено: позиция лишь подсказывает тон периода, а проживёте вы его в замкнутости или в спокойной ясности — зависит от осознанности и поддержки близких.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
