INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:9:point_f3', 'numerology', 'Разборчивость — вот слово для девятого Аркана в третьем квадранте. Отшельник умеет отделять важное от лишнего, и эта грань наделяет чутьём на подлинное: вас трудно увлечь мишурой, вы склонны проверять всё на прочность своим тихим внутренним светом. Такая избирательность бережёт от пустых дорог, хотя иногда просит смелости всё же довериться и сделать шаг. Как проявится это качество — жёстче или мягче, — во многом решаете вы сами, опираясь на весь рисунок карты.', 'reviewed', 2)
