  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:9:point_f4', 'numerology', 'К четвёртому квадранту октаграммы девятый Аркан добавляет зрелость наставника. Отшельник — не только тот, кто ищет, но и тот, кто, найдя, светит другим; эта грань располагает к спокойному авторитету, который держится не на громкости, а на глубине. Со временем к вам могут тянуться за советом — не потому, что вы его навязываете, а потому, что рядом с вашей тишиной легче думается. Это склонность, а не назначенная роль; насколько она раскроется, зависит от вашего согласия делиться тем, что накопили внутри.', 'reviewed', 2)
