INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:9:point_month', 'numerology', 'В роду по материнской линии годами собиралась тихая мудрость — та, что рождается в уединении, а не в словах. Отшельник, девятый Аркан, намекает: где-то в череде бабушек и матерей копилось умение выдерживать одиночество, искать смысл и хранить внутренний свет — иногда ценой отгороженности. Ваша часть работы — не повторять затвор как единственный сценарий, а взять из него зрелость и способность опираться на себя. Это склонность, которую можно развернуть в свою пользу: превратить наследие уединения в осознанную глубину, а не в привычку прятаться от близких.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
