  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:9:point_tasks', 'numerology', 'Если свести всю жизненную дорогу к одному глаголу, здесь это будет «понять». Главная задача, отмеченная девятым Арканом, разворачивается вокруг поиска смысла — не заимствованного, а выстраданного в тишине собственных размышлений. Отшельник не зовёт в бегство от мира; он предлагает время от времени уходить в сторону, чтобы услышать себя, а потом возвращаться с фонарём и делиться найденным. Это не предопределённый маршрут, а склонность: она реализуется настолько, насколько вы соглашаетесь идти вглубь, вместо того чтобы скользить по поверхности.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
