  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:9:point_year', 'numerology', 'Отцовская ветка приносит мотив странника с фонарём — того, кто уходит вперёд, чтобы осветить дорогу остальным. Девятый Аркан в этой точке говорит о родовой теме поиска смысла: возможно, мужчины рода искали ответы в одиночестве, в деле, в вере или в дороге. Задача здесь — не унаследовать холодную отстранённость, а перенять умение думать самостоятельно и находить опору внутри. Как именно это проявится, зависит от вашего выбора и всей карты целиком; сама по себе позиция лишь указывает направление, в котором рост даётся особенно естественно.', 'reviewed', 2)
