  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:9:purpose_ancestral', 'numerology', 'Через род сюда протянута нить хранителя — того, кто бережёт смысл и передаёт его дальше. Девятый Аркан в родовом предназначении намекает: вашей семейной линии близка тема тихой мудрости, уединённого труда, поиска глубины. Возможно, вам достаётся роль того, кто осмысляет опыт предков и очищает его от лишнего груза. Это не предопределённая обязанность, а склонность, которую можно принять по-своему. Как она развернётся — в замкнутость или в зрелое наставничество, — во многом зависит от вас.', 'reviewed', 2)
