INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:9:purpose_personal', 'numerology', 'Личное предназначение здесь звучит как приглашение стать самому себе проводником. Девятый Аркан, Отшельник, связывает вашу дорогу с поиском смысла и умением идти при свете собственного фонаря, а не по чужим указателям. Это путь того, кто сначала разбирается сам, а потом, если захочет, освещает тропу другим. Реализуется он не по расписанию и не автоматически: позиция лишь указывает склонность, а наполните вы её мудростью или замкнутостью — вопрос осознанного выбора и всей вашей истории целиком.', 'reviewed', 2)
