INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:9:purpose_social', 'numerology', 'В обществе Отшельнику отведена роль негромкого маяка. Девятый Аркан в социальном предназначении располагает к тому, чтобы влиять не числом и напором, а глубиной: быть тем, к кому приходят за трезвым взглядом, за словом, проверенным тишиной. Вам может быть ближе роль советника, исследователя, наставника, чем трибуна. Это склонность, а не назначенная должность — она проявится настолько, насколько вы согласитесь выносить накопленное вовне, а не держать только для себя. Форма зависит от вас и всей карты.', 'reviewed', 2)
