INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:9:purpose_spiritual', 'numerology', 'Духовная дорога под знаком Отшельника — про восхождение внутрь, а не наружу. Девятый Аркан говорит о призвании искать свет там, где темно, и находить его в тишине, а не в громких откровениях. Такая склонность располагает к созерцанию, к неспешному взрослению души, к вопросам, которые важнее ответов. Понимание этой особенности помогает мягче обходиться с собой — не гнать себя к результату, а позволить смыслу вызреть. Ничего здесь не предрешено: путь раскрывается ровно настолько, насколько вы готовы по нему идти.', 'reviewed', 2)
