INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('arcanum:9:relationship_line', 'numerology', 'В отношениях девятый Аркан просит бережного пространства. Отшельнику нужна не отгороженность от партнёра, а возможность иногда побыть с собой, чтобы вернуться цельным. Эта линия располагает к глубокой, неторопливой близости: вы склонны выбирать немногих, зато всерьёз, и цените, когда рядом уважают вашу тишину. Риск — уйти в свой мир и оставить другого за дверью; но это лишь тенденция, которую легко смягчить честным разговором. Каким будет союз, позиция не предрешает — она подсказывает, что вашим чувствам нужны и близость, и воздух.', 'reviewed', 2)
