  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('aspect:venus:sextile:pluto', 'western', 'Любовь как преображающая сила — так работает секстиль Венеры и Плутона. Привязанности здесь глубоки, страсть серьёзна, а магнетизм ощутим: такой человек умеет проживать чувство до дна и не пугается его интенсивности. Отношения становятся местом роста, где через близость с другим меняешься сам.

Секстиль смягчает эту мощь, превращая её из наваждения в ресурс, — но только если человек выбирает доверие вместо контроля, а честность вместо игр. Проявленный потенциал даёт верность, которая не боится глубины, и способность возрождать чувство там, где другие давно опустили руки. Без осознанности та же сила тянет к ревности и желанию удержать. Глубина здесь — приглашение, а не рок: её направление человек определяет сам.', 'reviewed', 2)
