  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('aspect:venus:sextile:saturn', 'western', 'Чувство, которое не боится времени, — так можно описать секстиль Венеры и Сатурна. Здесь притяжение к красоте и людям встречается с чувством меры, верностью и умением строить надолго. Такого человека трогает не вспышка, а то, что выдерживает годы: надёжная привязанность, спокойная преданность, отношения, в которых есть опора.

Секстиль не делает эту зрелость автоматической — он даёт задатки, что раскрываются через готовность вкладываться и отвечать за своё. Проявленный, он располагает к прочным связям, хорошему вкусу без показухи и умению ценить простое и настоящее. Если же усилия не приложить, тёплая сдержанность может застыть в сухость или страх открыться. Всё решает выбор — впустить в жизнь и тепло, и обязательства сразу.', 'reviewed', 2)
