  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('aspect:venus:sextile:selena', 'karmic', 'Всё держится на одном негромком выборе — любить щедро или с оглядкой, открыться или придержать себя. Секстиль Венеры с Белой Луной заключает в себе возможность сделать привязанность источником света: дарить нежность без условий, видеть в близком лучшее, вносить в отношения красоту и мир. Но эта дверь открывается только встречным шагом — в тот момент, когда проще обидеться или посчитать, а человек всё же выбирает довериться. Там, где выбор сделан, склонность расцветает обаянием без фальши, умением примирять и смягчать пространство вокруг; там, где нет, — просто дремлет приятной, но нераскрытой чертой. Здесь потенциал, а не данность: гармония в чувствах становится силой ровно настолько, насколько её впускают в живые, повседневные жесты заботы.', 'reviewed', 2)
