  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('aspect:venus:sextile:uranus', 'western', 'Свобода внутри привязанности — редкое искусство, и секстиль Венеры с Ураном к нему располагает. В чувствах такого человека есть искра непредсказуемости: его тянет к необычному, он легко очаровывается новым и не выносит, когда любовь превращается в клетку. Вкус нестандартный, симпатии внезапные, а в творчестве проскакивает свежесть, которую не подделать.

Аспект открывает возможность соединять близость и независимость, но требует зрелости: без неё живость оборачивается непостоянством, а тяга к новизне — бегством от глубины. Осознанная, эта энергия дарит отношения, где двоим не тесно, и способность видеть красоту там, где другие проходят мимо. Это приглашение к живой, дышащей близости, а не обещание вечного фейерверка.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
