  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('aspect:venus:square:chiron', 'karmic', 'В близости эта связка отзывается особенно остро: тяга любить и быть любимым упирается в давнюю рану. Человека преследует подозрение, что он недостаточно хорош, чтобы его выбрали, что за нежность придётся расплачиваться, что открыться — значит напроситься на боль. Отсюда качели: то сердце наглухо заперто, то оно бросается в отношения, где заранее больно. Ощущение неуютное, зато именно оно не даёт отнестись к любви поверхностно и вынуждает всерьёз разобраться с собственной ценностью, а не прятать её за красивым фасадом. Постепенная осознанная работа снимает остроту: человек начинает чувствовать себя достойным тепла без условий и заслуг. И тогда прожитое оборачивается глубокой, всё понимающей нежностью — умением любить того, кто сам считает себя нелюбимым. А раскроется ли этот потенциал, зависит от зрелости и всей карты целиком.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('aspect:venus:square:jupiter', 'western', 'Есть в этом сочетании широкий, щедрый жест — и соблазн не знать в нём меры. Квадрат Венеры и Юпитера располагает к любви ко всему прекрасному, обильному, приятному: к красоте, удовольствиям, роскоши, великодушию. Но там, где Венера ищет вкуса и соразмерности, Юпитер шепчет «ещё» — и рождается напряжение между тонким чувством меры и тягой к избытку, будь то в тратах, в чувствах или в желании нравиться всем сразу.

Этот внутренний спор — не порок, а приглашение найти собственную меру щедрости. Осознанность превращает склонность к излишеству в настоящую широту души: способность дарить и наслаждаться, не теряя вкуса и границ. Каким выйдет баланс, решает не аспект, а сам человек и общий рисунок карты.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('aspect:venus:square:lilith', 'karmic', 'Желание быть любимым здесь плохо уживается с нежеланием прогибаться ради этой любви — и в близости зреет напряжение. Квадрат Венеры и Лилит может проявляться как притяжение к сложным, «запретным» связям, как качели между жаждой слияния и страхом потерять свободу, как старая рана отвержения, что вмешивается в отношения. Порой человек испытывает партнёра на прочность или сам разрушает дорогое, боясь оказаться уязвимым. Но это трение — не проклятие, а точка роста. Когда человек учится соединять близость со свободой, а собственную ценность перестаёт ставить в зависимость от чужого одобрения, напряжение превращается в зрелую, честную чувственность. Квадрат ничего не предрешает и не обещает бед — он ставит задачу любить, не теряя себя; исход зависит от осознанности и всей карты.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('aspect:venus:square:mars', 'western', 'Влечение и нежность, желание обладать и желание любить — в этой связке они тянут в разные стороны. Квадрат Венеры и Марса вносит в чувственную жизнь заряд, в котором притяжение соседствует с трением: страсть вспыхивает быстро, но гармония даётся не даром, её приходится отвоёвывать. Отсюда живость, азарт, магнетизм — и вместе с тем склонность к спорам с близкими, к качелям между пылом и обидой.

Само по себе это напряжение не изъян, а горючее. При осознанном отношении оно превращается в умение соединять теплоту и смелость: желать открыто и при этом слышать другого. Тогда внутренний конфликт становится источником живой, а не разрушительной энергии в отношениях и творчестве. Проявится ли связка как драма или как страстная полнота — вопрос выбора и всей карты в целом, а не предопределённой судьбы.', 'reviewed', 2)
