INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('numerology:personal_month:1', 'numerology', 'Начинается новый двенадцатимесячный виток, и его первый месяц ощущается как чистый лист, на котором ещё нет ни одной строчки. Это фон для стартов: замыслов, первых шагов, решений, задающих направление на весь предстоящий цикл. Энергия единицы располагает к инициативе и самостоятельности — тянет действовать от себя, а не подстраиваться под обстоятельства. Стоит помнить, что тон месяца — это приглашение, а не сценарий: он подсвечивает удачное время закладывать намерения, но что именно вырастет из посеянного, зависит от ваших выборов и всей картины в целом. Сейчас полезнее наметить вектор, чем гнаться за мгновенным итогом.', 'reviewed', 2)
