  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('numerology:personal_month:3', 'numerology', 'Тройка звучит легко и разговорчиво. Месяц под её влиянием окрашен в тона самовыражения: тянет говорить, писать, шутить, показывать сделанное, заводить знакомства без внутреннего зажима. Общий фон располагает к творчеству и к тому, чтобы слова находились сами — коммуникация даётся проще обычного. Это склонность, а не обещание фейерверка: число задаёт настроение, а наполните вы его встречами, идеями или молчанием — решаете вы. Единственная тень тройки — распыление: когда всё интересно, легко не довести до конца ничего. Поэтому лёгкость месяца работает лучше всего, если оставить в ней хотя бы одну линию, которую доводишь до точки.', 'reviewed', 2)
