INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('numerology:personal_month:4', 'numerology', 'Четвёрка — про землю под ногами. Её месяц ощущается плотнее и медленнее: это фон для труда, наведения порядка и укрепления того фундамента, на котором будет стоять весь цикл. Хочется систем, списков, ясных правил — и рутина, обычно раздражающая, вдруг приносит спокойное удовлетворение. Число располагает к дисциплине и неброской работе, плоды которой видны не сразу. Стоит понимать, что речь о тоне периода, а не о гарантированной награде: усердие сейчас — это вклад, а не сделка с судьбой. Если единица была замыслом, то четвёрка — время класть кирпичи, спокойно и по одному, не требуя, чтобы дом вырос за месяц.', 'reviewed', 2)
