INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('numerology:personal_month:6', 'numerology', 'Шестёрка возвращает домой — в прямом и переносном смысле. Её месяц смещает внимание к близким, к обустройству пространства, к заботе и той тихой гармонии, что рождается, когда о ком-то или о чём-то по-настоящему печёшься. Фон периода тёплый и немного ответственный: хочется, чтобы рядом было хорошо не только вам. Число располагает к участию, красоте быта и примирению — но описывает оно настроение, а не сценарий семейных сцен. Тонкая грань шестёрки в том, чтобы забота не обернулась контролем или привычкой жить чужими делами в ущерб своим. Гармония этого месяца полнее всего там, где вы даёте тепло по выбору, а не из чувства долга.', 'reviewed', 2)
