INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('numerology:personal_year:7', 'numerology', 'Семёрка приглушает внешний шум. После деятельных лет наступает более тихий отрезок, когда тянет остановиться, осмотреться и заглянуть глубже — в книги, в собственные мысли, в вопросы, на которые прежде не хватало паузы. Фон периода созерцательный: внешняя активность может замедлиться, зато крепнет связь с внутренними опорами. Тенденция года — к анализу, к уединению, к неспешному разбору того, что накопилось внутри. Такое затишье легко принять за застой, хотя чаще это просто иная работа — вглубь, а не вширь. Стоит помнить: число цикла очерчивает лишь общее настроение времени, а не то, что случится; чем внимательнее эта пауза, тем яснее становится дальнейший путь.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
