  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('numerology:personal_year:8', 'numerology', 'Восьмёрка — про год урожая, когда накопленное прежде начинает проявляться в осязаемом. Внимание естественно смещается к материальной стороне жизни: к делу, к ресурсам, к результатам, которые наконец видны. Фон периода деловой и весомый; здесь чаще обычного важны трезвый расчёт, ответственность и умение довести до отдачи то, во что вкладывался. Склонность года — действовать уверенно и по-крупному, соизмеряя амбицию с реальностью. Важно не путать активность с суетой и помнить о балансе сил. И, как во всяком цикле, число описывает лишь общий характер отрезка, а не обещает конкретных приобретений: масштаб и качество плодов зависят от того, что и как вы делали.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('numerology:personal_year:9', 'numerology', 'Девятка закрывает круг. Последний год девятилетней дуги — про завершения: подводятся итоги, отпускается то, что отслужило своё, освобождается место для следующего витка. Общий фон располагает к прощаниям без драмы — с привычками, отношениями, ролями, которые больше не по размеру. Тенденция периода — расчищать, прощать, отдавать, доводить длинные линии до их естественного конца. Начинать здесь что-то большое обычно преждевременно: время скорее для точки, чем для запятой. Стоит держать в уме, что число цикла рисует лишь настроение отрезка, а не конкретные события, — а насколько мягким выйдет это освобождение, во многом решаете вы сами.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
