  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('numerology:personality:1', 'numerology', 'Единица в числе личности звучит как импульс к движению первым: там, где другие ещё присматриваются, у вас уже готов первый шаг. Это склонность к самостоятельности, инициативе и внутренней опоре на себя — способность начинать с чистого листа и вести за собой, не дожидаясь чужого разрешения. Такая энергия располагает к лидерству, но лидерство здесь не про власть над людьми, а про смелость взять ответственность. Обратная сторона — риск переупрямиться или тянуть всё в одиночку. Многое зависит от осознанности: единица раскрывается ярче, когда воля соединяется с умением слышать других, а решительность — с терпением. Как именно проявится этот заряд, во многом решаете вы сами.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('numerology:personality:11', 'numerology', 'Одиннадцать — из тех чисел, что звучат на повышенной ноте. Это мастер-число, и его тема — обострённая интуиция и способность вдохновлять: улавливать то, что носится в воздухе, и передавать это другим так, что у них загораются глаза. Такой натуре свойственны чувствительность, идеализм и внутренний свет, который тянет за собой. Дар одиннадцати — быть проводником идей и настроений. Но высокая нота требует настройки: та же тонкость легко оборачивается тревожностью, а планка «быть особенным» — давлением, с которым непросто жить. Это не готовая судьба, а потенциал. Когда чуткость находит опору в простых земных делах и спокойном ритме, вдохновение перестаёт изматывать и начинает по-настоящему освещать путь — свой и чужой.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('numerology:personality:2', 'numerology', 'Двойка настроена на тонкую материю отношений — на то, что происходит между людьми. Это чуткость к настроению собеседника, умение уловить недосказанное и найти слова, которые соединяют, а не разъединяют. Такое число личности располагает к дипломатии, сотрудничеству и роли того, кто уравновешивает крайности. Сила двойки — в мягкости, которая нередко оказывается прочнее прямого напора. Тенденция, о которой стоит помнить: чужие потребности легко заслоняют собственные, и, заботясь обо всех, важно не забывать про себя. Понимание этой грани помогает обходиться с собой бережнее и превращать чувствительность из уязвимости в ресурс — в редкий дар слышать другого по-настоящему.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('numerology:personality:22', 'numerology', 'Двадцать два соединяет мечту с чертежом. Это мастер-число «строителя»: его тема — масштабное практическое созидание, способность взять большую, почти утопическую идею и терпеливо перевести её в реальность — в проект, дело, начинание, которое переживёт автора. В двадцати двух встречаются размах мечтателя и основательность ремесленника: видеть далеко и при этом класть кирпичи один за другим. Дар этого числа — превращать замысел в нечто прочное и полезное многим. Оборотная сторона масштаба — груз: планка так высока, что легко или надорваться, или, испугавшись, вовсе не начать. Это не приговор, а склонность. Как раскроется потенциал строителя, решает выбор — двигаться шаг за шагом, соизмеряя мечту с сегодняшним днём, и не путать величие замысла с обязанностью сделать всё разом.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
