  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('numerology:personality:3', 'numerology', 'Там, где есть тройка, обычно есть и слово, краска, жест — что-то, что просится наружу. Это число личности про творческое самовыражение и лёгкость в общении: мысль охотно превращается в рассказ, а настроение — в образ. Тройке свойственны обаяние, живость и умение зажечь компанию, разрядить напряжение шуткой, найти нужную интонацию. Такая натура тянется делиться — идеями, эмоциями, впечатлениями. Оборотная сторона живости — распыление: когда интересов много, легко начать десять дел и не довести ни одного. Эта склонность не судьба, а материал: если направить искру в конкретное русло и добавить дисциплины, разговорчивость становится талантом рассказчика, а лёгкость — настоящим мастерством.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
