  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('numerology:personality:4', 'numerology', 'Четвёрка любит то, на что можно опереться: понятный порядок, надёжные договорённости, дело, доведённое до конца. Это число личности про основательность и структуру — про умение терпеливо, кирпичик за кирпичиком, выстраивать прочный фундамент там, где другие ищут коротких путей. Такому человеку обычно доверяют, потому что за словом следует дело, а за планом — исполнение. Ресурс четвёрки — устойчивость и трудолюбие. Тенденция, которую стоит замечать: порядок может закостенеть в упрямство, а надёжность — обернуться страхом перемен. Понимание этой особенности помогает мягче относиться к себе и к чужой спонтанности: фундамент нужен не сам по себе, а чтобы на нём выросло что-то живое.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('numerology:personality:5', 'numerology', 'Пятёрке тесно в раз и навсегда заведённом порядке — её стихия движение, новизна, разнообразный опыт. Это число личности про тягу к свободе и переменам: любопытство ведёт пробовать, ездить, знакомиться, менять ракурс. Такая натура быстро схватывает суть, легко адаптируется и оживает там, где что-то происходит. Свобода здесь не каприз, а способ дышать. Обратная сторона подвижности — трудность с постоянством: соблазн бросить на середине, едва угаснет азарт. Это не приговор, а склонность — и раскрывается она по-разному. Когда за жаждой нового встаёт осознанный выбор, а не бегство от скуки, пятёрка превращается из непоседливости в редкую широту и умение жить полно.', 'reviewed', 2)
