INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('numerology:personality:6', 'numerology', 'Шестёрка смотрит на мир через тех, кто рядом. Это число личности про заботу, ответственность за близких и потребность в ладе — дома, в семье, в кругу своих. Такому человеку важно, чтобы вокруг было тепло и справедливо; он охотно берёт на себя роль опоры, к которой приходят за поддержкой и советом. Дар шестёрки — умение создавать пространство, где другим спокойно. Тенденция, о которой стоит помнить: забота порой перерастает в гиперопеку или в привычку выручать всех, кроме себя. Эту грань хорошо развивать бережно: гармония снаружи держится, только когда есть согласие внутри, а помощь ценнее, если оставляет другому свободу оставаться собой.', 'reviewed', 2)
