  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('numerology:personality:7', 'numerology', 'Семёрка тянется вглубь, а не вширь. Это число личности про пытливый ум и внутренний поиск: желание понять, как всё устроено, добраться до сути, а не удовлетвориться готовым ответом. Такому человеку нужны тишина и одиночество — не от нелюдимости, а чтобы думать, наблюдать, сверяться с собой. Аналитический склад соединяется здесь с интуицией и тягой к смыслу, порой к вопросам духовным. Сила семёрки — в глубине и честности перед собой. Оборотная сторона уединения — риск замкнуться, спрятаться за скепсисом или холодным анализом. Эта склонность не судьба: когда внутренняя работа находит выход к людям и к делу, отстранённость оборачивается мудростью, а сомнение — зрелым знанием.', 'reviewed', 2)
