  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('numerology:personality:8', 'numerology', 'Восьмёрка мыслит результатом: идея интересна ей ровно настолько, насколько её можно воплотить. Это число личности про практическую реализацию, умение управлять ресурсами — временем, деньгами, людьми — и про здоровые амбиции, которым не стыдно хотеть большего. Такой натуре свойственны деловая хватка, чувство масштаба и готовность отвечать за исход. Сила восьмёрки — способность превращать замысел в устойчивую конструкцию, приносящую плоды. Тенденция, за которой стоит следить: азарт достижений может заслонить всё остальное, а влияние — стать самоцелью. Это не приговор, а склонность. Многое решает выбор: когда сила служит не только себе, амбиция становится созиданием, а власть — опорой для других.', 'reviewed', 2)
