  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('numerology:soul:1', 'numerology', 'Единица среди чисел души — про импульс первого шага. Такой человек нередко чувствует внутреннюю потребность идти впереди, брать инициативу и самому отвечать за направление, не дожидаясь, пока решат за него. В этом есть азарт первопроходца: пробовать там, где ещё нет протоптанной тропы, и опираться на собственную волю. Склонность к самостоятельности может проявляться как здоровая уверенность, а может оборачиваться нетерпением к чужому темпу — многое зависит от осознанности и от всей карты целиком. Единица не обрекает на одиночество вожака: её сила раскрывается, когда лидерство становится не соревнованием, а умением вести за собой, оставляя другим пространство. Это склонность, которую стоит узнавать в себе и направлять, а не приговор.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('numerology:soul:11', 'numerology', 'Одиннадцать вибрирует тоньше остальных. Это мастер-число, и оно про обострённое чутьё — способность улавливать то, что ещё не проговорено, и зажигать в других искру, которую они в себе не замечали. Такому человеку нередко даётся видеть чуть дальше и чувствовать чуть глубже; интуиция для него — рабочий инструмент, а не смутное ощущение. Но повышенная чувствительность несёт и нагрузку: тонкая настройка легко переходит в тревожность, а внутренняя планка «мастера» — в требовательность к себе на грани изнеможения. Раскроется дар вдохновлять или обернётся напряжением — решает осознанность и опора на всю карту. Одиннадцать ничего не предрешает. Понимание своей чувствительной природы помогает мягче обходиться с собой: чтобы вдохновлять других, важно беречь собственный ресурс.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
