  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('numerology:soul:2', 'numerology', 'В глубине души двойка тянется к согласию — ей важнее лад с другим, чем собственная правота. Число души 2 располагает к тонкой настройке на другого: уловить настроение, найти общий язык, сгладить острый угол прежде, чем он ранит. Это дар дипломата и партнёра — человека, который мыслит не «я», а «мы», и для которого согласие ценнее победы в споре. Чуткость к партнёру бывает опорой и в отношениях, и в работе, но та же мягкость иногда уводит в привычку растворяться, ставить чужие желания выше собственных. Как именно раскроется эта черта, зависит от осознанного выбора и всего рисунка личности. Понимание своей отзывчивой природы помогает мягче обходиться с собой: слышать другого — не значит терять себя, и умение держать баланс здесь и есть настоящий талант.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('numerology:soul:22', 'numerology', 'Двадцать два берёт мечту и переводит её на язык чертежей. Это мастер-число «строителя» — редкое сочетание большого видения с практической волей воплотить его в жизни, а не оставить парить в воображении. Такому человеку по плечу замыслы, от которых у других захватывает дух: он способен мыслить масштабно и при этом класть кирпич за кирпичом, соединяя идеал и расчёт. Оборотная сторона — груз собственных ожиданий: чем крупнее замах, тем сильнее давит страх не дотянуть, и тем важнее не обесценивать уже сделанное на пути. Проявится ли потенциал как созидание или останется невыносимым «надо было бы», зависит от осознанного выбора и всего рисунка личности. Это не приговор, а склонность к масштабному творчеству, и разворачивается она постепенно, шаг за шагом.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('numerology:soul:3', 'numerology', 'Тройка звучит. Это число души про голос, который просится наружу — через слово, краску, шутку, историю за общим столом. Человеку с тройкой обычно легко даётся общение и самовыражение: он оживляет компанию, находит форму для чувства, превращает будничное в яркое. За лёгкостью стоит потребность быть услышанным и увиденным. Творческая натура может проявляться как щедрый талант радовать и вдохновлять, а может рассеиваться на десяток начатых дел без единого завершённого — фокус здесь ценнее блеска. Тройка ничего не предопределяет: она лишь располагает к тому, чтобы искать своё выражение и не бояться его. Эту грань стоит развивать сознательно — тогда общительность становится не бегством от глубины, а способом делиться ею.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('numerology:soul:4', 'numerology', 'Четвёрка любит опору под ногами. Это число души тех, кто строит: по кирпичику, по плану, с оглядкой на прочность, а не на скорость. Надёжность, порядок и терпение — их естественная среда; на такого человека можно положиться, и он сам это знает и ценит. Стремление к структуре даёт устойчивость, но та же черта иногда твердеет в упрямство или в страх перемен, когда привычная система становится важнее живой ситуации. Проявится это как основательность или как жёсткость — зависит от осознанности и от карты в целом. Четвёрка не приговаривает к скучной надёжности: понимание своей природы помогает мягче обходиться с собой, оставляя место спонтанности рядом с тем фундаментом, который вы умеете возводить как мало кто другой.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('numerology:soul:5', 'numerology', 'Пятёрке тесно в четырёх стенах. Это число души про движение, вкус к новому и желание прожить как можно больше разного — сменить маршрут, попробовать незнакомое, распахнуть окно там, где другие закрывают дверь. Свобода для такого человека не каприз, а воздух, которым он дышит. Тяга к переменам делает его живым, любопытным, лёгким на подъём, но та же энергия иногда рассыпается на поверхностные впечатления, где не хватает терпения дойти до глубины. Как проявится эта подвижность, во многом решает осознанный выбор. Пятёрка ничего не обещает и ни к чему не принуждает — она лишь располагает к разнообразию опыта. Эту грань стоит развивать в свою пользу: свобода расцветает, когда у неё есть внутренний стержень, а не только внешний простор.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('numerology:soul:6', 'numerology', 'Шестёрка держит дом. За этим числом души — тепло заботы, чувство ответственности за близких и потребность в том, чтобы вокруг было ладно и по-доброму. Такой человек часто становится тем, к кому приходят за поддержкой; он умеет создавать уют не только вещами, но и самим присутствием. Стремление к гармонии — сила, но у неё есть тень: желание опекать может переходить в контроль, а забота о других — вытеснять заботу о себе. Раскроется ли шестёрка как щедрое великодушие или как жертвенность без границ, зависит от осознанности и всего портрета. Это не приговор, а склонность. Понимание её помогает мягче обходиться с собой: настоящая гармония начинается там, где вы включаете в круг заботы и собственные нужды.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('numerology:soul:7', 'numerology', 'Душа семёрки тянется вглубь — туда, где за внешним шумом открывается настоящий смысл. Это число души мыслителя и искателя — того, кто не берёт на веру, а хочет докопаться до сути, и кому уединение не в тягость, а в радость. Аналитический ум, интерес к скрытому, тяга к вопросам «почему» и «ради чего» — его родная территория. Склонность к внутреннему поиску даёт глубину и независимость суждений, но та же обращённость внутрь порой оборачивается отстранённостью, недоверием, привычкой держать других на расстоянии. Как это проявится, решает осознанный выбор, а не само число. Семёрка ничего не предопределяет — она лишь располагает к размышлению и духовному поиску. Эту грань стоит узнавать в себе бережно: глубина ценнее, когда ею есть с кем делиться.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('numerology:soul:8', 'numerology', 'Душу восьмёрки согревает не процесс, а весомый след, который остаётся после сделанного. Это число души про умение превращать замысел в дело, а идею — в ощутимый итог: ресурсы, структуру, конкретное достижение. Здоровые амбиции и деловая хватка для такого человека естественны, как дыхание; он видит, из чего сложить успех, и не боится ответственности за большое. Практичность — сильная сторона, но её оборотная грань — риск мерить всё пользой и выгодой, забывая, что не всё в жизни конвертируется в достижение. Проявится восьмёрка как зрелая реализация или как гонка за показателями — зависит от осознанности и всей карты. Это одна из граней личности, которую можно развивать в свою пользу, особенно когда сила и амбиция служат не только себе, но и делу, которое больше вас.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('numerology:soul:9', 'numerology', 'Девятка смотрит поверх границ. Замыкая ряд простых чисел, она несёт в себе широту: сострадание к людям вообще, интерес к большому миру, способность видеть картину целиком и доводить начатое до завершения. Человеку с девяткой близки идеалы, ему важно, чтобы в том, что он делает, был смысл сверх сиюминутной выгоды. Гуманизм и щедрость — его свет, но у широты есть тень: можно так увлечься спасением мира, что не заметишь близких рядом, или застрять на пороге финала, которого сам же и ждёшь. Как раскроется девятка, зависит от осознанного выбора. Это не приговор, а склонность к великодушию и завершению — и её стоит узнавать в себе, учась отдавать, не растворяясь без остатка.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet:chiron:overview', 'karmic', 'Почти у каждого есть место, которое отзывается болью от лёгкого прикосновения, — и одновременно именно там спрятана способность помогать другим. Об этой зоне рассказывает Хирон: о самом чувствительном опыте, который со временем может стать самым целительным. Это архетипическая тема, проявляющаяся в характере независимо от знака и дома, но их сочетание показывает, где ранимость тоньше всего и где рождается особая чуткость. Хиронианская сторона — одна из тех граней личности, которую можно развивать в свою пользу: не пряча уязвимое место и не стыдясь его, а постепенно превращая собственный трудный опыт в понимание чужой боли. Часто человек лучше всего поддерживает других именно в том, что когда-то давалось ему тяжелее всего. Больное место не обязано определять всю жизнь — при внимательном отношении оно становится источником мудрости и мягкости. Как это сложится, зависит от зрелости и от всей карты целиком.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet:jupiter:overview', 'western', 'Некоторым людям всегда тесно в узких рамках — им нужно больше воздуха, смысла, горизонта. За это стремление отвечает Юпитер: за рост, за оптимизм, за то, в чём человек ищет расширение и ради чего готов выходить за привычные пределы. Это архетипическая тема, которая звучит в характере сама по себе, но знак и дом задают ей конкретную окраску — кто-то расширяется через знания и дорогу, кто-то через веру и большие идеи, кто-то через щедрость к людям. Понимание этой особенности помогает мягче обходиться с собой и превращать её в ресурс, а не в слабое место. Ведь у той же тяги к большему есть и обратная сторона — обещать сверх сил, разбрасываться, переоценивать возможности. Осознавая свой «юпитерианский аппетит», человек учится отличать настоящий рост от простого увеличения и вкладывать оптимизм туда, где он и правда двигает вперёд. Юпитерианская вера в лучшее — хороший спутник, если она опирается на реальность, а не заменяет её: тогда широта взгляда открывает двери, а не оставляет с пустыми обещаниями. Как это сложится, зависит от зрелости и всей карты целиком.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet:lilith:overview', 'karmic', 'То, чему когда-то сказали «так нельзя», никуда не девается — оно лишь затихает и уходит вглубь. Об этой вытесненной, непризнанной стороне говорит Лилит: о желаниях, силе или свободе, которые человек однажды спрятал, а они всё равно просят признания. Это архетипическая тема, проявляющаяся в характере независимо от знака и дома, но их сочетание задаёт ей конкретную окраску — где-то это подавленная страсть, где-то неудобная честность, где-то отвергнутое право злиться и хотеть. Лилит — одна из тех граней личности, которую можно развивать в свою пользу, если перестать воевать с собой. Признанная и услышанная, эта энергия перестаёт прорываться исподволь и становится источником внутренней подлинности; вытесненная — продолжает напоминать о себе исподтишка. Речь не о том, чтобы дать волю всему подряд, а о том, чтобы честно увидеть отвергнутое в себе. Как это проявится, зависит от осознанности и всей карты целиком.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet:mars:overview', 'western', 'Когда приходит время не размышлять, а действовать, вперёд выходит Марс. Он отвечает за напор, за сам способ добиваться желаемого и отстаивать собственные границы: как человек говорит «нет», как выдерживает столкновение, откуда берёт энергию на рывок. Это архетипическая тема, которая проявляется в характере независимо от знака и дома, но их сочетание придаёт ей конкретную окраску — чей-то напор прямой и горячий, чей-то расчётливый и терпеливый, чей-то вспыхивает редко, но сильно. Марсианская сторона — не приговор, а склонность: то, как она проявится, во многом зависит от осознанного выбора. Одну и ту же силу можно тратить на бесплодные конфликты, а можно направить в дело, в спорт, в защиту важного — и тогда она из источника раздражения превращается в опору. Здоровый Марс — это не про то, чтобы всегда быть первым и громким, а про способность вовремя встать за себя и довести задуманное до конца, не растратив запал по дороге. Учиться злиться по адресу и вовремя, не глотая обиду и не сжигая всё вокруг, — работа целой жизни, и она в руках самого человека.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet:mercury:overview', 'western', 'Скорость, с которой в голове складываются слова, а мысли превращаются в разговор, — это уже почти портрет Меркурия. Он отвечает за мышление и речь, за то, как человек ловит информацию, переваривает её и передаёт дальше: одни рассуждают строго и по полочкам, другие перескакивают с образа на образ, третьи по-настоящему думают, только заговорив вслух. Эта архетипическая тема проявляется в характере сама по себе, а знак и дом лишь придают ей конкретный оттенок — где-то ум сухой и точный, где-то живой и ассоциативный. Меркурианская сторона — одна из тех граней личности, которую вполне можно развивать в свою пользу: тренировать внимание, учиться слушать не только чтобы ответить, подбирать слова так, чтобы тебя понимали. Ни один показатель не делает человека «умным» или «болтливым» раз и навсегда; способ мышления — это навык, который взрослеет вместе с человеком, и многое зависит от того, как он им распоряжается.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet:moon:overview', 'western', 'Раньше слов и раньше всякого рассуждения в человеке успевает откликнуться что-то более древнее — и этой ранней, дословесной областью ведает Луна. Она хранит эмоциональные потребности, привычные, почти рефлекторные реакции и то самое внутреннее чувство, по которому мы понимаем: здесь безопасно, а здесь тревожно. Это архетипическая тема, которая звучит в характере независимо от знака и дома, но их сочетание задаёт ей конкретную окраску — кому-то для покоя нужны тишина и предсказуемость, кому-то живое тепло рядом, кому-то ощущение, что он кому-то нужен. Важно помнить: лунная природа — не приговор и не жёсткая программа, а склонность. То, как она проявится, во многом зависит от осознанного выбора: можно годами следовать старым эмоциональным привычкам вслепую, а можно постепенно узнавать свои настоящие потребности и заботиться о них по-взрослому. Понимание своей Луны часто снимает лишнее чувство вины за «неправильные» эмоции — оказывается, у чувствительности есть своя внутренняя логика.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet:neptune:overview', 'western', 'Граница между явью и мечтой у разных людей проходит по-разному, и у тех, для кого она особенно тонка, громко звучит Нептун. Он отвечает за воображение, за чувствительность к тонким, невидимым материям и за склонность идеализировать — видеть в человеке или деле больше, чем лежит на поверхности. Это архетипическая тема, которая проявляется в характере независимо от знака и дома, но их сочетание придаёт ей конкретную окраску — кому-то это открывает дорогу в творчество и сострадание, кому-то приносит туман и разочарования. Нептунианская сторона — не приговор, а склонность: то, как она проявится, во многом зависит от осознанного выбора. Ту же тонкую настройку можно растворять в иллюзиях и бегстве, а можно превращать в источник вдохновения, эмпатии и веры. Нептун часто отвечает за способность сострадать, откликаться на музыку и образы, чувствовать чужую боль как свою — и эта же тонкость требует бережной опоры на факты, чтобы не растеряться в чужих ожиданиях. Учиться отличать мечту от самообмана, не теряя при этом способности мечтать, — деликатная работа, и она во многом в руках самого человека.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet:north_node:overview', 'karmic', 'Комфорт и рост редко указывают в одну и ту же сторону — и Северный узел ведёт как раз туда, где уюта меньше, но именно там по-настоящему растёшь. Он задаёт вектор осознанного развития — поначалу незнакомую территорию, движение к которой даётся не сразу, зато приносит ощущение подлинности. Это архетипическая тема, звучащая в характере независимо от знака и дома, но их сочетание задаёт ей конкретную окраску — для одного рост лежит через смелость, для другого через терпение, для третьего через умение просить помощь. Узловая тема — одна из тех граней личности, которую можно развивать в свою пользу: замечать, куда тянет по привычке, и всё же пробовать шаг в непривычную сторону. Здесь нет обязанности и нет расписания — есть приглашение. Никто не «должен» дойти до этой точки, но те, кто движется в её сторону, часто чувствуют, что живут своей, а не чужой жизнью. Как раскроется этот путь, покажет вся карта и собственный выбор человека.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet:pluto:overview', 'western', 'Под поверхностью привычного «я» есть глубина, где хранится то, что редко показывают, — и в этой глубине правит Плутон. Он отвечает за глубинную трансформацию, за скрытые ресурсы и за умение выдерживать интенсивные, порой тяжёлые внутренние процессы, из которых человек выходит другим. Это архетипическая тема, звучащая в характере независимо от знака и дома, но их сочетание задаёт ей конкретную окраску — где-то это упорная воля к обновлению, где-то тяга к контролю, где-то способность собираться заново после того, что казалось концом. Плутонианская сторона — одна из тех граней личности, которую можно развивать в свою пользу: учиться отпускать отжившее без страха, честно смотреть на собственную теневую силу и направлять её в глубокое, а не в разрушительное. Эта энергия не про катастрофы, а про способность перерождаться — и то, во что она сложится, зависит от осознанности и от всей карты в целом.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet:saturn:overview', 'western', 'Не всё в жизни даётся легко — и как раз о трудной, но честной части опыта говорит Сатурн. Он отвечает за дисциплину, за ответственность и за те области, где результат приходит не даром, а через терпение и труд. Это архетипическая тема, проявляющаяся в характере независимо от знака и дома, но именно их сочетание показывает, где человеку придётся взрослеть медленнее и основательнее других. Сатурн нередко переживается как внутренний строгий голос или как ощущение «здесь у меня не выходит само» — и понимание этой особенности помогает мягче обходиться с собой, не путая временную незрелость с приговором. То, что сначала кажется ограничением, со временем часто становится главной опорой: навык, выстроенный через усилие, держит крепче любого лёгкого таланта. Сатурнианскую сторону можно превратить в ресурс — научиться уважать медленный рост, доводить начатое и не требовать от себя мгновенного совершенства. Многое здесь зависит от выбора и от карты в целом.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet:selena:overview', 'karmic', 'Есть тонкая настройка восприятия, которая ловит больше, чем видно глазом, — и о ней рассказывает Селена. Она отвечает за мягкую интуитивную чувствительность и за ощущение связи с чем-то большим, чем ты сам, — с общим человеческим опытом. Это архетипическая тема, звучащая в характере независимо от знака и дома, но их сочетание задаёт ей конкретную окраску — у кого-то это тихая внутренняя ясность, у кого-то тяга к светлому и бережному, у кого-то дар вовремя почувствовать настроение других. Селена — не приговор и не обещание «особой миссии», а склонность: то, как она проявится, во многом зависит от осознанного выбора. Эту чувствительность можно оставлять смутным фоном, а можно бережно развивать — учиться доверять внутреннему чутью, не отключая при этом здравый смысл. Тонкость восприятия становится опорой, когда человек не возводит её в культ, а просто прислушивается. Многое здесь зависит от зрелости и от карты в целом.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet:sun:overview', 'western', 'В центре натальной карты всегда стоит Солнце — точка, из которой человек светит вовне и говорит о себе «я». Оно отвечает за осознанную волю, за ту жизненную силу, что поднимает утром с постели и заставляет добиваться своего, и за манеру, в которой человек предъявляет себя миру. Это архетип, звучащий в характере сам по себе, независимо от того, в каком знаке и доме он расположен, — но именно знак и дом окрашивают этот свет в конкретный оттенок: где-то он ровный и тёплый, где-то яркий и напористый, где-то заметен не сразу, но греет долго. Солнце описывает не столько то, каким человек кажется со стороны, сколько то, каким он ощущает себя изнутри, когда доверяет себе. Солнечная тема — не готовый приговор, а грань личности, которую можно осознанно развивать в свою пользу: учиться опираться на собственную волю, не путая её с упрямством, и находить дела, в которых внутренний огонь горит ровно, а не выжигает. Как именно раскроется эта энергия, зависит от зрелости человека и от всей карты в целом, а не от одного показателя.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet:uranus:overview', 'western', 'Одним свобода даётся как приятный бонус, другим она — воздух, без которого не дышится; за эту острую потребность в независимости отвечает Уран. Ему подвластны и оригинальность мышления, и готовность к переменам там, где другие держатся за привычное. Это архетипическая тема, звучащая в характере независимо от знака и дома, но их сочетание задаёт ей окраску — у одного бунт тихий и внутренний, у другого громкий и заметный, у третьего он вспыхивает только тогда, когда его пытаются загнать в рамки. Уранианская природа — не приговор, а склонность: то, как она проявится, во многом зависит от осознанного выбора. Ту же энергию можно тратить на протест ради протеста, а можно — на смелые, свежие решения и на верность себе среди чужих ожиданий. Свобода становится ценностью, а не капризом, когда человек понимает, ради чего именно ему нужна независимость. Как это раскроется, покажет вся карта и зрелость самого человека.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet:venus:overview', 'western', 'Что человек считает красивым, к чему тянется без принуждения и как ведёт себя, становясь нежным, — обо всём этом рассказывает Венера. Она отвечает за ценности, за притяжение к красоте и за личный стиль близости: манеру сближаться, дарить и принимать тепло, находить удовольствие в простом. Это архетипическая тема, звучащая в характере независимо от знака и дома, но именно их сочетание задаёт ей окраску — для одного любовь измеряется надёжностью, для другого лёгкостью и игрой, для третьего глубиной переживания. Венерианская природа — не приговор, а склонность: то, как она раскроется, во многом зависит от осознанного выбора и зрелости. Можно идти на поводу у первого влечения, а можно постепенно понять, что именно тебе по-настоящему дорого в отношениях и в жизни, и строить их из этого понимания. Венера говорит и о том, как человек умеет наслаждаться жизнью без чувства вины — замечать красоту в мелочах, позволять себе радость, ценить приятное не как излишество, а как часть здоровой полноты. Вкус, как и умение любить, не выдаётся готовым — он вырастает вместе с человеком.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_house:jupiter:1', 'western', 'Есть люди, которые входят в комнату — и она словно становится просторнее. Юпитер в первом доме нередко даёт именно такое присутствие: широкий жест, лёгкую улыбку, готовность встретить новое с интересом, а не с опаской. Начинать дела при этом располагает с размахом и с верой, что дорога впереди щедра. Внешне это может читаться как оптимизм, обаяние, привычка обещать чуть больше, чем удаётся выполнить, — и здесь же прячется главный урок положения: масштаб хорош, когда за ним поспевают дела. Стоит помнить, что архетип говорит о склонности, а не о судьбе: одна и та же щедрая энергия у кого-то превращается во вдохновляющую открытость, у кого-то — в желание казаться крупнее, чем есть. Куда качнётся маятник, во многом решают осознанность и вся карта целиком.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_house:jupiter:10', 'western', 'Карьера при таком раскладе редко строится ради одной лишь строчки в визитке. Юпитер в десятом доме связывает тему роста и веры с призванием, статусом и тем, каким тебя видят люди. Такое положение часто располагает к масштабным целям и к репутации человека, которому доверяют, — наставника, лица, к чьему слову прислушиваются. Дело хочется вести с размахом и по совести: не просто подняться, а сделать что-то стоящее и заметное. Продвижение нередко идёт легче, когда за спиной есть доброе имя. Тень положения — тяга обещать публично больше, чем готов вынести, или измерять себя только высотой должности; это склонность, а не судьба. Когда амбиция опирается на подлинную ценность, а не на позу, десятый дом с Юпитером даёт авторитет, который держится на уважении, а не на громкости.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_house:jupiter:11', 'western', 'Круг общения здесь имеет свойство расширяться сам собой. Юпитер в одиннадцатом доме окрашивает сферу дружбы, общих замыслов и надежд на будущее верой в людей и в то, что вместе можно больше. Такое положение часто располагает быть тем, кто собирает вокруг себя команду, знакомит нужных друг с другом, щедро делится связями и идеями. Дружба тут — не мелкая величина: от друзей приходят возможности, а сам человек охотно становится опорой для своего сообщества. Мечты о будущем склонны быть крупными, обращёнными к общему благу, а не только к личной выгоде. Оборотная сторона — раствориться в чужих проектах или пообещать сообществу больше, чем потянешь; это тенденция, а не приговор. Когда идеализм соединяется с делом, одиннадцатый дом с Юпитером дарит ощущение, что ты не один и что впереди есть ради чего собираться.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_house:jupiter:12', 'western', 'Самое ценное здесь часто зреет там, где никто не видит. Юпитер в двенадцатом доме связывает тему роста и веры с уединением, внутренней работой и тем, что остаётся за кадром обычной жизни. Такое положение нередко располагает к тихой, непоказной щедрости — помогать, не афишируя, и находить смысл в том, что не приносит очевидной отдачи. Тянет к созерцанию, к внутренней тишине, к большим вопросам, на которые не ответишь на бегу; вера здесь скорее личное дело, чем повод для трибуны. Богатство такого положения — способность черпать опору изнутри, из источника, не зависящего от внешних обстоятельств. Тень — уходить от мира, когда стоило бы действовать, или растворять себя в спасении других; но это склонность, а не судьба. Когда уединение питает, а не прячет, двенадцатый дом с Юпитером дарит редкий покой — быть в ладу с собой наедине.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_house:jupiter:2', 'western', 'Отношение к деньгам и вещам здесь редко бывает скупым. Юпитер во втором доме окрашивает тему ресурсов и собственных ценностей верой в то, что средства придут, если действовать честно и с размахом. Часто это располагает зарабатывать широко и так же широко тратить — на близких, на удовольствия, на то, что кажется по-настоящему стоящим. Ценности при этом тяготеют к крупному: не мелочная выгода, а ощущение достатка и внутренней опоры. Обратная сторона склонности — привычка недооценивать пределы и переоценивать «как-нибудь потом»; астрология описывает это как тенденцию, а не приговор. Здоровье кошелька тут зависит не от удачи, а от умения соединить щедрость с чувством меры. Когда широта уживается с трезвым счётом, второй дом с Юпитером даёт редкое чувство свободы — не бояться завтрашнего дня.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_house:jupiter:3', 'western', 'Любопытство здесь — не поза, а способ дышать. Юпитер в третьем доме расширяет сферу повседневного общения, учёбы и ближнего круга: разговор легко перерастает в рассказ, простой вопрос — в целую тему, а короткая дорога до соседней улицы кажется маленьким путешествием. Такое положение часто располагает к роли рассказчика и негласного учителя среди своих — того, кто связывает людей, идеи и новости. Ум тянется охватить многое сразу, и в этом же кроется соблазн растечься по верхам, набрать больше, чем получается усвоить. Это склонность, а не гарантия: тот же аппетит к знанию при внимании к деталям превращается в настоящую эрудицию. Многое зависит от того, хватает ли терпения доводить любопытство до понимания, — и от карты в целом.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_house:jupiter:4', 'western', 'Дом при таком положении хочется сделать больше — не обязательно по метражу, а по духу: чтобы было куда позвать гостей, где поместятся и родня, и книги, и общие праздники. Юпитер в четвёртом доме связывает тему роста и веры с корнями, семьёй и внутренней опорой. Нередко это располагает относиться к родному очагу как к источнику смысла, а не только крыши над головой; из семьи может идти ощущение, что мир в основе своей щедр и доброжелателен. Иногда широта оборачивается идеализацией прошлого или желанием опекать близких сверх меры — архетип описывает тенденцию, а не судьбу. Когда тепло дома не душит, а даёт крылья, четвёртый дом с Юпитером становится тем фундаментом, от которого легко отталкиваться во всём остальном.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_house:jupiter:5', 'western', 'Творчество, влюблённость, азарт игры — всё, что делает жизнь на вкус ярче, здесь получает простор. Юпитер в пятом доме щедро окрашивает сферу самовыражения, романтики и радости проживания момента. Такое положение часто располагает творить широко и от души, любить открыто, вкладываться в детей и учеников, делиться воодушевлением так, что оно заражает. Игра, сцена, холст, роман — площадки, где хочется размаха, а не полутонов. Тень у этой щедрости тоже есть: тяга к избытку, к драме побольше, к ставке повыше; но это склонность, а не приговор. Когда радость не превращается в погоню за всё более острыми ощущениями, пятый дом с Юпитером дарит редкую способность — находить праздник в самом проживании жизни и щедро делиться им.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_house:jupiter:6', 'western', 'Рутина — не самое очевидное место для щедрости, и всё же именно сюда Юпитер в шестом доме приносит свет и смысл. Тема роста и веры работает здесь через повседневный труд, привычки и заботу о теле. Такое положение нередко располагает искать в ежедневных делах не повинность, а призвание: помогать, налаживать, доводить до порядка — и получать от этого настоящее удовлетворение. Работа может расширяться сама собой, обрастать задачами и людьми, а забота о себе — становиться осмысленной практикой, а не гонкой. Оборотная сторона склонности — брать на себя больше, чем по силам, из веры, что «справлюсь». Это тенденция, а не судьба. Когда энтузиазм соединяется с чувством ритма, шестой дом с Юпитером превращает будни в опору, от которой прибавляется бодрости.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_house:jupiter:7', 'western', 'В другом человеке здесь ищут не столько тихую гавань, сколько простор для роста. Юпитер в седьмом доме расширяет сферу партнёрства, близких союзов и открытых договорённостей. Такое положение часто располагает видеть в спутнике учителя и соратника — того, рядом с кем становишься больше, чем в одиночку. К союзам тянет подходить щедро: доверять, давать свободу, радоваться чужим успехам как своим. Партнёр нередко приносит в жизнь новые горизонты — взгляды, среду, возможности. Есть и склонность идеализировать другого или ждать от союза слишком многого; архетип говорит о тенденции, а не об обещанном счастливом исходе. Когда великодушие взаимно и опирается на реальность, седьмой дом с Юпитером даёт партнёрство, в котором обоим просторно дышать.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_house:jupiter:8', 'western', 'Там, где многие видят только риск и потерю, здесь различают возможность обновления. Юпитер в восьмом доме связывает тему роста с глубокими переменами, общими ресурсами и тем сокровенным, чем делятся лишь с самыми близкими. Такое положение нередко располагает доверять процессам трансформации — проходить через кризис не как через тупик, а как через порог, за которым становишься сильнее. С чужими деньгами, наследствами, совместными вложениями отношения складываются ровнее, если за ними стоит честность. Глубина влечёт: психология, тайны, всё, что скрыто под поверхностью. Тень положения — соблазн переоценить собственную неуязвимость там, где есть настоящий риск; но это склонность, а не судьба. Когда доверие к переменам сочетается с трезвостью, восьмой дом с Юпитером учит расти именно там, где было страшнее всего.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_house:jupiter:9', 'western', 'Здесь Юпитер словно возвращается домой. Девятый дом — его родная территория: мировоззрение, высшее знание, дальние страны и большие вопросы о смысле. Такое положение часто располагает к роли вечного студента и одновременно проводника — того, кто и сам жадно учится, и охотно делится найденным. Дорога, чужая культура, философия, право, вера — всё это тянет как магнит, а горизонт хочется отодвигать всё дальше. Мир при таком раскладе видится большим и в основе доброжелательным, и это придаёт смелости пробовать. Есть и соблазн — принять свою картину мира за единственно верную, увлечься проповедью вместо диалога; но архетип описывает тенденцию, а не приговор. Когда широта взглядов уживается с уважением к чужой правде, девятый дом с Юпитером дарит редкое чувство — что учиться и расти можно всю жизнь.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_house:mars:1', 'western', 'Стоит такому человеку появиться на пороге — и в воздухе уже чувствуется напор. Марсианская энергия действия здесь достаётся самому облику и манере держаться: располагает к тому, чтобы заявлять о себе прямо, брать инициативу первым и начинать новое, не дожидаясь чужого разрешения. Смелость, скорость реакции, готовность идти напролом к тому, чего хочется, — всё это проступает в характере сразу, без долгих предисловий.

Оборотная сторона такого разгона — вспыльчивость и нетерпеливость: соблазн видеть препятствие там, где его нет, и вступать в спор раньше, чем стоило бы. Напор легко перерастает в резкость, а желание быть первым — в привычку идти по головам. Зрелая форма этой энергии — направленная воля: умение зажигаться делом, а не конфликтом, и тратить свой пыл на созидание, а не на борьбу с каждым встречным. Проявится ли это как здоровая напористость или как задиристость, зависит от осознанности и от всей карты целиком.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_house:mars:10', 'western', 'На самой вершине карты, там, где человека видно издалека, марсианская энергия обретает размах честолюбия. Тема дела жизни, статуса и репутации становится главным полем приложения силы: располагает к целеустремлённости, к желанию пробиваться наверх собственными руками, брать на себя ответственность и вести за собой. Такому человеку важно не просто трудиться, а добиваться своего, оставлять след и утверждать себя через достижения.

Тень этой вертикали — жёсткость в борьбе за место под солнцем: соблазн идти к цели напролом, сталкиваться с начальством, путать напор с бесцеремонностью и мерить себя одними лишь победами. Когда всё сводится к состязанию, дорога наверх усеивается нажитыми противниками. Зрелая форма — амбиция, служащая делу, а не тщеславию: способность вести не ради титула, а ради результата, направляя пыл на созидание, а не на устранение соперников. Станет ли высота достойным делом или ареной бесконечной борьбы — решает сам человек и остальные акценты карты.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_house:mars:11', 'western', 'В кругу единомышленников такой человек нередко становится двигателем — тем, кто задаёт темп общему движению. Марсианская энергия ищет выход не в одиночной партии, а в коллективном деле: располагает к тому, чтобы зажигать команду, бороться за общие цели и идеалы, брать на себя роль ведущего к горизонту вместе с другими. Дружеские союзы тут заряжены действием, а не просто приятельством.

Оборотная сторона — трение внутри круга: напор, полезный в общем деле, легко оборачивается спорами с друзьями, стремлением задавать тон единолично или желанием превратить соратников в соперников. Иногда борьба за идею заслоняет живых людей, что стоят рядом. Зрелая нота этого положения — направлять пыл на объединение, а не на господство, оставаясь двигателем команды, а не её точкой напряжения. Каким выйдет баланс между личным напором и общим «мы» — зависит от осознанности и всей карты целиком.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_house:mars:12', 'western', 'Здесь марсианский огонь горит вполсилы на виду — и в полную мощь там, где его не разглядеть: в уединении, во внутренней работе, за кулисами явной жизни. Энергия действия уходит вглубь: располагает к тому, чтобы трудиться незаметно, действовать исподволь, вести тихие битвы с самим собой и вкладывать силу в то, что остаётся за кадром. Мотивы и желания тут не всегда очевидны даже самому человеку — воля будто прячется в тени.

Сложность в том, что напор, лишённый прямого выхода, легко уходит внутрь: оборачивается подавленным раздражением, действием исподтишка или той странной привычкой мешать самому себе, когда энергия работает против собственных целей. Зрелая форма этого положения — вывести скрытую силу на свет: осознать свои желания, направить пыл на внутренний рост, на творчество в тишине или помощь тем, кто остаётся в тени. Обернётся ли эта глубинная энергия саботажем или тихой силой — вопрос осознанного выбора и всего рисунка гороскопа.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_house:mars:2', 'western', 'Здесь боевой запал уходит в дело наживное — в заработок, имущество и всё, что даёт ощущение твёрдой почвы под ногами. Тема добывания и защиты ресурсов становится ареной, где человек охотнее всего прилагает силу: располагает к тому, чтобы энергично зарабатывать, отстаивать своё и вкладывать пыл в создание материальной опоры. Деньги и вещи тут не просто быт — это территория, за которую хочется бороться и которой хочется владеть уверенно.

Тень этого положения — импульсивность в тратах и цепкость: соблазн покупать сгоряча, рисковать нажитым или мерить собственную состоятельность через готовность драться за каждую копейку. Иногда борьба за обладание заслоняет саму радость от достатка. Зрелый вариант — направить марсианскую хватку в спокойное, целенаправленное созидание благополучия, отделяя азарт добычи от жадности. Станет ли эта сила источником изобилия или поводом для вечной гонки за большим — зависит от выбора человека и остальных акцентов гороскопа.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_house:mars:3', 'western', 'Слово здесь становится оружием — острым, быстрым, точным. Марсианская энергия вливается в повседневное общение, учёбу и связи с ближним кругом: располагает к живому, напористому уму, к любви спорить и доказывать, к речи, которая бьёт в цель. Такому человеку тесно в медленном разговоре — его тянет задавать темп, схватывать на лету, срываться в короткие поездки и держать вокруг себя движение.

Есть и тень: язык, заточенный как клинок, легко ранит. Желание непременно переспорить оборачивается резкостью, перебиванием, привычкой превращать любую беседу в поединок, где важнее победить, чем понять. Мысль летит так быстро, что за ней не всегда поспевает терпение. Зрелая нота этого положения — учиться направлять словесный пыл на убеждение и защиту своей правоты без нужды кого-то сокрушить. Как именно раскроется эта острота ума — как дар полемиста или как задиристость, зависит от осознанности и от общей конфигурации карты.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_house:mars:4', 'western', 'Огонь этого положения горит у самого очага — там, где дом, корни и родовая почва. Энергия действия направлена внутрь, к семейным стенам: располагает к тому, чтобы рьяно обустраивать своё пространство, защищать близких как крепость и вкладывать немало силы в то место, которое можно назвать своим. Дом здесь — не только тихая гавань, но и территория, за которую человек готов постоять.

Оборотная грань в том, что марсианский напор в такой интимной сфере иногда оборачивается домашним напряжением: вспышками под родной крышей, трудным сосуществованием характеров, беспокойством, которое не даёт корням окрепнуть. Порой сама семейная история заряжена борьбой, и человеку нужно время, чтобы не переносить старые баталии в собственный дом. Зрелая форма — сделать дом источником силы, а не полем сражений: направить пыл на созидание уюта и защиту тех, кто дорог. Обернётся ли эта энергия крепостью или очагом раздора — вопрос выбора и всей карты целиком.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_house:mars:5', 'western', 'Едва ли есть сфера, где марсианскому огню так же вольготно, как здесь: творчество, влюблённость и азартная игра будто созданы для того, чтобы гореть в полную силу. Энергия желания и действия ищет выход в самовыражении — смелом, ярком, страстном: располагает к тому, чтобы творить с размахом, добиваться того, кто нравится, с прямотой и жаром, бросаться в спорт, на сцену и в любое дело, где можно проявить кураж. Радость проживания жизни тут добывается действием, а не созерцанием.

Тень этого пыла — импульсивность и драматизм: влюблённость, вспыхивающая и гаснущая как спичка, азарт, толкающий на риск ради самого риска, соперничество там, где хватило бы удовольствия. Творческий огонь без русла легко превращается в фейерверк без продолжения. Зрелая нота — вкладывать страсть в то, что растёт и остаётся: в мастерство, в живые отношения, в честную игру. Каким выйдет этот танец между смелостью и безрассудством — решает сам человек и остальные акценты гороскопа.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_house:mars:6', 'western', 'Свою силу этот человек чаще всего пускает в дело — в ежедневный труд, ремесло и заботу о собственном теле. Марсианская энергия оседает в рутине: располагает к неутомимой работоспособности, к умению засучить рукава и довести задачу до конца, к тяге держать тело в тонусе через нагрузку и движение. Здесь пыл проявляется не в громких жестах, а в том, как ловко и упорно человек справляется с делами.

Есть риск перегреться: когда напор не знает меры, работа превращается в гонку на износ, отдых начинает казаться слабостью, а раздражение на нерасторопных коллег отравляет будни. Тело, если гнать его без пауз, отвечает усталостью — и важно беречь бодрость как рабочий инструмент, а не как расходный материал. Зрелая форма этого положения — дисциплинированная энергия: умение прикладывать силу размеренно, находя достоинство в качественно сделанном деле и в заботе о собственном самочувствии. Баланс между усердием и самоистощением — дело осознанного выбора и всей карты.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_house:mars:7', 'western', 'Ярче всего эта энергия вспыхивает в присутствии другого — в паре, союзе, в открытом противостоянии лицом к лицу. Тема партнёрства становится тем полем, где марсианский пыл находит адресата: располагает к страстным, живым отношениям, к притяжению к сильным, деятельным спутникам и к тому, чтобы вкладывать в союз немало огня. Нередко именно через «ты» — через партнёра или даже оппонента — человек учится обращаться с собственной силой.

Оборотная сторона в том, что напор, направленный на близкого, легко оборачивается столкновением: отношения превращаются в состязание, где нужно непременно взять верх, а страсть соседствует с ссорой. Иногда собственная воинственность будто переселяется в партнёра — и тогда рядом упорно оказываются те, с кем приходится бороться. Зрелая форма — партнёрство, где двое направляют пыл не друг против друга, а вместе, где спор укрепляет, а не разрушает. Станет ли другой соратником или вечным соперником — зависит от осознанности и от всей карты целиком.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_house:mars:8', 'western', 'Этой энергии тесно на мелководье — её тянет туда, где кипят страсти и происходят перемены, меняющие человека до основания. Сфера глубокой близости, общих ресурсов и кризисов становится ареной, где марсианская сила действует в полную мощь: располагает к интенсивности во всём — в чувствах, в желании, в способности идти сквозь потрясения и выходить из них перекованным. Здесь пыл не боится тёмных глубин и умеет черпать в них энергию для обновления.

Тень такого положения — жажда контроля над тем, что по природе неподвластно: над чужими чувствами, деньгами, границами. Отсюда ревность, борьба за влияние, нежелание отпускать, напряжение вокруг общих денег и обязательств. Метафора смерти и возрождения работает тут как символ трансформации, а не как предсказание чего-либо. Зрелая форма этой силы — не власть, а честность перед глубиной: смелость довериться, отдать, пройти сквозь утрату прежнего к новому. Каким окажется это погружение, определяет сам человек и общий рисунок карты.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_house:mars:9', 'western', 'Такого человека манит даль — и он идёт к ней с азартом первопроходца. Марсианская энергия разворачивается там, где есть простор для убеждений и странствий: в философии, вере, больших идеях, дальних дорогах и чужих культурах. Располагает к тому, чтобы отстаивать своё мировоззрение с жаром, отправляться за горизонт без долгих сборов, добывать знание в движении и превращать поиск истины в личный поход.

Оборотная грань — воинственная убеждённость: соблазн принять свою картину мира за единственно верную и не столько делиться ею, сколько навязывать, споря о вере и принципах до последнего. Широта тогда оборачивается нетерпимостью, а вдохновение — проповедью с нажимом. Зрелая форма — направить пыл на честный поиск, оставаясь открытым чужой правде и помня, что горизонт отодвигается по мере приближения. В лучшем проявлении такой человек заражает других смелостью мыслить крупно и жить со смыслом. Куда приведёт эта дорога — зависит от выбора и от всей конфигурации гороскопа.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_house:mercury:1', 'western', 'У этого положения ум оказывается на самом виду — он часть первого впечатления, как черты лица или тембр голоса. Живая речь, быстрая реакция, любопытный взгляд, которым человек словно ощупывает всё вокруг, — вот чем он заявляет о себе прежде всего. Такое расположение располагает к тому, чтобы думать вслух, начинать знакомство с вопроса и входить в новое через слово, а не через силу или напор. Нередко окружающие первым делом отмечают именно сообразительность и словоохотливость.

Оборотная грань — беспокойный ум, которому трудно замолчать: мысль скачет, тянет прокомментировать каждую мелочь, а самоощущение начинает держаться на том, «достаточно ли я умён и остроумен». Тогда за словами не всегда поспевает пауза, а внутреннее напряжение выдаёт себя суетливостью. Зрелая нота здесь — когда быстрота ума соединяется с умением слушать и молчать, и человек не доказывает свою сообразительность, а просто пользуется ею. Как раскроется этот подвижный ум, зависит от осознанности и от всей карты целиком.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_house:mercury:10', 'western', 'На вершине карты слово выходит на публику, а ум работает на репутацию. Тема карьеры и общественного положения связана здесь с речью, информацией, умением объяснять и убеждать: человека нередко знают именно за то, что и как он говорит и пишет. Такое расположение располагает к делу, где важны гибкость мысли, находчивость и точная формулировка, — от преподавания и текста до переговоров, торговли и любых занятий, в которых ценится ясная голова. Профессиональное имя здесь во многом строится на словах.

Тень этой вертикали — соблазн привязать самоуважение к тому, всегда ли сказана «правильная» и умная вещь; тогда каждое публичное слово взвешивается с тревогой, а признание превращается почти в зависимость от чужой оценки. Иногда гибкость ума соскальзывает в приспособленчество — говорить то, что выгодно, а не то, что думаешь. Зрелая форма этой энергии — служить делу ясной мыслью и честным словом, а не эффектной репликой, помня, что человек больше своей должности и своей репутации. Станет ли этот дар речи опорой карьеры или источником вечного беспокойства о впечатлении — решает сам человек и остальные акценты карты.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
