  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_house:mercury:11', 'western', 'Мысль этого человека расцветает в разговоре многих. Дружеские круги, сообщества, команды и проекты, устремлённые в будущее, становятся той средой, где ум обменивается идеями и загорается от чужих. Такое положение располагает к тому, чтобы находить единомышленников по складу мышления, свободно генерировать идеи в общем котле, быть связующим звеном в компании и думать не только о своём, но и о том, куда движется целое. Дружба здесь нередко держится на общем языке и любопытстве к одним и тем же вещам.

Обратная сторона — риск раствориться в чужих мнениях и коллективных увлечениях, принять модную идею за собственную мысль или, наоборот, уйти в такие абстракции и планы на будущее, что за схемами перестаёшь замечать живых людей рядом. Зрелая нота здесь — вносить в общий разговор собственный ясный голос, не подстраиваясь и не теряя себя, и проверять красивые идеи на прочность реальностью. В таком ключе человек умеет объединять людей вокруг общей мысли. Каким выйдет баланс между «я думаю» и «мы решили» — зависит от осознанности и всей карты целиком.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_house:mercury:12', 'western', 'Есть мысли, что живут в тишине и не сразу находят слова, — и здесь ум уходит именно туда, за кулисы видимой жизни. Тема уединения и внутренней работы окрашивает мышление особым образом: оно становится тише, интуитивнее, образнее, питается снами, впечатлениями, тем, что улавливается на грани сознания. Такое положение располагает к богатому воображению, к умению думать в одиночестве и чувствовать невысказанное, а порой — к дару выражать словом самые тонкие, ускользающие состояния души.

Сложность в том, что чётко сформулировать и произнести вслух то, что творится внутри, здесь удаётся не всегда: мысль может путаться, а перед словом нередко встаёт робость или сомнение в своём праве говорить. Иногда ум в одиночестве уходит в тревожное обдумывание, прокручивая то, чего никто не слышит. Зрелая форма этой энергии — довериться этому тихому, глубокому уму, дать ему выход через письмо, творчество или созерцание и научиться переводить внутреннее на язык, понятный другим. Обернётся ли эта глубина смятением или редкой тонкостью восприятия — вопрос осознанного выбора и всего рисунка гороскопа.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
