  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_house:mercury:2', 'western', 'Свои ресурсы такой человек склонен обдумывать, пересчитывать и проговаривать. Тема денег и ценностей проходит здесь через ум: заработок нередко связан со словом, информацией, посредничеством, умением договориться и понятно объяснить, а идея легко превращается в источник дохода. Это положение располагает к практичной смекалке — прикидывать варианты, искать выгоду не в жадности, а в сообразительности, и ценить те вещи, которые можно осмыслить и применить с толком.

Есть и тень: ум, без конца пересчитывающий деньги в голове, способен превратить достаток в источник тревоги, а самооценку — привязать к тому, «верны ли были мои расчёты». Тогда мелочная скрупулёзность крадёт покой, а разговоры всё чаще сводятся к тому, кто сколько потратил. Зрелая форма этой энергии — ясная голова в денежных делах и умение отделять собственную ценность от суммы на счету и от чужих мнений о ней. Обернётся ли это финансовой находчивостью или вечным беспокойством о цифрах — вопрос выбора и общего рисунка гороскопа.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
