  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_house:mercury:4', 'western', 'Ум этого человека тянется к корням — туда, где дом, семья и память рода. Мысль обживает домашнее пространство: здесь любят читать в тишине, вести долгие кухонные разговоры, разбираться в семейной истории, а сам дом нередко оказывается местом, где думается и пишется лучше всего. Такое расположение располагает к тому, чтобы осмыслять своё прошлое, хранить и пересказывать семейные истории, быть тем, кто проговаривает вслух то, о чём в семье принято молчать.

Есть и тень: ум, обращённый внутрь, легко превращает дом в поле бесконечного обдумывания — тревожных мыслей о близких, старых разговоров, которые прокручиваются снова и снова. Иногда детские впечатления или чья-то давняя фраза так прочно оседают в голове, что человеку требуется время отделить собственные мысли от родовых. Зрелая форма этой энергии — сделать дом местом ясности, а не внутреннего шума, и превратить память в опору, а не в груз. Обернётся ли эта укоренённость живым интересом к своим истокам или привычкой мысленно возвращаться в прошлое — зависит от выбора и всей карты целиком.', 'reviewed', 2)
