  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_house:mercury:5', 'western', 'Здесь ум выходит поиграть — и делает это с явным удовольствием. Вся территория творчества, влюблённости, детей и радости проживания жизни окрашивается остроумием и словесной изобретательностью. Такое положение располагает к тому, чтобы выражать себя через слово с блеском: шутка, каламбур, меткая фраза, история, рассказанная так, что заслушаешься, — вот естественный язык этого человека. Флирт нередко начинается с разговора, а любимое дело почти всегда связано с игрой ума.

Тень этой лёгкости — соблазн подменить чувство остротой: когда важнее казаться остроумным, чем быть искренним, а голова вмешивается там, где нужна спонтанность, живая радость рискует остыть до игры на публику. Иногда мысль просто не даёт отдаться моменту. Зрелая нота здесь — творить и любить не ради эффектной реплики, а от души, позволяя уму служить чувству, а не заслонять его. В таком ключе человек щедро дарит вокруг лёгкость и вдохновение. Каким выйдет этот танец между остроумием и искренностью — решает сам человек и остальные акценты гороскопа.', 'reviewed', 2)
