  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_house:mercury:6', 'western', 'Сила этого положения — в умении разложить хаос на понятные детали. Ум уходит в повседневность: списки, расписания, отлаженные процессы, кропотливая аналитическая работа, где нужно замечать мелочи и доводить дело до точности. Такое расположение располагает к практичной сообразительности и настоящему мастерству в ремесле, требующем внимания: человек склонен наводить порядок там, где другие видят путаницу, и находить удовлетворение в чисто, аккуратно решённой задаче.

Тёмная сторона такой дотошности — привычка гонять по кругу одни и те же мысли: придирки к деталям, прокручивание рабочих забот, тревожные проверки «всё ли учтено». Такое напряжение бьёт по нервам и крадёт лёгкость, а перфекционизм превращает пользу в самоистязание. Стоит помнить, что бодрость и ясность головы держатся на отдыхе не меньше, чем на дисциплине. Зрелая форма этой энергии — точность без придирчивости и умение вовремя отпустить мысль, дав ей передохнуть. Станет ли этот аналитический дар источником мастерства или поводом для вечного беспокойства — зависит от осознанности и всей карты.', 'reviewed', 2)
