  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_house:mercury:7', 'western', 'В отношениях этот человек прежде всего ищет собеседника. Партнёрство, брак и близкие союзы раскрываются здесь через диалог: важно, чтобы с тем, кто рядом, было о чём говорить, чтобы мысль встречала мысль, а разговор не иссякал за месяц. Такое положение располагает к тому, чтобы выбирать спутника по уму и родству взглядов, вкладываться в общий язык пары и решать спорное через слово, а не через молчаливую обиду. Нередко именно в диалоге с другим человек яснее всего понимает и самого себя.

Обратная сторона — привычка без конца анализировать партнёра и отношения, превращать близость в разбор или спор, где хочется непременно оказаться правым. Иногда мечта об идеальном собеседнике заставляет придираться к живому человеку рядом. Зрелая форма этой энергии — умение не только формулировать, но и слушать, вести диалог равных, где слова сближают, а не соревнуются. Станет ли другой интеллектуальным партнёром и союзником или мишенью для придирчивого ума — зависит от выбора и от всей карты целиком.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_house:mercury:8', 'western', 'Этот ум не довольствуется тем, что лежит на поверхности, — его тянет туда, где начинаются тайны. Сфера глубоких связей, общих ресурсов, кризисов и внутренних перерождений становится полем для исследователя: хочется докопаться до скрытого мотива, понять, что движет людьми под маской, распутать то, о чём принято молчать. Такое положение располагает к проницательности, к вкусу к психологии и расследованию, к темам, от которых другие отводят взгляд. Мысль здесь острая, глубокая, способная выдержать серьёзный, неудобный разговор.

Тень — ум, застревающий в подозрениях и навязчивом обдумывании: одна тревожная мысль может часами ходить по кругу, а желание всё контролировать через понимание оборачивается недоверием. Иногда чужие секреты или общие деньги становятся почвой для мысленной борьбы за влияние. Зрелая форма этой энергии — использовать проницательность, чтобы понимать и исцелять, а не чтобы держать в узде, и уметь довериться там, где не всё раскладывается по полочкам. Символ смерти-и-возрождения здесь про обновление ума, а не про предсказание. Каким окажется это погружение, определяет сам человек и общий рисунок карты.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_house:mercury:9', 'western', 'Такому уму тесно в границах привычного — его манит простор больших идей. Философия, вера, право, дальние страны и чужие языки становятся той областью, где мысль разворачивается во всю ширь. Это положение располагает к тому, чтобы учиться всю жизнь, складывать разрозненные наблюдения в цельное мировоззрение и делиться им — в роли преподавателя, публициста, вечного студента, которого хлебом не корми, дай понять, как устроен мир. Дорога, книга и разговор о смысле здесь заряжают одинаково сильно.

Оборотная грань — соблазн принять собственные выводы за окончательную истину и начать поучать вместо того, чтобы исследовать; тогда широта оборачивается всезнайством, а живой интерес — догмой. Иногда ум так спешит к общей картине, что теряет терпение к деталям и фактам. Зрелая нота здесь — оставаться учеником даже в роли учителя и помнить, что настоящий кругозор всегда оставляет место для сомнения. В лучшем проявлении такой человек заражает других жаждой понимать и мыслить крупно. Куда приведёт эта дорога мысли — зависит от выбора и всей конфигурации гороскопа.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_house:moon:1', 'western', 'Когда спутник эмоций оказывается на самом фасаде карты, чувства человека перестают быть тайной — они читаются в лице, в интонации, в том, как он входит в комнату. Настроение здесь становится почти видимой чертой облика: сегодня открытость и теплота, завтра задумчивость, и всё это отражается на окружающих почти мгновенно. Такое расположение располагает к тонкой отзывчивости: новые дела человек начинает не с холодного расчёта, а с внутреннего отклика, с ощущения «моё — не моё». Первое впечатление он производит мягкое, участливое, будто сразу готов позаботиться. Оборотная сторона — зависимость самоощущения от того, что происходит вокруг: чужие эмоции легко становятся своими. Насколько это окажется даром эмпатии, а насколько — уязвимостью, зависит от осознанности и от всей карты в целом; сама по себе позиция лишь подсвечивает, что личность здесь пропитана чувством.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_house:moon:10', 'western', 'На вершине карты, там, где речь о деле жизни и общественном лице, чувства оказываются на виду. Такому человеку недостаточно просто добиться статуса — ему нужно, чтобы дело откликалось внутри, чтобы в нём были смысл и тепло. Публика словно считывает его настроение: эмоциональность становится частью репутации, и это может располагать людей, а может делать уязвимым перед их мнением. Часто тянет к занятиям, где есть забота, поддержка, работа с людьми, — туда, где можно опекать и питать, а не только руководить. Признание для него — не тщеславие, а подтверждение, что о нём помнят и ценят. Карьерный путь бывает переменчивым, следуя за внутренними приливами и отливами. Найти опору в себе, а не только в чужой оценке, — та задача, которую решает сам человек; позиция лишь подсвечивает, что путь наверх здесь идёт через сердце.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_house:moon:11', 'western', 'Тепло здесь ищет себе круг — друзей, единомышленников, сообщество, где можно быть своим. Для такого человека дружба нередко значит не меньше семьи: с близкими по духу он делится чувствами так же доверчиво, как с роднёй, и остро нуждается в ощущении принадлежности. Мечты о будущем у него не сухой план, а согреты эмоцией — важно, чтобы общее дело трогало, чтобы за ним стояли живые люди, а не одна абстрактная цель. В группах он часто берёт на себя роль того, кто заботится, объединяет, создаёт атмосферу принятия. Настроение зависит от того, чувствует ли он себя нужным среди своих: одиночество в толпе переживается тяжело. Склонность растворяться в коллективе иногда уводит от собственных желаний — и здесь важно не потерять себя. Как распорядиться этой потребностью в общности, человек выбирает сам.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_house:moon:12', 'western', 'Самая насыщенная жизнь здесь разворачивается там, где её не видно, — во внутренней тишине, в снах, в полутонах, ускользающих от посторонних глаз. Чувства такого человека глубоки, но часто спрятаны: он оберегает их, делится не сразу, многое проживает наедине с собой. Уединение для него не наказание, а необходимость — в тишине он восстанавливается, разбирает пережитое, слышит собственную интуицию, которая здесь особенно тонка. Есть большая способность к состраданию, к безмолвной помощи тем, кому трудно, — иногда в ущерб собственным границам. Порой эмоции копятся незамеченными, пока не потребуют выхода; учиться замечать их вовремя и давать им имя — важная внутренняя работа. Это расположение располагает к богатой душевной и творческой жизни за кадром — раскроется ли она даром или обернётся уходом от реальности, зависит от осознанности и всей карты в целом.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_house:moon:2', 'western', 'Здесь потребность в безопасности перетекает в область денег, вещей и того, что можно назвать «своим». Материальная опора для такого человека — не про статус, а про душевный покой: наличие подушки, запасов, знакомых предметов вокруг успокаивает не хуже объятий. Отношение к тратам часто связано с настроением — в тёплом состоянии рука щедрая, в тревожном хочется всё придержать и накопить. Ценности складываются из чувственного опыта: дорого не то, что престижно, а то, что греет и напоминает о близких. Такое положение располагает к бережливости и умению создавать уют из малого, но может делать самооценку заложницей содержимого кошелька. Ключ — учиться находить ощущение устойчивости внутри, а не только в имуществе; будет ли так, решает сам человек и вся карта, а не одна эта деталь.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_house:moon:3', 'western', 'Мысли и слова здесь окрашены настроением, а не сухой логикой. Человек с таким расположением схватывает информацию скорее чутьём, чем анализом: ему важно почувствовать тему, а не только понять её. Общение с соседями, братьями, сёстрами, случайными собеседниками насыщено эмоцией — он легко считывает, в каком состоянии тот, кто напротив, и подстраивает тон. Учёба идёт живее, когда предмет чем-то трогает; сухие абстракции даются труднее. Речь бывает переменчивой, как и настроение: то поток тёплых подробностей, то молчаливая задумчивость. Ближайшее окружение для такого человека — почти продолжение семьи, привычные маршруты и разговоры дают ощущение защищённости. Эта чувствительность к словам способна становиться и чуткостью, и повышенной ранимостью к чужим репликам — многое зависит от осознанности и остальных акцентов карты.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_house:moon:4', 'western', 'Дом, корни и память рода — родная стихия для этого расположения, и проявляется оно здесь особенно полно. Внутренняя опора человека держится на ощущении «есть куда вернуться»: своё пространство, знакомые стены, семейные привычки для него не мелочь, а фундамент, без которого трудно дышать. Связь с прошлым, с историей семьи, с образом того, кто когда-то заботился, ощущается глубоко и тепло. Такой человек часто сам становится хранителем очага — тем, вокруг кого собираются, кого тянет накормить и приютить других. Настроение сильно зависит от атмосферы дома: уют восстанавливает, разлад с близкими выбивает почву из-под ног. Склонность держаться за привычное и прошлое иногда мешает переменам, но та же укоренённость даёт редкую способность создавать тепло вокруг. Как распорядиться этим, человек решает сам.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_house:moon:5', 'western', 'Творчество, игра и нежность становятся тем руслом, куда естественно течёт душевная жизнь. Радость такой человек проживает открыто и по-детски искренне: ему важно не просто заниматься любимым делом, а чувствовать его, вкладывать в него сердце. Романтика здесь мягкая и трепетная — с потребностью заботиться о том, кто дорог, и получать нежность в ответ. Самовыражение идёт от эмоции: рисунок, музыка, кухня, воспитание детей — всё это способы проявить внутренний мир и ощутить себя живым. С детьми — своими или чужими — часто устанавливается особая, тёплая связь. Настроение влияет на вдохновение напрямую: в согласии с собой человек фонтанирует идеями, в тревоге творческий источник будто пересыхает. Такая чувствительность располагает к искренности, а не к позе, — и раскрывается тем полнее, чем свободнее человек позволяет себе чувствовать.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_house:moon:6', 'western', 'Забота о повседневном — распорядок, работа, внимание к телу — здесь пропитана эмоцией. Такому человеку важно, чтобы рутина не просто работала, а ощущалась уютной: любимая кружка, привычный ритм утра, порядок в мелочах дают чувство защищённости не меньше, чем крупные события. Через дело он часто выражает нежность — заботится о коллегах, кормит, поддерживает, берёт на себя незаметный труд ради других. Настроение и телесное самочувствие тесно переплетены: в согласии с собой прибавляется бодрости, в тревоге тело первым подаёт сигнал, что пора сбавить темп. Такое расположение располагает к чуткому вниманию к режиму, питанию, отдыху — и к риску растратить себя в опеке о ближних. Найти меру между «позаботиться о другом» и «позаботиться о себе» — задача, которую решает сам человек, а не звёзды за него.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_house:moon:7', 'western', 'Ближе всего к собственным чувствам такой человек оказывается рядом с другим. Партнёрство для него — не формальность, а способ обрести душевное тепло и ощущение, что о тебе есть кому позаботиться. В отношениях он ищет близость, участие, эмоциональный отклик; ему важно чувствовать, что связь живая, а не просто удобная. Настроение спутника он считывает мгновенно и легко откликается на него — иногда настолько, что теряет границу между своими эмоциями и чужими. Есть склонность искать в другом ту оберегающую, почти материнскую опору, которой не хватает внутри, и порой ждать заботы больше, чем предлагать самому. Договорённости с людьми даются лучше, когда в них есть человечность, а не голый расчёт. Станет ли такая чувствительность источником глубокой близости, а не зависимости, зависит от зрелости и всей карты целиком.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_house:moon:8', 'western', 'Эмоции здесь уходят на глубину, куда обычно не заглядывают. Такого человека не устраивает поверхностное — ему нужна близость, в которой можно раствориться, довериться до конца, разделить с другим самое сокрытое. Чувства сильны и не всегда высказаны: под спокойной поверхностью может кипеть целый океан. Тема общих ресурсов, чужих денег, наследства, всего, что делят с близкими, окрашивается сильными переживаниями — доверие и контроль здесь идут рядом. Это расположение располагает к внутренним трансформациям: человек умеет проживать кризисы насквозь и выходить обновлённым, будто заново собранным. Тонкая интуиция подсказывает то, что скрыто от других. Оборотная сторона — ревность, привязчивость, страх потерять дорогое; куда склонится чаша, решает осознанность, а не сама позиция. В зрелой форме это дар глубокого, преображающего чувства.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_house:moon:9', 'western', 'Душа здесь тянется за горизонт — к смыслам, дальним странам, большим идеям. Такому человеку важно не просто знать, а чувствовать правду мировоззрения нутром: вера, философия, культура становятся для него источником эмоциональной опоры. Дорога, чужие города и языки нередко дают ощущение дома лучше, чем привычные стены, — будто где-то там его ждёт что-то родное. Учёба высокого порядка идёт через увлечённость: сухая теория без внутреннего отклика быстро остывает, а идея, которая трогает, ведёт за собой годами. Взгляды могут меняться вместе с внутренним ростом, и это нормально — картина мира здесь живая, а не отлитая раз навсегда. Есть тяга делиться своим пониманием тепло, по-человечески, а не поучая. Станет ли мечта о дальнем путём, а не бегством от близкого, человек определяет сам.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_house:neptune:1', 'western', 'Такого человека трудно описать в двух словах — контур будто нарисован акварелью, а не карандашом. Нептун в первом доме смягчает черты личности и то, как человек входит в мир: в присутствии часто читаются мечтательность, чуткость, способность впитывать настроение вокруг, как губка впитывает воду. Новые дела здесь располагает начинать не по расчёту, а по наитию — угадывая момент, а не выстраивая план. Другие нередко видят в таком человеке то, что хотят увидеть: экран, на который легко проецировать собственные мечты. В этом и дар, и тень положения: тонкая проницаемость помогает сочувствовать и вдохновлять, но та же прозрачность способна размывать собственные границы, когда чужие желания принимаешь за свои. Астрология говорит здесь о склонности, а не о приговоре: насколько мягкость станет силой, а не потерей себя, решают осознанность и вся карта целиком.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_house:neptune:10', 'western', 'Призвание здесь трудно уложить в ровную строчку резюме — путь чувствуется скорее как зов, чем как заранее выбранная дорога. Карьеру, статус и то, каким тебя видят люди, Нептун в десятом доме пронизывает грёзой и вдохновением. Тянет к делу, где есть служение, творчество или помощь: работать «просто ради должности» тут скучно, нужен смысл. Публичный образ словно подёрнут дымкой — люди охотно проецируют на такого человека собственные мечты и идеалы, видят в нём то, чего сами ищут. В этом и сила вдохновлять собой, и уязвимость: жить чужими ожиданиями или самому не понимать, куда ведёт дорога. Это склонность, а не судьба. Пусть мечта о призвании обретёт ясные очертания и честную опору — тогда дело станет согревать не только тебя самого, но и тех, кто рядом.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_house:neptune:11', 'western', 'Мечта здесь редко бывает только личной — она тянется к чему-то общему, к миру, который мог бы стать добрее. Нептун в одиннадцатом доме окрашивает дружбу, коллективные замыслы и надежды на будущее идеализмом и состраданием к людям. Такое положение часто располагает собираться с теми, кто грезит о том же, — в кругах творческих, помогающих, вдохновлённых общей идеей. В друзьях легко видеть родственные души, а в совместном деле — способ послужить чему-то большему, чем собственная выгода. Тень положения — идеализировать людей и замыслы, раствориться в группе так, что теряешь свой голос, или обмануться в том, кто казался единомышленником. Это тенденция, а не приговор. Когда высокий идеал соединяется с трезвым выбором спутников, одиннадцатый дом с Нептуном дарит редкое ощущение — что мечтать о лучшем не наивно, если рядом те, с кем эта мечта понемногу становится делом.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_house:neptune:12', 'western', 'Здесь Нептун словно возвращается в родные воды. Двенадцатый дом — его глубина: уединение, внутренняя работа, сны и всё, что течёт за кадром обычной жизни. Такое положение располагает к богатой внутренней вселенной — созерцанию, тишине, тонкой связи с чем-то, что больше слов и обстоятельств. Сострадание тут почти безгранично: чужую боль улавливаешь как свою, а покой находишь не в шуме, а в отступлении вглубь. Творчество, молитва, медитация, сон — двери, за которыми граница между «я» и миром становится прозрачной. Тень положения — соблазн спрятаться от реальности, уплыть от того, что требует решения, раствориться в спасении других, забыв о себе. Это склонность, а не судьба. Стоит уединению питать, а не уводить от жизни, — и открывается редкий дар: черпать покой и смысл из источника, которого не отнять никакими внешними обстоятельствами.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_house:neptune:2', 'western', 'Деньги здесь ведут себя как вода: то прибывают неведомо откуда, то утекают сквозь пальцы, и уследить за ними на глаз бывает непросто. Так на теме ресурсов и ценностей сказывается Нептун во втором доме — материальное при нём словно теряет чёткие очертания. Сумма на счёте значит меньше, чем смысл и красота, а зарабатывать тянет там, где есть вдохновение, а не только выгода. Щедрость даётся легко, порой легче трезвого учёта: отдать и поделиться естественнее, чем считать до копейки. Оборотная сторона — склонность идеализировать, обольщаться лёгкими обещаниями, путать желаемое с действительным в денежных делах. Всё это тенденция, а не судьба: многое решают осознанность и карта в целом. Соедините мечту о щедром мире с ясными цифрами и здоровыми границами — и придёт редкое умение не делать из денег ни идола, ни источника тревоги.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_house:neptune:3', 'western', 'Слова здесь несут больше настроения, чем точной информации, — важнее не что сказано, а какой оттенок остался. Нептун в третьем доме окутывает повседневное общение, учёбу и ближний круг мягкой дымкой воображения. Такое положение часто располагает мыслить образами, а не строгими цепочками, схватывать смысл интуитивно, между строк, чувствовать недосказанное в чужой интонации. Речь может звучать поэтично, а память работает по-своему: легко забывается сухой факт, но живо хранится атмосфера разговора. Обратная сторона склонности — рассеянность, недопонимание, привычка слышать то, что хочется, а не то, что сказано на самом деле. Архетип описывает тенденцию, а не приговор. Когда чуткость к оттенкам смысла соединяется с привычкой уточнять и проверять, третий дом с Нептуном превращает обычный обмен словами в тонкое искусство понимать друг друга почти без слов.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_house:neptune:4', 'western', 'Дом здесь — не столько стены и адрес, сколько чувство, которое хочется поймать и удержать. К корням, семье и внутренней опоре Нептун в четвёртом доме добавляет грёзу и лёгкое растворение границ. Отсюда тоска по идеальному очагу — тихому, тёплому, почти сказочному — и особая чуткость к атмосфере родного пространства: настроение дома улавливается кожей. Семейная история порой окутана дымкой, где о ком-то из близких остаётся больше легенд, чем ясных фактов. В тени — привычка идеализировать прошлое или размывать границы с родными так, что перестаёшь понимать, где твои чувства, а где чужие. Всё это склонность, а не приговор, и её разворот зависит от осознанности. Стоит мечте о тёплом доме воплотиться в конкретную заботу, а не остаться туманом, — и появляется редкая опора: внутренняя тишина, к которой можно возвращаться из любой бури.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_house:neptune:5', 'western', 'Здесь воображение просится наружу — краской, музыкой, историей, ролью, в которую хочется раствориться без остатка. Нептун в пятом доме щедро окрашивает творчество, романтику и саму радость проживания момента. Такое положение часто располагает к искусству как к стихии: вдохновение приходит волной, а не по расписанию, и в лучшие минуты кажется, будто творишь не ты, а что-то большее через тебя. Влюблённость тут тоже сродни грёзе — с ореолом, с музыкой, с готовностью видеть в другом идеал. В этом и красота, и уязвимость положения: тот же дар очаровываться легко оборачивается разочарованием, когда живой человек не совпадает с придуманным образом. Архетип говорит о склонности, а не об обещанном сюжете. Когда мечта питает творчество и нежность, а не подменяет собой реальность, пятый дом с Нептуном дарит способность видеть волшебное в самом обыкновенном.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_house:neptune:6', 'western', 'Строгий распорядок здесь приживается плохо — будни хочется проживать по внутреннему чувству, а не по расчерченной сетке часов. Повседневный труд, привычки и забота о себе окрашены у Нептуна в шестом доме служением и чуткостью. В работе тянет искать не только результат, но и смысл: помогать, облегчать, вдохновлять, вкладывать душу — иначе дело быстро тускнеет, и особенно откликаются занятия, где есть сострадание и творчество, а не голая механика. Тело чутко отзывается на настроение и обстановку, так что бодрость поддерживает скорее мягкий ритм, отдых и тишина, чем железная дисциплина. В тени — размытость, ускользающие сроки, соблазн спрятаться от скучной рутины. Это тенденция, а не приговор. Добавьте к чуткости посильную опору на порядок — и обычные дела станут тихой практикой заботы о деле и о себе.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_house:neptune:7', 'western', 'В другом человеке здесь ищут не просто спутника, а родственную душу — того, с кем сольёшься почти без остатка. Нептун в седьмом доме окрашивает партнёрство, близкие союзы и открытые договорённости темой идеала и растворения границ. Такое положение часто располагает видеть в любимом больше, чем есть, — окружать его ореолом, угадывать без слов, сострадать и жертвовать. В лучшем своём проявлении это дар глубокого сопереживания, союз, где двое чувствуют друг друга на тонком уровне. В тени та же способность рисует образ, который живой человек не в силах вместить, и вслед за очарованием приходит разочарование, а граница между «я» и «ты» стирается так, что теряешь себя. Архетип описывает склонность, а не предначертанный исход. Когда сострадание уживается с трезвым взглядом и уважением к отдельности другого, седьмой дом с Нептуном дарит редкую близость — без иллюзий, но с настоящим теплом.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_house:neptune:8', 'western', 'Тянет туда, где кончается поверхность, — в глубину, к тому, что скрыто, к тайнам чужой и собственной души. Глубокие перемены, общие ресурсы и самое сокровенное, чем делятся лишь с ближайшими, — вот на что ложится здесь растворяющее влияние Нептуна в восьмом доме. Кризисы переживаются как погружение, из которого выходишь другим: старое размывается, чтобы уступить место новому, и трансформация ощущается почти мистически. Близость влечёт слиянием без остатка, а чуткость к скрытым течениям порой граничит с ясновидением. С общими деньгами и чужими обязательствами отношения лучше держать в ясности — именно тут легче всего обмануться или недоглядеть. Это склонность, а не судьба. Соедините доверие к переменам с трезвостью в делах — и придёт умение отпускать без страха, находя опору даже там, где почва уходит из-под ног.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_house:neptune:9', 'western', 'Горизонт зовёт не столько дальней страной, сколько обещанием смысла, который будто бы ждёт где-то за ней. Нептун в девятом доме окрашивает мировоззрение, высшее знание и дальние дороги тягой к возвышенному и таинственному. Такое положение часто располагает искать не сухую истину, а живое переживание веры — то, что нельзя доказать, но можно почувствовать. Философия тут звучит как поэзия, чужая культура манит своей инаковостью, а большие вопросы о смысле не отпускают. В лучшем своём проявлении это подлинная духовная жажда и способность вдохновляться идеалом. Тень положения — принять красивую иллюзию за прозрение, довериться тому, кто обещает готовые ответы, растворить критическое чутьё в притягательном учении. Архетип говорит о тенденции, а не о приговоре. Когда вдохновение уживается со здоровым сомнением, девятый дом с Нептуном дарит редкое чувство — что за видимым миром брезжит нечто большее, и к нему стоит идти своими ногами.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_house:pluto:1', 'western', 'Есть люди, чьё присутствие ощущается ещё до первого слова, — и это как раз тот случай. Личность, первое впечатление и манера входить в новое несут отпечаток глубины и внутренней силы: во взгляде читается что-то испытующее, а сам человек будто время от времени сбрасывает старую кожу и рождается заново, переписывая себя набело. Такое расположение располагает к магнетизму, к умению влиять одним лишь тем, кто ты есть, и к способности переживать личные кризисы не как крушение, а как перерождение.

Оборотная грань — тяга держать всё под контролем и прятать уязвимое поглубже: за плотной бронёй порой копится напряжение, а страх показать слабость оборачивается скрытностью или желанием подчинять пространство вокруг себя. Иногда интенсивность пугает окружающих раньше, чем те успевают разглядеть за ней живого человека. Зрелая нота здесь — направить эту силу не на власть над другими, а на честное преображение самого себя, позволяя себе меняться без страха потерять лицо. Каким выйдет этот характер — решает сам человек и вся карта целиком.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_house:pluto:10', 'western', 'На вершине этот человек стремится не просто оказаться, а оставить след, который переживёт его самого. Карьера, положение в обществе и репутация несут плутонический заряд власти и преображения: его тянет к делу, где можно влиять по-настоящему, идти в глубину и перестраивать устоявшееся, а не наводить лоск на фасад. Такое расположение располагает к магнетизму в публичной роли, к способности возрождать то, что пришло в упадок, и к авторитету, который держится на подлинной силе, а не на позе.

Оборотная грань этой вертикали — жажда власти как таковой и её теневые игры: закулисная борьба, страх утратить влияние, соблазн подчинять вместо того, чтобы вести. Иногда всё чувство собственной значимости привязывается к положению, и любое падение переживается как крушение. Зрелая форма этой энергии — направить влияние на настоящее преображение дела, а не на контроль над людьми, помня, что человек всегда больше своей роли. В таком ключе честолюбие становится силой, которая меняет к лучшему. Станет ли это восхождение подлинным вкладом или гонкой за властью — решает сам человек и остальные акценты карты.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_house:pluto:11', 'western', 'Компании ради компании этому человеку мало — его влечёт туда, где собираются, чтобы что-то по-настоящему изменить. Дружеские круги, дальние цели и общие проекты заряжены подспудной интенсивностью: связи здесь редко бывают лёгкими и поверхностными, зато глубоки до последней откровенности, а мечты о будущем несут в себе жажду преобразить сам порядок вещей. Такое положение располагает к силе внутри сообщества, к притяжению людей, идущих против течения, и к способности запускать перемены, которые чувствуют многие.

Оборотная сторона — власть и её изнанка в коллективе: борьба за влияние в кругу, склонность то сливаться с группой до потери себя, то резко порывать, ревность к близким друзьям. Иногда общий идеал превращается в одержимость, не терпящую инакомыслия. Зрелая форма этой энергии — вносить глубину и обновление, не подчиняя круг своей воле и не растворяясь в нём без остатка. В таком ключе несколько преображающих связей стоят больше сотни поверхностных приятельств. Каким выйдет баланс между силой и принадлежностью — решает сам человек и весь узор гороскопа.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_house:pluto:12', 'western', 'Самое сильное здесь укрыто глубже всего — под спудом, там, куда редко достаёт дневной свет. Уединение, внутренняя работа и то, что остаётся за кулисами, несут глубинный заряд: в тишине наедине с собой человек встречается с тем, что таится в его собственных недрах, и именно там, вдали от чужих глаз, происходят его самые серьёзные перерождения. Такое положение располагает к мощной интуиции, к способности исцелять сокрытое и к силе, которая куётся не на людях, а в одиноких погружениях в себя.

Тень этой глубины — то, что вытеснено и загнано вглубь: подспудные страхи, тревога без имени, ощущение тайной борьбы, которую человек ведёт сам с собой. Иногда сила прячется так надёжно, что её обладатель и сам о ней не подозревает. Зрелая форма этой энергии — не бежать от своих теней, а спуститься к ним и вынести на свет, обретая опору в самой глубине; уединение тогда становится не бегством, а мастерской перерождения. Образ распада и обновления здесь — про освобождение души, а не про буквальные события. Обернётся ли эта глубина смятением или тихой внутренней силой — вопрос осознанного выбора и всего рисунка гороскопа.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_house:pluto:2', 'western', 'Здесь ничем не владеют вполсилы — ни деньгами, ни вещами, ни собственными представлениями о том, что действительно ценно. Ресурсы, достаток и внутренняя система ценностей заряжены глубинной интенсивностью: человек склонен то накапливать с почти страстным упорством, то радикально пересматривать, за что вообще стоит держаться, и его отношения с материальным нередко проходят через серьёзные перестройки. Такое положение располагает к умению возрождать своё благосостояние даже из руин, к чутью на скрытую ценность там, где другие видят пустоту, и к внутренней опоре, которая не зависит от содержимого кошелька.

Тень этой глубины — превращение денег в поле власти и тревоги: страх потерять почву под ногами может перерасти в цепкую хватку, в желание контролировать ресурсы свои и чужие, а самооценку легко привязать к тому, чем обладаешь. Тогда владение оборачивается одержимостью, а нехватка — почти безотчётным ужасом. Зрелая форма этой энергии — научиться отпускать и обновлять, понимая, что подлинная ценность человека не сгорает вместе с утраченным. Обернётся ли это спокойной внутренней опорой или вечной борьбой за обладание — зависит от выбора и всей карты целиком.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_house:pluto:3', 'western', 'Ум здесь не скользит по поверхности — он бурит, докапывается до корней и не успокаивается, пока не доберётся до самой сути. Повседневное общение, учёба и ближний круг окрашены особой напряжённостью: человека тянет к тому, что скрыто между строк, к расследованию, к темам, которых другие сторонятся, а слово в его устах способно и ранить, и преобразить. Такое расположение располагает к проницательности почти следовательской, к умению видеть подоплёку событий и к речи, которая проникает глубоко и остаётся с собеседником надолго.

Оборотная сторона — навязчивость мысли: ум порой застревает на одном, прокручивая тревогу по кругу, а привычка подозревать второе дно способна отравить простое общение недоверием. Иногда слово превращается в орудие давления, а спор — в борьбу за то, чей верх. Зрелая нота здесь — направить эту силу проникновения на понимание, а не на контроль, и помнить, что не всякую мысль стоит доводить до одержимости. В таком ключе человек становится тем, кто умеет докопаться до правды и найти для неё точные слова. Каким выйдет баланс между глубиной и покоем ума — зависит от осознанности и всей карты.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_house:pluto:4', 'western', 'Под кровлей родного дома здесь всегда есть глубина, которую не разглядеть с порога, — подводные течения, идущие из самой толщи рода. Дом, корни и внутренняя опора семьи несут плутонический заряд: человек чутко улавливает то, о чём в семье молчат, ощущает груз унаследованных сценариев и нередко становится тем, кому выпадает разорвать старую цепь и переложить фундамент заново. Такое положение располагает к глубокой связи с истоками, к способности распутывать родовые узлы и превращать тяжёлое наследство в источник силы.

Тень этой глубины — власть прошлого, которое не отпускает: подспудные конфликты, потребность держать домашнее пространство под контролем или, наоборот, чувство, будто под ногами то и дело осыпается земля. Внутренние бури порой копятся там, где хочется тишины. Зрелая форма этой энергии — не бежать от семейных теней, а осветить их и переплавить, становясь для близких опорой, что стоит на честности, а не на замалчивании. Образ разрушения и обновления здесь — про взросление рода и души, а не про буквальные события. Обернётся ли эта укоренённость внутренней твёрдостью или вечной подземной тревогой — зависит от выбора и всего рисунка гороскопа.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_house:pluto:5', 'western', 'Полутонов тут не признают — любят и творят на разрыв, отдаваясь без остатка или не берясь вовсе. Творчество, романтика и радость проживания жизни заряжены неистовой страстью: влюблённость накрывает как стихия, а в самовыражении человек ищет не украшательство, а катарсис — то, что переворачивает и его самого, и того, кто смотрит. Такое расположение располагает к магнетическому обаянию, к искусству, рождённому из самых глубоких недр, и к способности проживать чувства во всю их мощь.

Оборотная грань этой страсти — ревность и жажда владеть тем, кого любишь: чувство легко сгущается до одержимости, а игра — до борьбы за власть в отношениях или до перфекционизма, который сжигает саму радость. Иногда сила переживаний пугает самого человека. Зрелая нота здесь — позволить страсти течь, не превращая её в тиски, и творить ради преображения, а не ради контроля над впечатлением. В таком ключе эта глубина рождает вещи, которые задевают за живое. Каким окажется этот танец между всепоглощающим чувством и внутренней свободой — решает сам человек и остальные акценты гороскопа.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
