  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_house:pluto:6', 'western', 'В любое дело человек с таким положением уходит с головой, до самого дна, — половинчатость здесь не в чести. Повседневная рутина, работа и забота о теле пронизаны почти одержимой основательностью: труд становится способом перерождения, привычки перестраиваются радикально, а внимание к деталям граничит с азартом докопаться до первопричины. Такое расположение располагает к недюжинной работоспособности, к дару восстанавливать порядок там, где всё пришло в упадок, и к умению обновлять свой уклад до самого основания.

Оборотная сторона — риск загнать себя перфекционизмом: стремление держать под контролем каждую мелочь превращает дело в изматывающую гонку, а напряжение оседает в теле и просит, чтобы его вовремя отпускали. Иногда работа становится ареной скрытой борьбы за влияние. Стоит помнить, что бодрость и ясная голова держатся на передышке не меньше, чем на усердии. Зрелая форма этой энергии — направить силу преображения в живой, устойчивый ритм, а не в бесконечное переделывание себя и мира вокруг. Станет ли эта глубина источником мастерства или вечного напряжения — зависит от осознанности и общего склада карты.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
