  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_house:pluto:7', 'western', 'Отношения здесь не проходят бесследно — из союза с другим человек выходит уже не тем, кем в него входил. Партнёрство, брак и открытые договорённости заряжены предельной интенсивностью: связь тянет к самой глубине, к слиянию, в котором раскрываются потаённые стороны обоих, и нередко именно близкий другой запускает большое внутреннее преображение. Такое положение располагает к отношениям огромной силы, к притяжению незаурядных, глубоких людей и к способности проживать близость без масок.

Тень этой глубины — борьба за власть и страх потери: в союзе могут вспыхивать ревность, желание удержать во что бы то ни стало, подспудное перетягивание каната. Иногда человек то сливается с партнёром до растворения, то возводит стену. Зрелая форма этой энергии — превращать отношения в пространство честного роста, где глубину не путают с контролем, а близость не держат в кулаке. В таком ключе союз становится настоящей алхимией двоих. Обернётся ли эта интенсивность драмой или глубокой преображающей связью — зависит от выбора и всего строя гороскопа.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
