  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_house:pluto:8', 'western', 'В тех сумеречных областях, откуда большинство спешит уйти, этот человек чувствует себя почти как дома. Общие ресурсы, кризисы, предельная близость и внутренние перерождения — родная стихия этой энергии: здесь Плутон звучит в полную мощь, наделяя способностью входить в самое тёмное и неудобное без паники, выдерживать то, что ломает других, и выходить из потрясений обновлённым. Такое расположение располагает к психологической глубине, к чутью на скрытое и запретное, к умению возрождаться словно из пепла — раз за разом.

Оборотная сторона — власть, которую даёт эта глубина, и соблазн ею злоупотребить: цепкий контроль над общими средствами или чужими тайнами, страх довериться до конца, притяжение к крайностям, в которых легко потеряться. Иногда напряжение копится в тёмных углах души, не находя выхода. Зрелая форма этой энергии — идти в глубину ради исцеления, а не ради власти, и учиться доверять там, где всё отдано на волю неизвестного. Образ смерти-и-возрождения здесь — про радикальное обновление души, а не про буквальное предсказание. Каким окажется это погружение — определяет сам человек и общий рисунок карты.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
