  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_house:pluto:9', 'western', 'Верить наполовину этот человек не умеет — если уж искать истину, то до самого корня, переворачивая по пути привычные представления о мире. Мировоззрение, большое знание и дальние горизонты заряжены страстью к последней правде: убеждения здесь не берут готовыми, а выстрадывают через кризисы смысла, и картина мира время от времени рушится, чтобы сложиться заново — глубже прежней. Такое положение располагает к проникновению в суть вещей, к тяге исследовать запретное и сокрытое в философии и вере, к взглядам, которые преображают не только своего носителя.

Тень этой глубины — фанатизм: выстраданная правда легко застывает в единственно верную догму, а желание обратить других в свою веру оборачивается давлением. Иногда одержимость поиском смысла лишает покоя. Зрелая нота здесь — оставаться ищущим даже там, где кажется, что истина найдена, и нести свои прозрения без нажима — как приглашение, а не приговор. В таком ключе человек становится проводником для тех, кто привык копать вглубь. Куда приведёт эта дорога мысли — зависит от осознанности и всей конфигурации гороскопа.', 'reviewed', 2)
