  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_house:saturn:3', 'western', 'Слово тут не разменивают попусту — оно на вес золота и звучит лишь после того, как обдумано. В повседневном общении, учёбе и ближнем круге проступает обстоятельность: мысль движется неспешно, зато глубоко, а учиться человек склонен методично, доводя понимание до самой сути. Такое расположение располагает к сосредоточенности, к умению говорить веско и по делу и к настоящему мастерству в предмете, который другие пробегают по верхам.

Оборотная сторона этой серьёзности — внутренняя скованность: в детстве могло казаться, что высказаться трудно, что тебя не слышат или что твои мысли недостаточно хороши, — и эта осторожность порой остаётся надолго. Ум склонен видеть препятствия там, где их можно было бы и не заметить, а речь звучит суше, чем чувствует сердце. Зрелая нота здесь — довериться собственному неспешному уму и понять, что одно вдумчивое слово весит больше десятка беглых. В таком ключе человек становится тем, к чьему мнению прислушиваются. Каким выйдет баланс между строгостью и лёгкостью мысли — зависит от осознанности и всей карты.', 'reviewed', 2)
