  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_house:saturn:4', 'western', 'Дом здесь — не столько про тепло с первого дня, сколько про фундамент, который закладывают надолго и на совесть. Корни, семья и внутренняя опора связаны с чувством долга: человек рано ощущает себя тем, на ком что-то держится, тянется к прочному основанию под ногами и вьёт своё гнездо терпеливо, не ожидая, что оно возникнет само. Такое положение располагает к верности своим истокам, к роли надёжной опоры для близких и к дому, который со временем становится настоящей крепостью.

Есть и тень: детство или родовая память могли ощущаться суровыми, скупыми на теплоту, и внутри порой живёт чувство, будто по-настоящему укрыться и расслабиться негде. Груз семейных обязанностей бывает тяжёл, а привычка держать чувства взаперти берёт начало именно здесь. Зрелая форма этой энергии — стать той опорой, которой самому когда-то не хватало, и позволить дому быть местом, где можно снять доспехи, а не только нести ответственность. Обернётся ли эта укоренённость одиночеством внутри стен или прочным душевным тылом — зависит от выбора и всей карты целиком.', 'reviewed', 2)
