  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_house:saturn:7', 'western', 'К союзу с другим этот человек подходит без легкомыслия — для него отношения не игра, а обязательство, которое берут всерьёз и надолго. Партнёрство, брак и открытые договорённости пронизаны чувством ответственности: важны верность, надёжность и уверенность, что рядом тот, на кого можно опереться в трудный день. Такое положение располагает к тому, чтобы строить связь медленно и основательно, ценить зрелость в другом и вкладываться в союз как в дело всей жизни, а не как в мимолётное увлечение.

Тень этой серьёзности — осторожность, доходящая до стены: страх довериться и разочароваться держит на расстоянии, а близость порой ощущается как груз обязанностей, а не как радость. Иногда человек то откладывает сближение, то, наоборот, цепляется за союз из страха одиночества. Зрелая форма этой энергии — партнёрство равных, где ответственность делят пополам, а доверие растёт постепенно и стоит на прочном основании. В таком ключе однажды заключённый союз становится по-настоящему надёжным. Обернётся ли эта сдержанность одиночеством за стеной или крепкой опорой на двоих — зависит от выбора и всей карты целиком.', 'reviewed', 2)
