INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_house:saturn:9', 'western', 'Убеждения здесь не берут готовыми — их выстрадывают, проверяют опытом и складывают по кирпичику. Мировоззрение, большое знание и дальние горизонты держатся на основательности: человек тянется к серьёзным дисциплинам, уважает традицию и проверенное временем, а к вере и философии подходит вдумчиво, не принимая красивое на слово. Такое положение располагает к глубокой, выстроенной картине мира и к мудрости, которая приходит не озарением, а годами честного размышления, — со временем к такому человеку прислушиваются как к тому, кто знает, о чём говорит.

Тень этой прочности — жёсткость: выношенные убеждения легко застывают в догму, а трезвость — в холодный скепсис, из-за которого чужое и незнакомое встречается с недоверием. Иногда осторожность мешает шагнуть за привычные границы — географические или мысленные. Зрелая нота здесь — оставаться учеником, даже став авторитетом, и помнить, что прочное мировоззрение всегда оставляет место вопросу. В таком ключе человек становится надёжным проводником для тех, кто ищет смысл. Куда приведёт эта дорога мысли — зависит от осознанности и всей конфигурации гороскопа.', 'reviewed', 2)
