  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_sign:mercury:virgo', 'western', 'Дьявол, как известно, в мелочах — и здесь ум чувствует себя в родной стихии. Меркурий силён в Деве: он замечает то, что другие пропускают, любит порядок в мыслях и словах и получает тихое удовольствие, доводя запутанное до ясной, работающей системы. Такой человек мыслит точно и по делу, проверяет прежде чем поверить, и почти инстинктивно ищет, чем его знание может пригодиться — как помочь, улучшить, отладить. Оборотная сторона зоркости — склонность к самокритике и вечное чувство, что можно было аккуратнее: внутренний редактор порой не выключается и там, где хватило бы «достаточно хорошо». Понимание этого помогает мягче обходиться с собой. Стоит направить требовательность на дело, а не на себя, — и внимание к деталям становится настоящей силой: надёжностью, на которую опираются, и умением видеть решение там, где другие видят лишь хаос.', 'reviewed', 2)
