  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_sign:pluto:virgo', 'western', 'Скальпель, а не молот — так работает Плутон в Деве. Его преображающая мощь входит в детали: в наведение порядка, в кропотливую разборку того, что разладилось, в стремление довести несовершенное до рабочего состояния. Обновление совершается через анализ и служение — через готовность разобрать сложное на части, чтобы понять, как оно устроено, и собрать заново чище прежнего. Такому сочетанию близко желание быть полезным по-настоящему, а не для галочки. Тень этой основательности — придирчивость к себе и миру, привычка искать изъян там, где можно было бы принять. Сила расположения раскрывается, когда точность служит улучшению, а не самоедству. Станет ли внимательность инструментом заботы или источником вечного недовольства — зависит от осознанности, а не предрешено.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_sign:saturn:aquarius', 'western', 'Правила и вызов правилам сходятся здесь в одной точке — и встреча выходит плодотворной. Сатурн, хранитель структуры, соединяется с водолейской независимостью мысли, и получается человек, способный не просто ломать устаревшее, а строить на его месте новое — продуманное и работающее на общую пользу. Дисциплина проявляется как верность принципам: убеждения тут не мода, а опора, ради которой можно идти против течения. Такому складу интересны системы — как устроено общество, сообщество, любое «мы», — и хочется вносить в них порядок с прицелом на будущее. Теневая грань — холодноватая отстранённость и упрямство ума, когда своя правота кажется единственно верной; уравновешивает их готовность слышать живых людей, а не только идеи. Свобода здесь крепнет, опираясь на ответственность. Как раскроется эта черта, покажут осознанность и карта в целом — это склонность, которую стоит развивать, а не предрешённый сценарий.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_sign:saturn:aries', 'western', 'Порыв и терпение — соседи не самые уживчивые, и именно их встречу описывает это положение. Сатурн предпочитает медленный, выверенный шаг, а Овен рвётся вперёд, ещё не додумав, — из этого напряжения складывается особый характер. Человек учится не гасить свой натиск, а придавать ему форму: доводить начатое до конца, а не разбрасывать искры по сторонам. Дисциплина здесь нередко проявляется как умение собрать смелость в один точный удар вместо десяти поспешных, и как тяга к самостоятельности — опору хочется искать в себе, а не ждать разрешения со стороны. Обратная сторона — нетерпение и досада, когда результат не приходит сразу; справиться с этим помогает привычка мерить успех не скоростью, а тем, что удалось достроить. Как именно раскроется этот рисунок, зависит от осознанности и от карты в целом: перед нами не сценарий, а материал, с которым можно работать в свою пользу.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_sign:saturn:cancer', 'western', 'Забота и строгость обычно кажутся жителями разных миров, но здесь они переплетаются вплотную. Внутренняя дисциплина обращается к самому уязвимому — к дому, к близким, к потребности в тепле и защищённости. Человека с такой окраской нередко тянет отвечать за родных, беречь семейный уклад, быть той опорой, к которой возвращаются; ответственность за эмоциональную сторону жизни он принимает всерьёз, порой серьёзнее, чем стоило бы. Слабое место — привычка сдерживать чувства, прятать мягкость за собранностью, скупиться на нежность к себе, будто тепло нужно ещё заслужить. Располагает это к неспешному сближению: доверие открывается не сразу, зато потом надолго. Легче обходиться с этой чертой помогает разрешение принимать поддержку, а не только раздавать её. Как всё сложится, зависит от осознанности и от карты в целом — это тенденция, с которой можно работать, а не то, что предрешено.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_sign:saturn:capricorn', 'western', 'Здесь планета порядка словно оказывается у себя дома, и её темы звучат в полный голос. Терпение, самообладание, умение работать вдолгую — не заимствованные качества, а сердцевина характера. Ведёт такого человека не сиюминутный порыв, а дальний ориентир: он готов подниматься медленно, ступень за ступенью, зная, что прочное строится годами. Дисциплина проявляется как ответственность, на которую можно опереться, и как авторитет, заработанный делом, а не полученный даром. Оборотная сторона — строгость, обращённая внутрь: планка бывает так высока, что человек не разрешает себе ни отдыха, ни ошибки, а успех обесценивает, едва достигнув. Смягчает это разрешение ценить пройденный путь, а не только вершину, и помнить, что тепло не мешает прочности. Как проявится эта основательность и во что вырастет, зависит от осознанности и всей карты — перед нами сильная склонность, а не предписанная судьба.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_sign:saturn:gemini', 'western', 'Ум, которому тесно на одном месте, встречается здесь с требованием довести мысль до порядка. Любопытство не бунтует против дисциплины, а ищет с ней союз: беглый, подвижный интеллект постепенно учится не только схватывать, но и удерживать, не только заводить разговор, но и договаривать до сути. Собранность проявляется как тяга к точности слова, к проверенным фактам, к знанию, выстроенному в систему, а не набранному по верхам. Такому складу свойственна серьёзность во всём, что касается информации: обещанное хочется подкрепить, сказанное — обосновать. Теневая сторона — внутренний критик, который сомневается в собственных мыслях и мешает говорить свободно; смягчает его понимание, что ясность приходит не сразу и рождается в самом процессе речи и письма. Как ляжет этот рисунок, решают осознанность и карта целиком — речь о склонности, а не о том, что решено заранее.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_sign:saturn:leo', 'western', 'Сцена, свет, обращённые к тебе взгляды — и строгий внутренний экзаменатор, который тихо спрашивает: а по праву ли ты здесь? Примерно так устроено это сочетание. Яркость, щедрость, тяга к самовыражению встречаются с сатурнианской взыскательностью, и признание перестаёт быть подарком — оно превращается в то, что заработано трудом и мастерством высокой пробы. Дисциплина проявляется как серьёзное отношение к творчеству и к роли ведущего: авторитет хочется не занять, а выстроить. Тень этой яркости — зависимость от чужой оценки и жёсткость к себе, когда аплодисментов меньше ожидаемого; уравновешивает её умение творить ради самого дела, а не ради взгляда со стороны. Такому складу идёт щедрость, растущая из уверенности, а не из желания понравиться. Как раскроется эта грань, покажут осознанность и вся карта — перед нами склонность, которую можно обратить в достоинство, а не заранее написанный сюжет.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
