  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_sign:saturn:libra', 'western', 'Справедливость здесь перестаёт быть отвлечённым словом и становится делом чести. Сатурн в этом положении наводит порядок там, где встречаются двое: в отношениях, договорённостях, в самой идее равновесия. Человека тянет взвешивать, учитывать чужую правоту, строить связи, которые выдержат проверку временем, а не рассыплются при первой трудности. Дисциплина проявляется как верность обязательствам и чувство меры — и в поступках, и в эстетике, где ценится сдержанная, выверенная красота. Уязвимость — в выборе: страх ошибиться и обидеть заставляет медлить, а желание всем угодить — прятать собственную позицию. Выручает признание, что честность порой важнее гладкости и что своё «нет» — тоже вклад в справедливость. Как ляжет этот рисунок, покажут осознанность и карта целиком — речь о склонности, которую стоит развивать, а не о предопределённом финале.', 'reviewed', 2)
