  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_sign:saturn:pisces', 'western', 'Как придать форму тому, что по природе своей ускользает, — вот тихий вопрос этого сочетания. Строгость и структура встречаются с текучестью, состраданием, богатым воображением, и человек учится не гасить свою тонкость, а давать ей русло. Дисциплина проявляется как умение воплощать неуловимое: превращать мечту в работу, сочувствие — в конкретную помощь, интуицию — в доведённое до результата дело. Такому складу свойственна чуткость к чужому настроению и потребность в уединении, где можно восстановиться. Уязвимое место — размытые границы и склонность сомневаться в реальности собственных ощущений, растворяться в чужих переживаниях; опорой служит привычка возвращать себя в тело, в ритм, в простые земные заботы. Вера здесь крепнет не вопреки трезвости, а рядом с ней. Как проявится эта черта, зависит от осознанности и карты целиком — это склонность, с которой можно расти, а не что-то решённое за вас.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_sign:saturn:sagittarius', 'western', 'Дальний горизонт манит, но Сатурн спрашивает про дорогу к нему — и в этом весь узел. Широкий взгляд, вера в лучшее и тяга к новому встречаются с сатурнианской требовательностью, и убеждения проходят проверку на прочность: во что действительно стоит верить, а что — красивая, но пустая идея? Дисциплина проявляется как серьёзное отношение к смыслу — к знанию, к мировоззрению, к слову, за которое отвечаешь. Человека тянет не просто мечтать о горизонте, а прокладывать к нему реальный маршрут. Другая сторона — колебание между жаждой простора и страхом обязательств, между «хочу всё сразу» и «вдруг ошибусь с выбором пути». Уравновешивает это понимание, что свобода крепнет, когда у неё есть опора и направление. Как раскроется этот рисунок, покажут осознанность и карта целиком — это склонность, которую можно обратить в мудрость, а не заранее заданный итог.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_sign:saturn:scorpio', 'western', 'Там, где иные отступают, этот склад характера будто только собирается с силами. Дисциплина соединяется с глубиной: неинтересно скользить по поверхности — важно дойти до сути, понять устройство, выдержать то, что других пугает. Сосредоточенность проявляется как редкая выносливость и умение доводить трудное до конца, не размениваясь по пути. Такому человеку свойственны сдержанность и контроль: чувства сильны, но выставлять их напоказ он не спешит, а доверие бережёт как ценность. Риск — упорство, переходящее в упрямство, и привычка держать в себе больше, чем стоит; облегчает это готовность иногда отпускать хватку и разрешать себе уязвимость. Такому характеру идёт способность обновляться — расставаться с отжившим, чтобы освободить место новому. Во что превратится эта черта, решают осознанность и вся карта: одну и ту же силу можно прожить как навязчивость, а можно — как источник опоры.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_sign:saturn:taurus', 'western', 'Есть характеры, которым спокойнее возводить дом на камне, чем спешить с новосельем, — это устройство как раз из таких. Ответственность и внутренняя собранность обретают здесь земную, вещественную опору: важно не просто задумать, а сделать прочно и надолго. Такого человека тянет к надёжности — в деле, в быту, в отношениях; ему по душе то, что можно потрогать, проверить временем, накопить постепенно. Дисциплина проявляется как терпеливое, почти ремесленное упорство: шаг за шагом, без рывков, зато основательно. Есть и изнанка — привязанность к привычному и трудный старт перемен: расставаться с наработанным бывает непросто. Мягче обходиться с этим помогает мысль, что устойчивость не в неподвижности, а в умении перестраивать опору, не теряя себя. Насколько ярко проявится черта и куда её направить — вопрос выбора и всей карты, а не предопределения.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_sign:saturn:virgo', 'western', 'Мелочей для такого устройства попросту не существует — в этом и его сила, и его испытание. Дисциплина обретает здесь почти ювелирную точность: важно не вообще сделать, а сделать выверенно, чисто, с пониманием, как всё устроено внутри. Человека тянет доводить до ума, отлаживать, приносить осязаемую пользу; работа спустя рукава вызывает у него внутренний протест. Ответственность проявляется как надёжность в деталях — на такого можно положиться там, где другие махнут рукой. Цена такой высокой планки — перфекционизм и придирчивость к себе: радость от результата не успевает прийти, потому что «идеально» всё время отодвигается. Смягчает это простая мысль: полезное и завершённое дороже безупречного и вечно недоделанного. Насколько заметно проявится черта и во что превратится — вопрос осознанности и карты в целом, а не предрешённого хода вещей.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_sign:sun:aquarius', 'western', 'Там, где принято соглашаться, такой человек скорее спросит: а почему, собственно, так, а не иначе? Солнце в Водолее строит личность вокруг независимости ума — способности смотреть на привычное со стороны и видеть варианты, которых не замечают внутри общего строя. Нестандартность здесь не поза, а естественный способ мышления: чужие правила не давят на него автоматическим авторитетом.

При этом взгляд Водолея обращён не только на себя — его по-настоящему трогает общее благо, будущее, идеи, которые сделают жизнь многих лучше. Тень этой отстранённости — холодок в близком: увлечённость человечеством вообще иногда мешает быть тёплым с конкретным человеком рядом. Осознанность помогает соединить широту взгляда с живым участием. Тогда оригинальность перестаёт отдалять и начинает объединять. Как проявится эта склонность идти своим путём — как одиночество или как способность вести за собой, — зависит от всей карты и от выбора самого человека.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_sign:sun:aries', 'western', 'Внутренний двигатель здесь запускается раньше, чем ум успевает подобрать доводы: желание сделать — и рука уже тянется к делу. Солнце в Овне окрашивает чувство собственного «я» в цвета старта, первопроходчества, прямого хода к цели. Такому человеку естественнее начинать, чем ждать, и в этом его сила: он умеет разрубить узел, из-за которого другие месяцами топчутся на месте.

Оборотная сторона той же энергии — нетерпение и вспышки, когда препятствие воспринимается как личный вызов. Это не изъян характера, а тот же огонь, только пока без русла. Осознанность здесь работает как клапан: если научиться доводить начатое, а не только зажигать, порывистость превращается в редкую способность вести за собой. Как именно раскроется эта склонность, зависит от всей карты и от того, куда человек решает направить свой напор, — воля Овна не приговор, а топливо, которым можно распорядиться по-разному.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_sign:sun:cancer', 'western', 'Внутренний мир здесь ощущается как дом, а близкие — как его стены: тепло, память, принадлежность значат больше громких достижений. Так проявляет себя Солнце в Раке. Личность питается из глубины чувств, тонко считывает настроение других раньше произнесённых слов и умеет создавать вокруг ту атмосферу заботы, в которой людям становится спокойно и безопасно.

Эта чуткость — большой дар, но она же делает человека уязвимым: чужие эмоции легко становятся своими, а обида нередко прячется в раковину вместо прямого разговора. Здесь важно бережно различать, где кончаются собственные переживания и начинаются подхваченные. Забота, обращённая в первую очередь и на себя, а не только вовне, перестаёт истощать. Привязанность к близким при этом остаётся стержнем — просто с более здоровыми границами. Насколько мягко или тревожно раскроется эта грань, во многом решает вся карта и внутренняя опора, которую человек в себе выращивает.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_sign:sun:capricorn', 'western', 'Есть люди, которые мыслят не днями, а годами, — и Солнце в Козероге как раз про такой масштаб. Личность здесь строится вокруг цели, к которой идут шаг за шагом, без спешки и без иллюзий: терпение, дисциплина и трезвый расчёт заменяют этому человеку фейерверки быстрых побед. Он готов вкладываться сейчас ради результата, который созреет нескоро, — и часто именно так добирается до вершин, недоступных нетерпеливым.

За внешней сдержанностью нередко прячется высокая внутренняя планка и привычка сначала заслужить, а уже потом позволить себе. Тень этого — суровость к себе и ощущение, что отдых надо оправдать. Стоит помнить: восхождение имеет смысл, если по дороге остаётся место и для радости, а не только для долга. Дисциплина Козерога — не приговор к вечной работе, а инструмент, и то, во что вложено это терпение, во многом определяет осознанный выбор. Насколько строгой или зрелой раскроется эта черта, покажет вся карта целиком.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_sign:sun:gemini', 'western', '«А почему?» и «а что, если?» — вопросы, которые у такого человека не заканчиваются никогда. Солнце в Близнецах наполняет чувство собственного «я» любопытством: мир воспринимается как бесконечная библиотека, где хочется полистать всё сразу. Ум здесь подвижный, схватывающий на лету, легко перескакивающий с темы на тему и умеющий связать несвязуемое неожиданной ассоциацией.

Такая натура расцветает в разнообразии — новые люди, идеи, маршруты держат её в тонусе, а однообразие быстро гасит интерес. Обратная сторона гибкости — рассеянность: когда любопытно всё, трудно выбрать одно и довести до конца. Это не поверхностность по природе, а просто много открытых дверей одновременно. Осознанность подсказывает: глубина не отменяет широты, если время от времени задерживаться на чём-то дольше обычного. Как проявится эта склонность к переменам — как разбросанность или как редкая живость ума, — зависит от всей карты и от того, что человек выбирает питать.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_sign:sun:leo', 'western', 'Там, где такой человек, обычно чуть теплее и светлее — он словно приносит с собой немного солнца в комнату. Солнце во Льве, в своей родной стихии, делает самовыражение сердцевиной личности: хочется творить, дарить, вдохновлять и получать в ответ живой отклик. Щедрость здесь не расчёт, а естественное состояние — рядом с таким человеком хочется быть лучшей версией себя.

Потребность быть увиденным — не тщеславие, а способ почувствовать, что ты настоящий. Тень появляется, когда признание становится единственным топливом: тогда за яркостью может прятаться зависимость от аплодисментов. Осознанность возвращает опору внутрь — когда человек светит потому, что это его природа, а не ради оценки, его тепло становится по-настоящему щедрым. Как именно раскроется эта склонность блистать, зависит от всей карты и от того, ищет ли человек одобрения — или радости самого творчества.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_sign:sun:libra', 'western', 'Резкость, дисбаланс, несправедливость такой человек ощущает почти физически — как фальшивую ноту, которую хочется поправить. Солнце в Весах строит личность вокруг гармонии: во внешнем — через красоту, вкус, чувство меры, во внутреннем — через справедливость и умение услышать сторону, которую другие пропускают. Способность встать на чужое место здесь не приём, а естественная оптика.

Из этого рождается настоящий дар посредника, но у него есть цена: постоянно взвешивая «за» и «против» и боясь задеть, легко застрять в нерешительности или раствориться в чужих желаниях. Баланс, о котором мечтают Весы, начинается с честности к самому себе — со своими предпочтениями, а не только с чужими. Когда стремление к согласию перестаёт означать отказ от собственного голоса, из этого качества вырастает редкая дипломатичность. Как проявится эта склонность к равновесию, зависит от всей карты и от того, включает ли человек в уравнение и себя.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_sign:sun:pisces', 'western', 'Границы между «я» и «мир» у такого человека тоньше, чем у большинства: чужую боль он чувствует как сквозняк, а красоту — как волну, что накрывает целиком. Солнце в Рыбах строит личность вокруг сочувствия и воображения. Внутри живёт целый океан образов, интуитивных догадок и полутонов, которые не всегда переводятся в слова, но безошибочно ощущаются.

Эта восприимчивость — источник творчества, доброты и почти безусловного понимания других. И она же — уязвимость: без внутренних берегов легко растворяться в чужих настроениях, спасать всех подряд или прятаться от слишком резкого мира. Здесь бесценно умение мягко очерчивать границы — не чтобы закрыться, а чтобы сохранить себя и было чем делиться. Когда чуткость опирается на устойчивость, она превращается в подлинный дар — вдохновлять, утешать, соединять. Насколько светлой или размытой раскроется эта тонкая природа, зависит от всей карты и от того, находит ли человек в себе опору.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_sign:sun:sagittarius', 'western', 'Горизонт для такого человека — не предел, а приглашение: там, дальше, наверняка есть что-то, чего он ещё не видел и не понял. Солнце в Стрельце наполняет личность оптимизмом и тягой к простору — географическому, интеллектуальному, духовному. Ему тесно в узких рамках; хочется смыслов покрупнее, идей посвободнее, опыта поразнообразнее.

Эта широта делает человека вдохновляющим спутником: рядом с ним будущее кажется открытым, а любая неудача — всего лишь поворотом сюжета. Тень оптимизма — невнимание к деталям и обещания, которые легко дать и труднее сдержать, когда следующий горизонт уже манит. Свобода, которой так дорожит Стрелец, крепнет, когда к ней добавляется верность взятому направлению. Тогда жажда нового перестаёт быть бегством и становится настоящим поиском. Насколько мудрой или беспокойной окажется эта тяга к странствиям, зависит от всей карты и от того, умеет ли человек не только рваться вдаль, но и возвращаться.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_sign:sun:scorpio', 'western', 'Поверхность такого человека почти не занимает — ему нужно то, что скрыто под ней: подлинные мотивы, изнанка вещей, суть за словами. Солнце в Скорпионе окрашивает личность в тона глубины и предельной сосредоточенности. Если уж он во что-то вкладывается, то целиком, без половинчатости, и способен идти до конца там, где другие давно отступили бы.

Эта интенсивность — источник огромной внутренней силы и способности к настоящему преображению: пережить, отпустить старое и внутренне обновиться для такого человека не метафора, а знакомый опыт. Оборотная сторона — ревность, скрытность, желание держать всё под контролем, когда доверять страшно. Здесь исцеляет не подавление чувств, а честность с их накалом. Когда сосредоточенность направлена на созидание, а не на удержание, она становится редкой преданностью и глубиной, которой не хватает многим. Как именно раскроется эта страстная природа, решает вся карта и то, во что человек вкладывает свой жар.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_sign:sun:taurus', 'western', 'Устойчивость важнее блеска, а надёжное заманчивее нового — так ощущает мир человек с Солнцем в Тельце. Чувство себя здесь строится медленно и основательно, как дом на хорошем фундаменте: через вещи, которые можно потрогать, через дело, доведённое до осязаемого результата, через верность тому, что однажды выбрано.

Таким людям обычно чужда суета: проверенное они предпочтут модному, а спокойную определённость — рискованным ставкам. Отсюда та тихая сила, на которую другим приятно опереться. Тень этого качества — упрямство и нежелание сходить с насиженного места даже тогда, когда обстоятельства давно переменились. Стоит помнить, что устойчивость и застой — не одно и то же: первое даёт опору, второе держит на привязи. Мягко относясь к своей потребности в стабильности и не путая её со страхом перемен, человек с таким Солнцем превращает медлительность в основательность, а привязанность — в верность. Насколько выразится эта черта, всегда решает вся карта и живой выбор.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_sign:sun:virgo', 'western', 'Замеченная другими небрежность, шероховатость, которую все привыкли терпеть, — именно здесь такой человек чувствует, что может навести порядок. Солнце в Деве строит чувство «я» вокруг мастерства в мелочах: разложить хаос по полочкам, доработать, отладить, сделать по-настоящему хорошо, а не «сойдёт». В этом внимании к деталям — тихая форма любви к делу и к людям, которым хочется быть полезным.

Аналитический ум видит несовершенства раньше остальных, и это ценнейший навык. Но тот же взгляд, повёрнутый внутрь, легко превращается в самокритику, которой ничем не угодишь. Стоит помнить: стремление улучшать создано, чтобы служить, а не чтобы грызть своего носителя. Когда планка перестаёт быть кнутом и становится ориентиром, придирчивость оборачивается настоящим качеством. Насколько строгой или созидательной окажется эта черта, всегда зависит от всей карты и от того, умеет ли человек быть к себе таким же снисходительным, как к любимому делу.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_sign:uranus:aquarius', 'western', 'Здесь Уран как дома: в знаке Водолея его тяга к свободе звучит в полную силу и без извинений. Независимость мышления для такого человека не поза, а естественная среда: он смотрит на привычное будто со стороны, замечает, что «так принято» ещё не значит «так верно», и легко представляет, как могло бы быть иначе. Его влечёт всё нестандартное, будущее, общее благо — идея, способная изменить жизнь многих, интереснее личной выгоды. Дар этого сочетания — оригинальный, опережающий время взгляд и умение объединять очень разных людей вокруг общего замысла. Тень — холодноватая отстранённость и упрямый бунт ради принципа, когда живые чувства прячутся за идеями, а несогласие становится самоцелью. Это не приговор, а склонность — то, как она проявится, во многом зависит от осознанного выбора: дать свободному уму русло в новаторстве, науке, технологиях, командных проектах на общую пользу. Тогда непохожесть перестаёт быть вызовом и становится вкладом.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_sign:uranus:aries', 'western', 'Свобода, которая доказывает себя не словом, а рывком, — вот интонация Урана в Овне. Потребность в независимости срабатывает здесь как разряд: человека тянет пробовать новое первым, ломать заведённый порядок прямым действием и не спрашивать разрешения там, где другие ещё сомневаются. Перемена для такого темперамента не тревога, а азарт; неожиданный поворот он встречает как приглашение к старту, а не как угрозу. Сильная сторона — смелость начинать с чистого листа, готовность идти против течения ради собственного пути и оживлять застоявшееся одним резким шагом. Обратная сторона — импульсивность и бунт ради самого бунта, когда свобода путается с упрямством, а нетерпение сжигает начатое раньше срока. Это не приговор, а грань характера, которую можно развернуть себе на пользу: направить искру в первопроходство, спорт, запуск нового, честную инициативу вместо взрывов на пустом месте. Как именно раскроется этот заряд, во многом зависит от осознанности и всей карты целиком.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_sign:uranus:cancer', 'western', 'Как быть свободным и при этом глубоко привязанным? Этот тихий парадокс несёт в себе Уран в Раке. Независимость здесь ищут не вопреки близким, а внутри тёплого круга: человеку нужно право чувствовать по-своему и строить дом не по чужому образцу, а так, как подсказывает сердце. Перемены он переживает остро, почти кожей, и нередко сам обновляет уклад заботы — придумывает новые способы поддержать своих, отходит от унаследованных семейных сценариев, которые больше не греют. В этом его дар — чуткая интуиция на перемену: он раньше других ощущает, что в отношениях или доме пора что-то менять. Оборотная сторона — тревожность и резкие смены настроения, когда потребность в свободе сталкивается со страхом потерять опору. Это не приговор, а склонность — то, как она проявится, во многом зависит от осознанного выбора. Такому Урану хорошо там, где обновление соединяется с теплом: в бережном пересборе семейных традиций, в создании своего, ни на что не похожего пространства.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_sign:uranus:capricorn', 'western', 'Реформатор внутри системы, а не снаружи, — таков Уран в Козероге. Свободу здесь добывают не бунтом на баррикадах, а терпеливым перестраиванием правил изнутри: человек берётся менять устоявшийся порядок методично, по кирпичу, чтобы новое встало прочно и всерьёз. Ему важно право строить жизнь на собственных основаниях, а не по унаследованному чертежу, и он готов идти к этому долго, не размениваясь на эффектные жесты. Его дар — умение приземлять смелые идеи в работающую структуру и доводить реформу до вершины, когда энтузиасты давно сошли с дистанции. Тень — сухость и жёсткость: свободолюбие может застыть в упрямый холод, а требовательность — в вечное «сделано мало». Понимание этой особенности помогает мягче обходиться с собой и опираться на неё как на ресурс: ценить достигнутое, а не только следующую ступень. Такому Урану естественно менять к лучшему то, что строится годами, — дело, карьеру, устройство сообщества.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_sign:uranus:gemini', 'western', 'Окно там, где была глухая стена, — Уран в Близнецах распахивает его новым вопросом, неожиданной связкой идей, взглядом под непривычным углом. Свободу такой человек добывает мыслью: ум у него подвижен и жаден до нового, легко перескакивает через рамки и находит выход через слово, шутку, короткий остроумный ход. Разнообразие для него воздух — одна колея душит, а несколько тем и разговоров разом, наоборот, бодрят. Его конёк — изобретательность и быстрая перестройка на ходу, умение уловить свежую идею раньше других и заразить ею. Уязвимость — рассеянность и нервная непоседливость: мыслей столько, что ни одна не доходит до глубины, а тяга к новизне оборачивается перепрыгиванием с темы на тему. Это не приговор, а склонность, и то, как она проявится, во многом зависит от осознанного выбора: дать любопытству законное русло — учёбу, тексты, эксперименты — и подвижный ум станет источником по-настоящему свежих решений.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_sign:uranus:leo', 'western', 'Быть собой ярко, в открытую, ни на кого не оглядываясь, — так проявляется потребность в свободе у Урана во Льве. Независимость становится здесь вопросом самовыражения: человеку важно творить и заявлять о себе своим, ни на кого не похожим способом, а не повторять чужие образцы блеска. Его тянет удивлять, вносить в привычное неожиданную краску, вести за собой не властью, а искрой оригинальности. Здесь много щедрого, смелого творчества и умения вдохновлять личным примером свободы. Тень — упрямая гордость и жажда выделяться во что бы то ни стало, когда оригинальность превращается в позу, а признание становится важнее сути. Это не приговор, а склонность, которую можно развивать себе на пользу — направить огонь в искусство, наставничество, любое дело, где ценят живую индивидуальность. Многое решает осознанность: если внутренняя опора крепка, потребность блистать перестаёт требовать аплодисментов и становится просто заражающим, свободным драйвом.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_sign:uranus:libra', 'western', 'Независимость вдвоём, без потери себя, — вот задача, которую по-своему решает Уран в Весах. Свободу здесь ищут не в одиночестве, а в отношениях: человеку важно строить связи на равных, без душных ролей, и он охотно пробует непривычные форматы близости и договорённостей. Его подкупает умение встать на чужую точку зрения, не изменив своей, и через это находить свежие, справедливые решения там, где другие видят лишь выбор «или — или». Сильная сторона сочетания — оригинальное чувство меры и красоты, тяга обновлять эстетику и правила общения. Обратная сторона — метания и нерешительность: ради баланса решение откладывается, а желание всем угодить спорит с потребностью в свободе. Понимание этой особенности помогает мягче обходиться с собой и опираться на неё как на ресурс: честно признавать свои желания наравне с чужими, а вкус к гармонии тратить на партнёрство, дизайн, посредничество, где ценится способность соединять несоединимое.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_sign:uranus:pisces', 'western', 'Границы здесь зыбки, и в этой зыбкости — особая свобода Урана в Рыбах. Независимость ищут не в резком жесте, а в способности выходить за пределы очевидного воображением и состраданием: человека осеняет там, где логика бессильна, и трогает чужой болью или красотой раньше, чем он успевает это объяснить. Эта проницаемость — дар: он улавливает витающие в воздухе перемены, предчувствует новое как настроение, а не как расчёт. Сила сочетания — вдохновенная, сочувственная интуиция и готовность освобождать других от боли и лишних рамок. Тень — ускользание и бегство: тяга к свободе может обернуться уходом от реальности, а тонкая восприимчивость — растворением в чужих состояниях без опоры на своё. Понимание этой особенности помогает мягче обходиться с собой и опираться на неё как на ресурс: давать интуиции форму — в искусстве, помощи, творческом и духовном поиске. Обретая опору, эта текучая свобода перестаёт рассеиваться и становится источником глубокого прозрения.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_sign:uranus:sagittarius', 'western', 'Тесно в четырёх стенах любой догмы — так можно описать Уран в Стрельце. Свободу здесь понимают как простор: право думать шире принятого, пробовать новый опыт, срываться за горизонт — в дорогу, в идею, в чужую культуру, в непривычный взгляд на мир. Такого человека воодушевляет всё, что раздвигает рамки; он с азартом ставит под сомнение готовые истины и ищет собственную, живую. Его дар — оптимизм первооткрывателя и умение зажечь других верой, что мир больше и интереснее, чем кажется из привычной колеи. Обратная сторона — нетерпимость к границам и склонность увлечься очередной большой идеей, теряя интерес к будничной середине пути. Понимание этой особенности помогает мягче обходиться с собой и использовать её как ресурс: находить тяге к простору законное русло — путешествия, учёбу, проекты с размахом, — а не корить себя за неусидчивость. Многое зависит от осознанности: обретая внутренний компас, эта жажда свободы перестаёт распыляться и ведёт к настоящему росту.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_sign:uranus:scorpio', 'western', 'Вглубь, а не вширь — так добывает свободу Уран в Скорпионе. Этому человеку тесно на поверхности: его тянет докапываться до сути, вскрывать спрятанное, идти туда, где страшно и запретно, и в самом этом бесстрашии он обретает независимость. Перемены он переживает не как лёгкий ветер, а как преображение до основания: отжившее сносится подчистую, чтобы освободить место новому. Сила этого сочетания — несгибаемая воля и способность проходить сквозь кризис не отступая, когда другие сдаются. Тень — одержимость и установка «всё или ничего», когда жажда докопаться до правды оборачивается разрушительным напряжением или недоверием. Это не приговор, а грань характера, которую можно обратить себе на пользу: направить эту силу в исследование, глубинную работу над собой, честное преображение обстоятельств. Как раскроется такая интенсивность, во многом зависит от осознанности и всей карты целиком — но сама по себе она даёт редкую способность начинать заново.', 'reviewed', 2)
