  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_sign:uranus:taurus', 'western', 'Планета внезапных перемен гостит в знаке, который больше всего на свете ценит устойчивость, — из этого напряжения и рождается особый характер Урана в Тельце. Свобода нужна такому человеку не в отрыве от земли, а в самой земле: право распоряжаться своими ресурсами, телом, деньгами, укладом по-своему, без чужого диктата. Революция здесь идёт медленно и основательно — не вспышкой, а упрямым перестраиванием привычного, пока новое не станет прочным и осязаемым. Отсюда редкий дар превращать смелые идеи в надёжные работающие вещи, а не в воздушные замки. Обратная сторона — тугое сопротивление переменам, когда меняться давно пора: свободолюбие странно уживается с цепкой привязанностью к нажитому. Это грань характера, которую стоит разворачивать себе на пользу — не корить себя за медлительность, а ценить в ней основательность. Такому Урану хорошо там, где новизну нужно сделать долговечной: в ремесле, финансах, устройстве по-настоящему своего быта.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_sign:uranus:virgo', 'western', 'Бунт здесь тихий и прицельный: Уран в Деве расшатывает не устои вообще, а конкретный неработающий порядок — метод, который давно пора переделать, привычку, которая только мешает. Свободу такой человек находит в праве делать по-своему и лучше: разобрать процесс на детали, увидеть, где он скрипит, и придумать более чистое, точное решение. Новизна тут служит пользе — не ради эффекта, а чтобы что-то заработало исправнее. В этом его дар — изобретательность в мелочах, которые другие проглядывают, и трезвый аналитический взгляд на то, что можно улучшить. Тень — придирчивая нервозность и вечное недовольство несовершенством, когда критический ум не даёт покоя ни делу, ни себе. Понимание этой особенности помогает мягче обходиться с собой и превращать требовательность в ресурс: направлять её на мастерство, анализ, ремесло — на всё, где вознаграждается умная, аккуратная переделка привычного.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_sign:venus:aquarius', 'western', 'Шаблоны этой Венере тесны. В знаке Водолея притяжение идёт непривычными путями: нравится необычное, самобытное, то, что не вписывается в общий ряд, а рядом ценится прежде всего свобода — своя и чужая. Такой человек нередко дружит и любит одновременно, строит отношения на равенстве и общих идеях, а не на ритуалах собственничества.

В чувствах ему важен воздух и уважение к личному пространству; удушающая близость гасит интерес быстрее ссоры. За кажущейся прохладой стоит искренняя теплота к людям вообще — интерес к общему благу, к тому, чтобы всем жилось честнее и свободнее. Оборотная сторона независимости — риск держать дистанцию там, где нужна простая теплота вдвоём. Это одна из граней характера, которую можно развивать в свою пользу: осознанность помогает соединить верность себе с настоящей близостью. Как развернётся эта склонность, решает вся карта целиком.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_sign:venus:aries', 'western', 'Влечение здесь не терпит долгих прелюдий: если что-то по-настоящему нравится, хочется получить это сразу, а не ходить кругами и намекать. Венера в Овне окрашивает саму способность любить и ценить в цвета решительности — симпатия быстро превращается в шаг навстречу, а красивым кажется то, что живо, смело и заряжено движением. Такой человек нередко первым признаётся, первым зовёт, первым тянется к тому, что зажигает интерес.

За этой прямотой стоит честность: чувства проще выразить в действии, чем прятать за расчётом. Оборотная сторона — азарт может остывать так же стремительно, как вспыхнул, и то, что вчера пленяло, сегодня уже наскучило. Это не приговор, а склонность: осознанность помогает отличить мимолётную искру от того, что стоит терпения. Многое зависит от всей карты целиком и от того, куда человек решает направить свой пыл — в погоню за новизной или в смелость оставаться рядом, когда первый огонь превратился в ровное тепло.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_sign:venus:cancer', 'western', 'Дом — вот где эта Венера чувствует себя собой. Тёплая кухня, забота, которую проще проявить делом, чем словом, память о тех, кто дорог, — привязанность в знаке Рака питается близостью и ощущением защищённости. Любить для такого человека часто значит опекать, кормить, создавать гнездо, в котором родному тепло; красивым кажется то, что хранит следы душевности и истории.

Чувства здесь глубоки и текучи, как приливы: настроение способно меняться, а прошлое остаётся живым куда дольше, чем у других. Это даёт удивительную преданность, но и уязвимость: обиду легко впитать и трудно отпустить. Оборотная сторона чуткости — риск раствориться в заботе о других, забыв о себе. Это не приговор, а склонность: то, как она развернётся, зависит от осознанного выбора и всей карты целиком. Замечать собственные границы — не эгоизм, а способ сделать свою нежность щедрой, а не жертвенной.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('planet_in_sign:venus:capricorn', 'western', 'Эта Венера доверяет времени. В знаке Козерога чувство проверяется делом и сроком: слова значат меньше, чем поступки, повторённые изо дня в день. Любить для такого человека — значит брать ответственность, быть опорой, строить то, что выдержит годы, а не сезон. Признания даются ему сдержанно, зато за скупой формой нередко стоит глубокая, надёжная преданность.

Вкус тяготеет к качеству и достоинству: ценится не мода, а вещи, которые не стыдно передать дальше. Оборотная сторона серьёзности — привычка сдерживать нежность, ставить долг выше близости и не позволять себе лёгкости. Понимание этой черты помогает мягче обходиться с собой: терпение и верность — большая сила, если не превращать любовь в ещё одну обязанность. Как именно проявится эта склонность, зависит от осознанности и всей карты в целом; теплу тоже стоит оставлять место в расписании.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
