  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('point_in_house:north_node:7', 'karmic', 'Другой человек — как зеркало и как задача — выходит здесь на первый план. Северный узел в седьмом доме располагает к тому, чтобы учиться настоящему партнёрству: слышать, договариваться, делить пространство и находить силу в союзе, а не только в самодостаточной автономии.

Рост тут — в готовности встретить кого-то на равных, без желания всё решать в одиночку и без страха потерять себя рядом с близким. Это приглашение к диалогу, компромиссу и доверию, которые не отменяют личность, а раскрывают её иначе. Проявится ли тенденция как крепкие союзы или как долгая учёба отношениям — зависит от осознанности и всей карты; узел не предопределяет сценарий, он лишь намечает, где человек взрослеет через связь с другим.', 'reviewed', 2)
