  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('point_in_house:north_node:8', 'karmic', 'Есть слой жизни, куда не заглянёшь мимоходом: близость без масок, общие деньги и доверие, кризисы, которые меняют человека изнутри. Северный узел в восьмом доме склоняет к тому, чтобы не бояться этой глубины — входить в перемены, отпускать отжившее и учиться подлинному соединению ресурсов и чувств с другим.

Это территория трансформации в её символическом смысле — не финала, а обновления, когда старое отступает, освобождая место новому. Задача-подсказка — довериться процессу, признать силу общего и перестать держать всё под единоличным контролем. Насколько интенсивно раскроется склонность, решают выбор и вся карта целиком: узел ничего не предвещает, лишь указывает, где рост идёт через отпускание и близость.', 'reviewed', 2)
