  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('point_in_house:north_node:9', 'karmic', 'Дальняя дорога, большие вопросы и поиск смысла, выходящего за пределы привычного двора, — вот куда устремлён этот вектор. Северный узел в девятом доме располагает к тому, чтобы расширять горизонт: учиться, путешествовать, выстраивать собственное мировоззрение и доверять большой картине, а не тонуть в частностях и чужих готовых мнениях.

Рост здесь — в смелости мыслить шире, искать свою правду и не бояться незнакомого: иной культуры, иной идеи, иного берега. Это приглашение перейти от коллекционирования разрозненных фактов к цельному взгляду на мир. Как именно проявится склонность — зависит от осознанности и всей конфигурации карты; узел не диктует маршрут, он лишь показывает, куда тянется жажда смысла.', 'reviewed', 2)
