  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('point_in_house:selena:1', 'karmic', 'Внутренний свет здесь считывается раньше, чем произнесено первое слово: Селена в первом доме связывает лучшую, светлую сторону натуры с самим способом являть себя миру. Это склонность нести в облике и в первом жесте что-то располагающее — не наигранное обаяние, а спокойное достоинство, которое смягчает даже трудные знакомства. В том, как такой человек берётся за новое дело, нередко чувствуется внутренний ориентир: тяга поступать по совести, начинать честно, без подвоха. Проявится ли это в полной мере, зависит от осознанности и от карты целиком — Селена не наделяет безупречностью, а лишь подсказывает, где у характера есть опора на светлое. Развивая эту грань, человек располагает к тому, чтобы само его присутствие становилось для других знаком, что рядом можно выдохнуть и довериться.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('point_in_house:selena:10', 'karmic', 'То, каким человека видят в деле и в обществе, — карьера, статус, репутация — становится сценой, на которой Селена в десятом доме проявляется заметнее всего. Светлая сторона натуры проступает в отношении к своему призванию: в склонности добиваться цели, не переступая через других, и дорожить добрым именем больше, чем громкой должностью. Такому человеку часто важно, чтобы его дело приносило пользу, а не только признание; репутация честного и надёжного здесь дороже быстрых побед. В публичной роли он способен быть примером спокойного достоинства. Это тенденция, а не обещание высот и наград: положение раскрывает лучшее лишь тогда, когда человек несёт его ответственно. Но склонность превращать статус в возможность служить, а не властвовать, у Селены в этом доме выражена особенно внятно.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('point_in_house:selena:11', 'karmic', 'Круг единомышленников, общие мечты, дело, которое делается сообща, — вот где Селена в одиннадцатом доме чувствует себя на своём месте. Светлая сторона натуры разворачивается в дружбе и коллективных начинаниях: здесь заметна склонность быть тем человеком, который скрепляет группу теплом, а не выгодой, и искренне радуется чужим успехам. Такому человеку часто важны цели, выходящие за пределы личного, — идеи о лучшем будущем, проекты на общее благо. В компании он нередко становится негласной опорой, к которой тянутся за поддержкой. Это склонность, а не гарантия верных друзей и сбывшихся планов: сообщество способно и вдохновлять, и разочаровывать. Но дар вносить в общие связи бескорыстие и надежду, ради которой хочется объединяться, у Селены в этом доме проявлен особенно ясно.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
