  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('point_in_house:selena:12', 'karmic', 'Тишина, в которой человек остаётся наедине с собой, — размышление, молитва, всё, что скрыто от посторонних глаз, — становится главным пространством Селены в двенадцатом доме. Светлая сторона натуры здесь уходит вглубь: в склонность к внутренней работе, состраданию без огласки, тихой помощи, о которой никто не узнает. Такому человеку часто свойственна особая чуткость к незримому — к настроениям, к чужой скрытой боли, к тонкой ткани переживаний. Уединение для него не наказание, а источник, из которого он возвращается обновлённым. Это склонность, а не приговор к одиночеству: свет двенадцатого дома разгорается, когда человек не прячется от себя, а честно встречается с внутренним миром. Именно здесь, вдали от шума, Селена нередко проявляет себя тише всего — и вместе с тем глубже всего.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('point_in_house:selena:2', 'karmic', 'Отношение к тому, чем владеешь, бывает разным — и у Селены во втором доме оно окрашено бережностью и внутренней щедростью одновременно. Светлая сторона натуры разворачивается в сфере ресурсов, устойчивости и ценностей: здесь заметна склонность зарабатывать и тратить так, чтобы не терять себя, чувствовать «достаточно» там, где другого тянет к жадности или тревоге. Деньги для такого человека нередко становятся продолжением совести — их приятно не только копить, но и вкладывать во что-то доброе. Это не обещание богатства и не лёгкость с финансами по умолчанию; скорее тенденция находить опору в простых надёжных вещах и делиться, не обедняя себя. Насколько раскроется этот дар меры, решают выборы человека и вся конфигурация карты — Селена лишь показывает, что в области материального у него есть тихий внутренний свет.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('point_in_house:selena:3', 'karmic', 'Короткий разговор в коридоре, письмо другу, вопрос, заданный вовремя, — повседневная ткань общения становится тем полем, где Селена в третьем доме проявляется ярче всего. Светлая сторона натуры прячется в мелочах речи: в умении сказать доброе слово к месту, объяснить без снисхождения, услышать собеседника раньше, чем начать спорить. Такому человеку часто свойственна лёгкая, незлобивая любознательность — тяга учиться и делиться узнанным без желания блеснуть. Ближайшее окружение, соседи, братья и сёстры нередко ощущают рядом с ним что-то успокаивающее. Это склонность, а не предопределённость: злословие и суета способны заглушить этот свет, а внимательность к словам — усилить. От того, как человек распорядится своей речью, и зависит, станет ли она источником тепла для тех, кто рядом.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('point_in_house:selena:4', 'karmic', 'Дом как место, куда хочется возвращаться, — вот образ, ближе всего описывающий Селену в четвёртом доме. Светлая сторона натуры уходит корнями в тему семьи, происхождения и внутренней опоры: здесь заметна склонность создавать вокруг себя атмосферу, в которой другим становится спокойнее дышать. Такой человек нередко бережёт память рода, тянется примирять близких, хранить то доброе, что передалось из детства, — даже если само детство было непростым. Своё внутреннее «здесь я в безопасности» он способен носить с собой и делиться им. Это не обещание идеальной семьи и не приговор судьбы: тепло очага раскрывается настолько, насколько человек сам решает его беречь и передавать. Но склонность быть тихим корнем, к которому тянутся за поддержкой, у Селены в этом доме выражена особенно ясно.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('point_in_house:selena:5', 'karmic', 'Там, где начинается игра, влюблённость и чистая радость творчества, Селена в пятом доме чувствует себя как дома. Светлая сторона натуры раскрывается через самовыражение: в желании создавать, дарить восхищение, проживать жизнь ярко и при этом не в ущерб другим. Такому человеку часто свойственна способность радоваться щедро и заражать этой радостью — будь то в искусстве, в отношениях с детьми или в самом умении удивляться. В романтике здесь проступает не жажда завоевания, а тяга к искренности и красоте чувства. Это склонность, а не гарантия счастливой любви или большого таланта: свет пятого дома разгорается, когда человек творит от полноты, а не ради признания. Развивая эту грань, он располагает к тому, чтобы вносить в мир немного больше тепла и живого света, чем взял.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('point_in_house:selena:6', 'karmic', 'Незаметный порядок вещей — вовремя сделанное дело, прибранное рабочее место, внимание к собственному самочувствию — становится территорией, где Селена в шестом доме раскрывается лучше всего. Светлая сторона натуры проступает в повседневном труде и заботе: в склонности служить не из-под палки, а по внутреннему согласию, находить смысл в малых обязанностях и поддерживать бодрость через простой распорядок. Такой человек нередко умеет заботиться о других деликатно, без навязчивости, и относиться к своему телу как к союзнику, а не как к механизму. Это тенденция, а не приговор: рутина способна и вдохновлять, и выматывать — многое зависит от того, наполняет ли человек её смыслом. Там, где он превращает обыденное в тихую форму добра, свет Селены в этом доме проявляется особенно естественно.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('point_in_house:selena:7', 'karmic', 'Встреча с другим человеком как с равным — вот где Селена в седьмом доме находит своё главное поле. Светлая сторона натуры разворачивается в партнёрстве, союзах и умении договариваться: здесь заметна склонность искать в отношениях не выгоду, а согласие, смягчать острые углы и видеть в собеседнике не соперника, а зеркало. Такому человеку часто удаётся вносить в близкие связи ноту справедливости и доброжелательности — быть тем, рядом с кем хочется становиться лучше. В браке и деловых договорённостях он тяготеет к честности и балансу. Это склонность, а не обещание безоблачных отношений: гармония в союзе рождается из усилий обоих и из зрелости самого человека. Но дар превращать «ты и я» в нечто большее, чем простая сумма двоих, у Селены в этом доме выражен по-особому.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('point_in_house:selena:8', 'karmic', 'Глубина, в которую другие боятся заглядывать, — общие ресурсы, кризисы, всё, чем люди делятся на пределе доверия, — оказывается той областью, где Селена в восьмом доме проявляется сильнее всего. Светлая сторона натуры здесь связана со способностью проходить через внутренние перемены, не теряя себя, и выносить из них не ожесточение, а мудрость. Такой человек нередко умеет бережно обходиться с чужими тайнами и болью, быть опорой в трудный час, честно распоряжаться тем, что доверено сообща. Тема трансформации звучит как обновление, сбрасывание старой кожи, а не как повод для страха. Это склонность, а не предопределение: глубина способна и питать, и затягивать — многое решает выбор человека доверять жизни. Там, где он превращает потрясение в рост, свет Селены в этом доме различим особенно ясно.', 'reviewed', 2)
