  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('point_in_house:selena:9', 'karmic', 'Тяга к дальним горизонтам — и географическим, и смысловым — задаёт тон Селене в девятом доме. Светлая сторона натуры раскрывается через поиск мировоззрения, обучение высшего порядка и открытость широкому миру: здесь заметна склонность искать истину не ради спора, а ради опоры, и делиться найденным без назидания. Такому человеку часто свойственна внутренняя вера — не обязательно религиозная, скорее ощущение, что у жизни есть смысл и добрый порядок. Он тянется учить и учиться, путешествовать, узнавать чужие культуры с уважением. Это склонность, а не гарантия мудрости или удачных странствий: широта взгляда легко оборачивается высокомерием, если забыть о смирении. Но когда человек хранит любопытство и терпимость, свет Селены в этом доме превращает знание в подлинный внутренний ориентир.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
