  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('point_in_house:south_node:1', 'karmic', 'Есть люди, для которых умение действовать в одиночку — не подвиг, а привычка, впитанная будто с рождения. Южный узел в первом доме описывает именно такую натоптанную тропу: сфера личности, того, как человек заявляет о себе и берётся за новое, ощущается предельно освоенной, почти автоматической. Здесь легко быть первым, полагаться только на себя, разворачивать инициативу без оглядки — и в этом кроется соблазн раз за разом возвращаться к знакомому сценарию «я сам». Такое положение не приговор и ничего не предопределяет: скорее оно подсказывает, где накоплен богатый, но уже привычный опыт. Тенденция — опираться на собственную самодостаточность там, где полнее раскрыться помогло бы доверие к другим и совместное действие. Насколько это проявится, зависит от осознанности и всей карты целиком; сам же узел лишь очерчивает зону, куда тянет по инерции.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('point_in_house:south_node:10', 'karmic', 'У иных ответственность становится почти второй кожей: держать планку, отвечать за результат, выстраивать имя и положение в мире привычно настолько, что отдых ощущается едва ли не виной. Южный узел в десятом доме рисует именно такую картину: карьера, статус и публичная репутация проработаны основательно, а роль ответственного и достигающего надета как удобный костюм. Здесь легко брать управление на себя, соответствовать ожиданиям, мерить себя признанием и высотой должности. Тенденция — возвращаться к образу человека на виду, к контролю и делу как к единственно надёжной опоре. Это не приговор и ничего не обещает наперёд: узел лишь показывает область, где амбиция и собранность отлажены до автоматизма. Тонкость в том, что привычка держать фасад может отодвигать тепло частной жизни и право быть уязвимым вне сцены. Как проявится этот акцент — зависит от выбора и всего строя карты.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('point_in_house:south_node:11', 'karmic', 'Раствориться в кругу единомышленников, жить общими планами, чувствовать себя частью чего-то большего — эта принадлежность бывает такой естественной, что вне группы человек будто теряет очертания. Южный узел в одиннадцатом доме описывает именно это: дружеские сообщества, цели на будущее и коллективные проекты ощущаются обжитым домом, где привычно быть своим среди многих. Здесь легко служить общей идее, полагаться на команду, мерить смысл масштабом и будущим. Склонность — прятаться за «мы» и дальние горизонты замыслов, откладывая собственное, личное и сегодняшнее. Ничего фатального тут нет: узел отмечает зону, где чувство общности отточено до привычки. Тонкость в том, что растворение в коллективе и идеалах может заглушать тихий голос личной радости и творчества здесь и сейчас. Насколько дар быть частью целого станет крылом, а не убежищем, проступит только в общем рисунке карты.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('point_in_house:south_node:12', 'karmic', 'Тишина и внутренние миры бывают человеку не тягостью, а самым родным пристанищем: уйти в тень, побыть наедине с собой, раствориться в созерцании тянет как к чему-то давно своему. Так проявляет себя Южный узел в двенадцатом доме: уединение, внутренняя работа и всё, что остаётся за кадром, ощущаются привычным убежищем. Здесь легко отступать от суеты, погружаться в мечты и созерцание, служить незаметно и тихо, скрываться от яркого света внешней жизни. Тенденция — снова уходить в укрытие, растворять себя там, где мир просит присутствия и ясного участия. Это не судьба и ничего не предопределяет: узел лишь отмечает область, где отрешённость и внутренняя жизнь накоплены с избытком. Тонкость в том, что привычка исчезать может отодвигать простые, земные дела и заботу о теле, через которые тоже приходит опора. Проявится ли это как дар глубины или как ускользание — покажет лишь весь контекст карты и мера осознанности.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('point_in_house:south_node:2', 'karmic', 'Ощущение почвы под ногами через то, чем владеешь, — знакомая опора, к которой рука тянется сама. Во втором доме Южный узел разворачивает свою тему в области ресурсов, материальной устойчивости и личных ценностей: именно здесь накоплен привычный навык обустраивать надёжность, держаться за проверенное, измерять себя тем, что удалось собрать и сохранить. Склонность — искать спокойствие в осязаемом и постоянном, возвращаться к стратегии «сначала обеспечу тыл». Это не хорошо и не плохо и уж точно не предрешено: узел лишь отмечает, где комфорт освоен настолько, что стал почти рефлексом. Тонкость в том, что чрезмерная привязка к однажды выстроенной устойчивости может тихо тормозить там, где просилось бы больше гибкости и готовности отпускать. Как именно отзовётся этот акцент — вопрос выбора и общего рисунка карты, а не фатальной программы.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('point_in_house:south_node:3', 'karmic', 'Разговоры, короткие поездки, обмен новостями, вечное любопытство к тому, что рядом, — эта среда бывает обжитой до последнего уголка. Такую картину рисует Южный узел в третьем доме: сфера повседневного общения, учёбы и ближайшего окружения ощущается родной, а ум привычно собирает факты, крутит их, переключается с темы на тему. Здесь легко быть своим среди соседей и знакомых, ловко находить слова, скользить по поверхности множества сведений. Тенденция — растворяться в потоке мелкой информации и знакомых контактов, оставаясь в кругу уже проверенного. Ничего фатального в этом нет: узел не диктует событий, а показывает область, где реакции отлажены до автоматизма. Стоит помнить, что накопленная лёгкость в словах — это ресурс, а не потолок; насколько она станет опорой или колеёй, решает осознанность и весь ансамбль карты.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('point_in_house:south_node:4', 'karmic', 'Тяга под родную крышу, к знакомым стенам и семейному укладу порой сильнее любых доводов. Южный узел в четвёртом доме говорит как раз об этом: тема дома, корней и внутренней семейной опоры проработана глубоко, почти на уровне телесной памяти. Здесь привычно искать защиту в прошлом, в атмосфере детства, в кругу близких, где всё предсказуемо и согрето. Располагает это к тому, чтобы отступать в надёжное убежище всякий раз, когда мир снаружи требует шага вперёд. Такое положение не судьба и ничего не обещает наперёд — оно лишь очерчивает зону наибольшего комфорта, ту, что тянет к себе по инерции. Богатый эмоциональный тыл может быть и крыльями, и якорем: многое зависит от того, насколько человек готов опираться на корни, не прирастая к ним намертво. Проявление всегда индивидуально и читается только в контексте всей карты.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('point_in_house:south_node:5', 'karmic', 'Быть замеченным, творить, влюбляться, проживать момент ярко — для кого-то это стихия столь родная, что кажется единственно возможной. Именно её подсвечивает Южный узел в пятом доме: творческое самовыражение, романтика и вкус к радости жизни ощущаются как хорошо разученная партия. Здесь легко очаровывать, выходить на сцену, искать восторг и признание, возвращаться к роли того, вокруг кого всё вращается. Склонность — снова и снова тянуться к аплодисментам и острому переживанию удовольствия как к привычному топливу. В этом нет ни вины, ни предрешённости: узел просто отмечает область, где обаяние и игра отлажены до блеска. Тонкость в том, что жажда быть в центре может незаметно заслонять более тихую радость сопричастности и общего дела. Останется ли дар самовыражения свободным крылом или станет капризной привычкой — покажет только весь рисунок карты и мера осознанности.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('point_in_house:south_node:6', 'karmic', 'Списки дел, выверенный распорядок, привычка приносить пользу — всё это может срабатывать раньше, чем человек успеет подумать. Об этом рассказывает Южный узел в шестом доме: сфера повседневной рутины, работы и заботы о теле освоена до тонкостей, до любви к отлаженным процедурам. Здесь легко служить, помогать, замечать детали, держать быт и распорядок в чётких рамках. Тенденция — искать опору в занятости и порядке, растворяться в списках дел и мелких обязанностях как в чём-то надёжно знакомом. Это не приговор и не программа событий: узел лишь показывает область, где старательность стала почти рефлексом. Стоит помнить, что бесконечная шлифовка деталей и привычка быть нужным способны заслонять более широкую картину и право просто быть, а не только делать. Забота о самочувствии здесь тоже привычна — вопрос лишь в том, служит ли она бодрости или превращается в тревожный контроль; ответ всегда индивидуален.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('point_in_house:south_node:7', 'karmic', 'Смотреть на себя глазами близкого человека, сверять решения с партнёром, искать целостность в паре — этот навык у некоторых доведён почти до совершенства. Южный узел в седьмом доме описывает именно такую обжитую территорию: партнёрство, брак и открытые договорённости с другими ощущаются привычной средой, где легко подстроиться, уступить, найти общий язык. Здесь тянет определять себя через «мы», опираться на чужое присутствие как на само собой разумеющееся. Склонность — снова растворяться в отношениях, доверять руль другому там, где стоило бы услышать собственный голос. Ничего предрешённого в этом нет: узел лишь отмечает зону накопленной дипломатии и умения быть вдвоём. Тонкость в том, что привычка опираться на партнёра может тихо отодвигать собственную опору и самостоятельный шаг. Как это проявится — зависит от осознанности и всего рисунка карты, а не от фатума.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('point_in_house:south_node:8', 'karmic', 'Бывает, что человека неудержимо тянет на глубину — к острым поворотам, чужим тайнам и общим ресурсам, где всё будто происходит по-настоящему, а спокойная гладь на этом фоне кажется пресной. Такую натуру выводит на первый план Южный узел в восьмом доме: тема совместных ресурсов, глубоких трансформаций и того, чем делятся на самом сокровенном уровне, проработана до дна. Здесь привычно жить на пределе, сливаться с другим, проходить через кризисы и возрождения, распоряжаться не только своим. Тенденция — тянуться к интенсивности и перелому как к знакомому способу чувствовать себя живым, доверять управление общему котлу. Это не судьба и ничего не предопределяет — узел показывает область, где опыт глубины накоплен с избытком. Тонкость в том, что жажда постоянного накала и слияния может заслонять простую ценность собственной устойчивости и покоя. Проявится ли это как дар проникать в суть или как привычка к драме — вопрос осознанности и всей карты.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('point_in_house:south_node:9', 'karmic', 'Иметь ответ на любой большой вопрос, видеть общий смысл, тянуться к дальним странам и высоким идеям — такая широта порой становится второй природой. На это указывает Южный узел в девятом доме: мировоззрение, обучение высшего порядка и дальние горизонты ощущаются освоенной высотой, с которой удобно обозревать жизнь. Здесь легко проповедовать, обобщать, верить в свою картину мира, отправляться за истиной вдаль. Склонность — опираться на уже сложившиеся убеждения и общие принципы как на готовый компас, скользя над частностями. В этом нет ни ошибки, ни предопределённости: узел отмечает зону, где убеждённость и охват стали привычкой. Тонкость в том, что уверенность в собственной правоте способна заслонять живое любопытство к конкретному и близкому. Станет ли накопленная мудрость опорой или догмой — решает осознанность и весь ансамбль карты, а не рок.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('point_in_sign:chiron:aquarius', 'karmic', 'Ощущение «я не отсюда», взгляд на компанию будто со стороны стекла — при Хироне в Водолее тема принадлежности к своим звучит особенно чутко. Уязвимой становится связь с коллективом: страх быть чужим, боль отвержения за непохожесть, метание между желанием влиться и гордым «мне никто не нужен». Собственная инаковость то кажется изъяном, то знаменем. Но именно из этой ранки рождается редкая ценность — способность принимать других такими, какие они есть, собирать вокруг себя тех, кому тоже негде было прижиться, отстаивать право на свободу и непохожесть. Ничто здесь не предрешено: это чувствительная зона, а не готовый сценарий, и её звучание меняется вместе с осознанностью и всей картой.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('point_in_sign:chiron:aries', 'karmic', 'Право хотеть, действовать первым, занимать своё место — у кого-то эта тема будто натёрта до чувствительности. При Хироне в Овне именно там, в области личной смелости и прямого «я хочу», ощущается самая тонкая струна карты. Порыв заявить о себе может смущать, злость казаться опасной, а инициатива — отдавать виной, будто желать за себя неприлично. Зато здесь же спрятан целительный ресурс: раз за разом разрешая себе действовать по-своему, человек нередко становится тем, кто умеет поддержать чужую решимость, разглядеть робеющего и подтолкнуть его к первому шагу. Это склонность, а не приговор: острота темы и её плоды во многом определяются осознанностью и всей картой в целом.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('point_in_sign:chiron:cancer', 'karmic', 'Дом, семья, право быть принятым просто так — при Хироне в Раке эта область будто без кожи. Тепла здесь хочется до дрожи, и оно же ранит: чужая холодность читается острее, память о ранних обидах держится дольше, а забота о близких порой оборачивается тревогой «а достаточно ли я делаю». Человек может одновременно жаждать уюта и не верить, что заслужил его. Но именно из этой чувствительности рождается редкий дар — согревать, чувствовать чужую боль без слов, создавать пространство, где другому наконец спокойно. Это склонность, а не приговор: острота темы со временем смягчается, а во что она вырастет, зависит от выбора и всей карты целиком.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('point_in_sign:chiron:capricorn', 'karmic', 'Сколько ни достигни, внутри всё равно звучит «мало» — при Хироне в Козероге эта нота знакома особенно хорошо. Уязвимой оказывается тема состоятельности и признания заслуг: ответственность давит рано и тяжело, право на отдых и на несовершенство приходится буквально отвоёвывать, а за холодной собранностью нередко прячется давний страх оказаться недостаточно взрослым и нужным. Зато из этого опыта вырастает надёжность особой пробы: такие люди становятся опорой и наставниками, теми, кто выдерживает вес и учит других строить прочно. Это не приговор, а склонность: то, как она проявится, во многом зависит от осознанного выбора и всей карты.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
