  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('point_in_sign:chiron:gemini', 'karmic', 'Иногда человек с ранних лет носит тихое подозрение: мои слова весят меньше чужих, меня недослушивают, я не так быстр и не так умён, как надо. При Хироне в Близнецах эта струна натянута особенно туго. Чувствительными становятся речь, обучение и право быть понятым: похвала за сообразительность греет сильнее обычного, а насмешка или «глупый вопрос» ранят глубже. И тут же — целительный поворот: именно такие люди часто вырастают в чутких собеседников и объяснителей, которые умеют подобрать слово для того, кому трудно выразить себя. Ничего не предопределено заранее: это направление, чувствительная зона, а не сценарий. Как она зазвучит, зависит от осознанности и от карты в целом.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('point_in_sign:chiron:leo', 'karmic', 'Выйти на свет и услышать «ты особенный» хочется до дрожи — и до дрожи же страшно. При Хироне во Льве тонкой становится тема признания и творческого самовыражения: критика бьёт по самому сокровенному, тихий вопрос «а есть ли во мне что-то ценное?» может звучать годами, и порой человек прячет своё яркое, лишь бы не рисковать. Зато тот же Хирон дарит особую щедрость к чужому таланту — умение разглядеть искру в другом, по-настоящему за неё порадоваться и помочь ей разгореться. Это не сценарий, а склонность: то, насколько ярко прозвучит тема, определяют осознанность и остальные грани карты.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('point_in_sign:chiron:libra', 'karmic', 'Отношения — та самая область, где при Хироне в Весах любое прикосновение отзывается сильнее обычного. Остро переживается всё, что связано с близостью на равных: страх быть отвергнутым, привычка подстраиваться ради мира, тихое ощущение «со мной будут, только если я удобен». Ссора или холодок в паре ранят глубже, чем видно со стороны, а поиск согласия и справедливости порой превращается в бесконечную работу. Но именно отсюда вырастает редкий талант — чувствовать чужую позицию, мирить, создавать между людьми пространство уважения. Со временем человек учится опираться на себя, а не растворяться в другом. Это склонность, а не приговор: во что она развернётся, решают выбор и вся карта.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('point_in_sign:chiron:pisces', 'karmic', 'Чувствовать больше, чем выдерживаешь, впитывать чужое настроение как своё, тосковать по чему-то безбрежному и невыразимому — при Хироне в Рыбах эта тонкость обострена до предела. Ранимыми оказываются границы и вера: легко потеряться в сострадании, спасать других в ущерб себе, прятаться от резкого мира в мечтах или разочаровываться, когда реальность оказывается грубее идеала. И здесь же — глубокий целительный дар: понимать без слов, утешать, чувствовать невидимое, возвращать людям надежду. Со временем приходит умение сострадать «с берегами» — оставаться открытым, но не растворяться. Это не сценарий, а склонность: как она проявится, зависит от осознанного выбора и всей карты целиком.', 'reviewed', 2)
