INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('point_in_sign:chiron:sagittarius', 'karmic', 'Во что верить и где искать смысл — при Хироне в Стрельце это не отвлечённый вопрос, а живая, порой саднящая тема. Уязвимыми оказываются вера, свобода и право на собственную правду: человек может метаться между жаждой большого смысла и разочарованием в прежних ориентирах, бояться, что его убеждениям не поверят, или прикрывать неуверенность нарочито громкой уверенностью. И здесь же — целительный дар: возвращать другим надежду, показывать перспективу там, где всё сузилось до тупика, вдохновлять на путь. Постепенно опора находится не в готовых догмах, а в живом, честном поиске. Это склонность, а не приговор — во что она вырастет, зависит от осознанного выбора и всей карты в целом.', 'reviewed', 2)
