  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('point_in_sign:chiron:scorpio', 'karmic', 'Есть люди, для которых впустить другого по-настоящему близко — почти подвиг. При Хироне в Скорпионе тема доверия и глубокой связи заряжена особой силой и риском. Чувствительными становятся близость и всё, что касается утрат: предательство здесь помнится долго, контроль кажется способом уберечься, а сильные чувства то притягивают, то пугают своей бездонностью. Иногда проще спрятать самое настоящее за бронёй. Но в этой же глубине зреет редкая сила — проходить с человеком его кризисы, не отводя глаз, быть рядом там, где другие отступают, помогать возрождаться после потерь. Это не сценарий, а склонность: острота темы и её плоды во многом зависят от осознанности и всей карты целиком.', 'reviewed', 2)
