INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('point_in_sign:chiron:taurus', 'karmic', 'Сколько нужно иметь под ногами, чтобы наконец выдохнуть и почувствовать себя в безопасности? При Хироне в Тельце этот вопрос звучит непривычно остро. Уязвимой оказывается сама тема ценности — своей и материальной: ощущение «мне не хватает», сомнение в собственной весомости, непростые отношения с деньгами, телом, покоем и правом на удовольствие. Но в этой же почве вызревает редкое умение — замедляться, обходиться с собой бережно, находить опору не только во внешнем достатке. Люди с таким положением со временем нередко становятся спокойной опорой для других, теми, рядом с кем перестаёт трясти. Это не диктует судьбу, а лишь намечает склонность: во что она развернётся, решают выбор и остальные акценты карты.', 'reviewed', 2)
