INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('point_in_sign:chiron:virgo', 'karmic', '«Недостаточно хорошо» — фраза, которая при Хироне в Деве способна звучать фоном многие годы. Уязвимой оказывается тема совершенства и пользы: хочется сделать всё безупречно, а внутренний критик находит изъян даже там, где другие видят отличный результат. Отсюда придирки к себе, страх ошибки, ощущение, что любовь надо заслужить старанием. И здесь же — целительная сторона: внимательность к деталям, умение по-настоящему помочь и навести порядок там, где у других опускаются руки. Постепенно приходит и главное открытие: ценность не нужно всё время доказывать. Это не приговор, а всего лишь склонность — во что она вырастет, во многом решает то, как человек с ней обходится, и вся карта в целом.', 'reviewed', 2)
