  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('point_in_sign:lilith:aquarius', 'karmic', 'Чувство «я не отсюда», которое одни носят как рану, а другие — как знамя. Лилит в Водолее указывает на непризнанную инаковость: право быть не как все, думать поперёк, держаться на своей орбите. Порой ребёнку дали понять, что странность — это плохо, и живая независимость ушла в тень, откуда возвращается то показным бунтом, то холодной отстранённостью, то страхом принадлежать хоть какой-то группе. За этим не эпатаж ради эпатажа, а подавленное право на собственную непохожесть. Признав её, человек находит редкую свободу: умение мыслить свежо, дружить без слияния, менять правила там, где они устарели. Как раскроется эта тенденция — как вечный протест или как спокойная самобытность — во многом зависит от осознанного выбора и от карты целиком. Это не участь, а направление, которое человек задаёт себе сам.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('point_in_sign:lilith:aries', 'karmic', 'Есть в каждом порыв, который когда-то научили приглушать, — прямое «я хочу», не спрашивающее разрешения. В карте Овна Лилит указывает именно на эту вытесненную волю: азарт, здоровую злость, готовность идти первой и не извиняться за желание побеждать. Нередко такой напор с детства называли «слишком резким», и естественная энергия обернулась чувством вины за собственную настойчивость. Понять это — значит перестать воевать с собой. Тень здесь не в силе, а в её запрете: подавленный огонь тлеет исподволь и прорывается вспышками там, где хотелось бы спокойствия. Когда человек возвращает себе право хотеть открыто, тот же импульс становится опорой — умением защищать границы и начинать без оглядки. Как именно развернётся эта склонность, зависит от осознанности и всей карты в целом; это приглашение к силе, а не приговор.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('point_in_sign:lilith:cancer', 'karmic', 'Голодная по теплу часть души, которую приучили не показывать, — вот о чём говорит Лилит в Раке. В тени здесь оказывается сама потребность в заботе и принадлежности: желание, чтобы тебя держали, укрывали, принимали слабым. Порой чувствительность в детстве встречали холодно, и человек решил, что нужда в близости — это стыдно; тогда она уходит вглубь и возвращается обидчивостью, привычкой опекать других вместо себя или страхом попросить о поддержке. За этим не капризность, а естественная жажда тепла, которой недодали права на существование. Признать её — значит перестать наказывать себя за уязвимость. Тот же исток даёт удивительную способность чувствовать чужое состояние и создавать вокруг настоящий дом. Обернётся ли это замкнутостью или зрелой заботой, зависит от осознанности и от всей карты — выбор остаётся за человеком.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('point_in_sign:lilith:capricorn', 'karmic', 'Право быть главным — и старый страх, что за амбицию накажут. Лилит в Козероге держит в тени именно честолюбие: желание влиять, строить, подниматься и распоряжаться своей жизнью, не оправдываясь за жажду власти над ней. Нередко человека рано научили, что рваться наверх «нескромно», и естественная воля к достижению спряталась — а из тени возвращается жёсткостью к себе, трудоголизмом или недоверием к собственному успеху. За этим не холодность, а вытесненное право занимать своё место всерьёз. Когда его признают, та же энергия становится зрелой ответственностью: умением держать структуру, доводить начатое, опираться на себя без надрыва. Обернётся ли это ледяным контролем или спокойным авторитетом — во многом дело осознанности и всей карты в целом. Это про мастерство взрослеть, а не про приговор.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('point_in_sign:lilith:gemini', 'karmic', 'Слово, которое просилось наружу, но осталось непроизнесённым, — вот с чего стоит начать разговор о Лилит в Близнецах. Здесь непризнанной оказывается сама речь: острый ум, любопытство без цензуры, право задавать неудобные вопросы и говорить не то, чего ждут. Иногда человеку рано внушили, что он «слишком много болтает» или «вечно спорит», и живая подвижность мысли ушла в тень — а оттуда даёт о себе знать внутренней разноголосицей, беспокойством, привычкой недоговаривать. На деле это не легкомыслие, а запертый дар выражать себя. Когда возвращаешь себе голос, та же энергия работает иначе: рождает точные формулировки, лёгкость в общении, смелость называть вещи своими именами. Форма, в которой раскроется эта тенденция, зависит от вашей внимательности к себе и от карты целиком — свободы тут больше, чем кажется.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('point_in_sign:lilith:leo', 'karmic', 'Желание сиять — и тайный страх, что за него осудят. Лилит во Льве держит в тени именно этот узел: право быть замеченным, гордиться собой, занимать центр без извинений. Многие с ранних лет усвоили, что «выпячиваться» нехорошо, и живая тяга к признанию спряталась — а спрятавшись, стала капризной: то преувеличенной жаждой похвалы, то показным равнодушием к тому, как сильно на самом деле хочется отклика. Здесь нет тщеславия как порока — есть подавленная творческая самость, которой запретили светить в полную силу. Когда человек разрешает себе быть видимым, тот же огонь превращается в щедрость, артистизм и умение вдохновлять, не требуя доказательств своей ценности. Как именно раскроется эта склонность — как борьба за внимание или как спокойное сияние — во многом зависит от осознанного выбора и всей карты.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('point_in_sign:lilith:libra', 'karmic', 'В отношениях иногда живёт та часть нас, которую мы отдали другому и перестали считать своей. Лилит в Весах указывает как раз на это: непризнанное право на собственное желание внутри связи, на несогласие, на то, чтобы нравиться себе, а не только нравиться. Бывает, человека рано научили быть удобным и гладким, и тогда живая тяга к близости смешивается со страхом конфликта — приходится угождать, откладывая своё «нет» и своё «хочу». За внешней уступчивостью прячется не слабость, а вытесненная способность быть равным партнёром. Признав её, человек находит редкое чувство меры: умеет создавать союз, не растворяясь, спорить, не разрушая, выбирать красоту без притворства. Обернётся ли это зависимостью от чужого одобрения или зрелым партнёрством — во многом зависит от осознанности и от всей карты.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('point_in_sign:lilith:pisces', 'karmic', 'Есть тонкость, которую в шумном мире легко списать на слабость, — способность растворяться, сострадать, чувствовать больше, чем можно объяснить словами. Лилит в Рыбах прячет именно её: право на мечту, на безграничность, на связь с тем, что лежит за пределами очевидного. Случается, что чувствительность и мечтательность в детстве обесценили — «витаешь в облаках», — и естественная глубина ушла в тень, откуда напоминает о себе тягой сбежать, спасать других в ущерб себе или терять свои границы. За этим не безволие, а вытесненное право быть проницаемым и мягким. Когда его признают, та же природа становится источником вдохновения, милосердия и почти безошибочного чутья. Обернётся ли она бегством от реальности или зрелым состраданием — во многом зависит от осознанности и от всей карты. Это приглашение к глубине, а не рок.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('point_in_sign:lilith:sagittarius', 'karmic', 'Тяга к простору и неудобная правда, которую хочется сказать вслух, — вот что Лилит в Стрельце нередко прячет от посторонних глаз. В тени здесь свобода и вера: право искать свой смысл, не спрашивая одобрения, жить широко и говорить как думаешь. Случается, что в детстве живость и прямоту осадили — «куда тебя понесло», — и естественная тяга к горизонту ушла вглубь, откуда даёт о себе знать беспокойством, категоричностью или бегством от всего, что связывает. За этим не безрассудство, а подавленное право быть вольным. Признав его, человек обретает редкую внутреннюю опору: убеждения без фанатизма, честность без грубости, умение вдохновлять смыслом. Станет ли эта склонность вечным побегом или зрелой свободой — во многом зависит от осознанного выбора и от всей карты.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('point_in_sign:lilith:scorpio', 'karmic', 'Глубина, которую принято обходить стороной, — страсть, власть, всё, что называют «слишком». Лилит в Скорпионе очерчивает эту заповедную зону: право на сильные желания, на близость без полумер, на честность с собственной темнотой. Часто такую интенсивность в детстве встречали испугом, и человек научился прятать её — а спрятанная, она возвращается ревностью, жаждой контроля или недоверием к самому себе. Здесь не порок, а огромная, загнанная вглубь витальность, которой отказали в праве проявиться. Когда её признают, та же сила становится способностью выдерживать кризисы, идти на настоящую близость и перерождаться там, где другие сдаются. Как развернётся эта тенденция — как борьба за власть или как честная глубина — во многом решает осознанность и вся карта; это про трансформацию, а не про рок.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('point_in_sign:lilith:taurus', 'karmic', 'Тело, вкус, неспешное удовольствие, ощущение собственной ценности — всё то, что иногда объявляют «низменным» или избыточным. Лилит в Тельце очерчивает эту территорию непризнанного: право обладать, наслаждаться, стоить дорого и не оправдываться за свои желания. Бывает, что тягу к комфорту и телесной радости человек прячет, считая её чем-то стыдным, — и тогда она возвращается упрямством, стремлением всё удержать или внезапной жадностью до впечатлений. За этим не порок, а недополученное разрешение просто хотеть. Стоит признать эту грань — и она превращается в редкую устойчивость: умение ценить себя без чужого одобрения, обходиться со своим телом бережно, выбирать качество вместо суеты. Проявится ли она как хватка собственника или как спокойное достоинство — во многом дело осознанного выбора и остальных нитей карты.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('point_in_sign:lilith:virgo', 'karmic', '«Со мной что-то не так» — тихая убеждённость, которую Лилит в Деве часто держит под спудом. В тени тут оказываются несовершенство и телесность: право быть неидеальным, ошибаться, не отмывать себя добела до бесконечности. Нередко человека рано приучили измерять себя пользой и аккуратностью, и естественное несовершенство превратилось в источник стыда — отсюда придирки к себе, гонка за безупречностью, ощущение вечной «недоделанности». За этим не занудство, а вытесненное право просто быть, а не заслуживать. Стоит признать эту грань — и дотошность оборачивается мастерством: вниманием к деталям, честной заботой о деле и о теле, умением наводить порядок там, где другие пасуют. Станет ли она самоедством или спокойной точностью, зависит от осознанности и от карты в целом — приговора здесь нет.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('point_in_sign:north_node:aquarius', 'karmic', 'Иногда самое важное начинается там, где твоё «я» встречается с «мы». Северный узел в Водолее выводит человека к широкому кругу: к идеям будущего, к дружеству и сообществу, к свободе быть непохожим и ценить непохожесть в других. Привычнее, может быть, добиваться личного признания и держаться в центре внимания — а зона роста раскрывается там, где ты отпускаешь потребность в аплодисментах ради общего дела и большего замысла. Это склонность, а не предопределённость: направление подсказано, но включиться в него — всегда выбор. Проявляться тема способна как тяга к новому и необычному, как интерес к прогрессу и коллективным проектам, как умение смотреть на жизнь трезво, чуть со стороны, замечая связи, которых не видно вблизи. Насколько ярко зазвучит эта грань, зависит от осознанности и карты в целом — узел лишь напоминает, что своё место в чём-то большем здесь стоит искать смелее.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('point_in_sign:north_node:aries', 'karmic', 'Стрелка внутреннего компаса здесь развёрнута в сторону смелости — той, что рождается, когда перестаёшь спрашивать разрешения. Северный узел в Овне намечает рост через самостоятельность: научиться начинать первым, отстаивать своё, действовать раньше, чем накопится страх. Привычнее, возможно, подстраиваться под других и растворяться в чужих ожиданиях — а зона развития лежит там, где решение принимаешь за себя сам. Это склонность, а не приговор: направление подсказано, но каждый шаг по нему остаётся выбором. Проявиться она может как тяга пробовать новое в одиночку, как умение сказать «я хочу» без долгих оправданий, как способность зажигаться собственным желанием, а не ждать импульса со стороны. Насколько живо раскроется эта грань, зависит от осознанности и от всей карты в целом — узел лишь показывает, куда стоит смелее шагнуть.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
