  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('point_in_sign:north_node:cancer', 'karmic', 'Расти можно не только вверх и вовне, но и вглубь — к теплу, к дому, к позволению чувствовать. Такой вектор задаёт Северный узел в Раке: он приглашает смягчиться, признать свои эмоции, научиться заботиться и принимать заботу, обустраивать пространство, где по-настоящему свои. Привычнее, вероятно, держать всё под контролем и мерить жизнь достижениями — а развитие ждёт там, где можно опереться на близость, а не на броню. Это склонность, а не сценарий с готовым финалом: направление подсказано, но каждый шаг к открытости человек делает сам. Проявиться оно может как тяга обустраивать гнездо, как чуткость к настроениям близких, как умение быть опорой и не стыдиться собственной уязвимости. Насколько глубоко раскроется эта грань, зависит от осознанности и всей карты — узел лишь показывает, что душевное тепло здесь не слабость, а точка роста.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('point_in_sign:north_node:capricorn', 'karmic', 'Взрослость — это не про возраст, а про готовность отвечать за свою жизнь; сюда и ведёт Северный узел в Козероге. Он намечает рост через ответственность: выстроить опору, освоить дело до мастерства, взять на себя роль и держать её, добиваться цели терпеливым восхождением. Привычнее, вероятно, искать защиты, опираться на близких и прошлое, оставаться в знакомом тепле — а развитие ждёт там, где ты становишься тем, на кого можно положиться. Это склонность, а не приговор: вершина видна, но каждый уступ на пути человек берёт по собственной воле. Проявляться тема может как тяга строить надолго, как уважение к дисциплине и структуре, как спокойная сила зрелости, что приходит с делом, доведённым до конца. Насколько высоко раскроется эта грань, зависит от осознанности и всей карты — узел лишь отмечает, куда стоит расти, чтобы прочно стоять на своих ногах.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('point_in_sign:north_node:gemini', 'karmic', 'Иногда взросление начинается с простого вопроса «а как на самом деле?». Северный узел в Близнецах разворачивает человека к любопытству: к живому интересу, к деталям, к умению слушать и переспрашивать, а не держаться за одну большую готовую истину. Комфортнее бывает вещать и убеждать, опираясь на общую картину, — а зона роста лежит в мелочах, в разговоре на равных, в готовности учиться у ближнего круга. Это не предопределённость, а склонность, и раскрывается она через выбор: задавать вопросы, собирать факты, связывать людей и мысли между собой. Проявляться тема может как тяга к чтению и письму, к обмену новостями, к лёгкости, с которой ум перескакивает с темы на тему и находит неожиданные мостики. Насколько ярко всё это оживёт, подскажет вся карта и мера внимательности — направление задано, шаги остаются за вами.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('point_in_sign:north_node:leo', 'karmic', 'Свет, который просишь у зала, на самом деле давно горит внутри. Северный узел во Льве ведёт человека к смелости этот свет показывать: творить от сердца, выходить на середину, радоваться, играть, быть собой заметно и без извинений. Привычнее, может быть, растворяться в общем, прятать «я» за интересами группы, ждать одобрения коллектива — а зона роста там, где ты позволяешь себе индивидуальность и авторский голос. Это склонность, а не приговор: направление намечено, но выбор — зажечься или притушить себя — остаётся твоим. Тема способна проявляться как тяга к творчеству, к сцене в любом её виде, к щедрой теплоте, которой хочется делиться, как умение вдохновлять просто фактом своего присутствия. Как именно раскроется этот огонь, зависит от осознанности и от карты в целом — узел лишь напоминает, что быть в центре собственной жизни не эгоизм, а задача роста.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('point_in_sign:north_node:libra', 'karmic', 'Другой человек — не помеха своей воле, а зеркало, в котором виднее ты сам. К этому подводит Северный узел в Весах: он намечает рост через партнёрство, сотрудничество, умение слышать чужую правду и искать равновесие вместо победы любой ценой. Привычнее, возможно, ставить своё на первое место и идти напролом в одиночку — а зона развития раскрывается там, где появляется «мы», где учишься уступать, договариваться, держать тонкий баланс интересов. Это склонность, а не предопределённость: направление подсказано, но каждый шаг навстречу другому остаётся выбором. Проявляться тема может как тяга к союзам и совместным делам, как чувство меры и вкуса, как способность сглаживать острые углы, не предавая себя. Насколько красиво зазвучит эта грань, зависит от осознанности и всей карты — узел лишь подсказывает, что искусство отношений здесь стоит осваивать всерьёз.', 'reviewed', 2)
ON CONFLICT ("key") DO UPDATE SET
  "text" = EXCLUDED."text",
  "quality" = 'reviewed',
  "version" = EXCLUDED."version",
  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('point_in_sign:north_node:pisces', 'karmic', 'Есть сила, которая приходит не через контроль, а через доверие, — и к ней склоняет Северный узел в Рыбах. Он намечает рост через мягкость: научиться отпускать, сострадать, прощать, доверять течению там, где раньше всё хотелось разложить по полочкам. Привычнее, вероятно, всё анализировать, поправлять, тревожиться о деталях — а развивающая тропа ведёт к принятию, к тишине внутри, к чувству связи со всем большим и целым. Это склонность, а не сценарий с готовым финалом: направление намечено, но каждый шаг к доверию человек делает сам. Проявляться тема может как тяга к творчеству и созерцанию, как тонкая чуткость к чужой боли, как умение отпустить лишнее и почувствовать, что не всё нужно держать в кулаке. Насколько глубоко раскроется эта грань, зависит от осознанности и всей карты — узел лишь намекает, что здесь мягкость и вера становятся точкой роста.', 'reviewed', 2)
