  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('point_in_sign:north_node:sagittarius', 'karmic', 'За частоколом мелких фактов иногда теряется главный вопрос — зачем. Северный узел в Стрельце зовёт к горизонту: к поиску смысла, к вере в большее, к широкому взгляду, который связывает разрозненное в цельную картину. Привычнее, может быть, тонуть в подробностях и чужих мнениях, перескакивать с темы на тему — а зона роста там, где рождается собственная убеждённость и доверие к внутреннему компасу. Это склонность, а не заданная колея: направление подсказано, но идти к своей правде человек решает сам. Проявляться тема способна как тяга к путешествиям и новым культурам, к учёбе ради смысла, к философии и дальним планам, как оптимизм, что помогает шагнуть за привычные границы. Как ярко раскроется этот простор, зависит от осознанности и карты в целом — узел лишь зовёт поднять взгляд выше и довериться дороге.', 'reviewed', 2)
