  "updated_at" = now();

INSERT INTO "interpretation_chunks" ("key", "tradition", "text", "quality", "version")
VALUES ('point_in_sign:north_node:scorpio', 'karmic', 'Порой рост требует отпустить то, за что держишься крепче всего. Такова тема Северного узла в Скорпионе: он зовёт в глубину — к честности с собой, к близости без брони, к готовности меняться и расставаться с отжившим ради нового. Привычнее бывает цепляться за комфорт, за нажитое, за спокойную неизменность — а развивающая тропа ведёт сквозь перемены, туда, где страшно, но живо. Это склонность, а не сценарий: направление намечено, но пройти его — всегда собственный выбор, шаг за шагом. Проявляться оно может как тяга к настоящей близости, как интерес к скрытому и глубинному, как сила, что рождается, когда переживаешь внутреннюю трансформацию и выходишь из неё обновлённым. Насколько полно раскроется эта грань, зависит от осознанности и всей карты — узел лишь указывает, что смелость смотреть в глубину здесь становится точкой роста, а не угрозой.', 'reviewed', 2)
